def _api_error(code, message, *, details=None):
    body = {"error": {"code": code, "message": message}}
    if details is not None:
        body["error"]["details"] = details
    return body


def _copy_jsonable(value):
    return json.loads(json.dumps(value))


def _live_agent_visible_action_contract(action_type):
    key = str(action_type or "").strip()
    contract = LIVE_AGENT_VISIBLE_ACTION_CONTRACTS.get(key)
    if not isinstance(contract, dict):
        return None
    copied = _copy_jsonable(contract)
    copied["serverExecutor"] = WORLD_ACTION_SERVER_RUNTIME_OWNER
    copied["serverRuntimeAuthority"] = True
    return copied


def _live_agent_visible_action_policy():
    return {
        "schemaVersion": LIVE_AGENT_VISIBLE_ACTION_CONTRACT_VERSION,
        "policy": "visible-world-execution-required",
        "hiddenWorldMutationAllowed": False,
        "appliesToSourceKind": "agent-live-mode",
        "requiredExecution": {
            "requiresWorldAction": True,
            "requiresMoveIntent": True,
            "requiresServerRuntimeAuthority": True,
            "requiresVisibleClientExecutor": True,
            "requiresVisibleCompletionEvent": True,
            "requiresPhysicalAgentPresence": True,
        },
        "proposalOnlyCapabilities": _copy_jsonable(LIVE_AGENT_PROPOSAL_ONLY_CAPABILITIES),
    }


def _live_agent_proposal_only_capability_for(action_type=None, capability_tag=None):
    action_key = str(action_type or "").strip()
    capability_key = str(capability_tag or "").strip()
    for capability in LIVE_AGENT_PROPOSAL_ONLY_CAPABILITIES:
        if action_key and action_key == capability.get("actionType"):
            return _copy_jsonable(capability)
    for capability in LIVE_AGENT_PROPOSAL_ONLY_CAPABILITIES:
        if capability_key and capability_key == capability.get("capabilityTag"):
            return _copy_jsonable(capability)
    if action_key.startswith("world.") or capability_key.startswith("world."):
        return {
            "id": f"{action_key or capability_key}.proposal",
            "actionType": action_key,
            "capabilityTag": capability_key,
            "label": action_key or capability_key,
            "status": "proposal_only",
            "blockedReason": "missing-visible-client-executor",
            "requiredExecutor": "typed-visible-world-executor",
            "requirement": "High-impact Live Mode world changes must be reviewed and given a typed visible executor before any persistent mutation is allowed.",
        }
    return None


def _validate_live_agent_visible_action_contract(payload, action_type=None, capability=None):
    if not isinstance(payload, dict):
        return None, None
    source = payload.get("source") if isinstance(payload.get("source"), dict) else {}
    if source.get("kind") != "agent-live-mode":
        return None, None
    resolved_action_type = str(action_type or payload.get("actionType") or payload.get("actionId") or "").strip()
    if not resolved_action_type:
        return None, None
    contract = _live_agent_visible_action_contract(resolved_action_type)
    if not contract:
        return None, _api_error(
            "hidden_action_not_allowed",
            "Agent Live Mode actions must have a visible world executor before they can mutate or reserve world state.",
            details={
                "actionType": resolved_action_type,
                "capabilityTag": capability or payload.get("capabilityTag"),
                "contractVersion": LIVE_AGENT_VISIBLE_ACTION_CONTRACT_VERSION,
                "policy": "visible-world-execution-required",
                "hiddenWorldMutationAllowed": False,
                "proposalOnlyCapabilities": _copy_jsonable(LIVE_AGENT_PROPOSAL_ONLY_CAPABILITIES),
            },
        )
    target = payload.get("target") if isinstance(payload.get("target"), dict) else {}
    target_kind = target.get("kind") or "object-instance"
    required_target_kind = contract.get("targetKind")
    if required_target_kind and target_kind != required_target_kind:
        return None, _api_error(
            "visible_executor_missing",
            "Agent Live Mode action target does not match the visible client executor contract.",
            details={
                "actionType": resolved_action_type,
                "targetKind": target_kind,
                "requiredTargetKind": required_target_kind,
                "clientExecutor": contract.get("clientExecutor"),
                "contractVersion": LIVE_AGENT_VISIBLE_ACTION_CONTRACT_VERSION,
            },
        )
    return contract, None


def _normalize_behavior_source_kind(value):
    kind = str(value or "").strip()
    if kind in BEHAVIOR_SOURCE_KINDS:
        return kind, None
    if kind in BEHAVIOR_SOURCE_ALIASES:
        return BEHAVIOR_SOURCE_ALIASES[kind], kind
    return None, None


def _behavior_selected_object_from_target(target):
    if not isinstance(target, dict):
        return {"kind": "none"}
    kind = target.get("kind") or "object-instance"
    if kind == "object-instance":
        object_id = target.get("objectInstanceId") or target.get("objectId") or target.get("id")
        return {
            "kind": "outdoor-node" if target.get("targetKind") == "outdoor-area-node" else "furniture",
            "id": object_id,
            "buildingId": target.get("buildingId"),
            "furnitureIndex": target.get("furnitureIndex"),
            "catalogId": target.get("catalogId") or target.get("objectCatalogId"),
            "objectType": target.get("objectType"),
            "nodeId": target.get("nodeId") if target.get("nodeId") != object_id else None,
        }
    if kind == "world-point":
        return {"kind": "world-point", "id": None, "buildingId": target.get("buildingId")}
    if kind == "building":
        return {"kind": "building", "id": target.get("buildingId"), "buildingId": target.get("buildingId")}
    if kind == "agent":
        return {"kind": "agent", "id": target.get("targetAgentId") or target.get("agentId")}
    return {"kind": kind, "id": target.get("id"), "buildingId": target.get("buildingId")}


def _behavior_selected_spot_from_target(target):
    if not isinstance(target, dict):
        return None
    return {
        "spotId": target.get("spotId") or target.get("interactionSpotId"),
        "slotId": target.get("slotId"),
        "seatId": target.get("seatId"),
        "interactionSpotId": target.get("interactionSpotId") or target.get("spotId"),
        "x": target.get("x") if target.get("x") is not None else target.get("worldX"),
        "y": target.get("y") if target.get("y") is not None else (target.get("z") if target.get("z") is not None else target.get("worldZ")),
        "floor": target.get("floor") or target.get("buildingFloor"),
    }


def _normalize_behavior_metadata(payload, source, target=None):
    if not isinstance(payload, dict):
        return None, _api_error("invalid_payload", "behavior metadata payload must be an object")
    if not isinstance(source, dict):
        return None, _api_error("invalid_behavior_source", "source must be an object with a valid behavior source kind", details={"allowed": sorted(BEHAVIOR_SOURCE_KINDS)})
    raw_kind = payload.get("behaviorSource") or payload.get("behaviorSourceKind") or source.get("behaviorSourceKind") or source.get("kind")
    source_kind, alias = _normalize_behavior_source_kind(raw_kind)
    if not source_kind:
        return None, _api_error("invalid_behavior_source", "Invalid behavior source kind.", details={"value": raw_kind, "allowed": sorted(BEHAVIOR_SOURCE_KINDS)})
    expected_mode = BEHAVIOR_MODE_BY_SOURCE[source_kind]
    mode = payload.get("behaviorMode") or source.get("behaviorMode") or expected_mode
    if mode != expected_mode:
        return None, _api_error("invalid_behavior_mode", "behaviorMode does not match behavior source kind.", details={"behaviorSourceKind": source_kind, "behaviorMode": mode, "expectedBehaviorMode": expected_mode})
    category = payload.get("behaviorCategory") if "behaviorCategory" in payload else source.get("behaviorCategory")
    if category is None and isinstance(payload.get("behavior"), dict):
        category = payload["behavior"].get("behaviorSelectedCategory")
    if category is not None and category not in BEHAVIOR_CATEGORIES:
        return None, _api_error("invalid_behavior_category", "behaviorCategory must be a known Phase 4 behavior category or null.", details={"value": category, "allowed": sorted(BEHAVIOR_CATEGORIES)})
    selected_object = payload.get("behaviorSelectedObject") if isinstance(payload.get("behaviorSelectedObject"), dict) else _behavior_selected_object_from_target(target)
    selected_spot = payload.get("behaviorSelectedSpot") if isinstance(payload.get("behaviorSelectedSpot"), dict) else _behavior_selected_spot_from_target(target)
    probability_roll = payload.get("behaviorProbabilityRoll") if isinstance(payload.get("behaviorProbabilityRoll"), dict) else None
    fallback_reason = payload.get("behaviorFallbackReason") if payload.get("behaviorFallbackReason") is not None else None
    return {
        "behaviorSourceKind": source_kind,
        "behaviorMode": mode,
        "behaviorAuthority": BEHAVIOR_AUTHORITY_BY_SOURCE[source_kind],
        "behaviorSelectedCategory": category,
        "behaviorSelectedObject": selected_object,
        "behaviorSelectedSpot": selected_spot,
        "behaviorProbabilityRoll": probability_roll,
        "behaviorFallbackReason": fallback_reason,
        "sourceAlias": alias,
    }, None


def _source_snapshot_with_behavior(source, behavior):
    source = source if isinstance(source, dict) else {}
    behavior = behavior if isinstance(behavior, dict) else {}
    keys = ["requestedBy", "requestId", "surface", "roles", "agentModelId", "modelId", "caller", "trusted"]
    snap = {"kind": behavior.get("behaviorSourceKind") or source.get("kind")}
    for key in keys:
        if source.get(key) is not None:
            snap[key] = source.get(key)
    if behavior.get("sourceAlias"):
        snap["legacyKind"] = behavior.get("sourceAlias")
    snap.update({
        "behaviorSourceKind": behavior.get("behaviorSourceKind"),
        "behaviorMode": behavior.get("behaviorMode"),
        "behaviorAuthority": behavior.get("behaviorAuthority"),
        "behaviorCategory": behavior.get("behaviorSelectedCategory"),
        "behavior": {k: behavior.get(k) for k in ["behaviorSourceKind", "behaviorMode", "behaviorAuthority", "behaviorSelectedCategory", "behaviorSelectedObject", "behaviorSelectedSpot", "behaviorProbabilityRoll", "behaviorFallbackReason"]},
    })
    return snap


def _live_agent_behavior_authority_admission(agent_id, source_kind):
    """Validate the one existing behavior hierarchy before action creation.

    This is deliberately a gate over the current world-action/runtime stack,
    not another dispatcher. Default scripted behavior is never admitted while
    a resident has an active Live activation, and Live autonomy is never
    admitted while direct user attention owns the controller.
    """
    source_kind = str(source_kind or "").strip()
    if not agent_id or source_kind == "user":
        return True, None
    setting = get_agent_live_mode_setting(agent_id) or {}
    live_enabled = setting.get("agentLiveModeEnabled") is True and setting.get("agentLiveModeLoopEnabled") is not False
    if source_kind in {"agent-scripted-mode", "system-schedule"} and live_enabled:
        return False, _api_error(
            "behavior_owner_conflict",
            "Default Mode cannot create a physical action while Live Agent Mode owns this resident.",
            details={
                "agentId": agent_id,
                "requestedOwner": source_kind,
                "activeOwner": "agent-live-mode",
                "authorityOrder": ["user", "agent-live-mode", "system-schedule", "agent-scripted-mode"],
            },
        )
    if source_kind == "agent-live-mode":
        attention = live_agent_user_attention_status(agent_id)
        if attention.get("active"):
            return False, _api_error(
                "user_attention_active",
                "Live autonomy cannot start a new physical action while the resident is attending to the user.",
                details={
                    "agentId": agent_id,
                    "requestedOwner": source_kind,
                    "activeOwner": "user",
                    "userAttention": attention,
                },
            )
    return True, None


def _compact_world_action_event_record(record):
    event = _copy_jsonable(record) if isinstance(record, dict) else None
    if not isinstance(event, dict):
        return None
    if _json_size_bytes(event) <= WORLD_ACTION_EVENT_RECORD_MAX_BYTES:
        return event
    compacted = {
        key: event.get(key)
        for key in (
            "schemaVersion",
            "name",
            "type",
            "id",
            "at",
            "timestamp",
            "sequence",
            "cursor",
            "actionId",
            "actionType",
            "status",
            "fromStatus",
            "toStatus",
            "from",
            "to",
            "agentId",
            "targetId",
            "targetKind",
            "routeId",
            "reservationId",
            "source",
            "behaviorSourceKind",
            "behaviorMode",
            "behaviorCategory",
            "actor",
            "reason",
        )
        if event.get(key) is not None
    }
    target = _compact_storage_target(event.get("target"))
    if target:
        compacted["target"] = target
    for key in ("behavior", "result", "error"):
        if event.get(key) is not None:
            compacted[key] = _compact_json_value_for_storage(
                event.get(key), max_depth=2, max_items=12, string_limit=600
            )
    compacted["storageCompaction"] = {
        "compacted": True,
        "originalBytes": _json_size_bytes(event),
    }
    if _json_size_bytes(compacted) > WORLD_ACTION_EVENT_RECORD_MAX_BYTES:
        compacted.pop("behavior", None)
        compacted["result"] = {
            "storageCompacted": True,
            "status": event.get("status") or event.get("toStatus"),
        }
        compacted["error"] = {
            "storageCompacted": True,
            "code": (event.get("error") or {}).get("code") if isinstance(event.get("error"), dict) else None,
        }
    return compacted


def default_world_action_events_store():
    return {
        "schemaVersion": WORLD_ACTION_EVENT_HOOKS_VERSION,
        "nextSequence": 1,
        "events": [],
        "retention": {"maxEvents": WORLD_ACTION_EVENTS_MAX_EVENTS},
        "storageBudget": {
            "maxBytes": WORLD_ACTION_EVENTS_MAX_BYTES,
            "recordMaxBytes": WORLD_ACTION_EVENT_RECORD_MAX_BYTES,
            "currentBytes": 2,
            "recordCount": 0,
            "recordsDropped": 0,
        },
        "subscription": {"mode": "poll", "endpoint": "/api/world-action-events", "cursorField": "sequence"},
    }


def _normalize_world_action_events_store(store):
    store = store if isinstance(store, dict) else {}
    raw_events = store.get("events") if isinstance(store.get("events"), list) else []
    events = [event for event in raw_events if isinstance(event, dict) and event.get("name") in WORLD_ACTION_EVENT_NAMES]
    try:
        next_sequence = int(store.get("nextSequence") or 1)
    except (TypeError, ValueError):
        next_sequence = 1
    if events:
        next_sequence = max(next_sequence, max(int(event.get("sequence") or 0) for event in events) + 1)
    next_store = default_world_action_events_store()
    stored_max = (store.get("retention") or {}).get("maxEvents") if isinstance(store.get("retention"), dict) else None
    try:
        max_events = min(WORLD_ACTION_EVENTS_MAX_EVENTS, max(1, int(stored_max or WORLD_ACTION_EVENTS_MAX_EVENTS)))
    except (TypeError, ValueError):
        max_events = WORLD_ACTION_EVENTS_MAX_EVENTS
    events, budget = _trim_storage_records(
        events,
        compact_record=_compact_world_action_event_record,
        max_records=max_events,
        max_bytes=WORLD_ACTION_EVENTS_MAX_BYTES,
        record_max_bytes=WORLD_ACTION_EVENT_RECORD_MAX_BYTES,
    )
    budget.pop("removedIds", None)
    next_store.update({
        "nextSequence": next_sequence,
        "events": events,
        "retention": {"maxEvents": max_events},
        "storageBudget": budget,
        "subscription": store.get("subscription") if isinstance(store.get("subscription"), dict) else next_store["subscription"],
    })
    return next_store


@_world_meta_transaction
def get_world_action_events_store(*, persist_migration=False):
    meta = load_world_meta()
    agent_life = meta.get("agentLife") if isinstance(meta.get("agentLife"), dict) else {}
    store = agent_life.get("worldActionEvents") if isinstance(agent_life.get("worldActionEvents"), dict) else None
    next_store = _normalize_world_action_events_store(store)
    changed = _json_compact_bytes(store or {}) != _json_compact_bytes(next_store)
    if persist_migration and changed:
        agent_life["worldActionEvents"] = next_store
        meta["agentLife"] = agent_life
        save_world_meta(meta)
    return next_store


@_world_meta_transaction
def save_world_action_events_store(store):
    meta = load_world_meta()
    agent_life = meta.get("agentLife") if isinstance(meta.get("agentLife"), dict) else {}
    next_store = _normalize_world_action_events_store(store)
    agent_life["worldActionEvents"] = next_store
    meta["agentLife"] = agent_life
    save_world_meta(meta)
    return next_store


def _world_action_target_id(action):
    target = action.get("target") if isinstance(action.get("target"), dict) else {}
    return target.get("objectInstanceId") or target.get("buildingId") or target.get("roomId") or target.get("targetAgentId") or target.get("id")


def _world_action_event_payload(action, name, now, *, from_status=None, to_status=None, reason=None, result=None, error=None, route=None, reservation=None, actor=None, source="api"):
    target = action.get("target") if isinstance(action.get("target"), dict) else {}
    action_source = action.get("source") if isinstance(action.get("source"), dict) else {}
    behavior = action_source.get("behavior") if isinstance(action_source.get("behavior"), dict) else {}
    current_result = result if isinstance(result, dict) else (action.get("result") if isinstance(action.get("result"), dict) else None)
    current_error = error if isinstance(error, dict) else None
    failure_reason = reason or action.get("failureReason")
    if current_error is None and failure_reason and name in {"failed", "cancelled", "reservation-released"}:
        current_error = {"code": failure_reason, "message": failure_reason.replace("_", " ")}
    return {
        "schemaVersion": WORLD_ACTION_EVENT_HOOKS_VERSION,
        "name": name,
        "type": name,
        "id": f"evt-{action.get('id')}-{name}-{now.replace(':', '').replace('-', '')}",
        "at": now,
        "timestamp": now,
        "actionId": action.get("id"),
        "actionType": action.get("actionType"),
        "status": to_status or action.get("status"),
        "fromStatus": from_status,
        "toStatus": to_status or action.get("status"),
        "from": from_status,
        "to": to_status or action.get("status"),
        "agentId": action.get("agentId"),
        "targetId": _world_action_target_id(action),
        "targetKind": target.get("kind"),
        "target": target,
        "routeId": (route or action.get("route") or {}).get("id") if isinstance(route or action.get("route"), dict) else None,
        "reservationId": (reservation or action.get("reservation") or {}).get("id") if isinstance(reservation or action.get("reservation"), dict) else None,
        "source": source,
        "behaviorSourceKind": behavior.get("behaviorSourceKind") or action.get("behaviorSourceKind") or action_source.get("behaviorSourceKind"),
        "behaviorMode": behavior.get("behaviorMode") or action.get("behaviorMode") or action_source.get("behaviorMode"),
        "behaviorCategory": behavior.get("behaviorSelectedCategory") if "behaviorSelectedCategory" in behavior else action.get("behaviorCategory"),
        "behavior": behavior or None,
        "actor": actor or _transition_actor(action.get("source"), None),
        "reason": failure_reason,
        "result": current_result,
        "error": current_error,
    }


@_world_meta_transaction
def _append_world_action_events(action, event_payloads):
    payloads = [event for event in event_payloads if isinstance(event, dict) and event.get("name") in WORLD_ACTION_EVENT_NAMES]
    if not payloads:
        return action
    store = get_world_action_events_store(persist_migration=True)
    sequence = int(store.get("nextSequence") or 1)
    existing_keys = {(event.get("actionId"), event.get("name"), event.get("fromStatus"), event.get("toStatus")) for event in store.get("events", [])}
    next_events = list(store.get("events", []))
    action_events = list(action.get("events") or [])
    for payload in payloads:
        key = (payload.get("actionId"), payload.get("name"), payload.get("fromStatus"), payload.get("toStatus"))
        if key in existing_keys:
            continue
        event = {**payload, "sequence": sequence, "cursor": sequence}
        sequence += 1
        existing_keys.add(key)
        next_events.append(event)
        action_events.append(event)
    save_world_action_events_store({**store, "nextSequence": sequence, "events": next_events})
    return {**action, "events": action_events}


def list_world_action_events(query=None):
    query = query if isinstance(query, dict) else {}
    store = get_world_action_events_store(persist_migration=True)
    events = list(store.get("events", []))
    since = (query.get("since") or query.get("after") or [None])[0] if isinstance(query.get("since") or query.get("after"), list) else query.get("since") or query.get("after")
    try:
        since = int(since) if since is not None else None
    except (TypeError, ValueError):
        since = None
    if since is not None:
        events = [event for event in events if int(event.get("sequence") or 0) > since]
    for field, key in (("agentId", "agentId"), ("actionId", "actionId"), ("targetId", "targetId"), ("name", "name")):
        value = (query.get(field) or [None])[0] if isinstance(query.get(field), list) else query.get(field)
        if value:
            events = [event for event in events if event.get(key) == value]
    try:
        limit = int(((query.get("limit") or [100])[0]) if isinstance(query.get("limit"), list) else query.get("limit") or 100)
    except (TypeError, ValueError):
        limit = 100
    limit = max(1, min(limit, 500))
    return {"ok": True, "schemaVersion": WORLD_ACTION_EVENT_HOOKS_VERSION, "subscription": store.get("subscription"), "events": events[-limit:], "nextCursor": store.get("nextSequence", 1) - 1}


def _normalize_token(value):
    return re.sub(r"[^a-z0-9]+", "", str(value or "").lower())


WORLD_ACTION_CATALOG_ID_ALIASES = {
    "printercopier": "all-in-one-printer-scanner",
    "printerscanner": "all-in-one-printer-scanner",
    "allinoneprinterscanner": "all-in-one-printer-scanner",
}


def _load_text_file(path):
    try:
        with open(path, "r") as f:
            return f.read()
    except OSError:
        return ""


def _normalize_capability_tag(tag):
    raw = str(tag or "").strip()
    if not raw:
        return None
    capability_text = _load_text_file(CAPABILITY_SCHEMA_FILE)
    if re.search(rf"['\"]{re.escape(raw)}['\"]\s*:", capability_text):
        return raw
    aliases = {
        "cosmetic": "appearance.customize", "cosmetics": "appearance.customize", "avatar": "appearance.customize",
        "mirror": "appearance.preview", "mannequin": "appearance.display", "barber": "appearance.salon",
        "rest": "life.rest", "recovery": "life.rest", "meal": "life.food", "drink": "life.hydration",
        "clinic": "life.medical", "shopping": "life.shopping", "retail": "life.shopping",
        "checkout": "maintenance.checkout", "trash": "maintenance.clean", "printer": "maintenance.printCopy",
        "diagnostic": "maintenance.diagnostics", "building": "world.build", "build": "world.build",
        "decor": "world.decorate", "wall": "world.structure", "terrain": "world.terrain", "outdoor": "world.exterior",
    }
    return aliases.get(raw) or aliases.get(raw.lower()) or aliases.get(_normalize_token(raw))


_CATALOG_BLOCKS_CACHE = {"sig": None, "blocks": {}}


def _catalog_blocks():
    try:
        stat = os.stat(CATALOG_SCHEMA_FILE)
        signature = (stat.st_mtime_ns, stat.st_size)
    except OSError:
        signature = None
    if signature is not None and _CATALOG_BLOCKS_CACHE.get("sig") == signature:
        return _CATALOG_BLOCKS_CACHE.get("blocks") or {}
    text = _load_text_file(CATALOG_SCHEMA_FILE)
    blocks = {}
    starts = [m.start() for m in re.finditer(r"\n\s*Object\.freeze\(\{\s*\n\s*id:\s*'", text)]
    for i, start in enumerate(starts):
        end = starts[i + 1] if i + 1 < len(starts) else len(text)
        block = text[start:end]
        match = re.search(r"id:\s*'([^']+)'", block)
        if match:
            blocks[_normalize_token(match.group(1))] = {"id": match.group(1), "block": block}
    _CATALOG_BLOCKS_CACHE["sig"] = signature
    _CATALOG_BLOCKS_CACHE["blocks"] = blocks
    return blocks


def _catalog_block_for(catalog_id):
    key = _normalize_token(catalog_id)
    if not key:
        return None
    aliased_catalog_id = WORLD_ACTION_CATALOG_ID_ALIASES.get(key)
    if aliased_catalog_id:
        key = _normalize_token(aliased_catalog_id)
    blocks = _catalog_blocks()
    if key in blocks:
        return blocks[key]
    schema = _load_text_file(CATALOG_SCHEMA_FILE)
    alias = re.search(rf"{re.escape(key)}:\s*'([^']+)'", schema) or re.search(rf"'{re.escape(str(catalog_id))}':\s*'([^']+)'", schema)
    if alias:
        return blocks.get(_normalize_token(alias.group(1)))
    for block_key, block in blocks.items():
        if key == block_key or key in block_key or block_key in key:
            return block
    return None


def _catalog_action_permission(catalog, action_type, capability_tag):
    block = (catalog or {}).get("block", "")
    if not block:
        return None
    pattern = r"Object\.freeze\(\{\s*id:\s*'([^']+)'[^}]*?primaryTag:\s*'([^']+)'[^}]*?permission:\s*'([^']+)'"
    actions = re.findall(pattern, block, flags=re.S)
    normalized_capability = _normalize_capability_tag(capability_tag)
    exact = [a for a in actions if a[0] == action_type]
    by_cap = [a for a in actions if _normalize_capability_tag(a[1]) == normalized_capability]
    chosen = exact[0] if exact else (by_cap[0] if by_cap else None)
    if not chosen:
        return None
    return {"actionType": chosen[0], "capabilityTag": _normalize_capability_tag(chosen[1]), "permissionLevel": chosen[2]}


def _catalog_has_spot(catalog, spot_id, action_type=None):
    if not spot_id:
        return True
    block = (catalog or {}).get("block", "")
    spot_pattern = rf"id:\s*'{re.escape(str(spot_id))}'"
    if not re.search(spot_pattern, block):
        return False
    if action_type and action_type not in block:
        # Some legacy ACTION_SPOTS only expose role/use spots. Capability still
        # gates the action; absence of an exact action on a spot is not fatal.
        return True
    return True


def _catalog_spot_capacity(catalog, spot_id):
    if not spot_id:
        return 1
    block = (catalog or {}).get("block", "")
    match = re.search(rf"id:\s*'{re.escape(str(spot_id))}'[^}}]*?capacity:\s*(\d+)", block, flags=re.S)
    if not match:
        return 1
    try:
        return max(1, int(match.group(1)))
    except (TypeError, ValueError):
        return 1


def _catalog_queue_spot(catalog):
    block = (catalog or {}).get("block", "")
    if not block:
        return None
    pattern = r"Object\.freeze\(\{(?P<body>[^{}]*?capacityKind:\s*'queue'[^{}]*?)\}\)"
    for match in re.finditer(pattern, block, flags=re.S):
        body = match.group("body") or ""
        spot_id = re.search(r"id:\s*'([^']+)'", body)
        if not spot_id:
            continue
        capacity = re.search(r"capacity:\s*(\d+)", body)
        return {
            "id": spot_id.group(1),
            "capacity": max(1, int(capacity.group(1))) if capacity else 1,
            "action": (re.search(r"action:\s*'([^']+)'", body) or [None, None])[1],
        }
    return None


def _catalog_concurrent_capacity(catalog):
    block = (catalog or {}).get("block", "")
    match = re.search(r"capacity:\s*Object\.freeze\(\{[^}]*?concurrentUsers:\s*(\d+)", block, flags=re.S)
    if not match:
        return 1
    try:
        return max(1, int(match.group(1)))
    except (TypeError, ValueError):
        return 1


def _catalog_is_api_service_queue(catalog, catalog_id=None):
    queue_spot = _catalog_queue_spot(catalog)
    if not queue_spot:
        return False
    identifiers = {_normalize_token((catalog or {}).get("id")), _normalize_token(catalog_id)}
    return any(identifier in WORLD_API_SERVICE_QUEUE_CATALOG_IDS for identifier in identifiers if identifier)


def _normalize_reservation_status(action):
    status = _canonical_world_action_status(action.get("status"))
    if status == "in_progress":
        return "in_use"
    return "reserved"


def _reservation_sort_key(action):
    timing = action.get("timing") if isinstance(action.get("timing"), dict) else {}
    return (timing.get("createdAt") or timing.get("updatedAt") or "", action.get("id") or "")


def _active_reservations_for(store, object_id, spot_id=None):
    reservations = []
    for active in sorted(store.get("active", []), key=_reservation_sort_key):
        reservation = active.get("reservation") if isinstance(active.get("reservation"), dict) else {}
        target = active.get("target") if isinstance(active.get("target"), dict) else {}
        if reservation.get("objectInstanceId") != object_id and target.get("objectInstanceId") != object_id:
            continue
        if spot_id is not None and reservation.get("spotId") != spot_id and target.get("interactionSpotId") != spot_id:
            continue
        state = reservation.get("state") or _normalize_reservation_status(active)
        if state not in WORLD_RESERVATION_ACTIVE_STATES:
            continue
        reservations.append({"action": active, "reservation": reservation})
    return reservations


def _reservation_is_queue(reservation):
    if not isinstance(reservation, dict):
        return False
    if reservation.get("capacityKind") == "queue" or reservation.get("queueSpotId"):
        return True
    state = str(reservation.get("state") or reservation.get("status") or "").lower()
    slot_id = str(reservation.get("slotId") or "")
    return state == "queued" or bool(re.search(r":\d+$", slot_id))


def _queue_availability_for(catalog, target, object_id, *, store=None, agent_id=None):
    queue_spot = _catalog_queue_spot(catalog)
    if not queue_spot or not object_id:
        return None
    requested_spot_id = target.get("interactionSpotId") or target.get("spotId")
    if requested_spot_id == queue_spot.get("id"):
        return None
    store = store if isinstance(store, dict) else get_world_actions_store(persist_migration=True)
    queue_reservations = [
        row for row in _active_reservations_for(store, object_id, queue_spot.get("id"))
        if _reservation_is_queue(row.get("reservation"))
    ]
    for row in queue_reservations:
        if row["action"].get("agentId") == agent_id:
            return {"state": "reserved", "reason": "duplicate_queue_action", "conflicts": [{"actionId": row["action"].get("id"), "agentId": agent_id}], "queue": None}
    occupied = set()
    for row in queue_reservations:
        slot_id = str((row.get("reservation") or {}).get("slotId") or "")
        match = re.search(r":(\d+)$", slot_id)
        if match:
            occupied.add(int(match.group(1)))
    capacity = max(1, int(queue_spot.get("capacity") or 1))
    next_index = next((index for index in range(capacity) if index not in occupied), None)
    if next_index is None:
        return {"state": "reserved", "reason": "queue_full", "conflicts": [{"actionId": row["action"].get("id"), "agentId": row["action"].get("agentId"), "slotId": (row.get("reservation") or {}).get("slotId"), "state": (row.get("reservation") or {}).get("state")} for row in queue_reservations], "queue": {"spotId": queue_spot.get("id"), "capacity": capacity}}
    return {
        "state": "available",
        "reason": None,
        "conflicts": [{"actionId": row["action"].get("id"), "agentId": row["action"].get("agentId"), "slotId": (row.get("reservation") or {}).get("slotId"), "state": (row.get("reservation") or {}).get("state")} for row in queue_reservations],
        "queue": {
            "spotId": queue_spot.get("id"),
            "slotId": f"{queue_spot.get('id')}:{next_index}",
            "index": next_index,
            "capacity": capacity,
            "action": queue_spot.get("action"),
        },
    }


def _queued_reservation_sort_key(action):
    reservation = action.get("reservation") if isinstance(action.get("reservation"), dict) else {}
    return (reservation.get("queuedAt") or (action.get("timing") or {}).get("queuedAt") or "", int(reservation.get("queueIndex") or 0), action.get("id") or "")


def _renumber_api_service_queue(active, object_id):
    queued_indexes = [
        index for index, action in enumerate(active)
        if isinstance(action.get("reservation"), dict)
        and action["reservation"].get("objectInstanceId") == object_id
        and action["reservation"].get("state") == "queued"
    ]
    sorted_indexes = sorted(queued_indexes, key=lambda index: _queued_reservation_sort_key(active[index]))
    for queue_index, action_index in enumerate(sorted_indexes):
        action = dict(active[action_index])
        reservation = dict(action.get("reservation") or {})
        queue_spot_id = reservation.get("queueSpotId") or reservation.get("spotId") or "queue"
        queue_slot_id = f"{queue_spot_id}:{queue_index}"
        reservation.update({"queueIndex": queue_index, "slotId": queue_slot_id, "spotId": queue_spot_id, "capacityKind": "queue"})
        action["reservation"] = reservation
        target = dict(action.get("target") or {})
        target["interactionSpotId"] = queue_spot_id
        queue_meta = dict(target.get("queue") or {})
        queue_meta.update({"spotId": queue_spot_id, "slotId": queue_slot_id, "index": queue_index})
        target["queue"] = queue_meta
        action["target"] = target
        route = dict(action.get("route") or {})
        if isinstance(route.get("target"), dict):
            route_target = dict(route.get("target") or {})
            route_target["interactionSpotId"] = queue_spot_id
            route_target["queue"] = queue_meta
            route["target"] = route_target
        if route:
            action["route"] = route
        active[action_index] = action
    return active


def _promote_next_api_service_queue_action(active, completed_action, now, reason="service-queue-promote-front"):
    reservation = completed_action.get("reservation") if isinstance(completed_action.get("reservation"), dict) else {}
    object_id = reservation.get("objectInstanceId") or (completed_action.get("target") or {}).get("objectInstanceId")
    if not object_id:
        return active
    if reservation.get("state") == "queued":
        return _renumber_api_service_queue(active, object_id)
    queued_indexes = [
        index for index, action in enumerate(active)
        if isinstance(action.get("reservation"), dict)
        and action["reservation"].get("objectInstanceId") == object_id
        and action["reservation"].get("state") == "queued"
    ]
    if not queued_indexes:
        return active
    promote_index = sorted(queued_indexes, key=lambda index: _queued_reservation_sort_key(active[index]))[0]
    promoted = dict(active[promote_index])
    promoted_reservation = dict(promoted.get("reservation") or {})
    requested_spot_id = promoted_reservation.get("requestedSpotId") or (promoted.get("target") or {}).get("requestedInteractionSpotId") or promoted_reservation.get("spotId")
    promoted_reservation.update({
        "state": "reserved",
        "status": "held",
        "availabilityState": "reserved",
        "spotId": requested_spot_id,
        "slotId": "slot-1",
        "promotedAt": now,
        "promotedFromQueue": True,
    })
    promoted["reservation"] = promoted_reservation
    promoted_target = dict(promoted.get("target") or {})
    promoted_target["interactionSpotId"] = requested_spot_id
    promoted_target["previousQueue"] = promoted_target.get("queue")
    promoted_target.pop("queue", None)
    promoted["target"] = promoted_target
    promoted_route = dict(promoted.get("route") or {})
    if promoted_route:
        promoted_route["state"] = "route_pending"
        promoted_route["setAgentTarget"] = True
        if isinstance(promoted_route.get("target"), dict):
            route_target = dict(promoted_route.get("target") or {})
            route_target["interactionSpotId"] = requested_spot_id
            route_target["previousQueue"] = route_target.get("queue")
            route_target.pop("queue", None)
            promoted_route["target"] = route_target
        promoted["route"] = promoted_route
    effects = list(promoted.get("effects") or [])
    effects.append({"type": "service-queue-promoted", "at": now, "from": "queued", "to": "reserved", "reason": reason})
    promoted["effects"] = effects
    promoted = _append_world_action_events(promoted, [
        _world_action_event_payload(promoted, "object-reserved", now, from_status="queued", to_status="reserved", reason=reason, result=promoted.get("result"), reservation=promoted.get("reservation"), actor="server.py#promote_api_service_queue", source="reservation"),
    ])
    active[promote_index] = promoted
    return _renumber_api_service_queue(active, object_id)


def _target_deleted_or_missing(target, resolved):
    if resolved:
        obj = resolved.get("object") if isinstance(resolved, dict) else None
        if isinstance(obj, dict) and (obj.get("deleted") is True or str(obj.get("status") or obj.get("state") or "").lower() == "deleted"):
            return "deleted"
        return None
    return "deleted" if isinstance(target, dict) and target.get("deleted") is True else "missing"


def get_object_availability(target, *, agent_id=None, store=None, resolved=None):
    target = target if isinstance(target, dict) else {}
    kind = target.get("kind") or "object-instance"
    if kind != "object-instance":
        return {"state": "available", "reason": None, "capacity": {"spot": 1, "object": 1}, "conflicts": [], "reservationSlot": None}
    resolved = resolved if resolved is not None else _find_world_action_target(target)
    missing_state = _target_deleted_or_missing(target, resolved)
    if missing_state:
        return {"state": missing_state, "reason": f"target_{missing_state}", "capacity": {"spot": 0, "object": 0}, "conflicts": [], "reservationSlot": None}
    obj = resolved.get("object") if isinstance(resolved, dict) else None
    status = str((obj or {}).get("status") or (obj or {}).get("state") or "").lower()
    if isinstance(obj, dict) and ((obj.get("disabled") is True) or status in {"disabled", "broken", "offline", "inactive"}):
        return {"state": "disabled", "reason": "target_disabled", "capacity": {"spot": 0, "object": 0}, "conflicts": [], "reservationSlot": None}
    if status == "blocked":
        return {"state": "blocked", "reason": "target_blocked", "capacity": {"spot": 0, "object": 0}, "conflicts": [], "reservationSlot": None}

    catalog_id = target.get("catalogId") or _object_catalog_id(obj)
    catalog = _catalog_block_for(catalog_id)
    object_id = target.get("objectInstanceId") or target.get("id") or ((resolved.get("candidateIds") or [None])[0] if isinstance(resolved, dict) else None)
    spot_id = target.get("interactionSpotId") or target.get("spotId")
    spot_capacity = _catalog_spot_capacity(catalog, spot_id)
    object_capacity = _catalog_concurrent_capacity(catalog)
    store = store if isinstance(store, dict) else get_world_actions_store(persist_migration=True)
    spot_reservations = _active_reservations_for(store, object_id, spot_id)
    object_reservations = [row for row in _active_reservations_for(store, object_id, None) if not _reservation_is_queue(row.get("reservation"))]
    conflict_rows = []
    occupied_slots = set()
    in_use = False
    for row in spot_reservations:
        action = row["action"]
        reservation = row["reservation"]
        slot_id = reservation.get("slotId") or "slot-1"
        occupied_slots.add(slot_id)
        state = reservation.get("state") or _normalize_reservation_status(action)
        in_use = in_use or state == "in_use" or _canonical_world_action_status(action.get("status")) == "in_progress"
        conflict_rows.append({"actionId": action.get("id"), "agentId": action.get("agentId"), "slotId": slot_id, "state": state})
    next_slot = None
    for index in range(1, spot_capacity + 1):
        candidate = f"slot-{index}"
        if candidate not in occupied_slots:
            next_slot = candidate
            break
    object_full = len(object_reservations) >= object_capacity and not any(row["action"].get("agentId") == agent_id for row in object_reservations)
    spot_full = next_slot is None and not any(row["action"].get("agentId") == agent_id for row in spot_reservations)
    queue_available = _queue_availability_for(catalog, target, object_id, store=store, agent_id=agent_id) if _catalog_is_api_service_queue(catalog, catalog_id) else None
    if queue_available and queue_available.get("conflicts") and not _reservation_is_queue({"spotId": spot_id}):
        return {"state": "reserved", "reason": "queue_pending", "capacity": {"spot": spot_capacity, "object": object_capacity}, "conflicts": queue_available.get("conflicts", []), "reservationSlot": None, "queueAvailability": queue_available}
    if object_full or spot_full:
        result = {"state": "in_use" if in_use else "reserved", "reason": "object_reserved", "capacity": {"spot": spot_capacity, "object": object_capacity}, "conflicts": conflict_rows, "reservationSlot": None}
        if queue_available:
            result["queueAvailability"] = queue_available
        return result
    return {"state": "available", "reason": None, "capacity": {"spot": spot_capacity, "object": object_capacity}, "conflicts": conflict_rows, "reservationSlot": next_slot or "slot-1", "queueAvailability": queue_available}


def _object_catalog_id(obj):
    if not isinstance(obj, dict):
        return None
    return obj.get("catalogId") or obj.get("objectCatalogId") or obj.get("assetId") or obj.get("renderType") or obj.get("type")


def _candidate_object_ids(building, obj, index, collection):
    building_id = building.get("id") if isinstance(building, dict) else None
    catalog_id = _object_catalog_id(obj)
    explicit = [obj.get(k) for k in ("objectInstanceId", "instanceId", "id", "nodeId") if isinstance(obj.get(k), str)]
    # Once a placed object has a stable id, index-derived ids are intentionally
    # not aliases. Otherwise deleting item N can make a stale target like
    # building:12 resolve to the different object that shifted into slot 12.
    if explicit:
        return {str(v) for v in explicit if v and str(v) != "None"}
    generated = [
        f"{building_id}:{index}",
        f"{building_id}-{index}",
        f"{building_id}:{collection}:{index}",
        f"{building_id}-{collection}-{index}",
        f"{building_id}:{catalog_id}:{index}",
        f"{building_id}-{catalog_id}-{index}",
        f"{catalog_id}-{index}",
    ]
    return {str(v) for v in generated if v and str(v) != "None"}


def _find_world_action_target(target):
    if not isinstance(target, dict):
        return None
    kind = target.get("kind") or "object-instance"
    building_id = target.get("buildingId")
    buildings = [load_building(building_id)] if building_id else list_buildings()
    buildings = [b for b in buildings if isinstance(b, dict)]
    if kind == "building":
        building = buildings[0] if buildings else None
        return {"kind": "building", "building": building, "object": None, "collection": None, "index": None} if building else None
    if kind == "room":
        return None
    if kind == "world-point":
        return {"kind": "world-point", "building": None, "object": None, "collection": None, "index": None}
    if kind == "agent":
        target_agent_id = _resolve_agent_id(target.get("targetAgentId"))
        if not target_agent_id:
            return None
        return {"kind": "agent", "agentId": target_agent_id, "object": None, "collection": None, "index": None}
    wanted_id = str(target.get("objectInstanceId") or target.get("id") or "")
    wanted_catalog = _normalize_token(target.get("catalogId") or target.get("objectCatalogId") or "")
    for building in buildings:
        for collection, records in (("furniture", ((building.get("interior") or {}).get("furniture") or [])), ("outdoor-node", ((building.get("outdoorArea") or {}).get("nodes") or []))):
            if not isinstance(records, list):
                continue
            for index, obj in enumerate(records):
                if not isinstance(obj, dict):
                    continue
                ids = _candidate_object_ids(building, obj, index, collection)
                catalog_matches = not wanted_catalog or wanted_catalog == _normalize_token(_object_catalog_id(obj))
                explicit_index = target.get("furnitureIndex") if collection == "furniture" else target.get("nodeIndex")
                index_matches = explicit_index is not None and int(explicit_index) == index
                if (wanted_id and wanted_id in ids and catalog_matches) or (not wanted_id and index_matches and catalog_matches):
                    return {"kind": "object-instance", "building": building, "object": obj, "collection": collection, "index": index, "candidateIds": sorted(ids)}
    return None


def _resolve_agent_id(agent_id):
    wanted = str(agent_id or "").strip()
    if not wanted:
        return None
    for agent in get_roster():
        candidates = {str(agent.get("id") or ""), str(agent.get("statusKey") or "")}
        if wanted in candidates:
            return str(agent.get("statusKey") or agent.get("id"))
    return None


def _source_roles(source):
    if not isinstance(source, dict):
        return set()
    roles = source.get("roles") or source.get("worldRoles") or []
    if not isinstance(roles, list):
        return set()
    inherited = set(str(r).strip().lower() for r in roles if str(r).strip())
    if "owner" in inherited:
        inherited.update(["admin", "manager", "assigned", "participant"])
    if "admin" in inherited:
        inherited.update(["manager", "assigned", "participant"])
    if "manager" in inherited:
        inherited.update(["assigned", "participant"])
    if "assigned" in inherited:
        inherited.add("participant")
    return inherited


def _permission_allows(level, agent_id, source, target_obj):
    level = level or "public"
    if level == "public":
        return True, None
    roles = _source_roles(source)
    if isinstance(source, dict) and source.get("kind") in {"system", "api"} and source.get("trusted") is True:
        return True, None
    if level == "assigned-role":
        assigned = []
        if isinstance(target_obj, dict):
            permissions = target_obj.get("permissions") if isinstance(target_obj.get("permissions"), dict) else {}
            assigned.extend(target_obj.get("assignedAgentIds") or permissions.get("assignedAgentIds") or [])
            assigned.extend([target_obj.get("assignedTo")] if target_obj.get("assignedTo") else [])
        if agent_id in {str(x) for x in assigned} or roles.intersection({"assigned", "manager", "admin", "owner"}):
            return True, None
        return False, "assigned-role permission requires the agent to be assigned or the source to carry assigned/manager/admin/owner world roles"
    if level == "manager" and roles.intersection({"manager", "admin", "owner"}):
        return True, None
    if level == "admin" and roles.intersection({"admin", "owner"}):
        return True, None
    if level == "owner-only" and "owner" in roles:
        return True, None
    return False, f"{level} permission was not satisfied by the selected source"


def _validate_create_world_action_payload(payload):
    if not isinstance(payload, dict):
        return None, _api_error("invalid_payload", "world action create payload must be an object")
    errors = []
    source = payload.get("source") if isinstance(payload.get("source"), dict) else None
    target = payload.get("target") if isinstance(payload.get("target"), dict) else None
    behavior = None
    if not source:
        errors.append("source must be an object with kind and requestedBy/requestId metadata")
    else:
        behavior, behavior_error = _normalize_behavior_metadata(payload, source, target)
        if behavior_error:
            return None, behavior_error
        source = _source_snapshot_with_behavior(source, behavior)
    if isinstance(source, dict) and source.get("kind") == "agent-live-mode" and not _agent_live_mode_runtime_enabled():
        return None, _agent_live_mode_feature_disabled_error()
    agent_id = _resolve_agent_id(payload.get("agentId"))
    if not agent_id:
        errors.append("agentId must reference an existing agent id or statusKey")
    if agent_id and isinstance(source, dict):
        authority_ok, authority_error = _live_agent_behavior_authority_admission(agent_id, source.get("kind"))
        if not authority_ok:
            return None, authority_error
    if agent_id and isinstance(source, dict) and source.get("kind") == "agent-live-mode":
        setting = get_agent_live_mode_setting(agent_id)
        if not setting or setting.get("agentLiveModeEnabled") is not True:
            return None, _agent_live_mode_disabled_error(agent_id)
    action_type = str(payload.get("actionType") or payload.get("actionId") or "").strip()
    if not action_type:
        errors.append("actionType must be a non-empty string")
    capability = _normalize_capability_tag(payload.get("capabilityTag"))
    if not capability:
        errors.append("capabilityTag must be a known capability tag")
    params = payload.get("params", {})
    if not isinstance(params, dict):
        errors.append("params must be an object when present")
    visible_action_contract = None
    if isinstance(source, dict) and source.get("kind") == "agent-live-mode":
        visible_action_contract, contract_error = _validate_live_agent_visible_action_contract(payload, action_type=action_type, capability=capability)
        if contract_error:
            return None, contract_error
    ui_context = payload.get("uiContext", None)
    if ui_context is not None and not isinstance(ui_context, dict):
        errors.append("uiContext must be an object when present")
    if not target:
        errors.append("target must be an object")
    elif (target.get("kind") or "object-instance") == "room":
        errors.append("room targets are not supported until canonical room ids exist; use building/floor or object target")
    resolved = _find_world_action_target(target) if target else None
    if target and not resolved:
        errors.append("target does not exist in persisted buildings/objects")
    if errors:
        return None, _api_error("invalid_request", "World action could not be created.", details=errors)

    target_kind = target.get("kind") or "object-instance"
    target_obj = resolved.get("object") if resolved else None
    if target_kind == "agent":
        target_agent_id = resolved.get("agentId") if isinstance(resolved, dict) else _resolve_agent_id(target.get("targetAgentId"))
        if not target_agent_id:
            return None, _api_error("target_missing", "Target agent does not exist.", details={"targetAgentId": target.get("targetAgentId")})
        if target_agent_id == agent_id:
            return None, _api_error("unsupported_target", "Agent Live Mode social actions cannot target the same agent.", details={"agentId": agent_id, "targetAgentId": target_agent_id})
    catalog_id = target.get("catalogId") or _object_catalog_id(target_obj) or target_kind
    catalog = _catalog_block_for(catalog_id) if target_kind == "object-instance" else None
    if target_kind == "object-instance" and not catalog:
        return None, _api_error("unsupported_target", "Target catalog is not known to the object catalog registry.", details={"catalogId": catalog_id})
    action_permission = _catalog_action_permission(catalog, action_type, capability) if catalog else {"actionType": action_type, "capabilityTag": capability, "permissionLevel": "public"}
    if target_kind == "object-instance" and not action_permission:
        return None, _api_error("unsupported_capability", "Target does not expose the requested capability/action.", details={"catalogId": catalog_id, "actionType": action_type, "capabilityTag": capability})
    if target_kind == "object-instance" and action_permission.get("capabilityTag") != capability:
        return None, _api_error("unsupported_capability", "Requested capabilityTag does not match the target action capability.", details=action_permission)
    spot_id = target.get("interactionSpotId") or target.get("spotId")
    if target_kind == "object-instance" and not _catalog_has_spot(catalog, spot_id, action_type):
        return None, _api_error("missing_interaction_spot", "Target does not expose the requested interaction/action spot.", details={"interactionSpotId": spot_id, "catalogId": catalog_id})
    allowed, deny_reason = _permission_allows(action_permission.get("permissionLevel"), agent_id, source, target_obj)
    if not allowed:
        return None, _api_error("permission_denied", "World action is not allowed from the selected source.", details=deny_reason)

    store = get_world_actions_store(persist_migration=True)
    request_id = source.get("requestId") if isinstance(source, dict) else None
    object_id = target.get("objectInstanceId") or target.get("id") or (resolved.get("candidateIds") or [None])[0]
    for active in store.get("active", []):
        active_source = active.get("source") if isinstance(active.get("source"), dict) else {}
        active_target = active.get("target") if isinstance(active.get("target"), dict) else {}
        if request_id and active_source.get("requestId") == request_id:
            return None, _api_error("duplicate_action", "A world action with this source.requestId already exists.", details={"actionId": active.get("id")})
        if active.get("agentId") == agent_id and active_target.get("objectInstanceId") == object_id and active_target.get("interactionSpotId") == spot_id:
            return None, _api_error("duplicate_action", "This agent already has an active action for the requested target/spot.", details={"actionId": active.get("id")})
    availability = get_object_availability({**target, "objectInstanceId": object_id, "catalogId": catalog_id, "interactionSpotId": spot_id}, agent_id=agent_id, store=store, resolved=resolved)
    queue_availability = availability.get("queueAvailability") if isinstance(availability.get("queueAvailability"), dict) else None
    queue_details = queue_availability.get("queue") if availability.get("state") in {"reserved", "in_use"} and isinstance(queue_availability, dict) and queue_availability.get("state") == "available" and isinstance(queue_availability.get("queue"), dict) else None
    if availability.get("state") in {"disabled", "blocked", "missing", "deleted"}:
        code = "target_disabled" if availability.get("state") == "disabled" else f"target_{availability.get('state')}"
        return None, _api_error(code, "Target is not available for world action reservation.", details=availability)
    if availability.get("state") in {"reserved", "in_use"}:
        if not queue_details:
            return None, _api_error("object_reserved", "Target interaction spot/capacity slot is already reserved by another active action.", details=availability)

    now = _utc_now_iso()
    safe_action = re.sub(r"[^A-Za-z0-9_.-]+", "-", action_type).strip("-") or "action"
    action_id = str(payload.get("id") or f"wa-{int(time.time() * 1000)}-{agent_id}-{safe_action}")
    building = resolved.get("building") if resolved else None
    target_snapshot = dict(target)
    target_snapshot["kind"] = target_kind
    target_snapshot["catalogId"] = catalog_id
    if target_kind == "object-instance":
        target_snapshot["objectInstanceId"] = object_id or (resolved.get("candidateIds") or [None])[0]
        target_snapshot["interactionSpotId"] = spot_id
        target_snapshot["buildingId"] = target.get("buildingId") or (building or {}).get("id")
        target_snapshot["floor"] = int(target.get("floor") or (target_obj or {}).get("floor") or (target_obj or {}).get("level") or 1)
        target_snapshot["roomId"] = target.get("roomId") if target.get("roomId") is not None else (target_obj or {}).get("roomId")
        if queue_details:
            target_snapshot["requestedInteractionSpotId"] = spot_id
            target_snapshot["interactionSpotId"] = queue_details.get("spotId")
            target_snapshot["queue"] = {"spotId": queue_details.get("spotId"), "slotId": queue_details.get("slotId"), "index": queue_details.get("index"), "capacity": queue_details.get("capacity"), "action": queue_details.get("action")}
    elif target_kind == "agent":
        target_snapshot["targetAgentId"] = resolved.get("agentId") if isinstance(resolved, dict) else target.get("targetAgentId")
        target_snapshot["buildingId"] = target.get("buildingId")
        target_snapshot["floor"] = int(target.get("floor") or 1)
    behavior = behavior or {}
    route_behavior = {k: behavior.get(k) for k in ["behaviorSourceKind", "behaviorMode", "behaviorAuthority", "behaviorSelectedCategory", "behaviorSelectedObject", "behaviorSelectedSpot", "behaviorProbabilityRoll", "behaviorFallbackReason"]}
    server_authoritative_runtime = bool(visible_action_contract)
    route_target = {
        "target": target_snapshot,
        "handoff": WORLD_ACTION_SERVER_RUNTIME_OWNER if server_authoritative_runtime else WORLD_ACTION_CREATE_ROUTE_OWNER,
        "routeOwner": "server-authoritative-runtime" if server_authoritative_runtime else "client-runtime",
        "setAgentTarget": False if server_authoritative_runtime else True,
        "serverExecutor": WORLD_ACTION_SERVER_RUNTIME_OWNER if server_authoritative_runtime else None,
        "serverRuntimeAuthority": server_authoritative_runtime,
        "source": source,
        "behavior": route_behavior,
        "behaviorSourceKind": behavior.get("behaviorSourceKind"),
        "behaviorMode": behavior.get("behaviorMode"),
        "behaviorCategory": behavior.get("behaviorSelectedCategory"),
    }
    action = {
        "id": action_id,
        "actionType": action_type,
        "agentId": agent_id,
        "source": source,
        "behaviorSourceKind": behavior.get("behaviorSourceKind"),
        "behaviorMode": behavior.get("behaviorMode"),
        "behaviorAuthority": behavior.get("behaviorAuthority"),
        "behaviorCategory": behavior.get("behaviorSelectedCategory"),
        "status": "reserved",
        "target": target_snapshot,
        "capabilityTag": capability,
        "priority": payload.get("priority") if payload.get("priority") in WORLD_ACTION_PRIORITIES else "normal",
        "permission": {"level": action_permission.get("permissionLevel"), "checked": True, "deniedReason": None, "source": "agent-life-object-catalog-schema.mjs#apiActions.permission"},
        "timing": {"createdAt": now, "updatedAt": now, "requestedAt": now, "reservedAt": now, "queuedAt": now, "timeoutMs": payload.get("timeoutMs") if isinstance(payload.get("timeoutMs"), (int, float)) and payload.get("timeoutMs") >= 0 else None},
        "lifecycle": {"previousStatus": "created", "allowedNext": _world_action_allowed_next("reserved"), "transitionLog": [
            {"at": now, "from": None, "to": "requested", "actor": _transition_actor(source, None), "source": source.get("behaviorSourceKind") or source.get("kind"), "behavior": route_behavior, "reason": "requested"},
            {"at": now, "from": "requested", "to": "created", "actor": "server.py#create_world_action", "source": source.get("behaviorSourceKind") or "api", "behavior": route_behavior, "reason": "validated"},
            {"at": now, "from": "created", "to": "reserved", "actor": "server.py#create_world_action", "source": "reservation", "behavior": route_behavior, "reason": "object-reserved"},
        ]},
        "reservation": {
            "id": f"res-{action_id}-{target_snapshot.get('objectInstanceId')}-{target_snapshot.get('interactionSpotId')}-{queue_details.get('slotId') if queue_details else availability.get('reservationSlot')}",
            "state": "queued" if queue_details else "reserved",
            "status": "queued" if queue_details else "held",
            "availabilityState": "reserved",
            "actionId": action_id,
            "actionType": action_type,
            "agentId": agent_id,
            "objectInstanceId": target_snapshot.get("objectInstanceId"),
            "spotId": target_snapshot.get("interactionSpotId"),
            "slotId": queue_details.get("slotId") if queue_details else (availability.get("reservationSlot") or "slot-1"),
            **({"requestedSpotId": spot_id, "queueSpotId": queue_details.get("spotId"), "queueIndex": queue_details.get("index"), "capacityKind": "queue"} if queue_details else {}),
            "capacity": availability.get("capacity"),
            "reservedAt": now,
            **({"queuedAt": now} if queue_details else {}),
        },
        "route": {"id": f"route-{action_id}", "state": "route_pending", **route_target},
        "params": params,
        "result": {"status": "pending"},
        "events": [],
        "audit": {"schemaVersion": WORLD_ACTION_SCHEMA_VERSION, "stateMachineVersion": WORLD_ACTION_STATE_MACHINE_VERSION, "createVersion": WORLD_ACTION_CREATE_VERSION, "eventHooksVersion": WORLD_ACTION_EVENT_HOOKS_VERSION, "reuseDecisions": [*WORLD_ACTION_CREATE_REUSE_NOTES, *WORLD_ACTION_EVENT_REUSE_NOTES], "routeGuardrails": WORLD_ACTION_EVENT_ROUTE_GUARDRAILS},
    }
    if visible_action_contract:
        action["visibility"] = {
            "schemaVersion": LIVE_AGENT_VISIBLE_ACTION_CONTRACT_VERSION,
            "policy": visible_action_contract.get("policy"),
            "visibleInWorld": True,
            "hiddenWorldMutationAllowed": False,
            "clientExecutor": visible_action_contract.get("clientExecutor"),
            "serverExecutor": WORLD_ACTION_SERVER_RUNTIME_OWNER,
            "serverRuntimeAuthority": True,
            "requiresMoveIntent": visible_action_contract.get("requiresMoveIntent") is True,
            "requiresPhysicalAgentPresence": True,
        }
        action["route"]["visibleActionContract"] = action["visibility"]
    if ui_context is not None:
        action["uiContext"] = ui_context
    record_errors = validate_world_action_record(action, expected_bucket="active")
    if record_errors:
        return None, _api_error("invalid_action_record", "Created world action failed schema validation.", details=record_errors)
    return action, None


def create_world_action(payload):
    action, error = _validate_create_world_action_payload(payload)
    if error:
        code = (error.get("error") or {}).get("code")
        status = {
            "invalid_payload": 400,
            "invalid_request": 400,
            "invalid_behavior_source": 400,
            "invalid_behavior_mode": 400,
            "invalid_behavior_category": 400,
            "unsupported_target": 422,
            "unsupported_capability": 422,
            "hidden_action_not_allowed": 422,
            "visible_executor_missing": 422,
            "missing_interaction_spot": 422,
            "target_disabled": 409,
            "target_blocked": 409,
            "target_missing": 404,
            "target_deleted": 410,
            "permission_denied": 403,
            "agent_live_mode_disabled": 403,
            "agent_live_mode_feature_disabled": _agent_live_mode_feature_disabled_status(),
            "behavior_owner_conflict": 409,
            "user_attention_active": 409,
            "duplicate_action": 409,
            "object_reserved": 409,
            "invalid_action_record": 500,
        }.get(code, 400)
        return False, error, status
    now = action.get("timing", {}).get("createdAt") if isinstance(action.get("timing"), dict) else _utc_now_iso()
    action = _append_world_action_events(action, [
        _world_action_event_payload(action, "action-created", now, from_status=None, to_status="created", reason="validated", result=action.get("result"), source="api", actor="server.py#create_world_action"),
        _world_action_event_payload(action, "object-reserved", now, from_status="created", to_status="reserved", reason="object-reserved", result=action.get("result"), reservation=action.get("reservation"), source="reservation", actor="server.py#create_world_action"),
    ])
    store = get_world_actions_store(persist_migration=True)
    ok, saved = save_world_actions_store({"active": [*store.get("active", []), action], "history": store.get("history", [])})
    if not ok:
        return False, _api_error("invalid_action_record", "World action could not be persisted.", details=saved), 500
    return True, {"ok": True, "action": action, "worldActions": {"activeCount": len(saved.get("active", [])), "historyCount": len(saved.get("history", []))}, "routeHandoff": action.get("route")}, 201

# ─── AGENT MOVE INTENT API ───────────────────────────────────────
def _compact_move_intent_history_record(record):
    if not isinstance(record, dict):
        return None
    storage_compaction = record.get("storageCompaction") if isinstance(record.get("storageCompaction"), dict) else {}
    if storage_compaction.get("compacted") and storage_compaction.get("removedDuplicatedRoutePayload"):
        return _copy_jsonable(record)
    route = record.get("route") if isinstance(record.get("route"), dict) else {}
    metadata = record.get("targetMetadata") if isinstance(record.get("targetMetadata"), dict) else {}
    compacted = {
        key: record.get(key)
        for key in (
            "id",
            "schemaVersion",
            "agentId",
            "actionId",
            "worldActionId",
            "status",
            "routeStatus",
            "failureReason",
            "behaviorSourceKind",
            "behaviorMode",
            "behaviorAuthority",
            "behaviorCategory",
            "createdAt",
            "updatedAt",
            "arrivedAt",
            "completedAt",
            "failedAt",
            "cancelledAt",
            "expiredAt",
            "invalidatedAt",
            "interruptedAt",
            "interruptedBy",
        )
        if record.get(key) is not None
    }
    target = _compact_storage_target(record.get("target") or route.get("target"))
    if target:
        compacted["target"] = target
    compact_metadata = {
        key: metadata.get(key)
        for key in (
            "objectInstanceId",
            "catalogId",
            "interactionSpotId",
            "buildingId",
            "buildingName",
            "floor",
            "roomId",
            "collection",
            "routingPlan",
        )
        if metadata.get(key) is not None
    }
    if compact_metadata:
        compacted["targetMetadata"] = compact_metadata
    compact_route = {
        key: route.get(key)
        for key in (
            "id",
            "state",
            "status",
            "routeOwner",
            "routingOwner",
            "serverExecutor",
            "serverRuntimeAuthority",
            "worldActionId",
            "failureReason",
            "arrivedAt",
            "failedAt",
            "cancelledAt",
            "distanceTravelled",
            "distanceRemaining",
            "durationSec",
            "attempts",
        )
        if route.get(key) is not None
    }
    planner = route.get("planner") if isinstance(route.get("planner"), dict) else {}
    if planner:
        compact_route["planner"] = {
            key: planner.get(key)
            for key in ("kind", "strategy", "buildingId", "floor", "roomId")
            if planner.get(key) is not None
        }
    if compact_route:
        compacted["route"] = compact_route
    source = _compact_storage_source(record.get("source") or route.get("source"))
    if source:
        compacted["source"] = source
    behavior = record.get("behavior") if isinstance(record.get("behavior"), dict) else {}
    if behavior:
        compacted["behavior"] = {
            key: behavior.get(key)
            for key in (
                "behaviorSourceKind",
                "behaviorMode",
                "behaviorAuthority",
                "behaviorSelectedCategory",
                "behaviorFallbackReason",
            )
            if behavior.get(key) is not None
        }
    for key in ("result", "error"):
        if record.get(key) is not None:
            compacted[key] = _compact_json_value_for_storage(
                record.get(key), max_depth=2, max_items=10, string_limit=500
            )
    compacted["storageCompaction"] = {
        "compacted": True,
        "originalBytes": _json_size_bytes(record),
        "removedDuplicatedRoutePayload": True,
    }
    if _json_size_bytes(compacted) > MOVE_INTENT_HISTORY_RECORD_MAX_BYTES:
        compacted.pop("behavior", None)
        compacted.pop("targetMetadata", None)
        compacted["result"] = {
            "storageCompacted": True,
            "status": record.get("routeStatus") or record.get("status"),
        }
        compacted.pop("error", None)
    return compacted


def default_move_intents_store():
    return {
        "schemaVersion": MOVE_INTENT_SCHEMA_VERSION,
        "active": [],
        "history": [],
        "retention": {"maxHistoryRecords": MOVE_INTENT_HISTORY_MAX_RECORDS},
        "storageBudget": {
            "historyMaxBytes": MOVE_INTENT_HISTORY_MAX_BYTES,
            "historyRecordMaxBytes": MOVE_INTENT_HISTORY_RECORD_MAX_BYTES,
            "activeRecordMaxBytes": MOVE_INTENT_ACTIVE_RECORD_MAX_BYTES,
            "historyCurrentBytes": 2,
            "historyRecordCount": 0,
            "historyRecordsDropped": 0,
        },
    }


def _normalize_move_intents_store(store):
    store = store if isinstance(store, dict) else {}
    active = [row for row in store.get("active", []) if isinstance(row, dict)]
    history = [row for row in store.get("history", []) if isinstance(row, dict)]
    history, budget = _trim_storage_records(
        history,
        compact_record=_compact_move_intent_history_record,
        max_records=MOVE_INTENT_HISTORY_MAX_RECORDS,
        max_bytes=MOVE_INTENT_HISTORY_MAX_BYTES,
        record_max_bytes=MOVE_INTENT_HISTORY_RECORD_MAX_BYTES,
    )
    next_store = default_move_intents_store()
    next_store["active"] = active
    next_store["history"] = history
    next_store["storageBudget"].update({
        "historyCurrentBytes": budget.get("currentBytes"),
        "historyRecordCount": budget.get("recordCount"),
        "historyRecordsDropped": budget.get("recordsDropped"),
        "oversizedActiveRecords": sum(
            1 for row in active if _json_size_bytes(row) > MOVE_INTENT_ACTIVE_RECORD_MAX_BYTES
        ),
    })
    if store.get("lastSavedAt"):
        next_store["lastSavedAt"] = store.get("lastSavedAt")
    return next_store


@_world_meta_transaction
def get_move_intents_store(*, persist_migration=False):
    meta = load_world_meta()
    agent_life = meta.get("agentLife") if isinstance(meta.get("agentLife"), dict) else {}
    store = agent_life.get("moveIntents") if isinstance(agent_life.get("moveIntents"), dict) else None
    next_store = _normalize_move_intents_store(store)
    changed = _json_compact_bytes(store or {}) != _json_compact_bytes(next_store)
    if persist_migration and changed:
        agent_life["moveIntents"] = next_store
        meta["agentLife"] = agent_life
        save_world_meta(meta)
    return next_store


@_world_meta_transaction
def save_move_intents_store(store):
    meta = load_world_meta()
    agent_life = meta.get("agentLife") if isinstance(meta.get("agentLife"), dict) else {}
    next_store = _normalize_move_intents_store(store)
    oversized_active = [
        {"id": row.get("id"), "bytes": _json_size_bytes(row)}
        for row in next_store.get("active", [])
        if _json_size_bytes(row) > MOVE_INTENT_ACTIVE_RECORD_MAX_BYTES
    ]
    if oversized_active:
        return False, {
            "error": "move_intent_active_record_too_large",
            "maxBytes": MOVE_INTENT_ACTIVE_RECORD_MAX_BYTES,
            "records": oversized_active,
        }
    next_store["lastSavedAt"] = _utc_now_iso()
    agent_life["moveIntents"] = next_store
    meta["agentLife"] = agent_life
    save_world_meta(meta)
    return True, next_store


def _building_unavailable(building):
    if not isinstance(building, dict):
        return "building_missing"
    status = str(building.get("status") or building.get("state") or "").lower()
    if building.get("deleted") is True or status == "deleted":
        return "building_deleted"
    if building.get("disabled") is True or status in {"disabled", "offline", "closed", "inactive", "unavailable"}:
        return "building_unavailable"
    if status == "blocked":
        return "target_blocked"
    return None


def _spot_blocked(obj, spot_id):
    if not isinstance(obj, dict) or not spot_id:
        return False
    spot_id = str(spot_id)
    blocked_lists = [obj.get("blockedSpots"), obj.get("disabledSpots"), obj.get("unavailableSpots")]
    state = obj.get("state") if isinstance(obj.get("state"), dict) else {}
    blocked_lists.extend([state.get("blockedSpots"), state.get("disabledSpots"), state.get("unavailableSpots")])
    for value in blocked_lists:
        if isinstance(value, list) and spot_id in {str(v) for v in value}:
            return True
        if isinstance(value, dict) and value.get(spot_id):
            return True
    spots = obj.get("spots") if isinstance(obj.get("spots"), dict) else state.get("spots") if isinstance(state.get("spots"), dict) else {}
    spot_state = spots.get(spot_id) if isinstance(spots, dict) else None
    if isinstance(spot_state, dict):
        status = str(spot_state.get("status") or spot_state.get("state") or "").lower()
        return status in {"blocked", "disabled", "unavailable", "deleted"}
    return False


def _move_intent_id(agent_id):
    return f"move-{int(time.time() * 1000)}-{re.sub(r'[^A-Za-z0-9_.-]+', '-', str(agent_id)).strip('-') or 'agent'}"


def _number_or_none(value):
    if isinstance(value, (int, float)) and not isinstance(value, bool):
        return float(value)
    if isinstance(value, str) and value.strip():
        try:
            return float(value)
        except ValueError:
            return None
    return None


def _active_world_action_for_move(action_id, agent_id):
    if not action_id:
        return None
    store = get_world_actions_store(persist_migration=True)
    for action in store.get("active", []):
        if action.get("id") == action_id and action.get("agentId") == agent_id:
            return _normalize_world_action_record(action)
    return None


def _move_target_invalid_reason(target):
    if not isinstance(target, dict):
        return "target_missing"
    kind = target.get("kind") or "object-instance"
    if kind == "world-point":
        building_id = target.get("buildingId")
        if building_id:
            return _building_unavailable(load_building(building_id))
        return None
    building_id = target.get("buildingId")
    if kind in {"building", "room"}:
        return _building_unavailable(load_building(building_id))
    resolved = _find_world_action_target(target)
    if not resolved:
        return "target_missing"
    if kind == "agent":
        return None
    building_reason = _building_unavailable(resolved.get("building"))
    if building_reason:
        return building_reason
    obj = resolved.get("object")
    missing_state = _target_deleted_or_missing(target, resolved)
    if missing_state:
        return f"target_{missing_state}"
    status = str((obj or {}).get("status") or (obj or {}).get("state") or "").lower()
    if isinstance(obj, dict) and (obj.get("deleted") is True or status == "deleted"):
        return "target_deleted"
    if isinstance(obj, dict) and (obj.get("disabled") is True or status in {"disabled", "broken", "offline", "inactive"}):
        return "target_disabled"
    if status == "blocked" or _spot_blocked(obj, target.get("interactionSpotId") or target.get("spotId")):
        return "target_blocked"
    return None


def _linked_world_action_terminal_for_move(intent):
    if not isinstance(intent, dict):
        return None
    action_id = _move_intent_linked_world_action_id(intent)
    if not action_id:
        return None
    store = get_world_actions_store(persist_migration=True)
    bucket, _, action = _find_world_action_record(store, action_id)
    if action is None:
        return {"status": "failed", "reason": "linked_action_missing", "actionId": action_id}
    status = _canonical_world_action_status(action.get("status"))
    if bucket == "active" and status not in WORLD_ACTION_TERMINAL_STATES:
        return None
    terminal_status = {
        "completed": "arrived",
        "cancelled": "cancelled",
        "failed": "failed",
        "expired": "expired",
    }.get(status, "failed")
    return {
        "status": terminal_status,
        "reason": action.get("failureReason") or status or "linked_action_terminal",
        "actionId": action_id,
        "worldActionId": action_id,
        "worldActionStatus": status,
    }


def _move_intent_linked_world_action_id(intent):
    if not isinstance(intent, dict):
        return None
    target = intent.get("target") if isinstance(intent.get("target"), dict) else {}
    metadata = intent.get("targetMetadata") if isinstance(intent.get("targetMetadata"), dict) else {}
    route = intent.get("route") if isinstance(intent.get("route"), dict) else {}
    route_target = route.get("target") if isinstance(route.get("target"), dict) else {}
    route_metadata = route.get("targetMetadata") if isinstance(route.get("targetMetadata"), dict) else {}
    for value in (
        intent.get("worldActionId"),
        intent.get("actionId"),
        target.get("worldActionId"),
        target.get("actionId"),
        metadata.get("worldActionId"),
        metadata.get("actionId"),
        route.get("worldActionId"),
        route_target.get("worldActionId"),
        route_target.get("actionId"),
        route_metadata.get("worldActionId"),
        route_metadata.get("actionId"),
    ):
        if value:
            return value
    return None


def reconcile_move_intents():
    with _live_agent_action_handoff_lock:
        return _reconcile_move_intents_unlocked()


def _reconcile_move_intents_unlocked():
    store = get_move_intents_store(persist_migration=True)
    now = _utc_now_iso()
    active = []
    history = list(store.get("history", []))
    changed = False
    for intent in store.get("active", []):
        linked_terminal = _linked_world_action_terminal_for_move(intent)
        reason = linked_terminal.get("reason") if linked_terminal else _move_target_invalid_reason(intent.get("target"))
        if reason:
            failed = dict(intent)
            route_status = linked_terminal.get("status") if linked_terminal else "failed"
            failed.update({"status": route_status if linked_terminal else "invalidated", "routeStatus": route_status, "failureReason": None if route_status == "arrived" else reason, "invalidatedAt": now, "updatedAt": now})
            route = dict(failed.get("route") or {})
            route.update({"state": route_status, "status": route_status, "setAgentTarget": False, "failureReason": None if route_status == "arrived" else reason})
            if linked_terminal:
                route["linkedWorldAction"] = linked_terminal
            failed["route"] = route
            history.append(failed)
            changed = True
        else:
            active.append(intent)
    next_store = {"active": active, "history": history}
    if changed:
        _, next_store = save_move_intents_store(next_store)
    return next_store


def _agent_busy_for_move(agent_id, action_id=None):
    for action in get_world_actions_store(persist_migration=True).get("active", []):
        if action.get("agentId") != agent_id:
            continue
        status = _canonical_world_action_status(action.get("status"))
        if status in WORLD_ACTION_ACTIVE_STATES and (not action_id or action.get("id") != action_id):
            return {"type": "world-action", "id": action.get("id"), "status": status}
    for intent in reconcile_move_intents().get("active", []):
        intent_action_id = _move_intent_linked_world_action_id(intent)
        if intent.get("agentId") == agent_id and intent.get("routeStatus") in MOVE_INTENT_ACTIVE_STATES and (not action_id or intent_action_id != action_id):
            return {"type": "move-intent", "id": intent.get("id"), "status": intent.get("routeStatus")}
    return None


def _behavior_source_kind_from_record(record):
    source = record.get("source") if isinstance(record, dict) and isinstance(record.get("source"), dict) else {}
    return record.get("behaviorSourceKind") or source.get("behaviorSourceKind") or source.get("kind")


def _active_behavior_records_for_agent(agent_id):
    records = []
    for action in get_world_actions_store(persist_migration=True).get("active", []):
        if action.get("agentId") != agent_id:
            continue
        status = _canonical_world_action_status(action.get("status"))
        if status in WORLD_ACTION_ACTIVE_STATES:
            records.append({"type": "world-action", "id": action.get("id"), "status": status, "behaviorSourceKind": _behavior_source_kind_from_record(action), "record": action})
    for intent in reconcile_move_intents().get("active", []):
        if intent.get("agentId") != agent_id or intent.get("routeStatus") not in MOVE_INTENT_ACTIVE_STATES:
            continue
        records.append({"type": "move-intent", "id": intent.get("id"), "status": intent.get("routeStatus"), "worldActionId": _move_intent_linked_world_action_id(intent), "behaviorSourceKind": _behavior_source_kind_from_record(intent), "record": intent})
    return records


def _interrupt_scripted_move_intent(intent_id, *, reason="interrupted_by_agent_live_mode"):
    with _live_agent_action_handoff_lock:
        return _interrupt_scripted_move_intent_unlocked(intent_id, reason=reason)


def _interrupt_scripted_move_intent_unlocked(intent_id, *, reason="interrupted_by_agent_live_mode"):
    if not intent_id:
        return None
    store = get_move_intents_store(persist_migration=True)
    now = _utc_now_iso()
    active = []
    interrupted = None
    for intent in store.get("active", []):
        if intent.get("id") != intent_id:
            active.append(intent)
            continue
        interrupted = dict(intent)
        route = dict(interrupted.get("route") or {})
        route.update({"state": "cancelled", "status": "cancelled", "setAgentTarget": False, "cancelledAt": now, "reason": reason})
        interrupted.update({"status": "cancelled", "routeStatus": "cancelled", "failureReason": "cancelled_by_system", "interruptedBy": "agent-live-mode", "interruptedAt": now, "updatedAt": now, "route": route})
    if interrupted:
        ok, saved = save_move_intents_store({"active": active, "history": [interrupted, *store.get("history", [])]})
        if not ok:
            return {"type": "move-intent", "id": intent_id, "error": "persist_failed", "details": saved}
        return {"type": "move-intent", "id": intent_id, "status": "cancelled", "reason": reason}
    return None


def _prepare_agent_live_mode_action_call(agent_id):
    interrupted = []
    for active in _active_behavior_records_for_agent(agent_id):
        source_kind = active.get("behaviorSourceKind")
        if source_kind == "user":
            return None, _api_error("active_user_directed_intent", "Agent Live Mode cannot override an active user-directed action or move intent.", details={k: active.get(k) for k in ["type", "id", "status", "behaviorSourceKind"]}), 409
        if source_kind in {"agent-scripted-mode", "system-schedule"}:
            if active.get("type") == "world-action":
                ok, result, status = cancel_world_action(active.get("id"), {"failureReason": "cancelled_by_system", "reason": "cancelled_by_system", "actor": "agent-live-mode", "source": "agent-live-mode"})
                if not ok:
                    return None, _api_error("scripted_interrupt_failed", "Agent Live Mode could not interrupt the active scripted world action.", details={"active": active, "result": result}), status
                interrupted.append({"type": "world-action", "id": active.get("id"), "status": "cancelled"})
            else:
                released = _interrupt_scripted_move_intent(active.get("id"))
                if isinstance(released, dict) and released.get("error"):
                    return None, _api_error("scripted_interrupt_failed", "Agent Live Mode could not interrupt the active scripted move intent.", details=released), 500
                if released:
                    interrupted.append(released)
            continue
        return None, _api_error("agent_unavailable", "Agent already has an active higher/equal authority action or move intent.", details={k: active.get(k) for k in ["type", "id", "status", "behaviorSourceKind"]}), 409
    return interrupted, None, None


def create_agent_live_mode_action_request(payload):
    if not isinstance(payload, dict):
        return False, _api_error("invalid_payload", "Agent Live Mode action request payload must be an object."), 400
    source = payload.get("source") if isinstance(payload.get("source"), dict) else None
    if not source or source.get("kind") != "agent-live-mode":
        return False, _api_error("invalid_behavior_source", "Agent Live Mode action caller requires source.kind to be agent-live-mode.", details={"required": "agent-live-mode"}), 400
    if not _agent_live_mode_runtime_enabled():
        return False, _agent_live_mode_feature_disabled_error(), 409
    agent_id = _resolve_agent_id(payload.get("agentId"))
    if not agent_id:
        return False, _api_error("agent_not_found", "agentId must reference an existing agent id or statusKey"), 404
    setting = get_agent_live_mode_setting(agent_id)
    if not setting or setting.get("agentLiveModeEnabled") is not True:
        return False, _agent_live_mode_disabled_error(agent_id), 403
    live_world = setting.get("liveWorld") if isinstance(setting.get("liveWorld"), dict) else _agent_live_world_claim_payload(agent_id)
    if live_world.get("conflict"):
        return False, _api_error(
            "agent_live_mode_world_conflict",
            live_world.get("notice") or "This agent is currently live in another Virtual World.",
            details={
                "agentId": agent_id,
                "currentWorld": live_world.get("currentWorld"),
                "activeWorld": live_world.get("claim"),
                "notice": live_world.get("notice"),
            },
        ), 409

    visible_action_contract, contract_error = _validate_live_agent_visible_action_contract(payload, action_type=payload.get("actionType") or payload.get("actionId"), capability=payload.get("capabilityTag"))
    if contract_error:
        proposal = None
        with _live_agent_loop_lock:
            state = get_live_agent_loop_state(persist_migration=True)
            proposal = _live_agent_loop_record_operator_proposal_from_rejection(state, agent_id, payload, contract_error)
            if proposal:
                save_live_agent_loop_state(state)
        if proposal and isinstance(contract_error.get("error"), dict):
            contract_error = _copy_jsonable(contract_error)
            details = contract_error["error"].setdefault("details", {})
            if isinstance(details, dict):
                details["operatorProposal"] = {
                    "schemaVersion": LIVE_AGENT_OPERATOR_PROPOSAL_SCHEMA_VERSION,
                    "id": proposal.get("id"),
                    "status": proposal.get("status"),
                    "executesOnApproval": False,
                    "endpoint": "GET /api/agent-live-loop/proposals",
                }
        return False, contract_error, 422

    with _live_agent_action_handoff_lock:
        interrupted, error, status = _prepare_agent_live_mode_action_call(agent_id)
        if error:
            return False, error, status

        action_payload = {**payload, "agentId": agent_id, "source": {**source, "kind": "agent-live-mode"}}
        visible_params = {
            "visibleActionContractVersion": LIVE_AGENT_VISIBLE_ACTION_CONTRACT_VERSION,
            "visibleActionPolicy": "visible-world-execution-required",
            "visibleWorldAction": True,
            "hiddenWorldMutationAllowed": False,
            "visibleExecutor": visible_action_contract.get("clientExecutor") if visible_action_contract else None,
            "requiresPhysicalAgentPresence": True,
        }
        if isinstance(payload.get("params"), dict):
            action_payload["params"] = {**payload.get("params"), **visible_params}
        elif payload.get("params") is None:
            action_payload["params"] = visible_params
        ok, action_result, action_status = create_world_action(action_payload)
        if not ok:
            return False, action_result, action_status
        action = action_result.get("action") if isinstance(action_result, dict) else None
        action_id = action.get("id") if isinstance(action, dict) else None
        move_payload = {
            "agentId": agent_id,
            "actionAgentId": agent_id,
            "actionId": action_id,
            "worldActionId": action_id,
            "source": action_payload["source"],
            "behaviorCategory": action_payload.get("behaviorCategory"),
            "behaviorSelectedObject": action_payload.get("behaviorSelectedObject"),
            "behaviorSelectedSpot": action_payload.get("behaviorSelectedSpot"),
            "behaviorProbabilityRoll": action_payload.get("behaviorProbabilityRoll"),
            "behaviorFallbackReason": action_payload.get("behaviorFallbackReason"),
            "target": {**(action.get("target") if isinstance(action, dict) and isinstance(action.get("target"), dict) else payload.get("target") or {}), "actionId": action_id, "worldActionId": action_id},
        }
        ok, move_result, move_status = create_move_intent(agent_id, move_payload)
        if not ok:
            cancel_world_action(action_id, {"failureReason": "cancelled_by_system", "reason": "cancelled_by_system", "actor": "agent-live-mode", "source": "agent-live-mode"})
            return False, _api_error("move_intent_handoff_failed", "Agent Live Mode action was validated but could not create the existing move-intent/AgentIntent handoff; the reserved action was cancelled.", details=move_result), move_status
        return True, {"ok": True, "action": action_result.get("action"), "worldAction": action_result, "moveIntent": move_result.get("moveIntent"), "routeHandoff": move_result.get("routeHandoff"), "linkedAction": move_result.get("linkedAction"), "interruptedLowerLayer": interrupted, "callerContract": {"endpoint": "POST /api/agent-model/actions", "requiredSourceKind": "agent-live-mode", "requiresAgentLiveModeEnabled": True, "usesExistingWorldActionValidation": True, "usesExistingMoveIntentHandoff": True, "visibleActionContractVersion": LIVE_AGENT_VISIBLE_ACTION_CONTRACT_VERSION, "visibleWorldExecutionRequired": True, "hiddenWorldMutationAllowed": False, "visibleExecutor": visible_action_contract.get("clientExecutor") if visible_action_contract else None, "overrideOrder": ["user", "agent-live-mode", "agent-scripted-mode"]}}, 202


# ─── AGENT LIVE MODE PERSISTENT LOOP ─────────────────────────────
def _epoch_to_utc_iso(epoch):
    try:
        return time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime(float(epoch)))
    except (TypeError, ValueError, OSError):
        return _utc_now_iso()


def default_live_agent_loop_state():
    now = _utc_now_iso()
    return {
        "schemaVersion": LIVE_AGENT_LOOP_SCHEMA_VERSION,
        "enabled": LIVE_AGENT_LOOP_DEFAULTS["enabled"],
        "createdAt": now,
        "updatedAt": now,
        "lastTickAt": None,
        "pausedUntil": None,
        "pauseReason": None,
        "pausedAt": None,
        "pausedBy": None,
        "schedulerCursorAgentId": None,
        "featureKill": None,
        "intervalSec": LIVE_AGENT_LOOP_DEFAULTS["intervalSec"],
        "minActionIntervalSec": LIVE_AGENT_LOOP_DEFAULTS["minActionIntervalSec"],
        "clientActiveTtlSec": LIVE_AGENT_LOOP_DEFAULTS["clientActiveTtlSec"],
        "maxActionsPerTick": LIVE_AGENT_LOOP_DEFAULTS["maxActionsPerTick"],
        "worldClientRequired": LIVE_AGENT_LOOP_DEFAULTS["worldClientRequired"],
        "serverRuntimeAuthority": LIVE_AGENT_LOOP_DEFAULTS["serverRuntimeAuthority"],
        "modelDecisionEnabled": LIVE_AGENT_LOOP_DEFAULTS["modelDecisionEnabled"],
        "modelDecisionTimeoutSec": LIVE_AGENT_LOOP_DEFAULTS["modelDecisionTimeoutSec"],
        "modelDecisionMinIntervalSec": LIVE_AGENT_LOOP_DEFAULTS["modelDecisionMinIntervalSec"],
        "userChatPreemptionEnabled": LIVE_AGENT_LOOP_DEFAULTS["userChatPreemptionEnabled"],
        "userChatPreemptionHoldSec": LIVE_AGENT_LOOP_DEFAULTS["userChatPreemptionHoldSec"],
        "agents": {},
        "events": [],
        "stats": {"ticks": 0, "actionsCreated": 0, "dryRuns": 0, "errors": 0},
        "storageBudget": {
            "stateMaxBytes": LIVE_AGENT_LOOP_STATE_MAX_BYTES,
            "collectionMaxBytes": LIVE_AGENT_LOOP_COLLECTION_MAX_BYTES,
        },
    }


def _normalize_int(value, fallback, *, minimum=None, maximum=None):
    try:
        number = int(value)
    except (TypeError, ValueError):
        number = fallback
    if minimum is not None:
        number = max(minimum, number)
    if maximum is not None:
        number = min(maximum, number)
    return number


def _normalize_live_agent_loop_state(raw):
    state = default_live_agent_loop_state()
    if isinstance(raw, dict):
        for key in ("enabled", "createdAt", "updatedAt", "lastTickAt", "worldClientRequired", "serverRuntimeAuthority", "pausedUntil", "pauseReason", "pausedAt", "pausedBy", "schedulerCursorAgentId", "featureKill"):
            if key in raw:
                state[key] = raw[key]
        state["intervalSec"] = _normalize_int(raw.get("intervalSec"), state["intervalSec"], minimum=10, maximum=300)
        state["minActionIntervalSec"] = _normalize_int(raw.get("minActionIntervalSec"), state["minActionIntervalSec"], minimum=10, maximum=3600)
        state["clientActiveTtlSec"] = _normalize_int(raw.get("clientActiveTtlSec"), state["clientActiveTtlSec"], minimum=10, maximum=300)
        state["maxActionsPerTick"] = _normalize_int(raw.get("maxActionsPerTick"), state["maxActionsPerTick"], minimum=1, maximum=5)
        if isinstance(raw.get("modelDecisionEnabled"), bool):
            state["modelDecisionEnabled"] = raw["modelDecisionEnabled"]
        state["modelDecisionTimeoutSec"] = _normalize_int(raw.get("modelDecisionTimeoutSec"), state["modelDecisionTimeoutSec"], minimum=10, maximum=180)
        state["modelDecisionMinIntervalSec"] = _normalize_int(raw.get("modelDecisionMinIntervalSec"), state["modelDecisionMinIntervalSec"], minimum=10, maximum=3600)
        if isinstance(raw.get("userChatPreemptionEnabled"), bool):
            state["userChatPreemptionEnabled"] = raw["userChatPreemptionEnabled"]
        state["userChatPreemptionHoldSec"] = _normalize_int(raw.get("userChatPreemptionHoldSec"), state["userChatPreemptionHoldSec"], minimum=30, maximum=1800)
        if isinstance(raw.get("agents"), dict):
            state["agents"] = {str(k): v for k, v in raw["agents"].items() if isinstance(v, dict)}
        if isinstance(raw.get("events"), list):
            state["events"] = _live_agent_loop_trim_list(raw["events"], LIVE_AGENT_LOOP_DEFAULTS["eventRetention"])
        if isinstance(raw.get("operatorProposals"), list):
            state["operatorProposals"] = _live_agent_loop_trim_list(raw["operatorProposals"], LIVE_AGENT_LOOP_DEFAULTS["operatorProposalRetention"])
        if isinstance(raw.get("stats"), dict):
            state["stats"].update({k: v for k, v in raw["stats"].items() if isinstance(v, (int, float))})
    state["schemaVersion"] = LIVE_AGENT_LOOP_SCHEMA_VERSION
    state["enabled"] = bool(state.get("enabled"))
    state["serverRuntimeAuthority"] = True
    state["worldClientRequired"] = False
    if state.get("schedulerCursorAgentId") is not None:
        state["schedulerCursorAgentId"] = str(state.get("schedulerCursorAgentId") or "").strip() or None
    if not isinstance(state.get("featureKill"), dict):
        state["featureKill"] = None
    state["storageBudget"] = {
        "stateMaxBytes": LIVE_AGENT_LOOP_STATE_MAX_BYTES,
        "collectionMaxBytes": LIVE_AGENT_LOOP_COLLECTION_MAX_BYTES,
    }
    if state.get("pausedUntil") and not _parse_isoish_epoch(state.get("pausedUntil")):
        state["pausedUntil"] = None
        state["pauseReason"] = None
        state["pausedAt"] = None
        state["pausedBy"] = None
    _live_agent_loop_normalize_operator_proposals(state)
    normalized_agents = {}
    for agent_id, row in (state.get("agents") or {}).items():
        if not isinstance(row, dict):
            continue
        agent_row = dict(row)
        agent_row.setdefault("enabled", True)
        normalized_agents[str(agent_id)] = _live_agent_loop_normalize_memory(agent_row)
    state["agents"] = normalized_agents
    return _live_agent_loop_enforce_state_budget(state)


def _live_agent_loop_event_key(event):
    if not isinstance(event, dict):
        return ""
    return json.dumps({
        "at": event.get("at"),
        "type": event.get("type"),
        "agentId": event.get("agentId"),
        "details": event.get("details") if isinstance(event.get("details"), dict) else {},
    }, sort_keys=True, default=str)


def _live_agent_loop_merge_events(existing_events, incoming_events):
    rows = []
    seen = set()
    for event in [*(existing_events or []), *(incoming_events or [])]:
        if not isinstance(event, dict):
            continue
        key = _live_agent_loop_event_key(event)
        if not key or key in seen:
            continue
        seen.add(key)
        rows.append(event)
    rows.sort(key=lambda item: _parse_isoish_epoch(item.get("at")) or 0)
    return _live_agent_loop_trim_list(rows, LIVE_AGENT_LOOP_DEFAULTS["eventRetention"])


def _live_agent_loop_prefer_episode_candidate(current, candidate):
    if not current:
        return candidate
    if not candidate:
        return current
    current_active = _live_agent_loop_episode_is_active(current)
    candidate_active = _live_agent_loop_episode_is_active(candidate)
    if current_active and not candidate_active:
        return candidate
    if candidate_active and not current_active:
        return current
    current_epoch = _parse_isoish_epoch(current.get("updatedAt")) or 0
    candidate_epoch = _parse_isoish_epoch(candidate.get("updatedAt")) or 0
    return candidate if candidate_epoch >= current_epoch else current


def _live_agent_loop_prefer_plan_candidate(current, candidate):
    if not current:
        return candidate
    if not candidate:
        return current
    current_active = _live_agent_loop_plan_is_active(current)
    candidate_active = _live_agent_loop_plan_is_active(candidate)
    if current_active and not candidate_active:
        return candidate
    if candidate_active and not current_active:
        return current
    current_epoch = _parse_isoish_epoch(current.get("updatedAt")) or 0
    candidate_epoch = _parse_isoish_epoch(candidate.get("updatedAt")) or 0
    return candidate if candidate_epoch >= current_epoch else current


def _live_agent_loop_merge_agent_episodes(existing_agent, incoming_agent):
    by_id = {}
    for raw in [
        *((existing_agent or {}).get("episodes") or []),
        (existing_agent or {}).get("activeEpisode"),
        *((incoming_agent or {}).get("episodes") or []),
        (incoming_agent or {}).get("activeEpisode"),
    ]:
        episode = _live_agent_loop_normalize_episode(raw)
        if not episode:
            continue
        episode_id = episode.get("id")
        by_id[episode_id] = _live_agent_loop_prefer_episode_candidate(by_id.get(episode_id), episode)
    episodes = sorted(by_id.values(), key=lambda item: _parse_isoish_epoch(item.get("updatedAt")) or 0)
    episodes = _live_agent_loop_trim_list(episodes, LIVE_AGENT_LOOP_DEFAULTS["episodeRetention"])
    active = [item for item in episodes if _live_agent_loop_episode_is_active(item)]
    active.sort(key=lambda item: _parse_isoish_epoch(item.get("updatedAt")) or 0, reverse=True)
    return episodes, (active[0] if active else None)


def _live_agent_loop_merge_agent_plans(existing_agent, incoming_agent):
    by_id = {}
    for raw in [
        *((existing_agent or {}).get("plans") or []),
        (existing_agent or {}).get("activePlan"),
        *((incoming_agent or {}).get("plans") or []),
        (incoming_agent or {}).get("activePlan"),
    ]:
        plan = _live_agent_loop_normalize_plan(raw)
        if not plan:
            continue
        plan_id = plan.get("id")
        by_id[plan_id] = _live_agent_loop_prefer_plan_candidate(by_id.get(plan_id), plan)
    plans = sorted(by_id.values(), key=lambda item: _parse_isoish_epoch(item.get("updatedAt")) or 0)
    plans = _live_agent_loop_trim_list(plans, LIVE_AGENT_LOOP_DEFAULTS["planRetention"])
    active = [item for item in plans if _live_agent_loop_plan_is_active(item)]
    active.sort(key=lambda item: _parse_isoish_epoch(item.get("updatedAt")) or 0, reverse=True)
    return plans, (active[0] if active else None)


def _live_agent_loop_merge_agent_goals(existing_agent, incoming_agent):
    return _live_agent_goals.merge_goals(
        existing_agent,
        incoming_agent,
        retention=LIVE_AGENT_LOOP_DEFAULTS["durableGoalRetention"],
    )


def _live_agent_loop_reconcile_agent_records_from_events(agents, events):
    episode_events = {}
    plan_events = {}
    durable_goal_verification_events = {}
    for event in events or []:
        if not isinstance(event, dict):
            continue
        details = event.get("details") if isinstance(event.get("details"), dict) else {}
        event_type = event.get("type")
        at = event.get("at") if _parse_isoish_epoch(event.get("at")) else _utc_now_iso()
        if event_type in {"episode-verified", "episode-verification-failed"} and details.get("episodeId"):
            episode_id = details.get("episodeId")
            current = episode_events.get(episode_id)
            if not current or (_parse_isoish_epoch(at) or 0) >= (_parse_isoish_epoch(current.get("at")) or 0):
                episode_events[episode_id] = {"type": event_type, "at": at, "details": details}
        if event_type in {"plan-completed", "plan-failed"} and details.get("planId"):
            plan_id = details.get("planId")
            current = plan_events.get(plan_id)
            if not current or (_parse_isoish_epoch(at) or 0) >= (_parse_isoish_epoch(current.get("at")) or 0):
                plan_events[plan_id] = {"type": event_type, "at": at, "details": details}

        # A successful embodied-step verification is monotonic evidence. State
        # saves can race with a planner reply or another metadata writer that
        # still holds the pre-verification goal snapshot. Episodes and plans
        # already recover from their terminal events below; durable steps need
        # the same protection so completed work is not repeated.
        if (
            event_type in {"durable-goal-step-verified", "durable-goal-completed"}
            and details.get("ok") is True
            and event.get("agentId")
            and details.get("goalId")
            and details.get("goalTaskId")
            and details.get("goalStepId")
            and details.get("actionId")
        ):
            goal_key = (
                str(event.get("agentId")),
                str(details.get("goalId")),
                str(details.get("goalTaskId")),
                str(details.get("goalStepId")),
            )
            current = durable_goal_verification_events.get(goal_key)
            if not current or (_parse_isoish_epoch(at) or 0) >= (_parse_isoish_epoch(current.get("at")) or 0):
                durable_goal_verification_events[goal_key] = {"type": event_type, "at": at, "details": details}

    for agent_id, row in agents.items():
        if not isinstance(row, dict):
            continue
        reconciled_episodes = []
        for raw in row.get("episodes") or []:
            episode = _live_agent_loop_normalize_episode(raw)
            if not episode:
                continue
            event = episode_events.get(episode.get("id"))
            if event and (_parse_isoish_epoch(event.get("at")) or 0) >= (_parse_isoish_epoch(episode.get("updatedAt")) or 0):
                details = event.get("details") or {}
                verification = episode.get("verification") if isinstance(episode.get("verification"), dict) else {}
                verification = {
                    **verification,
                    "id": verification.get("id") or details.get("verificationId"),
                    "ok": details.get("ok") is True,
                    "status": "verified" if details.get("ok") is True else "failed",
                    "at": verification.get("at") or event.get("at"),
                }
                episode["verification"] = verification
                episode["updatedAt"] = event.get("at")
                if event.get("type") == "episode-verified":
                    episode["status"] = "completed"
                    episode["phase"] = "continue"
                    episode["verifiedAt"] = episode.get("verifiedAt") or event.get("at")
                    episode["completedAt"] = episode.get("completedAt") or event.get("at")
                    episode["operatorSummary"] = "Episode verified; planner can continue with evidence in memory."
                    history_event = "verification-passed"
                else:
                    reportable_failure = details.get("reportableFailure") is not False
                    if reportable_failure:
                        episode["status"] = "awaiting_report"
                        episode["phase"] = "report"
                        if details.get("issueId"):
                            episode["issueId"] = details.get("issueId")
                        episode["operatorSummary"] = "Verification failed; report to Coder before treating this loop as learned."
                        history_event = "verification-failed"
                    else:
                        episode["status"] = "failed"
                        episode["phase"] = "continue"
                        episode.pop("issueId", None)
                        episode["failedAt"] = episode.get("failedAt") or event.get("at")
                        episode["operatorSummary"] = "Verification failed after a retryable world interruption; re-observe and retry only when route, target, or conditions change."
                        history_event = "verification-failed-nonreportable"
                existing_history = {
                    (item.get("event"), item.get("verificationId"))
                    for item in (episode.get("history") or [])
                    if isinstance(item, dict)
                }
                history_key = (history_event, details.get("verificationId"))
                if history_key not in existing_history:
                    episode.setdefault("history", []).append({
                        "at": event.get("at"),
                        "phase": "verify",
                        "event": history_event,
                        "verificationId": details.get("verificationId"),
                    })
            reconciled_episodes.append(_live_agent_loop_normalize_episode(episode))
        row["episodes"] = _live_agent_loop_trim_list(reconciled_episodes, LIVE_AGENT_LOOP_DEFAULTS["episodeRetention"])
        active_episodes = [item for item in row["episodes"] if _live_agent_loop_episode_is_active(item)]
        active_episodes.sort(key=lambda item: _parse_isoish_epoch(item.get("updatedAt")) or 0, reverse=True)
        if active_episodes:
            row["activeEpisode"] = active_episodes[0]
        else:
            row.pop("activeEpisode", None)

        reconciled_plans = []
        for raw in row.get("plans") or []:
            plan = _live_agent_loop_normalize_plan(raw)
            if not plan:
                continue
            event = plan_events.get(plan.get("id"))
            if event and (_parse_isoish_epoch(event.get("at")) or 0) >= (_parse_isoish_epoch(plan.get("updatedAt")) or 0):
                details = event.get("details") or {}
                plan["updatedAt"] = event.get("at")
                if event.get("type") == "plan-completed":
                    plan["status"] = "completed"
                    plan["completedAt"] = plan.get("completedAt") or event.get("at")
                    plan["operatorSummary"] = f"Verified and completed plan: {plan.get('title')}."
                else:
                    plan["status"] = "failed"
                    plan["failedAt"] = plan.get("failedAt") or event.get("at")
                    plan["failureReason"] = _live_agent_loop_clean_plan_text(details.get("status") or "verification failed", limit=240)
                    plan["operatorSummary"] = f"Plan failed verification: {plan.get('failureReason') or 'verification failed'}."
            reconciled_plans.append(_live_agent_loop_normalize_plan(plan))
        row["plans"] = _live_agent_loop_trim_list(reconciled_plans, LIVE_AGENT_LOOP_DEFAULTS["planRetention"])
        active_plans = [item for item in row["plans"] if _live_agent_loop_plan_is_active(item)]
        active_plans.sort(key=lambda item: _parse_isoish_epoch(item.get("updatedAt")) or 0, reverse=True)
        if active_plans:
            row["activePlan"] = active_plans[0]
        else:
            row.pop("activePlan", None)

        reconciled_goals = []
        for raw in row.get("durableGoals") or []:
            goal = _live_agent_goals.normalize_goal(raw)
            if not goal:
                continue
            for task in goal.get("tasks") or []:
                for step in task.get("steps") or []:
                    event = durable_goal_verification_events.get((
                        str(agent_id),
                        str(goal.get("id")),
                        str(task.get("id")),
                        str(step.get("id")),
                    ))
                    if not event:
                        continue
                    details = event.get("details") or {}
                    current_outcome = step.get("outcome") if isinstance(step.get("outcome"), dict) else {}
                    if current_outcome.get("verified") is True:
                        continue
                    # Only replay evidence for the same attempt. This prevents
                    # an older success from satisfying a deliberately retried
                    # or newly replanned step that reuses stable ids.
                    if str(step.get("actionId") or "") != str(details.get("actionId") or ""):
                        continue
                    event_epoch = _parse_isoish_epoch(event.get("at")) or 0
                    step_epoch = _parse_isoish_epoch(step.get("updatedAt")) or 0
                    if event_epoch < step_epoch:
                        continue
                    recorded = details.get("outcome") if isinstance(details.get("outcome"), dict) else {}
                    goal, _ = _live_agent_goals.record_verified_outcome(
                        goal,
                        {
                            "id": details.get("verificationId") or recorded.get("verificationId"),
                            "actionId": details.get("actionId"),
                            "goalTaskId": details.get("goalTaskId"),
                            "goalStepId": details.get("goalStepId"),
                            "ok": True,
                            "reason": recorded.get("reason") or "",
                            "evidence": _copy_jsonable(recorded.get("evidence")) if isinstance(recorded.get("evidence"), dict) else {},
                        },
                        now_iso=event.get("at"),
                    )
            reconciled_goals.append(goal)
        row["durableGoals"] = reconciled_goals
        _live_agent_goals.normalize_agent_goals(
            row,
            retention=LIVE_AGENT_LOOP_DEFAULTS["durableGoalRetention"],
        )
    return agents


def _live_agent_loop_merge_state_for_save(existing, incoming):
    if not isinstance(existing, dict):
        return incoming
    merged = dict(incoming if isinstance(incoming, dict) else {})
    merged["events"] = _live_agent_loop_merge_events(existing.get("events"), merged.get("events"))
    existing_agents = existing.get("agents") if isinstance(existing.get("agents"), dict) else {}
    incoming_agents = merged.get("agents") if isinstance(merged.get("agents"), dict) else {}
    terminal_events_by_agent = {}
    for event in merged.get("events") or []:
        if not isinstance(event, dict) or event.get("type") != "durable-goal-completed" or not event.get("agentId"):
            continue
        details = event.get("details") if isinstance(event.get("details"), dict) else {}
        if details.get("ok") is not True or not details.get("goalId"):
            continue
        terminal_events_by_agent.setdefault(str(event.get("agentId")), []).append({
            "goalId": details.get("goalId"),
            "status": "completed",
            "at": event.get("at"),
            "actionId": details.get("actionId"),
            "verificationId": details.get("verificationId"),
            "goalTaskId": details.get("goalTaskId"),
            "goalStepId": details.get("goalStepId"),
            "outcome": _copy_jsonable(details.get("outcome")) if isinstance(details.get("outcome"), dict) else None,
        })
    agents = {}
    for agent_id in sorted({*existing_agents.keys(), *incoming_agents.keys()}):
        existing_agent = existing_agents.get(agent_id) if isinstance(existing_agents.get(agent_id), dict) else {}
        incoming_agent = incoming_agents.get(agent_id) if isinstance(incoming_agents.get(agent_id), dict) else {}
        row = {**existing_agent, **incoming_agent}
        row["terminalGoalTombstones"] = _live_agent_loop_normalize_terminal_goal_tombstones([
            *(existing_agent.get("terminalGoalTombstones") or []),
            *(incoming_agent.get("terminalGoalTombstones") or []),
            *(terminal_events_by_agent.get(str(agent_id)) or []),
        ])
        episodes, active_episode = _live_agent_loop_merge_agent_episodes(existing_agent, incoming_agent)
        row["episodes"] = episodes
        if active_episode:
            row["activeEpisode"] = active_episode
        else:
            row.pop("activeEpisode", None)
        plans, active_plan = _live_agent_loop_merge_agent_plans(existing_agent, incoming_agent)
        row["plans"] = plans
        if active_plan:
            row["activePlan"] = active_plan
        else:
            row.pop("activePlan", None)
        goals, active_goal = _live_agent_loop_merge_agent_goals(existing_agent, incoming_agent)
        row["goalLedgerSchemaVersion"] = LIVE_AGENT_GOAL_LEDGER_SCHEMA_VERSION
        row["durableGoals"] = goals
        if active_goal:
            row["activeGoal"] = active_goal
        else:
            row.pop("activeGoal", None)
        agents[agent_id] = row
    merged["agents"] = _live_agent_loop_reconcile_agent_records_from_events(agents, merged.get("events") or [])
    return merged


@_world_meta_transaction
def get_live_agent_loop_state(*, persist_migration=False, meta=None):
    meta = meta if isinstance(meta, dict) else load_world_meta_fast()
    agent_life = meta.get("agentLife") if isinstance(meta.get("agentLife"), dict) else {}
    existing = agent_life.get("liveModeLoop")
    state = _normalize_live_agent_loop_state(existing)
    if persist_migration and state != existing:
        agent_life["liveModeLoop"] = state
        meta["agentLife"] = agent_life
        save_world_meta(meta)
    return state


@_world_meta_transaction
def save_live_agent_loop_state(state, *, merge_existing=True):
    # World actions and controller checkpoints share world-meta.json. Treat the
    # targeted update as one transaction so neither writer can restore a stale
    # snapshot of the other's subtree.
    with _WORLD_META_LOCK:
        meta = load_world_meta()
        agent_life = meta.get("agentLife") if isinstance(meta.get("agentLife"), dict) else {}
        if merge_existing:
            state = _live_agent_loop_merge_state_for_save(agent_life.get("liveModeLoop"), state)
        state = _normalize_live_agent_loop_state(state)
        state["updatedAt"] = _utc_now_iso()
        agent_life["liveModeLoop"] = state
        meta["agentLife"] = agent_life
        save_world_meta(meta)
    return state


@contextlib.contextmanager
def _live_agent_loop_observability_lock(timeout_sec=LIVE_AGENT_OBSERVABILITY_LOCK_TIMEOUT_SEC):
    try:
        acquired = _live_agent_loop_lock.acquire(timeout=max(0.0, float(timeout_sec)))
    except (TypeError, ValueError):
        acquired = _live_agent_loop_lock.acquire(blocking=False)
    try:
        yield bool(acquired)
    finally:
        if acquired:
            _live_agent_loop_lock.release()


def _live_agent_loop_readonly_state_snapshot():
    try:
        return get_live_agent_loop_state(persist_migration=False, meta=load_world_meta_fast())
    except Exception:
        return default_live_agent_loop_state()


def _clean_live_agent_loop_client_detail(value, limit=160):
    if value is None:
        return None
    text = str(value).strip()
    if not text:
        return None
    return text[:limit]


def note_live_agent_loop_world_client_activity(source="/api/world-actions/active", client_version=None, client_info=None):
    global _live_agent_loop_last_client_at, _live_agent_loop_last_client_info
    if not _agent_live_mode_runtime_enabled():
        return False
    if client_version != LIVE_AGENT_LOOP_CLIENT_MARKER_VERSION:
        return False
    now_epoch = time.time()
    state = get_live_agent_loop_state()
    ttl = _normalize_int(state.get("clientActiveTtlSec"), LIVE_AGENT_LOOP_DEFAULTS["clientActiveTtlSec"], minimum=10, maximum=300)
    info = client_info if isinstance(client_info, dict) else {}
    runtime_state = str(info.get("runtimeState") or "").strip().lower()
    runtime_connected = str(info.get("runtimeConnected") or "").strip().lower()
    if runtime_state in {"stale", "reconnecting", "disconnected"} or runtime_connected in {"false", "0", "no"}:
        clear_live_agent_loop_world_client_activity()
        return False
    cleaned = {
        "sessionId": _clean_live_agent_loop_client_detail(info.get("sessionId"), limit=96),
        "client": _clean_live_agent_loop_client_detail(info.get("client"), limit=80) or "main3d-live-sync",
        "version": _clean_live_agent_loop_client_detail(client_version, limit=96),
        "source": _clean_live_agent_loop_client_detail(source, limit=120) or "/api/world-actions/active",
        "page": _clean_live_agent_loop_client_detail(info.get("page"), limit=160),
        "visibility": _clean_live_agent_loop_client_detail(info.get("visibility"), limit=32),
        "runtimeState": _clean_live_agent_loop_client_detail(runtime_state, limit=32),
        "runtimeConnected": _clean_live_agent_loop_client_detail(runtime_connected, limit=16),
        "snapshotAgeMs": _clean_live_agent_loop_client_detail(info.get("snapshotAgeMs"), limit=24),
        "userAgent": _clean_live_agent_loop_client_detail(info.get("userAgent"), limit=160),
        "lastSeenAt": _epoch_to_utc_iso(now_epoch),
    }
    cleaned = {key: value for key, value in cleaned.items() if value is not None}
    incoming_session = cleaned.get("sessionId") or cleaned.get("client")
    with _live_agent_loop_lock:
        current_info = dict(_live_agent_loop_last_client_info or {})
        current_session = current_info.get("sessionId") or current_info.get("client")
        last_seen = float(_live_agent_loop_last_client_at or 0)
        current_active = bool(last_seen and (now_epoch - last_seen) <= ttl)
        if current_active and current_session and incoming_session and current_session != incoming_session:
            return False
        _live_agent_loop_last_client_at = now_epoch
        _live_agent_loop_last_client_info = cleaned
    return True


def clear_live_agent_loop_world_client_activity():
    global _live_agent_loop_last_client_at, _live_agent_loop_last_client_info
    with _live_agent_loop_lock:
        had_client = bool(_live_agent_loop_last_client_at)
        _live_agent_loop_last_client_at = 0
        _live_agent_loop_last_client_info = {}
    return had_client


def _live_agent_loop_world_client_status(state=None):
    state = state if isinstance(state, dict) else get_live_agent_loop_state()
    ttl = _normalize_int(state.get("clientActiveTtlSec"), LIVE_AGENT_LOOP_DEFAULTS["clientActiveTtlSec"], minimum=10, maximum=300)
    now = time.time()
    last_seen = float(_live_agent_loop_last_client_at or 0)
    age = (now - last_seen) if last_seen else None
    active = bool(last_seen and age is not None and age <= ttl)
    client_info = dict(_live_agent_loop_last_client_info or {})
    if last_seen:
        client_info.setdefault("lastSeenAt", _epoch_to_utc_iso(last_seen))
        client_info["ageSec"] = round(age, 3) if age is not None else None
        client_info["active"] = active
    diagnostic = None
    if active:
        session_label = client_info.get("sessionId") or client_info.get("client") or "unknown client"
        diagnostic = f"Client session {session_label} is within the active TTL and can enable new visible Live Mode actions."
    elif client_info:
        session_label = client_info.get("sessionId") or client_info.get("client") or "unknown client"
        diagnostic = f"Last client session {session_label} is stale; the loop will wait for a fresh 3D sync marker."
    return {
        "active": active,
        "lastSeenAt": _epoch_to_utc_iso(last_seen) if last_seen else None,
        "ageSec": round(age, 3) if age is not None else None,
        "ttlSec": ttl,
        "source": "/api/world-actions/active",
        "requiredClientVersion": LIVE_AGENT_LOOP_CLIENT_MARKER_VERSION,
        "client": client_info or None,
        "diagnostic": diagnostic,
    }


def _live_agent_loop_pause_status(state, now_epoch=None):
    now_epoch = float(now_epoch or time.time())
    paused_until_epoch = _parse_isoish_epoch(state.get("pausedUntil"))
    active = bool(paused_until_epoch and paused_until_epoch > now_epoch)
    return {
        "active": active,
        "pausedUntil": state.get("pausedUntil") if paused_until_epoch else None,
        "remainingSec": max(0, int(round(paused_until_epoch - now_epoch))) if active else 0,
        "reason": state.get("pauseReason") if active else None,
        "pausedAt": state.get("pausedAt") if active else None,
        "pausedBy": state.get("pausedBy") if active else None,
    }


##############################################################################
# LIVE AGENT MODE - USER ATTENTION (chat preemption)
##############################################################################

def _live_agent_user_attention_hold_sec():
    try:
        state = get_live_agent_loop_state()
        return _normalize_int(state.get("userChatPreemptionHoldSec"), LIVE_AGENT_LOOP_DEFAULTS["userChatPreemptionHoldSec"], minimum=30, maximum=1800)
    except Exception:
        return LIVE_AGENT_LOOP_DEFAULTS["userChatPreemptionHoldSec"]


def live_agent_note_user_attention(
    agent_id,
    *,
    source="chat",
    message_preview="",
    hold_sec=None,
    interrupt_current=False,
    mode="conversation",
):
    """Acquire the existing Live controller's user-attention lease.

    Ordinary conversation blocks admission of the *next* autonomous action but
    lets a safe physical action already owned by the world finish. Explicit
    stop/redirect callers opt into ``interrupt_current``. This keeps user
    authority above Live autonomy without turning conversation into a second
    movement/controller system.
    """
    if not _agent_live_mode_runtime_enabled():
        return None
    resolved = _resolve_agent_id(agent_id) or str(agent_id or "").strip()
    if not resolved:
        return None
    hold = _normalize_int(hold_sec, _live_agent_user_attention_hold_sec(), minimum=30, maximum=1800)
    now_epoch = time.time()
    record = {
        "agentId": resolved,
        "startedAt": _epoch_to_utc_iso(now_epoch),
        "holdUntilEpoch": now_epoch + hold,
        "holdUntil": _epoch_to_utc_iso(now_epoch + hold),
        "holdSec": hold,
        "source": str(source or "chat")[:80],
        "messagePreview": str(message_preview or "")[:160],
        "mode": "paused" if str(mode or "").lower() == "paused" else "conversation",
        "interruptCurrent": bool(interrupt_current),
        "blockNewActions": True,
    }
    with _live_agent_user_attention_lock:
        _live_agent_user_attention[resolved] = record
    interrupted = []
    if interrupt_current:
        try:
            interrupted = _live_agent_halt_live_actions_for_user(resolved)
        except Exception as exc:
            print(f"⚠️  Live Mode user preemption halt failed for {resolved}: {exc}")
    _live_agent_model_decision_cancel(resolved, reason="user-chat-preemption")
    record["interrupted"] = interrupted

    def _log_attention_event():
        try:
            with _live_agent_user_attention_lock:
                if _live_agent_user_attention.get(resolved) is not record:
                    return
            with _live_agent_loop_lock:
                if not _agent_live_mode_runtime_enabled():
                    return
                with _live_agent_user_attention_lock:
                    if _live_agent_user_attention.get(resolved) is not record:
                        return
                state = get_live_agent_loop_state(persist_migration=True)
                if state.get("userChatPreemptionEnabled", True):
                    _live_agent_loop_add_event(state, "user-attention", agent_id=resolved, details={"source": record["source"], "holdSec": hold, "mode": record["mode"], "interruptCurrent": bool(interrupt_current), "interrupted": interrupted})
                    agent_state = _live_agent_loop_agent_state(state, resolved)
                    agent_state["userAttention"] = {k: v for k, v in record.items() if k != "holdUntilEpoch"}
                    _live_agent_loop_controller_update(
                        resolved,
                        agent_state,
                        "paused" if record["mode"] == "paused" else "conversing",
                        reason="direct user attention",
                        attention=live_agent_user_attention_status(resolved),
                    )
                    save_live_agent_loop_state(state)
        except Exception as exc:
            print(f"⚠️  Live Mode user attention event log failed for {resolved}: {exc}")

    # The attention hold + action halt above are already effective. Audit logging
    # runs in the background so chat sends never wait on a long-held loop lock
    # (for example while a model decision is in flight).
    threading.Thread(target=_log_attention_event, daemon=True, name=f"vw-user-attention-{resolved}").start()
    return record


def live_agent_clear_user_attention(agent_id):
    resolved = _resolve_agent_id(agent_id) or str(agent_id or "").strip()
    if not resolved:
        return False
    with _live_agent_user_attention_lock:
        return _live_agent_user_attention.pop(resolved, None) is not None


def live_agent_user_attention_status(agent_id, now_epoch=None):
    resolved = _resolve_agent_id(agent_id) or str(agent_id or "").strip()
    now_epoch = float(now_epoch or time.time())
    with _live_agent_user_attention_lock:
        record = _live_agent_user_attention.get(resolved)
        if not record:
            return {"active": False, "agentId": resolved}
        if float(record.get("holdUntilEpoch") or 0) <= now_epoch:
            _live_agent_user_attention.pop(resolved, None)
            return {"active": False, "agentId": resolved, "expired": True}
        remaining = max(0, int(round(float(record.get("holdUntilEpoch") or 0) - now_epoch)))
        return {
            "active": True,
            "agentId": resolved,
            "startedAt": record.get("startedAt"),
            "holdUntil": record.get("holdUntil"),
            "remainingSec": remaining,
            "source": record.get("source"),
            "mode": record.get("mode") or "conversation",
            "interruptCurrent": bool(record.get("interruptCurrent")),
            "blockNewActions": True,
        }


def handle_live_agent_user_attention(payload):
    if not _agent_live_mode_runtime_enabled():
        return False, _agent_live_mode_feature_disabled_error(), _agent_live_mode_feature_disabled_status()
    if not isinstance(payload, dict):
        return False, _api_error("invalid_payload", "user-attention payload must be an object."), 400
    agent_id = payload.get("agentId") or payload.get("agent")
    if not agent_id:
        return False, _api_error("invalid_payload", "agentId is required."), 400
    if payload.get("clear") is True:
        cleared = live_agent_clear_user_attention(agent_id)
        return True, {"ok": True, "cleared": cleared, "agentId": _resolve_agent_id(agent_id) or agent_id}, 200
    record = live_agent_note_user_attention(
        agent_id,
        source=str(payload.get("source") or "api"),
        message_preview=str(payload.get("messagePreview") or "")[:160],
        hold_sec=payload.get("holdSec"),
        interrupt_current=payload.get("interruptCurrent") is True,
        mode=payload.get("mode") or ("paused" if payload.get("interruptCurrent") is True else "conversation"),
    )
    if not record:
        if not _agent_live_mode_runtime_enabled():
            return False, _agent_live_mode_feature_disabled_error(), _agent_live_mode_feature_disabled_status()
        return False, _api_error("agent_not_found", "agentId must reference an existing agent."), 404
    return True, {"ok": True, "userAttention": {key: value for key, value in record.items() if key != "holdUntilEpoch"}}, 200


def _live_agent_cancel_live_actions(agent_id, *, actor="agent-live-mode", move_reason="interrupted_by_live_mode", failure_reason="cancelled_by_system"):
    interrupted = []
    detailed_reason = str(failure_reason or "cancelled_by_system")
    actor_text = str(actor or "")
    lifecycle_reason = detailed_reason if detailed_reason in {"cancelled_by_user", "cancelled_by_system"} else (
        "cancelled_by_user" if "user" in actor_text.lower() or "user" in detailed_reason.lower() else "cancelled_by_system"
    )
    for active in _active_behavior_records_for_agent(agent_id):
        if active.get("behaviorSourceKind") != "agent-live-mode":
            continue
        if active.get("type") == "world-action":
            ok, result, status = cancel_world_action(active.get("id"), {
                "failureReason": lifecycle_reason,
                "reason": lifecycle_reason,
                "result": {
                    "status": "cancelled",
                    "reason": detailed_reason,
                    "lifecycleReason": lifecycle_reason,
                    "actor": actor_text,
                },
                "actor": actor,
                "source": "agent-live-mode",
            })
            interrupted.append({
                "type": "world-action",
                "id": active.get("id"),
                "cancelled": bool(ok),
                "status": status,
                "reason": detailed_reason,
                "lifecycleReason": lifecycle_reason,
                **({"error": result.get("error")} if isinstance(result, dict) and result.get("error") else {}),
            })
        elif active.get("type") == "move-intent":
            released = _interrupt_scripted_move_intent(active.get("id"), reason=move_reason)
            if released:
                interrupted.append(released)
    return interrupted


def _live_agent_halt_live_actions_for_user(agent_id):
    """Cancel active live-mode world actions and live-loop move intents for this agent
    so it can attend to the user. User-directed and scripted work of other sources is untouched."""
    return _live_agent_cancel_live_actions(
        agent_id,
        actor="user-chat-preemption",
        move_reason="interrupted_by_user_chat",
        failure_reason="cancelled_by_user_attention",
    )


def _live_agent_loop_stat(container, key, amount=1):
    stats = container.setdefault("stats", {})
    try:
        stats[key] = int(stats.get(key) or 0) + amount
    except (TypeError, ValueError):
        stats[key] = amount
    return stats[key]


def _live_agent_loop_add_event(state, event_type, *, agent_id=None, details=None):
    retention = LIVE_AGENT_LOOP_DEFAULTS["eventRetention"]
    event = {"at": _utc_now_iso(), "type": event_type}
    if agent_id:
        event["agentId"] = agent_id
    if isinstance(details, dict):
        event["details"] = details
    events = [event for event in (state.get("events") or []) if isinstance(event, dict)]
    events.append(event)
    state["events"] = _live_agent_loop_trim_list(events, retention)
    return event


def _live_agent_internal_notes_default():
    now = _utc_now_iso()
    return {
        "schemaVersion": LIVE_AGENT_INTERNAL_NOTE_SCHEMA_VERSION,
        "createdAt": now,
        "updatedAt": now,
        "agents": {},
    }


def _trim_agent_document_records(data, collection_key, *, max_records_per_agent, max_bytes):
    data = data if isinstance(data, dict) else {}
    agents = data.get("agents") if isinstance(data.get("agents"), dict) else {}
    base = {**data, "agents": {}}
    base.pop("storageBudget", None)
    candidates = []
    for agent_id, raw_row in agents.items():
        row = raw_row if isinstance(raw_row, dict) else {}
        records = [item for item in (row.get(collection_key) or []) if isinstance(item, dict)][-max(1, int(max_records_per_agent)):]
        base["agents"][str(agent_id)] = {**row, collection_key: []}
        for index, item in enumerate(records):
            stamp = item.get("createdAt") or item.get("startedAt") or item.get("completedAt") or item.get("updatedAt") or item.get("at")
            candidates.append({
                "agentId": str(agent_id),
                "index": index,
                "epoch": _parse_isoish_epoch(stamp) or 0,
                "item": item,
                "bytes": _json_size_bytes(item),
            })
    candidates.sort(key=lambda row: (row["epoch"], row["index"]), reverse=True)
    selected = []
    selected_keys = set()
    used = _json_size_bytes(base) + 512  # reserve envelope/storageBudget overhead

    # Keep the newest record for each agent first, then spend the remaining
    # budget on the newest records globally. This prevents a noisy agent from
    # evicting every trace of quieter residents.
    newest_per_agent = []
    seen_agents = set()
    for row in candidates:
        if row["agentId"] not in seen_agents:
            seen_agents.add(row["agentId"])
            newest_per_agent.append(row)
    for row in [*newest_per_agent, *candidates]:
        key = (row["agentId"], row["index"])
        if key in selected_keys:
            continue
        extra = row["bytes"] + 1
        if row["bytes"] and used + extra <= max_bytes:
            selected_keys.add(key)
            selected.append(row)
            used += extra

    for row in sorted(selected, key=lambda item: (item["agentId"], item["index"])):
        base["agents"][row["agentId"]][collection_key].append(row["item"])
    for agent_id, row in list(base["agents"].items()):
        if not row.get(collection_key):
            base["agents"].pop(agent_id, None)
    base["storageBudget"] = {
        "maxBytes": max_bytes,
        "currentBytes": _json_size_bytes(base),
        "recordCount": len(selected),
        "recordsDropped": max(0, len(candidates) - len(selected)),
    }
    return base


def _load_live_agent_internal_notes():
    try:
        data = _read_json_file(LIVE_AGENT_INTERNAL_NOTES_FILE)
    except (FileNotFoundError, json.JSONDecodeError, OSError):
        data = _live_agent_internal_notes_default()
    if not isinstance(data, dict):
        data = _live_agent_internal_notes_default()
    if not isinstance(data.get("agents"), dict):
        data["agents"] = {}
    data["schemaVersion"] = LIVE_AGENT_INTERNAL_NOTE_SCHEMA_VERSION
    return data


def _live_agent_internal_note_semantic_key(note):
    if not isinstance(note, dict):
        return ""
    basis = "|".join(
        re.sub(r"\s+", " ", str(note.get(key) or "").strip().lower())
        for key in ("agentId", "type", "title", "text")
    )
    return hashlib.sha256(basis.encode("utf-8", errors="ignore")).hexdigest()


def _live_agent_note_details_has_planner_frame(value, *, depth=0):
    if depth > 5:
        return False
    if isinstance(value, dict):
        planner_keys = {
            "prompt",
            "reply",
            "decisionframe",
            "goalframe",
            "perception",
            "candidates",
            "affordances",
            "plannerframe",
            "rawresponse",
        }
        if any(str(key).replace("_", "").lower() in planner_keys for key in value):
            return True
        return any(_live_agent_note_details_has_planner_frame(item, depth=depth + 1) for item in value.values())
    if isinstance(value, list):
        return any(_live_agent_note_details_has_planner_frame(item, depth=depth + 1) for item in value[:40])
    return False


def _live_agent_note_semantic_details(details):
    if not isinstance(details, dict):
        return {}
    semantic = {}
    for key in (
        "actionId",
        "worldActionId",
        "loopActionId",
        "planId",
        "planStepId",
        "status",
        "failureReason",
        "targetKey",
        "issueId",
        "relationshipId",
        "otherAgentId",
        "lesson",
        "reflection",
        "currentGoal",
    ):
        if details.get(key) is not None:
            semantic[key] = _compact_json_value_for_storage(
                details.get(key), max_depth=2, max_items=8, string_limit=900
            )
    target = _compact_storage_target(details.get("target"))
    if target:
        semantic["target"] = target
    return semantic


def _compact_live_agent_internal_note_record(note):
    if not isinstance(note, dict):
        return None
    compacted = _copy_jsonable(note)
    compacted["title"] = _live_agent_loop_clean_plan_text(compacted.get("title"), limit=180) or "Live Agent note"
    compacted["text"] = _live_agent_loop_clean_plan_text(compacted.get("text"), limit=1600) or ""
    details = compacted.get("details") if isinstance(compacted.get("details"), dict) else {}
    original_bytes = _json_size_bytes(note)
    planner_details = _live_agent_note_details_has_planner_frame(details)
    if planner_details:
        details = {
            **_live_agent_note_semantic_details(details),
            "storageCompacted": True,
            "legacyPlannerFrameRemoved": True,
            "originalDetailsBytes": _json_size_bytes(compacted.get("details")),
        }
    elif _json_size_bytes(details) > LIVE_AGENT_INTERNAL_NOTE_DETAILS_MAX_BYTES:
        details = _compact_json_value_for_storage(details, max_depth=4, max_items=20, string_limit=900)
        if not isinstance(details, dict) or _json_size_bytes(details) > LIVE_AGENT_INTERNAL_NOTE_DETAILS_MAX_BYTES:
            details = {
                **_live_agent_note_semantic_details(compacted.get("details")),
                "storageCompacted": True,
                "originalDetailsBytes": _json_size_bytes(compacted.get("details")),
            }
        else:
            details["storageCompacted"] = True
            details["originalDetailsBytes"] = _json_size_bytes(compacted.get("details"))
    if details:
        compacted["details"] = details
    else:
        compacted.pop("details", None)
    if _json_size_bytes(compacted) > LIVE_AGENT_INTERNAL_NOTE_RECORD_MAX_BYTES:
        semantic = _live_agent_note_semantic_details(compacted.get("details"))
        compacted["details"] = {
            **semantic,
            "storageCompacted": True,
            "originalRecordBytes": original_bytes,
        }
    return compacted


def _compact_live_agent_internal_notes_document(data):
    data = _copy_jsonable(data) if isinstance(data, dict) else _live_agent_internal_notes_default()
    agents = data.get("agents") if isinstance(data.get("agents"), dict) else {}
    next_agents = {}
    for agent_id, raw_row in agents.items():
        row = raw_row if isinstance(raw_row, dict) else {}
        deduped = {}
        order = []
        for note in [item for item in (row.get("notes") or []) if isinstance(item, dict)]:
            compacted = _compact_live_agent_internal_note_record(note)
            if not compacted or not compacted.get("text"):
                continue
            key = _live_agent_internal_note_semantic_key(compacted)
            if key not in deduped:
                deduped[key] = compacted
                order.append(key)
                continue
            previous = deduped[key]
            previous_epoch = _storage_record_epoch(previous)
            current_epoch = _storage_record_epoch(compacted)
            newest = compacted if current_epoch >= previous_epoch else previous
            oldest = previous if current_epoch >= previous_epoch else compacted
            newest["repeatCount"] = int(previous.get("repeatCount") or 1) + int(compacted.get("repeatCount") or 1)
            newest["firstCreatedAt"] = oldest.get("firstCreatedAt") or oldest.get("createdAt")
            newest["lastRepeatedAt"] = newest.get("updatedAt") or newest.get("createdAt")
            deduped[key] = newest
        notes = [deduped[key] for key in order if key in deduped]
        notes.sort(key=_storage_record_epoch)
        if notes:
            next_agents[str(agent_id)] = {**row, "notes": notes}
    data["agents"] = next_agents
    return data


def _save_live_agent_internal_notes(data):
    data = data if isinstance(data, dict) else _live_agent_internal_notes_default()
    data["schemaVersion"] = LIVE_AGENT_INTERNAL_NOTE_SCHEMA_VERSION
    data["updatedAt"] = _utc_now_iso()
    data = _compact_live_agent_internal_notes_document(data)
    data = _trim_agent_document_records(
        data,
        "notes",
        max_records_per_agent=LIVE_AGENT_LOOP_DEFAULTS["memoryRetention"] * 2,
        max_bytes=LIVE_AGENT_INTERNAL_NOTES_MAX_BYTES,
    )
    data["schemaVersion"] = LIVE_AGENT_INTERNAL_NOTE_SCHEMA_VERSION
    data["updatedAt"] = _utc_now_iso()
    _atomic_write_text(LIVE_AGENT_INTERNAL_NOTES_FILE, _json_compact_bytes(data).decode("utf-8"))
    return data


def _live_agent_internal_note_id(agent_id, note_type, title, text, details=None):
    basis = json.dumps({
        "agentId": agent_id,
        "type": note_type,
        "title": title,
        "text": text,
        "details": _copy_jsonable(details) if isinstance(details, dict) else {},
    }, sort_keys=True, default=str)
    return f"note-{hashlib.sha256(basis.encode('utf-8', errors='ignore')).hexdigest()[:16]}"


def _live_agent_loop_append_internal_note(agent_id, *, note_type="note", title="", text="", details=None, state=None, agent_state=None):
    resolved = _resolve_agent_id(agent_id) or str(agent_id or "").strip()
    if not resolved:
        return None
    title = _live_agent_loop_clean_plan_text(title or note_type, limit=180) or "Live Agent note"
    text = _live_agent_loop_clean_plan_text(text, limit=1600) or ""
    if not text:
        return None
    details = _copy_jsonable(details) if isinstance(details, dict) else {}
    if _json_size_bytes(details) > LIVE_AGENT_INTERNAL_NOTE_DETAILS_MAX_BYTES:
        original_bytes = _json_size_bytes(details)
        details = _compact_json_value_for_storage(details, max_depth=4, max_items=20, string_limit=900)
        if not isinstance(details, dict) or _json_size_bytes(details) > LIVE_AGENT_INTERNAL_NOTE_DETAILS_MAX_BYTES:
            details = {"storageCompacted": True, "originalBytes": original_bytes}
        else:
            details["storageCompacted"] = True
            details["originalBytes"] = original_bytes
    now_iso = _utc_now_iso()
    note = {
        "id": _live_agent_internal_note_id(resolved, note_type, title, text, details),
        "schemaVersion": LIVE_AGENT_INTERNAL_NOTE_SCHEMA_VERSION,
        "agentId": resolved,
        "type": str(note_type or "note")[:80],
        "title": title,
        "text": text,
        "createdAt": now_iso,
        "updatedAt": now_iso,
        "source": "live-agent-mode",
    }
    if details:
        note["details"] = details

    with _live_agent_internal_notes_lock:
        data = _load_live_agent_internal_notes()
        agents = data.setdefault("agents", {})
        row = agents.setdefault(resolved, {"notes": []})
        if not isinstance(row, dict):
            row = {"notes": []}
            agents[resolved] = row
        notes = [item for item in (row.get("notes") or []) if isinstance(item, dict) and item.get("id") != note["id"]]
        notes.append(note)
        notes.sort(key=lambda item: _parse_isoish_epoch(item.get("createdAt")) or 0)
        row["notes"] = notes[-LIVE_AGENT_LOOP_DEFAULTS["memoryRetention"] * 2:]
        row["updatedAt"] = now_iso
        _save_live_agent_internal_notes(data)

    if isinstance(agent_state, dict):
        memory = agent_state.get("memory") if isinstance(agent_state.get("memory"), dict) else {}
        memory["internalNotes"] = _live_agent_loop_trim_list([*(memory.get("internalNotes") or []), note], LIVE_AGENT_LOOP_DEFAULTS["memoryRetention"])
        agent_state["memory"] = memory
    if isinstance(state, dict):
        _live_agent_loop_add_event(state, "internal-note-written", agent_id=resolved, details={"noteId": note["id"], "type": note["type"], "title": note["title"]})
    return note


def _live_agent_loop_recent_internal_notes(agent_id, limit=6):
    resolved = _resolve_agent_id(agent_id) or str(agent_id or "").strip()
    if not resolved:
        return []
    data = _load_live_agent_internal_notes()
    row = (data.get("agents") or {}).get(resolved) if isinstance(data.get("agents"), dict) else {}
    row = row if isinstance(row, dict) else {}
    notes = [item for item in (row.get("notes") or []) if isinstance(item, dict)]
    notes.sort(key=lambda item: _parse_isoish_epoch(item.get("createdAt")) or 0, reverse=True)
    return notes[:max(1, int(limit))]


def _live_agent_loop_clamp_need(value):
    try:
        number = float(value)
    except (TypeError, ValueError):
        number = 0
    return round(max(0, min(1.25, number)), 3)


def _live_agent_loop_is_benign_system_cancel(status, reason):
    return _canonical_world_action_status(status) == "cancelled" and str(reason or "").strip() in {
        "cancelled_by_system",
        "superseded-by-new-plan",
        "preempted-by-higher-priority",
    }


def _live_agent_loop_is_retryable_world_failure(status, reason):
    """Classify one operational failure as re-observe/replan, not a bug report.

    A stale or temporarily unreachable route can result from a service restart,
    stale snapshot, collision, or moving target. The existing failure-streak
    logic promotes the issue after two consecutive matching failures.
    """
    status = _canonical_world_action_status(status)
    if status not in {"failed", "expired", "cancelled"}:
        return False
    token = str(reason or "").strip().lower().replace("-", "_").replace(" ", "_")
    return token in {
        "route_stale",
        "route_unreachable",
        "route_stalled",
        "target_unavailable",
        "target_disappeared",
        "object_reserved",
        "reservation_unavailable",
        "world_runtime_restarted",
    }


def _live_agent_loop_is_user_control_cancel(status, reason):
    """Return whether a terminal cancellation reflects user authority, not a
    failed Resident/world interaction.

    World actions must use the small lifecycle reason vocabulary accepted by
    the action API, while ``result.reason`` preserves the more specific cause.
    Both forms are accepted here so legacy records are repaired on read.
    """
    if _canonical_world_action_status(status) != "cancelled":
        return False
    token = str(reason or "").strip().lower().replace("-", "_").replace(" ", "_")
    return token in {
        "cancelled_by_user",
        "cancelled_by_user_redirect",
        "cancelled_by_user_attention",
        "redirected_by_user",
        "direct_user_redirect",
        "interrupted_by_user_chat",
        "user_chat_preemption",
    }


def _live_agent_loop_normalize_recent_action_record(record):
    if not isinstance(record, dict):
        return None
    normalized = _copy_jsonable(record)
    failure = normalized.get("failure") if isinstance(normalized.get("failure"), dict) else {}
    status = _canonical_world_action_status(normalized.get("status") or failure.get("status"))
    reason = (
        failure.get("reason")
        or failure.get("resultReason")
        or failure.get("failureReason")
        or normalized.get("resultReason")
        or normalized.get("failureReason")
        or status
    )
    user_control_cancel = _live_agent_loop_is_user_control_cancel(status, reason)
    benign_system_cancel = _live_agent_loop_is_benign_system_cancel(status, reason)
    retryable_world_failure = (
        _live_agent_loop_is_retryable_world_failure(status, reason)
        or _live_agent_loop_is_retryable_world_failure(status, failure.get("failureReason"))
    )
    if user_control_cancel or benign_system_cancel or retryable_world_failure:
        failure = dict(failure)
        failure["status"] = failure.get("status") or status
        failure["reason"] = failure.get("reason") or reason
        failure["reportable"] = False
        if user_control_cancel:
            failure["userControlCancel"] = True
            failure["superseded"] = True
        elif benign_system_cancel:
            failure["benignSystemCancel"] = True
        else:
            failure["retryableWorldFailure"] = True
        normalized["failure"] = failure
    return normalized


def _live_agent_loop_episode_matches_nonreportable_failure(agent_state, episode):
    if not isinstance(agent_state, dict) or not isinstance(episode, dict):
        return False
    if episode.get("status") not in {"awaiting_report", "reported", "awaiting_coder"}:
        return False
    verification = episode.get("verification") if isinstance(episode.get("verification"), dict) else {}
    if verification.get("ok") is True:
        return False
    memory = agent_state.get("memory") if isinstance(agent_state.get("memory"), dict) else {}
    loop_action_id = episode.get("loopActionId")
    target_key = episode.get("targetKey")
    matched = False
    for item in memory.get("recentActions") or []:
        if not isinstance(item, dict):
            continue
        if loop_action_id and item.get("loopActionId") != loop_action_id:
            continue
        failure = item.get("failure") if isinstance(item.get("failure"), dict) else {}
        if failure.get("reportable") is not False:
            continue
        item_target_key = item.get("targetKey") or failure.get("targetKey") or _live_agent_loop_target_key(item.get("target"))
        if not _live_agent_loop_target_keys_compatible(target_key, item_target_key):
            continue
        matched = True
        break
    if not matched:
        return False
    recent = _live_agent_loop_recent_outcome_summary(agent_state)
    for issue in recent.get("issues") or []:
        if not isinstance(issue, dict):
            continue
        if loop_action_id and issue.get("loopActionId") != loop_action_id:
            continue
        if not _live_agent_loop_target_keys_compatible(target_key, issue.get("targetKey")):
            continue
        return False
    return True


def _live_agent_loop_clear_nonreportable_episode(episode):
    episode = _copy_jsonable(episode) if isinstance(episode, dict) else {}
    if not episode:
        return None
    now_iso = _utc_now_iso()
    verification = episode.get("verification") if isinstance(episode.get("verification"), dict) else {}
    verification = dict(verification)
    verification["reportableFailure"] = False
    episode["verification"] = verification
    episode["status"] = "failed"
    episode["phase"] = "continue"
    episode["failedAt"] = episode.get("failedAt") or episode.get("reportedAt") or episode.get("updatedAt") or now_iso
    episode["updatedAt"] = episode.get("reportedAt") or episode.get("updatedAt") or now_iso
    episode["operatorSummary"] = "Verification failed after a retryable world interruption; no Coder follow-up is required unless the same grounded failure repeats."
    history = episode.setdefault("history", [])
    if not any(isinstance(item, dict) and item.get("event") == "verification-failed-nonreportable" for item in history):
        history.append({"at": episode["updatedAt"], "phase": "verify", "event": "verification-failed-nonreportable", "verificationId": verification.get("id")})
    return episode


def _live_agent_loop_resolve_reported_episode_from_recent_actions(agent_state, episode):
    if not isinstance(agent_state, dict) or not isinstance(episode, dict):
        return episode, None
    if _live_agent_loop_episode_status(episode.get("status")) not in {
        "awaiting_report",
        "reported",
        "awaiting_coder",
        "coder_responded",
    }:
        return episode, None
    memory = agent_state.get("memory") if isinstance(agent_state.get("memory"), dict) else {}
    episode_target_key = str(episode.get("targetKey") or "").strip()
    episode_loop_action_id = str(episode.get("loopActionId") or "").strip()
    episode_action_type = str(episode.get("actionType") or "").strip()
    failed_action_id = str(episode.get("actionId") or "").strip()
    verification = episode.get("verification") if isinstance(episode.get("verification"), dict) else {}
    episode_epoch = max(
        (
            _parse_isoish_epoch(value) or 0
            for value in (
                verification.get("at"),
                episode.get("failedAt"),
                episode.get("reportedAt"),
                episode.get("coderRespondedAt"),
                episode.get("updatedAt"),
                episode.get("createdAt"),
            )
        ),
        default=0,
    )
    candidates = []
    for item in memory.get("recentActions") or []:
        if not isinstance(item, dict) or _canonical_world_action_status(item.get("status")) != "completed":
            continue
        action_id = str(item.get("actionId") or "").strip()
        if not action_id or action_id == failed_action_id:
            continue
        action_epoch = _parse_isoish_epoch(item.get("at")) or 0
        if not action_epoch or action_epoch <= episode_epoch:
            continue
        item_target_key = str(item.get("targetKey") or _live_agent_loop_target_key(item.get("target")) or "").strip()
        same_social_action = episode_action_type == "life.social" and item.get("actionType") == "life.social"
        if not same_social_action and (episode_target_key or item_target_key):
            if not episode_target_key or not item_target_key:
                continue
            if not _live_agent_loop_target_keys_compatible(episode_target_key, item_target_key):
                continue
        same_loop_action = bool(episode_loop_action_id and item.get("loopActionId") == episode_loop_action_id)
        same_action_type = bool(episode_action_type and item.get("actionType") == episode_action_type)
        if not same_loop_action and not same_action_type:
            continue
        candidates.append((action_epoch, item, item_target_key))
    if not candidates:
        return episode, None

    _, verified_action, verified_target_key = max(candidates, key=lambda candidate: candidate[0])
    resolved_at = verified_action.get("at") or _utc_now_iso()
    resolved = _copy_jsonable(episode)
    resolved["status"] = "completed"
    resolved["phase"] = "continue"
    resolved["updatedAt"] = resolved_at
    resolved["completedAt"] = resolved_at
    resolved["resolution"] = {
        "kind": "later-verified-action-history",
        "at": resolved_at,
        "actionId": verified_action.get("actionId"),
        "loopActionId": verified_action.get("loopActionId"),
        "targetKey": verified_target_key,
    }
    resolved["operatorSummary"] = "Resolved by a later verified action after route, target, or conditions changed."
    history = resolved.setdefault("history", [])
    if not any(
        isinstance(item, dict)
        and item.get("event") == "resolved-by-later-verification"
        and item.get("actionId") == verified_action.get("actionId")
        for item in history
    ):
        history.append({
            "at": resolved_at,
            "phase": "continue",
            "event": "resolved-by-later-verification",
            "actionId": verified_action.get("actionId"),
        })
    return resolved, resolved.get("issueId")


def _live_agent_loop_normalize_action_awareness(value):
    if not isinstance(value, dict):
        return None
    action_id = _live_agent_loop_clean_plan_text(value.get("actionId"), limit=180)
    if not action_id:
        return None
    row = {
        "schemaVersion": LIVE_AGENT_ACTION_AWARENESS_SCHEMA_VERSION,
        "actionId": action_id,
        "updatedAt": value.get("updatedAt") if _parse_isoish_epoch(value.get("updatedAt")) else _utc_now_iso(),
    }
    for key, limit in (
        ("loopActionId", 120), ("actionType", 120), ("status", 80),
        ("conclusion", 180), ("reason", 500), ("targetKey", 320),
    ):
        clean = _live_agent_loop_clean_plan_text(value.get(key), limit=limit)
        if clean:
            row[key] = clean
    for key in ("expected", "observed", "evidence"):
        if isinstance(value.get(key), dict):
            row[key] = _compact_json_value_for_storage(value.get(key), max_depth=4, max_items=36, string_limit=700)
    if isinstance(value.get("expectedMet"), bool):
        row["expectedMet"] = value.get("expectedMet")
    return row


def _live_agent_loop_normalize_controller(agent_state):
    raw = agent_state.get("controller") if isinstance(agent_state.get("controller"), dict) else {}
    state_name = str(raw.get("state") or "observing").strip().lower()
    if state_name not in LIVE_AGENT_CONTROLLER_STATES:
        state_name = "observing"
    row = {
        "schemaVersion": LIVE_AGENT_CONTROLLER_SCHEMA_VERSION,
        "state": state_name,
        "behaviorOwner": "agent-live-mode",
        "updatedAt": raw.get("updatedAt") if _parse_isoish_epoch(raw.get("updatedAt")) else _utc_now_iso(),
    }
    for key, limit in (
        ("reason", 500), ("activationId", 180), ("activeGoalId", 140),
        ("activeTaskId", 140), ("activeStepId", 140), ("activeActionId", 180),
        ("activeSkillId", 140), ("wakeReason", 240), ("rejectedOwnerReason", 500),
    ):
        clean = _live_agent_loop_clean_plan_text(raw.get(key), limit=limit)
        if clean:
            row[key] = clean
    if isinstance(raw.get("attentionLease"), dict):
        row["attentionLease"] = _compact_json_value_for_storage(raw.get("attentionLease"), max_depth=2, max_items=16, string_limit=300)
    if isinstance(raw.get("waiting"), dict):
        row["waiting"] = _compact_json_value_for_storage(raw.get("waiting"), max_depth=3, max_items=20, string_limit=500)
    awareness = _live_agent_loop_normalize_action_awareness(raw.get("actionAwareness") or agent_state.get("actionAwareness"))
    if awareness:
        row["actionAwareness"] = awareness
    agent_state["controller"] = row
    return row


def _live_agent_loop_normalize_operational_memory(agent_state):
    now_epoch = time.time()
    cooldowns = {}
    for key, raw in (agent_state.get("targetCooldowns") or {}).items() if isinstance(agent_state.get("targetCooldowns"), dict) else []:
        if not isinstance(raw, dict):
            continue
        expires_epoch = _parse_isoish_epoch(raw.get("expiresAt"))
        if not expires_epoch or expires_epoch <= now_epoch:
            continue
        cooldowns[str(key)[:320]] = {
            "targetKey": str(raw.get("targetKey") or key)[:320],
            "reason": _live_agent_loop_clean_plan_text(raw.get("reason"), limit=500) or "recent verified failure",
            "createdAt": raw.get("createdAt") if _parse_isoish_epoch(raw.get("createdAt")) else _utc_now_iso(),
            "expiresAt": raw.get("expiresAt"),
            "sourceActionId": _live_agent_loop_clean_plan_text(raw.get("sourceActionId"), limit=180),
        }
    agent_state["targetCooldowns"] = cooldowns

    procedural = {}
    raw_procedural = agent_state.get("proceduralMemory") if isinstance(agent_state.get("proceduralMemory"), dict) else {}
    ordered = sorted(
        ((str(key)[:140], value) for key, value in raw_procedural.items() if isinstance(value, dict)),
        key=lambda item: _parse_isoish_epoch(item[1].get("updatedAt")) or 0,
    )[-LIVE_AGENT_PROCEDURAL_MEMORY_LIMIT:]
    for key, raw in ordered:
        attempts = max(0, int(raw.get("attempts") or 0))
        successes = max(0, min(attempts, int(raw.get("successes") or 0)))
        failures = max(0, min(attempts, int(raw.get("failures") or 0)))
        procedural[key] = {
            "skillId": key,
            "attempts": attempts,
            "successes": successes,
            "failures": failures,
            "successRate": round(successes / attempts, 3) if attempts else 0.0,
            "averageDurationSec": round(max(0.0, float(raw.get("averageDurationSec") or 0.0)), 3),
            "lastStatus": _live_agent_loop_clean_plan_text(raw.get("lastStatus"), limit=80),
            "lastTargetKey": _live_agent_loop_clean_plan_text(raw.get("lastTargetKey"), limit=320),
            "lastFailureReason": _live_agent_loop_clean_plan_text(raw.get("lastFailureReason"), limit=500),
            "updatedAt": raw.get("updatedAt") if _parse_isoish_epoch(raw.get("updatedAt")) else _utc_now_iso(),
        }
    agent_state["proceduralMemory"] = procedural

    waiting = agent_state.get("waitingState") if isinstance(agent_state.get("waitingState"), dict) else None
    if waiting:
        expires_epoch = _parse_isoish_epoch(waiting.get("expiresAt"))
        if expires_epoch and expires_epoch > now_epoch:
            agent_state["waitingState"] = {
                "startedAt": waiting.get("startedAt") if _parse_isoish_epoch(waiting.get("startedAt")) else _utc_now_iso(),
                "expiresAt": waiting.get("expiresAt"),
                "reason": _live_agent_loop_clean_plan_text(waiting.get("reason"), limit=500) or "deliberate wait",
                "wakeConditions": _live_agent_loop_normalize_text_list(waiting.get("wakeConditions"), limit=6, item_limit=260),
            }
        else:
            agent_state.pop("waitingState", None)
    _live_agent_loop_normalize_controller(agent_state)
    return agent_state


def _live_agent_loop_controller_update(
    agent_id,
    agent_state,
    state_name,
    *,
    reason="",
    active_action_id=None,
    awareness=None,
    waiting=None,
    attention=None,
    wake_reason=None,
    persist_session=True,
):
    if not isinstance(agent_state, dict):
        return None
    state_name = str(state_name or "observing").strip().lower()
    if state_name not in LIVE_AGENT_CONTROLLER_STATES:
        state_name = "observing"
    goal = _live_agent_loop_active_durable_goal(agent_state)
    goal_context = _live_agent_goals.current_context(goal) if isinstance(goal, dict) else {}
    task = goal_context.get("task") if isinstance(goal_context.get("task"), dict) else {}
    step = goal_context.get("step") if isinstance(goal_context.get("step"), dict) else {}
    session = _live_agent_session_current(agent_id) if persist_session else None
    controller = {
        "schemaVersion": LIVE_AGENT_CONTROLLER_SCHEMA_VERSION,
        "state": state_name,
        "behaviorOwner": "agent-live-mode",
        "updatedAt": _utc_now_iso(),
        "reason": _live_agent_loop_clean_plan_text(reason, limit=500) or state_name,
        "activationId": (session or {}).get("activationId"),
        "activeGoalId": (goal or {}).get("id"),
        "activeTaskId": task.get("id"),
        "activeStepId": step.get("id"),
        "activeActionId": active_action_id,
        "activeSkillId": ((agent_state.get("skillExecution") or {}).get("skillId") if isinstance(agent_state.get("skillExecution"), dict) else None),
        "wakeReason": _live_agent_loop_clean_plan_text(wake_reason, limit=240),
    }
    if isinstance(attention, dict) and attention.get("active"):
        controller["attentionLease"] = {key: attention.get(key) for key in ("active", "startedAt", "holdUntil", "remainingSec", "source", "mode") if attention.get(key) is not None}
    if isinstance(waiting, dict):
        controller["waiting"] = _copy_jsonable(waiting)
    normalized_awareness = _live_agent_loop_normalize_action_awareness(awareness)
    if normalized_awareness:
        controller["actionAwareness"] = normalized_awareness
        agent_state["actionAwareness"] = normalized_awareness
    controller = {key: value for key, value in controller.items() if value is not None}
    agent_state["controller"] = controller
    if persist_session and session:
        checkpoint = {
            "phase": state_name,
            "currentStep": state_name,
            "controllerState": state_name,
            "behaviorOwner": "agent-live-mode",
            "activeGoalId": controller.get("activeGoalId"),
            "activeTaskId": controller.get("activeTaskId"),
            "activeStepId": controller.get("activeStepId"),
            "currentActionId": active_action_id,
            "attentionLease": controller.get("attentionLease"),
            "waiting": controller.get("waiting"),
            "actionAwareness": controller.get("actionAwareness"),
        }
        _live_agent_session_update(agent_id, checkpoint=checkpoint)
    return controller


def _live_agent_loop_normalize_memory(agent_state):
    if not isinstance(agent_state.get("needs"), dict):
        agent_state["needs"] = dict(LIVE_AGENT_LOOP_NEED_DEFAULTS)
    else:
        needs = dict(LIVE_AGENT_LOOP_NEED_DEFAULTS)
        needs.update({key: _live_agent_loop_clamp_need(value) for key, value in agent_state.get("needs", {}).items() if key in LIVE_AGENT_LOOP_NEED_DEFAULTS})
        agent_state["needs"] = needs
    memory = agent_state.get("memory") if isinstance(agent_state.get("memory"), dict) else {}
    memory.setdefault("recentActions", [])
    memory.setdefault("observations", [])
    memory.setdefault("reflections", [])
    memory.setdefault("internalNotes", [])
    memory["recentActions"] = _live_agent_loop_trim_list(
        _live_agent_loop_dedupe_settled_records(
            [_live_agent_loop_normalize_recent_action_record(item) for item in (memory.get("recentActions") or []) if isinstance(item, dict)],
            lambda item: _live_agent_loop_settled_action_key(item.get("actionId"), item.get("status")),
        ),
        LIVE_AGENT_LOOP_DEFAULTS["memoryRetention"],
    )
    memory["observations"] = _live_agent_loop_trim_list(
        _live_agent_loop_dedupe_settled_records(
            memory.get("observations"),
            lambda item: _live_agent_loop_settled_action_key(item.get("actionId"), item.get("status")),
        ),
        LIVE_AGENT_LOOP_DEFAULTS["memoryRetention"],
    )
    memory["reflections"] = _live_agent_loop_trim_list(
        _live_agent_loop_dedupe_settled_records(memory.get("reflections"), lambda item: item.get("actionId")),
        LIVE_AGENT_LOOP_DEFAULTS["reflectionRetention"],
    )
    memory["internalNotes"] = _live_agent_loop_trim_list(
        _live_agent_loop_dedupe_settled_records(memory.get("internalNotes"), lambda item: item.get("id")),
        LIVE_AGENT_LOOP_DEFAULTS["memoryRetention"],
    )
    agent_state["memory"] = memory
    now_epoch = time.time()
    support_requests = []
    for item in agent_state.get("supportRequests") or []:
        if not isinstance(item, dict):
            continue
        at_epoch = _parse_isoish_epoch(item.get("at")) or _parse_isoish_epoch(item.get("createdAt")) or now_epoch
        if now_epoch - at_epoch > LIVE_AGENT_SUPPORT_REQUEST_TTL_SEC:
            continue
        kind = str(item.get("kind") or "note")[:80]
        text = _live_agent_loop_clean_plan_text(item.get("text"), limit=500) or ""
        if not text:
            continue
        issue_id = str(item.get("issueId") or "").strip()[:160]
        if kind == "coder-report" and not issue_id:
            issue_id = _live_agent_loop_support_request_issue_id({"kind": kind, "text": text})
        if kind == "coder-report" and (not issue_id or issue_id.startswith("support.")) and _live_agent_loop_support_request_kind(text) != "coder-report":
            continue
        request_id = str(item.get("id") or "").strip()[:120] or _live_agent_loop_support_request_id(kind, text, issue_id=issue_id)
        if str(item.get("status") or "").strip().lower() in {"handled", "completed", "consumed"}:
            continue
        if kind == "coder-report" and issue_id and _live_agent_loop_recent_support_report(agent_state, issue_id):
            continue
        if kind == "coder-report" and issue_id.startswith("support.") and _live_agent_loop_successful_support_outcome_after(agent_state, "coder-report", at_epoch):
            continue
        clean = {
            "id": request_id,
            "at": item.get("at") if _parse_isoish_epoch(item.get("at")) else _epoch_to_utc_iso(at_epoch),
            "kind": kind,
            "text": text,
            "source": str(item.get("source") or "live-agent-mode")[:120],
        }
        if issue_id:
            clean["issueId"] = issue_id
        if item.get("evidenceKind"):
            clean["evidenceKind"] = str(item.get("evidenceKind"))[:80]
        if item.get("evidenceIssueId"):
            clean["evidenceIssueId"] = str(item.get("evidenceIssueId"))[:160]
        if item.get("evidenceSummary"):
            clean["evidenceSummary"] = _live_agent_loop_clean_plan_text(item.get("evidenceSummary"), limit=500)
        support_requests.append(clean)
    agent_state["supportRequests"] = support_requests[-12:]
    if not isinstance(agent_state.get("supportOutcomes"), list):
        agent_state["supportOutcomes"] = []
    else:
        agent_state["supportOutcomes"] = _live_agent_loop_trim_list(
            _live_agent_loop_dedupe_settled_records(agent_state.get("supportOutcomes"), lambda item: item.get("id")),
            LIVE_AGENT_LOOP_DEFAULTS["memoryRetention"],
        )
    normalized_episodes = []
    for episode in agent_state.get("episodes") or []:
        normalized = _live_agent_loop_normalize_episode(episode)
        if normalized:
            if _live_agent_loop_episode_matches_nonreportable_failure(agent_state, normalized):
                normalized = _live_agent_loop_clear_nonreportable_episode(normalized)
            normalized_episodes.append(normalized)
    active_episode = _live_agent_loop_normalize_episode(agent_state.get("activeEpisode"))
    if active_episode:
        # Repair legacy/pre-hardening snapshots where action admission failed
        # after an episode was opened but before an action id existed. The
        # terminal plan is authoritative: leaving the episode active makes the
        # agent believe an old physical attempt is still underway and can
        # later produce a false Coder report.
        matching_plan = None
        for raw_plan in [*(agent_state.get("plans") or []), agent_state.get("activePlan")]:
            plan = _live_agent_loop_normalize_plan(raw_plan)
            if plan and plan.get("id") == active_episode.get("planId"):
                matching_plan = _live_agent_loop_prefer_plan_candidate(matching_plan, plan)
        plan_status = str((matching_plan or {}).get("status") or "").strip().lower()
        plan_action_ids = {
            str(step.get("actionId") or "").strip()
            for step in ((matching_plan or {}).get("steps") or [])
            if isinstance(step, dict) and str(step.get("actionId") or "").strip()
        }
        if (
            matching_plan
            and plan_status in {"failed", "cancelled"}
            and not active_episode.get("actionId")
            and not plan_action_ids
            and not active_episode.get("verification")
        ):
            settled_at = (
                matching_plan.get("failedAt")
                or matching_plan.get("cancelledAt")
                or matching_plan.get("updatedAt")
                or _utc_now_iso()
            )
            active_episode["status"] = "cancelled" if plan_status == "cancelled" else "failed"
            active_episode["phase"] = "continue"
            active_episode["updatedAt"] = settled_at
            active_episode["failedAt"] = settled_at
            active_episode.pop("issueId", None)
            active_episode["verification"] = {
                "ok": False,
                "status": "cancelled" if plan_status == "cancelled" else "failed",
                "reportableFailure": False,
                "reason": "The physical action was not admitted; re-observe before retrying.",
            }
            active_episode["operatorSummary"] = "Episode ended before a physical action was admitted; no product failure was inferred."
            active_episode.setdefault("history", []).append({
                "at": settled_at,
                "phase": "continue",
                "event": "pre-execution-plan-settled",
                "planStatus": plan_status,
            })
        if _live_agent_loop_episode_matches_nonreportable_failure(agent_state, active_episode):
            active_episode = _live_agent_loop_clear_nonreportable_episode(active_episode)
        normalized_episodes = [episode for episode in normalized_episodes if episode.get("id") != active_episode.get("id")]
        normalized_episodes.append(active_episode)
    resolved_issue_ids = set()
    reconciled_episodes = []
    for episode in normalized_episodes:
        reconciled, issue_id = _live_agent_loop_resolve_reported_episode_from_recent_actions(agent_state, episode)
        reconciled_episodes.append(reconciled)
        if issue_id:
            resolved_issue_ids.add(issue_id)
    normalized_episodes = reconciled_episodes
    if active_episode:
        active_episode = next(
            (episode for episode in normalized_episodes if episode.get("id") == active_episode.get("id")),
            active_episode,
        )
    if resolved_issue_ids:
        agent_state["supportRequests"] = [
            item
            for item in (agent_state.get("supportRequests") or [])
            if not isinstance(item, dict) or item.get("issueId") not in resolved_issue_ids
        ]
    agent_state["episodes"] = _live_agent_loop_trim_list(normalized_episodes, LIVE_AGENT_LOOP_DEFAULTS["episodeRetention"])
    if active_episode and _live_agent_loop_episode_is_active(active_episode):
        agent_state["activeEpisode"] = active_episode
    elif "activeEpisode" in agent_state:
        agent_state.pop("activeEpisode", None)
    goal_progress = agent_state.get("goalProgress") if isinstance(agent_state.get("goalProgress"), dict) else {}
    cleaned_progress = {}
    for key, row in list(goal_progress.items())[-8:]:
        if not isinstance(row, dict):
            continue
        cleaned_progress[str(key)[:80]] = {
            "completedTargets": [str(item)[:160] for item in (row.get("completedTargets") or []) if item][-24:],
            "failedTargets": [str(item)[:160] for item in (row.get("failedTargets") or []) if item][-24:],
            "updatedAt": row.get("updatedAt"),
        }
    agent_state["goalProgress"] = cleaned_progress
    autonomy_plan = _live_agent_loop_normalize_autonomy_plan(agent_state.get("autonomyPlan"))
    if autonomy_plan:
        agent_state["autonomyPlan"] = autonomy_plan
    else:
        agent_state.pop("autonomyPlan", None)
    rejected_intention = agent_state.get("lastRejectedIntention")
    if isinstance(rejected_intention, dict):
        agent_state["lastRejectedIntention"] = _compact_json_value_for_storage(
            rejected_intention,
            max_depth=3,
            max_items=24,
            string_limit=600,
        )
    else:
        agent_state.pop("lastRejectedIntention", None)
    _live_agent_loop_apply_terminal_goal_tombstones(agent_state)
    durable_goals, active_durable_goal = _live_agent_goals.normalize_agent_goals(
        agent_state,
        retention=LIVE_AGENT_LOOP_DEFAULTS["durableGoalRetention"],
    )
    autonomy_plan = agent_state.get("autonomyPlan") if isinstance(agent_state.get("autonomyPlan"), dict) else None
    if autonomy_plan and autonomy_plan.get("status") == "active" and not active_durable_goal:
        linked_id = str(autonomy_plan.get("durableGoalId") or "").strip()
        plan_title = str(autonomy_plan.get("currentGoal") or "").strip().lower()
        terminal_goal = next((
            goal for goal in reversed(durable_goals)
            if isinstance(goal, dict)
            and goal.get("status") in _live_agent_goals.TERMINAL_GOAL_STATUSES
            and (
                (linked_id and goal.get("id") == linked_id)
                or (not linked_id and plan_title and str(goal.get("title") or "").strip().lower() == plan_title)
            )
        ), None)
        if terminal_goal:
            autonomy_plan["status"] = terminal_goal.get("status")
            autonomy_plan["durableGoalId"] = terminal_goal.get("id")
            autonomy_plan["lastOutcome"] = f"Equivalent durable goal already ended as {terminal_goal.get('status')}."
            autonomy_plan.pop("nextStep", None)
    if not isinstance(agent_state.get("feedbackReports"), list):
        agent_state["feedbackReports"] = []
    else:
        agent_state["feedbackReports"] = _live_agent_loop_trim_list(
            _live_agent_loop_dedupe_settled_records(agent_state.get("feedbackReports"), _live_agent_loop_feedback_dedupe_key),
            LIVE_AGENT_LOOP_DEFAULTS["feedbackRetention"],
        )
    retained_keys = sorted(_live_agent_loop_existing_settled_keys(agent_state))
    agent_state["settledActionKeys"] = retained_keys[-LIVE_AGENT_LOOP_DEFAULTS["settledActionRetention"]:]
    normalized_plans = []
    for plan in agent_state.get("plans") or []:
        normalized = _live_agent_loop_normalize_plan(plan)
        if normalized:
            normalized_plans.append(normalized)
    active_plan = _live_agent_loop_normalize_plan(agent_state.get("activePlan"))
    if active_plan:
        normalized_plans = [plan for plan in normalized_plans if plan.get("id") != active_plan.get("id")]
        normalized_plans.append(active_plan)
    agent_state["plans"] = _live_agent_loop_trim_list(normalized_plans, LIVE_AGENT_LOOP_DEFAULTS["planRetention"])
    if active_plan and _live_agent_loop_plan_is_active(active_plan):
        agent_state["activePlan"] = active_plan
    elif "activePlan" in agent_state:
        agent_state.pop("activePlan", None)
    return _live_agent_loop_normalize_operational_memory(agent_state)


def _live_agent_loop_agent_state(state, agent_id):
    agents = state.setdefault("agents", {})
    row = dict(agents.get(agent_id) or {})
    row.setdefault("enabled", True)
    row.setdefault("stats", {
        "ticks": 0,
        "actionsCreated": 0,
        "skippedActive": 0,
        "skippedCooldown": 0,
        "skippedNoClient": 0,
        "targetMisses": 0,
        "errors": 0,
    })
    _live_agent_loop_normalize_memory(row)
    agents[agent_id] = row
    return row


def _live_agent_loop_update_needs(agent_state, now_epoch=None):
    _live_agent_loop_normalize_memory(agent_state)
    now_epoch = float(now_epoch or time.time())
    last_epoch = _parse_isoish_epoch(agent_state.get("lastNeedUpdateAt")) or now_epoch
    elapsed_min = max(0, min(60, (now_epoch - last_epoch) / 60.0))
    needs = dict(agent_state.get("needs") or LIVE_AGENT_LOOP_NEED_DEFAULTS)
    for key, rate in LIVE_AGENT_LOOP_NEED_RATES_PER_MIN.items():
        needs[key] = _live_agent_loop_clamp_need(needs.get(key, LIVE_AGENT_LOOP_NEED_DEFAULTS.get(key, 0)) + (rate * elapsed_min))
    agent_state["needs"] = needs
    agent_state["lastNeedUpdateAt"] = _epoch_to_utc_iso(now_epoch)
    return needs


def _live_agent_loop_decay_need_after_action(agent_state, need_key, completed=True, *, bump_curiosity=True):
    needs = dict((agent_state or {}).get("needs") or LIVE_AGENT_LOOP_NEED_DEFAULTS)
    if need_key in needs:
        needs[need_key] = _live_agent_loop_clamp_need(0.12 if completed else min(1.25, needs.get(need_key, 0.5) + 0.12))
    if completed and bump_curiosity and need_key != "curiosity":
        needs["curiosity"] = _live_agent_loop_clamp_need(needs.get("curiosity", LIVE_AGENT_LOOP_NEED_DEFAULTS["curiosity"]) + 0.04)
    agent_state["needs"] = needs
    return needs


def _live_agent_loop_action_satisfied_needs(action_def):
    if not isinstance(action_def, dict):
        return []
    needs = []
    for value in [action_def.get("need"), *(action_def.get("satisfiesNeeds") or [])]:
        key = str(value or "").strip()
        if key and key in LIVE_AGENT_LOOP_NEED_DEFAULTS and key not in needs:
            needs.append(key)
    return needs


def _live_agent_loop_trim_list(values, limit, *, max_bytes=LIVE_AGENT_LOOP_COLLECTION_MAX_BYTES):
    values = [item for item in (values or []) if isinstance(item, dict)][-max(1, int(limit)):]
    selected = []
    used = 2
    for item in reversed(values):
        candidate = item
        size = _json_size_bytes(candidate)
        if size > max_bytes:
            compacted = _compact_json_value_for_storage(candidate, max_depth=4, max_items=20, string_limit=1000)
            if isinstance(compacted, dict):
                for key in ("id", "actionId", "loopActionId", "status", "at", "createdAt", "updatedAt"):
                    if key in candidate:
                        compacted[key] = candidate[key]
                compacted["storageCompacted"] = True
                compacted["originalBytes"] = size
                candidate = compacted
                size = _json_size_bytes(candidate)
        extra = size + (1 if selected else 0)
        if size and used + extra <= max_bytes:
            selected.append(candidate)
            used += extra
    selected.reverse()
    return selected


def _live_agent_loop_compact_snapshot(value, *, max_bytes=64 * 1024):
    if not isinstance(value, dict) or _json_size_bytes(value) <= max_bytes:
        return value
    compacted = _compact_json_value_for_storage(value, max_depth=4, max_items=24, string_limit=900)
    if isinstance(compacted, dict):
        compacted["storageCompacted"] = True
        compacted["originalBytes"] = _json_size_bytes(value)
    return compacted


def _live_agent_loop_enforce_state_budget(state):
    if not isinstance(state, dict):
        return state
    if _json_size_bytes(state) > LIVE_AGENT_LOOP_STATE_MAX_BYTES:
        state["events"] = _live_agent_loop_trim_list(
            state.get("events"),
            min(20, LIVE_AGENT_LOOP_DEFAULTS["eventRetention"]),
            max_bytes=min(128 * 1024, LIVE_AGENT_LOOP_COLLECTION_MAX_BYTES),
        )
        proposals = [item for item in (state.get("operatorProposals") or []) if isinstance(item, dict)]
        unresolved = [item for item in proposals if item.get("status") in {None, "pending"}]
        resolved = [item for item in proposals if item not in unresolved]
        state["operatorProposals"] = _live_agent_loop_trim_list(
            [*resolved[-8:], *unresolved],
            LIVE_AGENT_LOOP_DEFAULTS["operatorProposalRetention"],
            max_bytes=min(192 * 1024, LIVE_AGENT_LOOP_COLLECTION_MAX_BYTES),
        )
        for agent_state in (state.get("agents") or {}).values():
            if not isinstance(agent_state, dict):
                continue
            memory = agent_state.get("memory") if isinstance(agent_state.get("memory"), dict) else {}
            for key, count in (
                ("recentActions", 12),
                ("observations", 12),
                ("reflections", 10),
                ("internalNotes", 8),
            ):
                memory[key] = _live_agent_loop_trim_list(
                    memory.get(key),
                    count,
                    max_bytes=min(96 * 1024, LIVE_AGENT_LOOP_COLLECTION_MAX_BYTES),
                )
            agent_state["memory"] = memory
            for key, count in (
                ("episodes", 8),
                ("plans", 6),
                ("durableGoals", 8),
                ("feedbackReports", 10),
                ("supportOutcomes", 10),
                ("decisionTrace", 80),
                ("livedExperiences", 40),
            ):
                agent_state[key] = _live_agent_loop_trim_list(
                    agent_state.get(key),
                    count,
                    max_bytes=min(128 * 1024, LIVE_AGENT_LOOP_COLLECTION_MAX_BYTES),
                )
            for key in ("lastPerception", "lastDecision", "lastOutcome", "lastTurnStatus", "lastRejectedIntention", "autonomyPlan", "experienceState"):
                if isinstance(agent_state.get(key), dict):
                    agent_state[key] = _live_agent_loop_compact_snapshot(agent_state[key])
    current_bytes = _json_size_bytes(state)
    state["storageBudget"] = {
        "stateMaxBytes": LIVE_AGENT_LOOP_STATE_MAX_BYTES,
        "collectionMaxBytes": LIVE_AGENT_LOOP_COLLECTION_MAX_BYTES,
        "currentBytes": current_bytes,
        "overBudget": current_bytes > LIVE_AGENT_LOOP_STATE_MAX_BYTES,
    }
    return state


def _live_agent_loop_clean_plan_text(value, limit=220):
    if value is None:
        return None
    text = str(value).strip()
    if not text:
        return None
    return text[:limit]


def _live_agent_loop_normalize_text_list(values, *, limit=8, item_limit=240):
    if isinstance(values, str):
        values = [values]
    if not isinstance(values, list):
        return []
    result = []
    for item in values[:limit]:
        if isinstance(item, dict):
            text = item.get("label") or item.get("text") or item.get("step") or item.get("intent") or item.get("description")
        else:
            text = item
        clean = _live_agent_loop_clean_plan_text(text, limit=item_limit)
        if clean:
            result.append(clean)
    return result


def _live_agent_loop_normalize_next_step(value):
    if isinstance(value, str):
        value = {"intent": value}
    if not isinstance(value, dict):
        return {}
    action_value = value.get("action") or value.get("interactionId") or value.get("loopActionId") or value.get("actionId")
    if isinstance(action_value, dict):
        action_value = action_value.get("id") or action_value.get("loopActionId") or action_value.get("name")
    target_value = value.get("targetCriteria") or value.get("target") or value.get("object") or value.get("where")
    if isinstance(target_value, dict):
        target_value = json.dumps(_copy_jsonable(target_value), sort_keys=True, default=str)
    normalized = {}
    for key, raw, limit in (
        ("taskId", value.get("taskId") or value.get("task_id"), 140),
        ("stepId", value.get("stepId") or value.get("step_id"), 140),
        ("intent", value.get("intent") or value.get("activity") or value.get("goal") or value.get("description"), 420),
        ("action", action_value, 120),
        ("actionFamily", value.get("actionFamily") or value.get("action_family"), 120),
        ("category", value.get("category") or value.get("objectCategory") or value.get("targetCategory"), 80),
        ("targetCriteria", target_value, 420),
        ("targetIdentity", value.get("targetIdentity") or value.get("target_identity"), 260),
        ("evidenceDomain", value.get("evidenceDomain") or value.get("evidence_domain"), 160),
        ("successCriteria", value.get("successCriteria") or value.get("success") or value.get("doneWhen"), 420),
        ("failureCriteria", value.get("failureCriteria") or value.get("failure") or value.get("watchFor"), 420),
        ("successPostconditions", value.get("successPostconditions") or value.get("success_postconditions"), 420),
        ("failurePostconditions", value.get("failurePostconditions") or value.get("failure_postconditions"), 420),
    ):
        clean = _live_agent_loop_clean_plan_text(raw, limit=limit)
        if clean:
            normalized[key] = clean
    wait_seconds = value.get("waitSeconds") if value.get("waitSeconds") is not None else value.get("wait_seconds")
    if wait_seconds is not None:
        normalized["waitSeconds"] = _normalize_int(
            wait_seconds,
            LIVE_AGENT_WAIT_DEFAULT_SEC,
            minimum=LIVE_AGENT_WAIT_MIN_SEC,
            maximum=LIVE_AGENT_WAIT_MAX_SEC,
        )
    wake_conditions = _live_agent_loop_normalize_text_list(
        value.get("wakeConditions") or value.get("wake_conditions"),
        limit=8,
        item_limit=220,
    )
    if wake_conditions:
        normalized["wakeConditions"] = wake_conditions
    return normalized


def _live_agent_loop_normalize_autonomy_plan(plan):
    if not isinstance(plan, dict):
        return None
    now_iso = _utc_now_iso()
    next_step = _live_agent_loop_normalize_next_step(plan.get("nextStep"))
    normalized = {
        "schemaVersion": LIVE_AGENT_AUTONOMY_PLAN_SCHEMA_VERSION,
        "updatedAt": plan.get("updatedAt") if _parse_isoish_epoch(plan.get("updatedAt")) else now_iso,
    }
    if _parse_isoish_epoch(plan.get("createdAt")):
        normalized["createdAt"] = plan.get("createdAt")
    else:
        normalized["createdAt"] = normalized["updatedAt"]
    for key, limit in (
        ("reflection", 700),
        ("currentGoal", 500),
        ("status", 80),
        ("lesson", 500),
        ("lastOutcome", 500),
        ("durableGoalId", 140),
    ):
        clean = _live_agent_loop_clean_plan_text(plan.get(key), limit=limit)
        if clean:
            normalized[key] = clean
    steps = _live_agent_loop_normalize_text_list(plan.get("steps") or plan.get("plan"), limit=10, item_limit=260)
    if steps:
        normalized["steps"] = steps
    if next_step:
        normalized["nextStep"] = next_step
    tool_requests = _live_agent_loop_normalize_text_list(plan.get("toolRequests") or plan.get("tools") or plan.get("requestedTools"), limit=5, item_limit=220)
    if tool_requests:
        normalized["toolRequests"] = tool_requests
    event_requests = _live_agent_loop_normalize_text_list(plan.get("eventRequests") or plan.get("events") or plan.get("requestedEvents"), limit=5, item_limit=220)
    if event_requests:
        normalized["eventRequests"] = event_requests
    return normalized if any(key in normalized for key in ("reflection", "currentGoal", "steps", "nextStep", "lesson", "toolRequests", "eventRequests")) else None


def _live_agent_loop_autonomy_plan_from_planner_turn(planner_turn, now_iso=None):
    if not isinstance(planner_turn, dict):
        return None
    memory_update = planner_turn.get("memoryUpdate") if isinstance(planner_turn.get("memoryUpdate"), dict) else {}
    plan = {
        "createdAt": now_iso or _utc_now_iso(),
        "updatedAt": now_iso or _utc_now_iso(),
        "status": "active",
        "reflection": planner_turn.get("reflection"),
        "currentGoal": planner_turn.get("currentGoal") or planner_turn.get("goal"),
        "plan": planner_turn.get("plan") or planner_turn.get("steps"),
        "nextStep": planner_turn.get("nextStep") or planner_turn.get("next"),
        "lesson": memory_update.get("lesson") or memory_update.get("text") or planner_turn.get("lesson"),
        "toolRequests": planner_turn.get("toolRequests") or planner_turn.get("tools") or planner_turn.get("requestedTools"),
        "eventRequests": planner_turn.get("eventRequests") or planner_turn.get("events") or planner_turn.get("requestedEvents"),
    }
    return _live_agent_loop_normalize_autonomy_plan(plan)


def _live_agent_loop_normalize_terminal_goal_tombstones(values):
    rows = {}
    for item in values or []:
        if not isinstance(item, dict):
            continue
        goal_id = str(item.get("goalId") or item.get("id") or "").strip()[:140]
        status = str(item.get("status") or "completed").strip().lower()
        if not goal_id or status not in _live_agent_goals.TERMINAL_GOAL_STATUSES:
            continue
        at = item.get("at") if _parse_isoish_epoch(item.get("at")) else item.get("completedAt") if _parse_isoish_epoch(item.get("completedAt")) else _utc_now_iso()
        clean = {
            "goalId": goal_id,
            "status": status,
            "at": at,
        }
        for key, limit in (("title", 500), ("actionId", 180), ("verificationId", 180), ("goalTaskId", 140), ("goalStepId", 140)):
            value = _live_agent_loop_clean_plan_text(item.get(key), limit=limit)
            if value:
                clean[key] = value
        if isinstance(item.get("outcome"), dict):
            clean["outcome"] = _copy_jsonable(item["outcome"])
        current = rows.get(goal_id)
        if not current or (_parse_isoish_epoch(clean.get("at")) or 0) >= (_parse_isoish_epoch(current.get("at")) or 0):
            rows[goal_id] = clean
    return sorted(rows.values(), key=lambda item: _parse_isoish_epoch(item.get("at")) or 0)[-LIVE_AGENT_LOOP_DEFAULTS["durableGoalRetention"]:]


def _live_agent_loop_record_terminal_goal_tombstone(agent_state, goal):
    if not isinstance(agent_state, dict) or not isinstance(goal, dict) or goal.get("status") not in _live_agent_goals.TERMINAL_GOAL_STATUSES:
        return None
    marker = {
        "goalId": goal.get("id"),
        "title": goal.get("title"),
        "status": goal.get("status"),
        "at": goal.get("completedAt") or goal.get("failedAt") or goal.get("cancelledAt") or goal.get("updatedAt") or _utc_now_iso(),
        "outcome": _copy_jsonable(goal.get("outcome")) if isinstance(goal.get("outcome"), dict) else None,
    }
    agent_state["terminalGoalTombstones"] = _live_agent_loop_normalize_terminal_goal_tombstones([
        *(agent_state.get("terminalGoalTombstones") or []),
        marker,
    ])
    return next((item for item in agent_state["terminalGoalTombstones"] if item.get("goalId") == goal.get("id")), marker)


def _live_agent_loop_apply_terminal_goal_tombstones(agent_state):
    if not isinstance(agent_state, dict):
        return []
    tombstones = _live_agent_loop_normalize_terminal_goal_tombstones(agent_state.get("terminalGoalTombstones"))
    agent_state["terminalGoalTombstones"] = tombstones
    by_id = {item.get("goalId"): item for item in tombstones}
    goals = []
    for raw in agent_state.get("durableGoals") or []:
        goal = _live_agent_goals.normalize_goal(raw)
        if not goal:
            continue
        marker = by_id.get(goal.get("id"))
        if marker and goal.get("status") not in _live_agent_goals.TERMINAL_GOAL_STATUSES:
            goal["status"] = marker.get("status") or "completed"
            goal["updatedAt"] = marker.get("at") or goal.get("updatedAt")
            if marker.get("status") == "completed":
                goal["completedAt"] = marker.get("at") or goal.get("completedAt")
                goal["outcome"] = _copy_jsonable(marker.get("outcome")) if isinstance(marker.get("outcome"), dict) else {
                    "status": "completed",
                    "verified": True,
                    "at": marker.get("at"),
                    "actionId": marker.get("actionId"),
                    "verificationId": marker.get("verificationId"),
                }
            goal["replanRequired"] = False
            goal.pop("replanReason", None)
            goal.pop("blockedReason", None)
            history_key = ("terminal-tombstone-applied", marker.get("verificationId"), marker.get("actionId"))
            existing_history = {
                (item.get("event"), item.get("verificationId"), item.get("actionId"))
                for item in (goal.get("history") or []) if isinstance(item, dict)
            }
            if history_key not in existing_history:
                goal.setdefault("history", []).append({
                    "at": marker.get("at"),
                    "event": "terminal-tombstone-applied",
                    "verificationId": marker.get("verificationId"),
                    "actionId": marker.get("actionId"),
                })
            goal = _live_agent_goals.normalize_goal(goal)
        goals.append(goal)
    agent_state["durableGoals"] = goals
    _live_agent_goals.normalize_agent_goals(agent_state, retention=LIVE_AGENT_LOOP_DEFAULTS["durableGoalRetention"])
    return tombstones


def _live_agent_loop_active_durable_goal(agent_state):
    _live_agent_loop_apply_terminal_goal_tombstones(agent_state)
    _, active = _live_agent_goals.normalize_agent_goals(
        agent_state,
        retention=LIVE_AGENT_LOOP_DEFAULTS["durableGoalRetention"],
    )
    return active


def _live_agent_loop_store_durable_goal(agent_state, goal):
    normalized = _live_agent_goals.normalize_goal(goal)
    if not normalized:
        return None
    _live_agent_loop_apply_terminal_goal_tombstones(agent_state)
    tombstone = next((
        item for item in (agent_state.get("terminalGoalTombstones") or [])
        if isinstance(item, dict) and item.get("goalId") == normalized.get("id")
    ), None)
    if tombstone and normalized.get("status") not in _live_agent_goals.TERMINAL_GOAL_STATUSES:
        existing = next((
            item for item in (agent_state.get("durableGoals") or [])
            if isinstance(item, dict) and item.get("id") == normalized.get("id") and item.get("status") in _live_agent_goals.TERMINAL_GOAL_STATUSES
        ), None)
        if existing:
            return existing
        normalized["status"] = tombstone.get("status") or "completed"
        normalized["updatedAt"] = tombstone.get("at") or normalized.get("updatedAt")
        normalized["replanRequired"] = False
        if normalized["status"] == "completed":
            normalized["completedAt"] = tombstone.get("at")
            normalized["outcome"] = _copy_jsonable(tombstone.get("outcome")) if isinstance(tombstone.get("outcome"), dict) else {"status": "completed", "verified": True, "at": tombstone.get("at")}
    stored = _live_agent_goals.store_goal(
        agent_state,
        normalized,
        retention=LIVE_AGENT_LOOP_DEFAULTS["durableGoalRetention"],
    )
    if stored and stored.get("status") in _live_agent_goals.TERMINAL_GOAL_STATUSES:
        _live_agent_loop_record_terminal_goal_tombstone(agent_state, stored)
    return stored


def _live_agent_loop_find_durable_goal(agent_state, goal_id):
    goal_id = str(goal_id or "").strip()
    if not goal_id:
        return None
    _live_agent_goals.normalize_agent_goals(
        agent_state,
        retention=LIVE_AGENT_LOOP_DEFAULTS["durableGoalRetention"],
    )
    active = agent_state.get("activeGoal") if isinstance(agent_state.get("activeGoal"), dict) else None
    if active and active.get("id") == goal_id:
        return active
    return next((goal for goal in agent_state.get("durableGoals") or [] if isinstance(goal, dict) and goal.get("id") == goal_id), None)


def _live_agent_loop_ensure_durable_goal(agent_state, agent_id):
    active = _live_agent_loop_active_durable_goal(agent_state)
    if active:
        return active
    legacy = _live_agent_loop_normalize_autonomy_plan(agent_state.get("autonomyPlan"))
    if not legacy:
        return None
    linked_goal_id = legacy.get("durableGoalId")
    if linked_goal_id:
        linked_goal = _live_agent_loop_find_durable_goal(agent_state, linked_goal_id)
        if linked_goal:
            return linked_goal if linked_goal.get("status") not in _live_agent_goals.TERMINAL_GOAL_STATUSES else None
    planner_turn = {
        "currentGoal": legacy.get("currentGoal"),
        "plan": legacy.get("steps") or [],
        "nextStep": legacy.get("nextStep") or {},
        "memoryUpdate": {"lesson": legacy.get("lesson")},
    }
    goal = _live_agent_goals.goal_from_planner_turn(agent_id, planner_turn, now_iso=_utc_now_iso())
    if not goal:
        return None
    goal["source"] = "legacy-autonomy-plan-migration"
    goal.setdefault("history", []).append({"at": _utc_now_iso(), "event": "migrated-from-autonomy-plan"})
    return _live_agent_loop_store_durable_goal(agent_state, goal)


def _live_agent_loop_upsert_durable_goal_from_planner(agent_state, agent_id, planner_turn, *, chosen_action=None):
    if not isinstance(planner_turn, dict):
        return None
    now_iso = _utc_now_iso()
    current = _live_agent_loop_active_durable_goal(agent_state)
    incoming = _live_agent_goals.goal_from_planner_turn(
        agent_id,
        planner_turn,
        previous_goal=current,
        chosen_action=chosen_action,
        now_iso=now_iso,
    )
    if not incoming:
        return None
    existing_same_id = _live_agent_loop_find_durable_goal(agent_state, incoming.get("id"))
    if existing_same_id and existing_same_id.get("status") in _live_agent_goals.TERMINAL_GOAL_STATUSES:
        raw_goal = planner_turn.get("goal") if isinstance(planner_turn.get("goal"), dict) else {}
        if raw_goal.get("id"):
            return None
        # Repeating the same natural-language commitment after it reached a
        # terminal state is not a new goal. Previously this generated endless
        # `.run-*` clones, allowing any newly selected object to rubber-stamp
        # the same finished goal. A genuinely new run must carry an explicit
        # new goal id from the model/user.
        if isinstance(agent_state.get("autonomyPlan"), dict):
            agent_state["autonomyPlan"] = {
                **agent_state["autonomyPlan"],
                "status": existing_same_id.get("status"),
                "durableGoalId": existing_same_id.get("id"),
                "lastOutcome": f"Equivalent durable goal already ended as {existing_same_id.get('status')}.",
            }
            agent_state["autonomyPlan"].pop("nextStep", None)
        agent_state["lastTerminalGoalReplay"] = {
            "at": now_iso,
            "nonce": uuid.uuid4().hex[:12],
            "goalId": existing_same_id.get("id"),
            "title": existing_same_id.get("title"),
            "status": existing_same_id.get("status"),
            "requestedAction": str(chosen_action or "")[:120],
            "reason": "equivalent durable goal is already terminal",
        }
        return None
    if current and current.get("id") != incoming.get("id") and current.get("status") not in _live_agent_goals.TERMINAL_GOAL_STATUSES:
        current["status"] = "superseded"
        current["updatedAt"] = now_iso
        current["operatorSummary"] = f"Superseded by durable goal: {incoming.get('title')}."
        current.setdefault("history", []).append({"at": now_iso, "event": "goal-superseded", "supersededBy": incoming.get("id")})
        _live_agent_loop_store_durable_goal(agent_state, current)
    stored = _live_agent_loop_store_durable_goal(agent_state, incoming)
    return stored


def _live_agent_loop_durable_goal_context(agent_state):
    active = _live_agent_loop_active_durable_goal(agent_state)
    if not active:
        return {"goal": None, "task": None, "step": None}
    return _live_agent_goals.current_context(active)


LIVE_AGENT_GOAL_EVIDENCE_DOMAINS = {
    "coffee": ("coffee", "countertop coffee machine", "countertopcoffeemachine", "getcoffee"),
    "water": ("water cooler", "watercooler", "get water", "getwater", "hydrate with water"),
    "food": ("vending", "snack", "microwave", "heat food", "heated food", "buyvending", "heatfood"),
    "seating": ("seat", "seating", "chair", "armchair", "sofa", "couch", "bench", "stool", "gazebo", "sit", "rest"),
    "whiteboard": ("whiteboard", "brainstorm"),
    "printer": ("printer", "copier", "print", "copy", "scanner"),
    "social": ("social", "talk with", "conversation", "speak with", "nearby resident"),
    "home": ("home", "shelter", "construction site", "build structure"),
    "coder-report": ("coder", "developer", "field report", "support request", "report issue", "blocker report"),
    "internal-note": ("internal note", "durable note", "write note", "record note"),
}


def _live_agent_loop_evidence_domains(*values):
    text = " ".join(str(value or "") for value in values).lower()
    normalized = _normalize_token(text) or ""
    domains = set()
    for domain, terms in LIVE_AGENT_GOAL_EVIDENCE_DOMAINS.items():
        for term in terms:
            if term in text or (_normalize_token(term) or "") in normalized:
                domains.add(domain)
                break
    return domains


def _live_agent_loop_goal_action_evidence_compatibility(goal, loop_action_id, selected):
    """Check whether this physical/support result can prove the current step.

    The model may still perform an auxiliary action, but a whiteboard, printer,
    or report cannot complete a coffee-machine goal unless the declared step
    itself is explicitly about that auxiliary domain.
    """
    goal = goal if isinstance(goal, dict) else {}
    selected = selected if isinstance(selected, dict) else {}
    context = _live_agent_goals.current_context(goal) if goal else {}
    task = context.get("task") if isinstance(context.get("task"), dict) else {}
    step = context.get("step") if isinstance(context.get("step"), dict) else {}
    target = selected.get("target") if isinstance(selected.get("target"), dict) else {}
    selected_action = selected.get("action") if isinstance(selected.get("action"), dict) else {}
    action_def = _live_agent_loop_action_definition(loop_action_id, selected_action.get("actionType")) or selected_action
    action_domains = _live_agent_loop_evidence_domains(
        loop_action_id,
        action_def.get("label"),
        action_def.get("experience"),
        action_def.get("actionType"),
        target.get("catalogId"),
        selected.get("objectType"),
        target.get("supportTool"),
    )
    step_domains = _live_agent_loop_evidence_domains(
        step.get("loopActionId"),
        step.get("title"),
        step.get("targetCriteria"),
        step.get("category"),
        " ".join(str(item) for item in (step.get("successCriteria") or [])),
        " ".join(str(item) for item in (step.get("failureCriteria") or [])),
        task.get("title"),
    )
    tasks = [item for item in (goal.get("tasks") or []) if isinstance(item, dict)]
    goal_domains = _live_agent_loop_evidence_domains(
        goal.get("title"),
        goal.get("description"),
        " ".join(str(item) for item in (goal.get("successCriteria") or [])),
    ) if len(tasks) <= 1 else set()
    required_domains = set(step_domains)
    required_domains.update(goal_domains)
    if required_domains and action_domains.isdisjoint(required_domains):
        return False, {
            "reason": "selected action evidence is semantically unrelated to the current durable goal step",
            "goalDomains": sorted(required_domains),
            "actionDomains": sorted(action_domains),
            "loopActionId": loop_action_id,
        }
    return True, {
        "goalDomains": sorted(required_domains),
        "actionDomains": sorted(action_domains),
        "loopActionId": loop_action_id,
    }


def _live_agent_loop_bind_durable_goal_action(
    agent_state,
    loop_action_id,
    selected,
    *,
    allow_replan=False,
    replan_action_ids=None,
    now_iso=None,
):
    context = _live_agent_loop_durable_goal_context(agent_state)
    goal = context.get("goal")
    step = context.get("step")
    if not goal:
        return None
    selected = selected if isinstance(selected, dict) else {}
    compatible, compatibility = _live_agent_loop_goal_action_evidence_compatibility(goal, loop_action_id, selected)
    if not compatible:
        now_iso = now_iso or _utc_now_iso()
        context = _live_agent_goals.current_context(goal)
        goal = context.get("goal") or goal
        step = context.get("step") if isinstance(context.get("step"), dict) else None
        reason = compatibility.get("reason") or "selected action cannot verify the current durable goal step"
        goal["status"] = "blocked"
        goal["replanRequired"] = True
        goal["replanReason"] = reason
        goal["updatedAt"] = now_iso
        goal.setdefault("history", []).append({
            "at": now_iso,
            "event": "goal-evidence-mismatch",
            **compatibility,
        })
        if step:
            step["status"] = "blocked"
            step["blockedReason"] = reason
            step["updatedAt"] = now_iso
            step.setdefault("history", []).append({"at": now_iso, "event": "evidence-mismatch", **compatibility})
        _live_agent_loop_store_durable_goal(agent_state, goal)
        agent_state["lastGoalEvidenceMismatch"] = {"at": now_iso, **compatibility}
        return None
    target = selected.get("target") if isinstance(selected.get("target"), dict) else {}
    target_key = _live_agent_loop_target_key(target)
    if goal.get("replanRequired"):
        if not allow_replan:
            return None
        assigned = str((step or {}).get("loopActionId") or "").strip()
        explicitly_allowed = {
            str(item).strip()
            for item in (replan_action_ids or [])
            if str(item).strip()
        }
        if loop_action_id != assigned and loop_action_id not in explicitly_allowed:
            return None
        stored_goal, _ = _live_agent_goals.replan_with_action(
            goal,
            loop_action_id,
            target=target,
            target_key=target_key,
            reason=goal.get("replanReason") or "planner selected a replacement action",
            now_iso=now_iso or _utc_now_iso(),
        )
    else:
        assigned = (step or {}).get("loopActionId") if isinstance(step, dict) else None
        if assigned and assigned != loop_action_id:
            return None
        stored_goal, _ = _live_agent_goals.bind_selected_action(
            goal,
            loop_action_id,
            target=target,
            target_key=target_key,
            now_iso=now_iso or _utc_now_iso(),
        )
    if not stored_goal:
        return None
    stored_goal = _live_agent_loop_store_durable_goal(agent_state, stored_goal)
    stored_context = _live_agent_goals.current_context(stored_goal)
    task = stored_context.get("task") or {}
    step = stored_context.get("step") or {}
    return {
        "goalId": stored_goal.get("id"),
        "goalRevision": stored_goal.get("revision"),
        "goalTaskId": task.get("id"),
        "goalStepId": step.get("id"),
        "goalTitle": stored_goal.get("title"),
    }


def _live_agent_loop_model_replan_action_ids(model_detail):
    """Actions explicitly authorized by the applied model repair turn."""
    if not isinstance(model_detail, dict) or model_detail.get("applied") != "async-previous-request":
        return set()
    intention = model_detail.get("intention") if isinstance(model_detail.get("intention"), dict) else {}
    planner_turn = model_detail.get("plannerTurn") if isinstance(model_detail.get("plannerTurn"), dict) else intention.get("plannerTurn")
    next_step = planner_turn.get("nextStep") if isinstance(planner_turn, dict) and isinstance(planner_turn.get("nextStep"), dict) else {}
    category = next_step.get("category") or intention.get("category")
    action_tokens = [model_detail.get("chosen"), intention.get("action"), next_step.get("action"), next_step.get("loopActionId")]
    allowed = {
        _live_agent_loop_planner_action_id(token, category=category)
        for token in action_tokens
        if str(token or "").strip() and str(token).strip().lower() != "skip"
    }
    resolved_category = LIVE_AGENT_INTENTION_CATEGORY_ALIASES.get(_normalize_token(category) or "")
    dynamic = LIVE_AGENT_DYNAMIC_OBJECT_AFFORDANCES.get(resolved_category) if resolved_category else None
    if isinstance(dynamic, dict) and dynamic.get("id"):
        allowed.add(str(dynamic["id"]))
    return {item for item in allowed if item}


def _live_agent_loop_mark_durable_goal_action_started(state, agent_id, agent_state, goal_context, action_id, loop_action_id, now_iso):
    if not isinstance(goal_context, dict) or not goal_context.get("goalId"):
        return None
    goal = _live_agent_loop_find_durable_goal(agent_state, goal_context.get("goalId"))
    if not goal:
        return None
    stored, step = _live_agent_goals.mark_step_started(
        goal,
        action_id=action_id,
        loop_action_id=loop_action_id,
        now_iso=now_iso,
    )
    stored = _live_agent_loop_store_durable_goal(agent_state, stored)
    _live_agent_loop_add_event(
        state,
        "durable-goal-step-started",
        agent_id=agent_id,
        details={
            **goal_context,
            "actionId": action_id,
            "loopActionId": loop_action_id,
            "attempt": ((step or {}).get("retry") or {}).get("attempts"),
        },
    )
    return stored


def _live_agent_loop_record_durable_goal_verification(state, agent_id, agent_state, verification, now_iso):
    if not isinstance(verification, dict):
        return None
    goal = _live_agent_loop_find_durable_goal(agent_state, verification.get("goalId"))
    if not goal:
        return None
    stored, outcome = _live_agent_goals.record_verified_outcome(goal, verification, now_iso=now_iso)
    stored = _live_agent_loop_store_durable_goal(agent_state, stored)
    event_type = "durable-goal-step-verified" if verification.get("ok") is True else "durable-goal-step-retry"
    if stored.get("status") in {"blocked", "failed"}:
        event_type = "durable-goal-replan-required"
    elif stored.get("status") == "completed":
        event_type = "durable-goal-completed"
    _live_agent_loop_add_event(
        state,
        event_type,
        agent_id=agent_id,
        details={
            "goalId": stored.get("id"),
            "goalTaskId": verification.get("goalTaskId"),
            "goalStepId": verification.get("goalStepId"),
            "actionId": verification.get("actionId"),
            "verificationId": verification.get("id"),
            "ok": verification.get("ok") is True,
            "goalStatus": stored.get("status"),
            "replanRequired": stored.get("replanRequired"),
            "outcome": outcome,
        },
    )
    return stored


def _live_agent_loop_reconcile_durable_goal_world(state, agent_id, agent_state, perception, now_iso):
    goal = _live_agent_loop_ensure_durable_goal(agent_state, agent_id)
    if not goal:
        return None
    affordances = [item for item in (perception or {}).get("affordances") or [] if isinstance(item, dict)]
    available = {item.get("id") for item in affordances if item.get("id") and item.get("available")}
    target_keys = {
        item.get("id"): _live_agent_loop_target_key(item.get("target"))
        for item in affordances
        if item.get("id") and item.get("available") and isinstance(item.get("target"), dict)
    }
    reconciled, reason = _live_agent_goals.reconcile_world(
        goal,
        world_revision=_live_agent_goals.world_revision(affordances),
        available_actions=available,
        target_keys=target_keys,
        now_iso=now_iso,
    )
    stored = _live_agent_loop_store_durable_goal(agent_state, reconciled)
    if stored and stored.get("status") in _live_agent_goals.TERMINAL_GOAL_STATUSES:
        reason = None
    if reason:
        _live_agent_loop_add_event(
            state,
            "durable-goal-world-changed",
            agent_id=agent_id,
            details={
                "goalId": stored.get("id"),
                "reason": reason,
                "worldRevision": stored.get("worldRevision"),
                "replanCount": stored.get("replanCount"),
            },
        )
        try:
            _live_agent_model_decision_allow_immediate(agent_id, reason="durable-goal-world-changed")
        except Exception:
            pass
    return stored


def get_live_agent_goals(agent_id):
    with _live_agent_loop_observability_lock() as locked:
        resolved = _resolve_agent_id(agent_id)
        if not resolved:
            return False, _api_error("agent_not_found", "Unknown agent id for durable goals.", details={"agentId": agent_id}), 404
        state = get_live_agent_loop_state(persist_migration=False) if locked else _live_agent_loop_readonly_state_snapshot()
        agent_state = _live_agent_loop_agent_state(state, resolved)
        goals, active = _live_agent_goals.normalize_agent_goals(
            agent_state,
            retention=LIVE_AGENT_LOOP_DEFAULTS["durableGoalRetention"],
        )
        summary = {
            status: sum(1 for goal in goals if goal.get("status") == status)
            for status in sorted(_live_agent_goals.GOAL_STATUSES)
            if any(goal.get("status") == status for goal in goals)
        }
        return True, {
            "ok": True,
            "schemaVersion": LIVE_AGENT_GOAL_LEDGER_SCHEMA_VERSION,
            "agentId": resolved,
            "busy": not locked,
            "readOnlySnapshot": not locked,
            "activeGoal": active,
            "goals": goals,
            "summary": {"total": len(goals), "byStatus": summary},
        }, 200


def update_live_agent_goals(agent_id, payload):
    if not _agent_live_mode_runtime_enabled():
        return False, _agent_live_mode_feature_disabled_error(), _agent_live_mode_feature_disabled_status()
    resolved = _resolve_agent_id(agent_id)
    if not resolved:
        return False, _api_error("agent_not_found", "Unknown agent id for durable goals.", details={"agentId": agent_id}), 404
    if not isinstance(payload, dict):
        return False, _api_error("invalid_payload", "Durable goal payload must be an object."), 400
    operation = str(payload.get("operation") or ("upsert" if payload.get("goal") else "create")).strip().lower().replace("-", "_")
    now_iso = _utc_now_iso()
    with _live_agent_loop_lock:
        state = get_live_agent_loop_state(persist_migration=False)
        agent_state = _live_agent_loop_agent_state(state, resolved)
        goals, active = _live_agent_goals.normalize_agent_goals(agent_state, retention=LIVE_AGENT_LOOP_DEFAULTS["durableGoalRetention"])
        stored = None
        event_type = "durable-goal-updated"
        if operation in {"create", "upsert"}:
            raw_goal = payload.get("goal") if isinstance(payload.get("goal"), dict) else payload
            errors = _live_agent_goals.validate_goal_payload(raw_goal)
            if errors:
                return False, _api_error("invalid_durable_goal", "Durable goal validation failed.", details={"errors": errors}), 400
            normalized = _live_agent_goals.normalize_goal(raw_goal, agent_id=resolved, now_iso=now_iso)
            existing = next((goal for goal in goals if goal.get("id") == normalized.get("id")), None)
            if operation == "create" and existing:
                return False, _api_error("durable_goal_exists", "A durable goal with this id already exists.", details={"goalId": normalized.get("id")}), 409
            if operation == "upsert" and existing and existing.get("status") in _live_agent_goals.TERMINAL_GOAL_STATUSES:
                return False, _api_error(
                    "durable_goal_terminal",
                    "A terminal durable goal cannot be replaced in place; create a new goal id.",
                    details={"goalId": normalized.get("id"), "status": existing.get("status")},
                ), 409
            if operation == "upsert" and existing:
                normalized = _live_agent_goals.goal_from_planner_turn(
                    resolved,
                    {
                        "goal": raw_goal,
                        "currentGoal": raw_goal.get("title") or raw_goal.get("currentGoal"),
                        "tasks": raw_goal.get("tasks") or [],
                        "successCriteria": raw_goal.get("successCriteria") or [],
                        "nextStep": raw_goal.get("nextStep") or {},
                    },
                    previous_goal=existing,
                    now_iso=now_iso,
                )
                normalized["source"] = str(raw_goal.get("source") or "operator-api")[:120]
            if active and active.get("id") != normalized.get("id") and normalized.get("status") == "active":
                active["status"] = "paused"
                active["pausedAt"] = now_iso
                active["updatedAt"] = now_iso
                active["operatorSummary"] = f"Paused while operator activated {normalized.get('title')}."
                _live_agent_loop_store_durable_goal(agent_state, active)
            stored = _live_agent_loop_store_durable_goal(agent_state, normalized)
            event_type = "durable-goal-created" if not existing else "durable-goal-updated"
        else:
            goal_id = str(payload.get("goalId") or "").strip()
            goal = _live_agent_loop_find_durable_goal(agent_state, goal_id)
            if not goal:
                return False, _api_error("durable_goal_not_found", "Unknown durable goal id.", details={"goalId": goal_id}), 404
            if operation in {"activate", "resume"}:
                if goal.get("status") in _live_agent_goals.TERMINAL_GOAL_STATUSES:
                    return False, _api_error(
                        "durable_goal_terminal",
                        "A terminal durable goal cannot be reactivated; create a new goal or retry an unfinished goal.",
                        details={"goalId": goal_id, "status": goal.get("status")},
                    ), 409
                if active and active.get("id") != goal_id:
                    active["status"] = "paused"
                    active["pausedAt"] = now_iso
                    active["updatedAt"] = now_iso
                    _live_agent_loop_store_durable_goal(agent_state, active)
                goal["status"] = "active"
                goal["activatedAt"] = goal.get("activatedAt") or now_iso
                goal.pop("pausedAt", None)
                event_type = "durable-goal-activated"
            elif operation == "pause":
                goal["status"] = "paused"
                goal["pausedAt"] = now_iso
                event_type = "durable-goal-paused"
            elif operation == "cancel":
                goal["status"] = "cancelled"
                goal["cancelledAt"] = now_iso
                goal["outcome"] = {"status": "cancelled", "verified": False, "at": now_iso, "reason": str(payload.get("reason") or "operator cancelled")[:500]}
                event_type = "durable-goal-cancelled"
            elif operation == "replan":
                goal["status"] = "blocked"
                goal["replanRequired"] = True
                goal["replanReason"] = str(payload.get("reason") or "operator requested replan")[:500]
                goal["replanCount"] = int(goal.get("replanCount") or 0) + 1
                goal["lastReplannedAt"] = now_iso
                event_type = "durable-goal-replan-required"
                try:
                    _live_agent_model_decision_allow_immediate(resolved, reason="operator-requested-replan")
                except Exception:
                    pass
            elif operation == "retry":
                replacement = str(payload.get("loopActionId") or "").strip()
                goal, _ = _live_agent_goals.replan_with_action(
                    goal,
                    replacement or ((_live_agent_goals.current_context(goal).get("step") or {}).get("loopActionId")),
                    reason=str(payload.get("reason") or "operator requested retry")[:500],
                    now_iso=now_iso,
                )
                event_type = "durable-goal-retried"
            else:
                return False, _api_error("invalid_operation", "Unsupported durable goal operation.", details={"operation": operation, "allowed": ["create", "upsert", "activate", "resume", "pause", "cancel", "replan", "retry"]}), 400
            goal["updatedAt"] = now_iso
            goal.setdefault("history", []).append({"at": now_iso, "event": event_type, "actor": str(payload.get("actor") or "api")[:120]})
            stored = _live_agent_loop_store_durable_goal(agent_state, goal)
        _live_agent_loop_add_event(state, event_type, agent_id=resolved, details={"goalId": stored.get("id"), "status": stored.get("status"), "revision": stored.get("revision")})
        saved = save_live_agent_loop_state(state)
        saved_agent = ((saved.get("agents") or {}).get(resolved) or {})
        saved_goal = next((goal for goal in saved_agent.get("durableGoals") or [] if goal.get("id") == stored.get("id")), stored)
        return True, {"ok": True, "agentId": resolved, "operation": operation, "goal": saved_goal, "activeGoal": saved_agent.get("activeGoal")}, 200


def _live_agent_loop_operator_proposal_status(value, default="pending"):
    status = str(value or default).strip().lower().replace("-", "_")
    allowed = {"pending", "acknowledged", "vetoed", "dismissed", "superseded"}
    return status if status in allowed else default


def _live_agent_loop_normalize_operator_proposal(proposal):
    if not isinstance(proposal, dict):
        return None
    proposal_id = _live_agent_loop_clean_plan_text(proposal.get("id"), limit=160)
    if not proposal_id:
        return None
    now_iso = _utc_now_iso()
    normalized = {
        "schemaVersion": LIVE_AGENT_OPERATOR_PROPOSAL_SCHEMA_VERSION,
        "id": proposal_id,
        "status": _live_agent_loop_operator_proposal_status(proposal.get("status")),
        "title": _live_agent_loop_clean_plan_text(proposal.get("title"), limit=180) or "Live Mode proposal",
        "summary": _live_agent_loop_clean_plan_text(proposal.get("summary"), limit=500) or "",
        "requestedAt": proposal.get("requestedAt") if _parse_isoish_epoch(proposal.get("requestedAt")) else now_iso,
        "updatedAt": proposal.get("updatedAt") if _parse_isoish_epoch(proposal.get("updatedAt")) else now_iso,
        "policy": "operator-review-required-before-visible-executor",
        "hiddenWorldMutationAllowed": False,
        "executesOnApproval": False,
    }
    for key, limit in (
        ("agentId", 120),
        ("actionType", 120),
        ("capabilityTag", 120),
        ("sourceKind", 80),
        ("blockedReason", 180),
        ("requiredExecutor", 180),
        ("requirement", 500),
        ("operatorNote", 500),
        ("resolvedBy", 120),
    ):
        cleaned = _live_agent_loop_clean_plan_text(proposal.get(key), limit=limit)
        if cleaned:
            normalized[key] = cleaned
    for key in ("resolvedAt",):
        if _parse_isoish_epoch(proposal.get(key)):
            normalized[key] = proposal.get(key)
    for key in ("capability", "target", "payloadPreview", "rejection"):
        value = proposal.get(key)
        if isinstance(value, dict):
            normalized[key] = _copy_jsonable(value)
    return normalized


def _live_agent_loop_limited_operator_proposals(state, *, agent_id=None, include_resolved=False, limit=None):
    retention = LIVE_AGENT_LOOP_DEFAULTS["operatorProposalRetention"]
    limit_value = _normalize_int(limit, retention, minimum=1, maximum=retention) if limit not in (None, "") else retention
    proposals = []
    for item in state.get("operatorProposals") or []:
        proposal = _live_agent_loop_normalize_operator_proposal(item)
        if not proposal:
            continue
        if agent_id and proposal.get("agentId") != agent_id:
            continue
        if not include_resolved and proposal.get("status") != "pending":
            continue
        proposals.append(proposal)
    return proposals[-limit_value:]


def _live_agent_loop_normalize_operator_proposals(state):
    proposals = []
    for item in state.get("operatorProposals") or []:
        proposal = _live_agent_loop_normalize_operator_proposal(item)
        if proposal:
            proposals.append(proposal)
    state["operatorProposals"] = _live_agent_loop_trim_list(proposals, LIVE_AGENT_LOOP_DEFAULTS["operatorProposalRetention"])
    return state["operatorProposals"]


def _live_agent_loop_record_operator_proposal_from_rejection(state, agent_id, payload, rejection):
    if not isinstance(state, dict) or not isinstance(payload, dict):
        return None
    action_type = str(payload.get("actionType") or payload.get("actionId") or "").strip()
    capability_tag = str(payload.get("capabilityTag") or "").strip()
    capability = _live_agent_proposal_only_capability_for(action_type, capability_tag)
    if not capability:
        return None
    now_iso = _utc_now_iso()
    source = payload.get("source") if isinstance(payload.get("source"), dict) else {}
    target = payload.get("target") if isinstance(payload.get("target"), dict) else {}
    seed = json.dumps(
        {
            "agentId": agent_id,
            "actionType": action_type,
            "capabilityTag": capability_tag,
            "target": target,
            "capabilityId": capability.get("id"),
        },
        sort_keys=True,
        default=str,
    )
    proposal_id = "live-proposal-" + hashlib.sha1(seed.encode("utf-8")).hexdigest()[:16]
    existing = _live_agent_loop_limited_operator_proposals(state, include_resolved=True, limit=LIVE_AGENT_LOOP_DEFAULTS["operatorProposalRetention"])
    existing = [item for item in existing if item.get("id") != proposal_id]
    proposal = _live_agent_loop_normalize_operator_proposal({
        "id": proposal_id,
        "status": "pending",
        "agentId": agent_id,
        "actionType": action_type,
        "capabilityTag": capability_tag or capability.get("capabilityTag"),
        "sourceKind": source.get("kind"),
        "title": f"Review {capability.get('label') or action_type}",
        "summary": f"{agent_id} requested {action_type or capability.get('id')}, but Live Mode kept it proposal-only because no typed visible executor is available.",
        "requestedAt": now_iso,
        "updatedAt": now_iso,
        "blockedReason": capability.get("blockedReason"),
        "requiredExecutor": capability.get("requiredExecutor"),
        "requirement": capability.get("requirement"),
        "capability": capability,
        "target": _copy_jsonable(target),
        "payloadPreview": {
            "actionType": action_type,
            "capabilityTag": capability_tag,
            "target": _copy_jsonable(target),
            "params": _copy_jsonable(payload.get("params")) if isinstance(payload.get("params"), dict) else None,
        },
        "rejection": _copy_jsonable(rejection.get("error")) if isinstance(rejection.get("error"), dict) else _copy_jsonable(rejection),
    })
    state["operatorProposals"] = _live_agent_loop_trim_list([*existing, proposal], LIVE_AGENT_LOOP_DEFAULTS["operatorProposalRetention"])
    _live_agent_loop_add_event(state, "operator-proposal-created", agent_id=agent_id, details={"proposalId": proposal_id, "actionType": action_type, "capabilityId": capability.get("id")})
    return proposal


def _live_agent_loop_plan_status(value, default="planned"):
    status = str(value or default).strip().lower().replace("-", "_")
    allowed = {"planned", "in_progress", "retrying", "completed", "failed", "cancelled"}
    return status if status in allowed else default


def _live_agent_loop_step_status(value, default="pending"):
    status = str(value or default).strip().lower().replace("-", "_")
    allowed = {"pending", "in_progress", "completed", "failed", "skipped"}
    return status if status in allowed else default


def _live_agent_loop_episode_status(value, default="in_progress"):
    status = str(value or default).strip().lower().replace("-", "_")
    allowed = {
        "in_progress",
        "executing",
        "verifying",
        "verified",
        "failed",
        "awaiting_report",
        "reported",
        "awaiting_coder",
        "coder_responded",
        "completed",
        "cancelled",
    }
    return status if status in allowed else default


def _live_agent_loop_episode_phase(value, default="observe"):
    phase = str(value or default).strip().lower().replace("_", "-")
    allowed = {"observe", "reflect", "decide", "execute", "verify", "report", "await-coder", "learn", "continue"}
    return phase if phase in allowed else default


def _live_agent_loop_episode_is_active(episode):
    return isinstance(episode, dict) and _live_agent_loop_episode_status(episode.get("status")) in {
        "in_progress",
        "executing",
        "verifying",
        "awaiting_report",
        "reported",
        "awaiting_coder",
        "coder_responded",
    }


def _live_agent_loop_episode_id(agent_id, plan_id, loop_action_id, now_iso=None):
    seed = f"{agent_id}:{plan_id}:{loop_action_id}:{now_iso or _utc_now_iso()}"
    return "episode-" + hashlib.sha1(seed.encode("utf-8", errors="ignore")).hexdigest()[:16]


def _live_agent_loop_normalize_episode(episode):
    if not isinstance(episode, dict):
        return None
    episode_id = _live_agent_loop_clean_plan_text(episode.get("id"), limit=140)
    if not episode_id:
        return None
    now_iso = _utc_now_iso()
    normalized = {
        "schemaVersion": LIVE_AGENT_EPISODE_SCHEMA_VERSION,
        "id": episode_id,
        "status": _live_agent_loop_episode_status(episode.get("status")),
        "phase": _live_agent_loop_episode_phase(episode.get("phase")),
        "createdAt": episode.get("createdAt") if _parse_isoish_epoch(episode.get("createdAt")) else now_iso,
        "updatedAt": episode.get("updatedAt") if _parse_isoish_epoch(episode.get("updatedAt")) else now_iso,
    }
    for key, limit in (
        ("agentId", 120),
        ("planId", 160),
        ("loopActionId", 120),
        ("actionType", 120),
        ("actionId", 160),
        ("issueId", 180),
        ("title", 220),
        ("currentGoal", 500),
        ("hypothesis", 700),
        ("operatorSummary", 700),
        ("targetKey", 220),
        ("conversationId", 220),
    ):
        cleaned = _live_agent_loop_clean_plan_text(episode.get(key), limit=limit)
        if cleaned:
            normalized[key] = cleaned
    for key in ("completedAt", "failedAt", "reportedAt", "coderRespondedAt", "verifiedAt"):
        if _parse_isoish_epoch(episode.get(key)):
            normalized[key] = episode.get(key)
    for key in ("target", "decision", "verification", "resolution"):
        value = episode.get(key)
        if isinstance(value, dict):
            normalized[key] = _copy_jsonable(value)
    for key, limit in (("evidence", 10), ("reports", 8), ("coderResponses", 8), ("history", 18)):
        value = episode.get(key)
        if isinstance(value, list):
            normalized[key] = [_copy_jsonable(item) for item in value if isinstance(item, dict)][-limit:]
    response_floor_epoch = (
        _parse_isoish_epoch(normalized.get("reportedAt"))
        or _parse_isoish_epoch(normalized.get("createdAt"))
        or 0
    )
    if normalized.get("coderResponses"):
        deduped_responses = []
        response_keys = set()
        for item in normalized.get("coderResponses") or []:
            item_epoch = _parse_isoish_epoch(item.get("at")) or 0
            if item_epoch < response_floor_epoch:
                continue
            semantic_key = (
                str(item.get("conversationId") or ""),
                str(item.get("text") or "").strip(),
                int(item_epoch),
            )
            if semantic_key in response_keys:
                continue
            response_keys.add(semantic_key)
            deduped_responses.append(item)
        normalized["coderResponses"] = deduped_responses
    if normalized.get("history"):
        normalized["history"] = [
            item
            for item in normalized.get("history") or []
            if item.get("event") != "coder-response-received"
            or (_parse_isoish_epoch(item.get("at")) or 0) >= response_floor_epoch
        ][-18:]
    if normalized.get("status") == "coder_responded" and not normalized.get("coderResponses"):
        normalized["status"] = "awaiting_coder"
        normalized["phase"] = "await-coder"
        normalized.pop("coderRespondedAt", None)
        normalized["operatorSummary"] = "Reported to Coder; waiting for feedback tied to this episode."
    successful_reports = [
        item for item in (normalized.get("reports") or [])
        if item.get("ok") is True or str(item.get("status") or "").strip().lower() in {"delivered", "sent", "reported", "completed"}
    ]
    if normalized.get("status") == "awaiting_report" and successful_reports:
        successful_reports.sort(key=lambda item: _parse_isoish_epoch(item.get("at")) or 0)
        latest_report = successful_reports[-1]
        report_at = latest_report.get("at")
        normalized["status"] = "awaiting_coder"
        normalized["phase"] = "await-coder"
        if _parse_isoish_epoch(report_at):
            normalized["reportedAt"] = report_at
            if (_parse_isoish_epoch(report_at) or 0) >= (_parse_isoish_epoch(normalized.get("updatedAt")) or 0):
                normalized["updatedAt"] = report_at
        normalized["operatorSummary"] = "Reported to Coder; waiting for Coder feedback before marking the issue resolved."
    return normalized


def _live_agent_loop_store_episode(agent_state, episode):
    normalized = _live_agent_loop_normalize_episode(episode)
    if not normalized:
        return None
    episodes = []
    for item in agent_state.get("episodes") or []:
        existing = _live_agent_loop_normalize_episode(item)
        if existing and existing.get("id") != normalized.get("id"):
            episodes.append(existing)
    episodes.append(normalized)
    agent_state["episodes"] = _live_agent_loop_trim_list(episodes, LIVE_AGENT_LOOP_DEFAULTS["episodeRetention"])
    if _live_agent_loop_episode_is_active(normalized):
        agent_state["activeEpisode"] = normalized
    elif isinstance(agent_state.get("activeEpisode"), dict) and agent_state["activeEpisode"].get("id") == normalized.get("id"):
        agent_state.pop("activeEpisode", None)
    return normalized


def _live_agent_loop_find_episode(agent_state, *, episode_id=None, plan_id=None, action_id=None, issue_id=None):
    candidates = []
    active = _live_agent_loop_normalize_episode(agent_state.get("activeEpisode")) if isinstance(agent_state, dict) else None
    if active:
        candidates.append(active)
    for item in (agent_state.get("episodes") or []) if isinstance(agent_state, dict) else []:
        episode = _live_agent_loop_normalize_episode(item)
        if episode and all(episode.get("id") != existing.get("id") for existing in candidates):
            candidates.append(episode)
    for episode in reversed(candidates):
        if episode_id and episode.get("id") == episode_id:
            return episode
        if plan_id and episode.get("planId") == plan_id:
            return episode
        if action_id and episode.get("actionId") == action_id:
            return episode
        if issue_id and episode.get("issueId") == issue_id:
            return episode
    return None


def _live_agent_loop_normalize_plan(plan):
    if not isinstance(plan, dict):
        return None
    plan_id = _live_agent_loop_clean_plan_text(plan.get("id"), limit=120)
    if not plan_id:
        return None
    now_iso = _utc_now_iso()
    raw_steps = [step for step in (plan.get("steps") or []) if isinstance(step, dict)]
    steps = []
    for index, step in enumerate(raw_steps[:8]):
        step_id = _live_agent_loop_clean_plan_text(step.get("id"), limit=120) or f"step-{index + 1}"
        normalized_step = {
            "id": step_id,
            "label": _live_agent_loop_clean_plan_text(step.get("label"), limit=160) or step_id,
            "status": _live_agent_loop_step_status(step.get("status")),
            "attempts": _normalize_int(step.get("attempts"), 0, minimum=0, maximum=20),
        }
        for key, limit in (
            ("loopActionId", 120), ("actionType", 120), ("actionId", 160),
            ("failureReason", 220), ("goalId", 140), ("goalTaskId", 140),
            ("goalStepId", 140), ("executionKind", 80),
        ):
            cleaned = _live_agent_loop_clean_plan_text(step.get(key), limit=limit)
            if cleaned:
                normalized_step[key] = cleaned
        for key in ("startedAt", "settledAt", "updatedAt"):
            if _parse_isoish_epoch(step.get(key)):
                normalized_step[key] = step.get(key)
        steps.append(normalized_step)
    current_index = _normalize_int(plan.get("currentStepIndex"), 0, minimum=0, maximum=max(0, len(steps) - 1))
    normalized = {
        "schemaVersion": LIVE_AGENT_LOOP_PLAN_SCHEMA_VERSION,
        "id": plan_id,
        "status": _live_agent_loop_plan_status(plan.get("status")),
        "title": _live_agent_loop_clean_plan_text(plan.get("title"), limit=180) or "Live Mode plan",
        "createdAt": plan.get("createdAt") if _parse_isoish_epoch(plan.get("createdAt")) else now_iso,
        "updatedAt": plan.get("updatedAt") if _parse_isoish_epoch(plan.get("updatedAt")) else now_iso,
        "currentStepIndex": current_index,
        "steps": steps,
        "retries": _normalize_int(plan.get("retries"), 0, minimum=0, maximum=20),
        "maxRetries": _normalize_int(plan.get("maxRetries"), LIVE_AGENT_LOOP_DEFAULTS["planMaxRetries"], minimum=0, maximum=5),
    }
    for key, limit in (
        ("agentId", 120), ("loopActionId", 120), ("actionType", 120),
        ("need", 80), ("lastActionId", 160), ("failureReason", 240),
        ("operatorSummary", 500), ("goalId", 140), ("goalTaskId", 140),
        ("goalStepId", 140), ("goalTitle", 500),
    ):
        cleaned = _live_agent_loop_clean_plan_text(plan.get(key), limit=limit)
        if cleaned:
            normalized[key] = cleaned
    if plan.get("goalRevision") is not None:
        normalized["goalRevision"] = _normalize_int(plan.get("goalRevision"), 1, minimum=1, maximum=100000)
    for key in ("startedAt", "completedAt", "failedAt", "cancelledAt"):
        if _parse_isoish_epoch(plan.get(key)):
            normalized[key] = plan.get(key)
    return normalized


def _live_agent_loop_plan_current_step(plan):
    if not isinstance(plan, dict):
        return None
    steps = plan.get("steps") if isinstance(plan.get("steps"), list) else []
    if not steps:
        return None
    index = _normalize_int(plan.get("currentStepIndex"), 0, minimum=0, maximum=max(0, len(steps) - 1))
    return steps[index] if index < len(steps) else None


def _live_agent_loop_plan_is_active(plan):
    return isinstance(plan, dict) and _live_agent_loop_plan_status(plan.get("status")) in {"planned", "in_progress", "retrying"}


def _live_agent_loop_current_plan_action_id(agent_state):
    plan = _live_agent_loop_normalize_plan(agent_state.get("activePlan")) if isinstance(agent_state, dict) else None
    if not _live_agent_loop_plan_is_active(plan):
        return None
    step = _live_agent_loop_plan_current_step(plan)
    if not isinstance(step, dict):
        return None
    return step.get("loopActionId") if step.get("status") in {"pending", "in_progress", "failed"} else None


def _live_agent_loop_store_plan(agent_state, plan):
    normalized = _live_agent_loop_normalize_plan(plan)
    if not normalized:
        return None
    plans = []
    for item in agent_state.get("plans") or []:
        existing = _live_agent_loop_normalize_plan(item)
        if existing and existing.get("id") != normalized.get("id"):
            plans.append(existing)
    plans.append(normalized)
    agent_state["plans"] = _live_agent_loop_trim_list(plans, LIVE_AGENT_LOOP_DEFAULTS["planRetention"])
    if _live_agent_loop_plan_is_active(normalized):
        agent_state["activePlan"] = normalized
    elif isinstance(agent_state.get("activePlan"), dict) and agent_state["activePlan"].get("id") == normalized.get("id"):
        agent_state.pop("activePlan", None)
    return normalized


def _live_agent_loop_begin_episode(state, agent_id, agent_state, plan, action_def, decision, selected, now_iso):
    plan = _live_agent_loop_normalize_plan(plan)
    if not plan:
        return None
    existing = _live_agent_loop_find_episode(agent_state, plan_id=plan.get("id"))
    if existing:
        existing["updatedAt"] = now_iso
        existing.setdefault("history", []).append({"at": now_iso, "phase": existing.get("phase"), "event": "episode-resumed"})
        return _live_agent_loop_store_episode(agent_state, existing)
    action_def = action_def if isinstance(action_def, dict) else {}
    decision = decision if isinstance(decision, dict) else {}
    selected = selected if isinstance(selected, dict) else {}
    target = selected.get("target") if isinstance(selected.get("target"), dict) else {}
    goal_frame = decision.get("goalFrame") if isinstance(decision.get("goalFrame"), dict) else {}
    top_goal = next((item for item in (goal_frame.get("goals") or []) if isinstance(item, dict)), {})
    episode = {
        "schemaVersion": LIVE_AGENT_EPISODE_SCHEMA_VERSION,
        "id": _live_agent_loop_episode_id(agent_id, plan.get("id"), plan.get("loopActionId"), now_iso),
        "agentId": agent_id,
        "planId": plan.get("id"),
        "loopActionId": plan.get("loopActionId"),
        "actionType": plan.get("actionType"),
        "title": plan.get("title"),
        "status": "in_progress",
        "phase": "decide",
        "createdAt": now_iso,
        "updatedAt": now_iso,
        "currentGoal": _live_agent_loop_clean_plan_text(top_goal.get("text") or top_goal.get("reason") or decision.get("reason"), limit=500) or plan.get("title"),
        "hypothesis": _live_agent_loop_clean_plan_text(
            f"{plan.get('title')} should address {action_def.get('need') or plan.get('need') or 'the selected goal'} and produce verifiable evidence before the loop moves on.",
            limit=700,
        ),
        "target": _copy_jsonable(target),
        "targetKey": _live_agent_loop_target_key(target),
        "decision": {
            "selectedActionId": decision.get("selectedActionId"),
            "reason": decision.get("reason"),
            "score": decision.get("score"),
            "mode": decision.get("mode"),
        },
        "evidence": [],
        "reports": [],
        "coderResponses": [],
        "history": [{"at": now_iso, "phase": "decide", "event": "episode-created", "planId": plan.get("id")}],
        "operatorSummary": "Episode created; waiting for execution evidence.",
    }
    stored = _live_agent_loop_store_episode(agent_state, episode)
    if isinstance(state, dict):
        _live_agent_loop_add_event(state, "episode-created", agent_id=agent_id, details={"episodeId": stored.get("id"), "planId": plan.get("id"), "loopActionId": plan.get("loopActionId")})
    return stored


def _live_agent_loop_mark_episode_executing(state, agent_id, agent_state, plan, action_id, now_iso):
    episode = _live_agent_loop_find_episode(agent_state, plan_id=(plan or {}).get("id"))
    if not episode:
        return None
    episode["status"] = "executing"
    episode["phase"] = "execute"
    episode["actionId"] = action_id
    episode["updatedAt"] = now_iso
    episode.setdefault("history", []).append({"at": now_iso, "phase": "execute", "event": "action-created", "actionId": action_id})
    episode["operatorSummary"] = "Executing visible/support action; verification will run after terminal outcome."
    stored = _live_agent_loop_store_episode(agent_state, episode)
    if isinstance(state, dict):
        _live_agent_loop_add_event(state, "episode-executing", agent_id=agent_id, details={"episodeId": stored.get("id"), "actionId": action_id, "planId": (plan or {}).get("id")})
    return stored


def _live_agent_loop_settled_action_key(action_id, status):
    if not action_id or not status:
        return None
    return f"{action_id}:{_canonical_world_action_status(status)}"


def _live_agent_loop_dedupe_settled_records(values, key_fn):
    deduped = []
    seen = set()
    for item in (values or []):
        if not isinstance(item, dict):
            continue
        key = key_fn(item)
        if key and key in seen:
            continue
        if key:
            seen.add(key)
        deduped.append(item)
    return deduped


def _live_agent_loop_feedback_dedupe_key(item):
    details = item.get("details") if isinstance(item.get("details"), dict) else {}
    action_key = _live_agent_loop_settled_action_key(details.get("actionId"), details.get("status"))
    if not action_key:
        return None
    return f"{action_key}:{item.get('level')}:{item.get('message')}"


def _live_agent_loop_existing_settled_keys(agent_state):
    keys = set(str(key) for key in (agent_state.get("settledActionKeys") or []) if isinstance(key, str))
    memory = agent_state.get("memory") if isinstance(agent_state.get("memory"), dict) else {}
    for item in memory.get("recentActions") or []:
        if not isinstance(item, dict):
            continue
        key = _live_agent_loop_settled_action_key(item.get("actionId"), item.get("status"))
        if key:
            keys.add(key)
    for item in agent_state.get("feedbackReports") or []:
        if not isinstance(item, dict):
            continue
        details = item.get("details") if isinstance(item.get("details"), dict) else {}
        key = _live_agent_loop_settled_action_key(details.get("actionId"), details.get("status"))
        if key:
            keys.add(key)
    return keys


def _live_agent_loop_mark_settled_action(agent_state, action_id, status):
    key = _live_agent_loop_settled_action_key(action_id, status)
    if not key:
        return None
    retention = max(1, int(LIVE_AGENT_LOOP_DEFAULTS.get("settledActionRetention") or 120))
    existing = [str(item) for item in (agent_state.get("settledActionKeys") or []) if isinstance(item, str) and item != key]
    agent_state["settledActionKeys"] = [*existing, key][-retention:]
    return key


def _live_agent_loop_add_feedback(state, agent_id, level, message, details=None):
    agent_state = _live_agent_loop_agent_state(state, agent_id)
    report = {
        "at": _utc_now_iso(),
        "level": level or "info",
        "message": str(message or "").strip()[:500],
    }
    if isinstance(details, dict):
        report["details"] = details
    reports = _live_agent_loop_trim_list([*(agent_state.get("feedbackReports") or []), report], LIVE_AGENT_LOOP_DEFAULTS["feedbackRetention"])
    agent_state["feedbackReports"] = reports
    _live_agent_loop_add_event(state, "feedback-report", agent_id=agent_id, details={"level": report["level"], "message": report["message"], **({"actionId": details.get("actionId")} if isinstance(details, dict) and details.get("actionId") else {})})
    return report


def _live_agent_loop_enabled_roster():
    if not _agent_live_mode_runtime_enabled():
        return []
    roster = _merge_agent_profiles(get_roster())
    enabled = []
    for agent in roster:
        agent_id = agent.get("statusKey") or agent.get("id")
        if not agent_id:
            continue
        if agent.get("agentLiveModeEnabled") is True:
            enabled.append({**agent, "agentId": agent_id})
    return enabled


def _live_agent_loop_round_robin_roster(roster, cursor_agent_id=None):
    rows = [row for row in (roster or []) if isinstance(row, dict) and row.get("agentId")]
    cursor = str(cursor_agent_id or "").strip()
    if not rows or not cursor:
        return rows
    for index, row in enumerate(rows):
        if str(row.get("agentId") or "") == cursor:
            return [*rows[index + 1:], *rows[:index + 1]]
    return rows


def _live_agent_loop_note_scheduled(state, agent_id):
    if isinstance(state, dict) and agent_id:
        state["schedulerCursorAgentId"] = str(agent_id)


def _live_agent_loop_presence(agent_id, state, task):
    if not (_presence_enabled and _gateway_presence):
        return False
    try:
        current = _gateway_presence.get_agent_state(agent_id) if hasattr(_gateway_presence, "get_agent_state") else {}
        current_state = str((current or {}).get("state") or "").lower()
        current_task = str((current or {}).get("task") or "")
        if state == "idle" and current_state in {"working", "finishing"} and "Living in My Virtual World" not in current_task:
            return False
        _gateway_presence.set_manual_override(agent_id, state, task)
        return True
    except Exception as e:
        print(f"⚠️  Live Mode loop presence update failed for {agent_id}: {e}")
        return False


def _live_agent_loop_agent_aliases(agent_id):
    aliases = {str(agent_id or "").strip()}
    aliases.discard("")
    wanted = set(aliases)
    for agent in get_roster():
        if not isinstance(agent, dict):
            continue
        agent_aliases = {str(agent.get("id") or "").strip(), str(agent.get("statusKey") or "").strip()}
        agent_aliases.discard("")
        if wanted.intersection(agent_aliases):
            aliases.update(agent_aliases)
    return aliases


def _live_agent_loop_existing_home_for_agent(agent_id):
    aliases = _live_agent_loop_agent_aliases(agent_id)
    if not aliases:
        return None
    for building in list_buildings():
        if not isinstance(building, dict) or _building_unavailable(building):
            continue
        home_for = str(building.get("liveModeHomeForAgentId") or building.get("ownerAgentId") or "").strip()
        if home_for and home_for in aliases:
            return building
    return None


def _live_agent_loop_building_footprint(building):
    if not isinstance(building, dict) or _building_unavailable(building):
        return None
    footprint = _building_footprint_tile_rect(building)
    if not footprint:
        return None
    return {
        "minX": footprint["minX"],
        "minY": footprint["minZ"],
        "maxX": footprint["maxX"],
        "maxY": footprint["maxZ"],
    }


def _live_agent_loop_footprints_overlap(candidate, existing, padding=0):
    if not candidate or not existing:
        return False
    pad = max(0, float(padding or 0))
    return (
        candidate["minX"] < existing["maxX"] + pad
        and candidate["maxX"] > existing["minX"] - pad
        and candidate["minY"] < existing["maxY"] + pad
        and candidate["maxY"] > existing["minY"] - pad
    )


def _live_agent_loop_agent_display_name(agent_id):
    aliases = _live_agent_loop_agent_aliases(agent_id)
    for agent in get_roster():
        if not isinstance(agent, dict):
            continue
        if str(agent.get("id") or "").strip() in aliases or str(agent.get("statusKey") or "").strip() in aliases:
            return str(agent.get("name") or agent.get("statusKey") or agent.get("id") or agent_id).strip()
    return str(agent_id or "Agent").strip() or "Agent"


def _live_agent_loop_home_build_site_record(
    *,
    agent_id,
    agent_token,
    display_name,
    world_x,
    world_y,
    width,
    height,
    approach_x,
    approach_y,
    rotation=0,
    street_approach=None,
):
    building_id = f"live-home-{agent_token}"
    build_site = {
        "schemaVersion": "agent-live-mode-build-site/v1",
        "siteKind": "agent-home",
        "buildingId": building_id,
        "buildingName": f"{display_name}'s Home",
        "type": "home",
        "worldX": world_x,
        "worldY": world_y,
        "widthTiles": width,
        "heightTiles": height,
        "ownerAgentId": agent_id,
        "liveModeHomeForAgentId": agent_id,
        "exterior": {"wallColor": "#c8b89a", "roofColor": "#795548"},
    }
    if rotation:
        build_site["_rotation"] = rotation
    if isinstance(street_approach, dict):
        build_site["streetApproach"] = _copy_jsonable(street_approach)
    target = {
        "kind": "world-point",
        "x": int(round(float(approach_x) * LIVE_AGENT_LOOP_API_TILE)),
        "y": int(round(float(approach_y) * LIVE_AGENT_LOOP_API_TILE)),
        "z": int(round(float(approach_y) * LIVE_AGENT_LOOP_API_TILE)),
        "floor": 1,
        "siteKind": "agent-home",
        "buildSite": _copy_jsonable(build_site),
    }
    return {
        "target": target,
        "buildingName": build_site["buildingName"],
        "objectType": "construction-site",
        "availability": {"state": "available", "reason": None, "siteKind": "agent-home"},
        "buildSite": build_site,
    }


def _live_agent_loop_home_build_site_candidates(agent_id, agent_token, display_name, width, height):
    meta = load_world_meta()
    streets = ensure_checkpoint_streets(meta, persist=False)
    seed = sum(ord(ch) for ch in agent_token)
    candidates = []

    def append_candidate(index, street, street_rect, world_x, world_y, approach_x, approach_y, rotation, side, slot):
        build_site = {
            "id": f"candidate-{index}-{side}-{slot}",
            "worldX": world_x,
            "worldY": world_y,
            "widthTiles": width,
            "heightTiles": height,
            "_rotation": rotation,
        }
        placement = validate_building_placement(build_site, streets=streets)
        if not placement.get("ok"):
            return
        street_approach = {
            "schemaVersion": "agent-live-mode-build-site-approach/v1",
            "source": "street-adjacent-build-site",
            "streetIndex": index,
            "side": side,
            "slot": slot,
            "street": _copy_jsonable(street),
            "streetSurface": _copy_jsonable(street_rect),
            "approachTile": {"x": approach_x, "y": approach_y},
            "guidance": "Route to this street-side walkable point before constructing the new home.",
        }
        candidates.append({
            "sortKey": (index, slot, side),
            "record": _live_agent_loop_home_build_site_record(
                agent_id=agent_id,
                agent_token=agent_token,
                display_name=display_name,
                world_x=world_x,
                world_y=world_y,
                width=width,
                height=height,
                approach_x=approach_x,
                approach_y=approach_y,
                rotation=rotation,
                street_approach=street_approach,
            ),
        })

    for index, street in enumerate(streets if isinstance(streets, list) else []):
        if not isinstance(street, dict) or street.get("type"):
            continue
        street_rect = _street_surface_tile_rect(street)
        if not street_rect:
            continue
        x1 = _float_or_none(street.get("x1"))
        z1 = _float_or_none(street.get("z1"))
        x2 = _float_or_none(street.get("x2"))
        z2 = _float_or_none(street.get("z2"))
        if x1 is None or z1 is None or x2 is None or z2 is None:
            continue
        is_horizontal = abs(x2 - x1) >= abs(z2 - z1)
        if is_horizontal:
            min_x = math.ceil(min(x1, x2))
            max_x = math.floor(max(x1, x2) + 1 - width)
            if max_x < min_x:
                continue
            step = max(width + 4, 1)
            slots = list(range(min_x, max_x + 1, step))
            if max_x not in slots:
                slots.append(max_x)
            if not slots:
                continue
            slot_start = seed % len(slots)
            ordered_slots = slots[slot_start:] + slots[:slot_start]
            side_order = ["north-of-street", "south-of-street"] if (seed + index) % 2 == 0 else ["south-of-street", "north-of-street"]
            for slot, world_x in enumerate(ordered_slots):
                center_x = world_x + width / 2
                for side in side_order:
                    if side == "north-of-street":
                        world_y = math.ceil(street_rect["maxZ"])
                        approach_y = math.floor(street_rect["maxZ"])
                        rotation = 180
                    else:
                        world_y = math.floor(street_rect["minZ"] - height)
                        approach_y = math.ceil(street_rect["minZ"])
                        rotation = 0
                    append_candidate(
                        index,
                        street,
                        street_rect,
                        world_x,
                        world_y,
                        center_x,
                        approach_y,
                        rotation,
                        side,
                        slot,
                    )
        else:
            # For 90/270-degree homes the rendered footprint swaps width/depth.
            footprint_width = height
            footprint_depth = width
            min_y = math.ceil(min(z1, z2))
            max_y = math.floor(max(z1, z2) + 1 - footprint_depth)
            if max_y < min_y:
                continue
            step = max(footprint_depth + 4, 1)
            slots = list(range(min_y, max_y + 1, step))
            if max_y not in slots:
                slots.append(max_y)
            if not slots:
                continue
            slot_start = seed % len(slots)
            ordered_slots = slots[slot_start:] + slots[:slot_start]
            side_order = ["east-of-street", "west-of-street"] if (seed + index) % 2 == 0 else ["west-of-street", "east-of-street"]
            for slot, world_y in enumerate(ordered_slots):
                center_y = world_y + footprint_depth / 2
                for side in side_order:
                    if side == "east-of-street":
                        world_x = math.ceil(street_rect["maxX"])
                        approach_x = math.floor(street_rect["maxX"])
                        rotation = 90
                    else:
                        world_x = math.floor(street_rect["minX"] - footprint_width)
                        approach_x = math.ceil(street_rect["minX"])
                        rotation = 270
                    append_candidate(
                        index,
                        street,
                        street_rect,
                        world_x,
                        world_y,
                        approach_x,
                        center_y,
                        rotation,
                        side,
                        slot,
                    )

    candidates.sort(key=lambda item: item["sortKey"])
    if not candidates:
        return []
    start = seed % len(candidates)
    return [item["record"] for item in (candidates[start:] + candidates[:start])]


def _live_agent_loop_find_home_build_site(agent_id):
    if _live_agent_loop_existing_home_for_agent(agent_id):
        return None
    agent_token = re.sub(r"[^a-z0-9_-]+", "-", str(agent_id or "agent").lower()).strip("-") or "agent"
    display_name = _live_agent_loop_agent_display_name(agent_id)
    width = LIVE_AGENT_HOME_BUILD_SITE_WIDTH_TILES
    height = LIVE_AGENT_HOME_BUILD_SITE_HEIGHT_TILES
    existing_footprints = [fp for fp in (_live_agent_loop_building_footprint(b) for b in list_buildings()) if fp]
    for selected in _live_agent_loop_home_build_site_candidates(agent_id, agent_token, display_name, width, height):
        candidate = _live_agent_loop_building_footprint(selected.get("buildSite"))
        if any(_live_agent_loop_footprints_overlap(candidate, existing, padding=2) for existing in existing_footprints):
            continue
        return selected
    return None


def _live_agent_loop_unavailable_reason(action_def, agent_id):
    if action_def.get("targetKind") == "support-tool":
        if action_def.get("supportTool") == "coder-report":
            return "no-unreported-issue-or-support-request"
        if action_def.get("supportTool") == "internal-note":
            return "no-new-note-material"
        return "support-tool-unavailable"
    if action_def.get("id") == "build-small-home-site" and _live_agent_loop_existing_home_for_agent(agent_id):
        return "agent-home-already-built"
    if action_def.get("id") == "rest-at-home" and not _live_agent_loop_existing_home_for_agent(agent_id):
        return "agent-home-not-built"
    if action_def.get("targetKind") == "agent":
        return "no-nearby-visible-agent"
    if action_def.get("targetKind") == "world-point":
        return "no-open-construction-site"
    if action_def.get("targetKind") == "agent-home-building":
        return "agent-home-not-built"
    if action_def.get("targetKind") == "seating-object":
        return "no-available-seating-target"
    if action_def.get("category"):
        return f"no-available-{action_def.get('category')}-target"
    return "no-available-target"


def _live_agent_loop_seating_action_for_catalog(catalog_id):
    catalog_token = _normalize_token(catalog_id)
    if not catalog_token:
        return None
    for candidate in LIVE_AGENT_SEATING_ACTION_CANDIDATES:
        wanted = {_normalize_token(item) for item in candidate.get("catalogIds") or ()}
        if catalog_token in wanted:
            return candidate
        catalog = _catalog_block_for(catalog_id)
        catalog_key = _normalize_token((catalog or {}).get("id"))
        if catalog_key and catalog_key in wanted:
            return candidate
    return None


def _live_agent_loop_goal_progress_row(agent_state, key):
    progress = agent_state.setdefault("goalProgress", {}) if isinstance(agent_state, dict) else {}
    row = progress.get(key)
    if not isinstance(row, dict):
        row = {"completedTargets": [], "failedTargets": [], "updatedAt": None}
        progress[key] = row
    row.setdefault("completedTargets", [])
    row.setdefault("failedTargets", [])
    return row


def _live_agent_loop_is_seating_action(action_def=None, summary=None):
    action_def = action_def if isinstance(action_def, dict) else {}
    summary = summary if isinstance(summary, dict) else {}
    return (
        action_def.get("category") == "seating"
        or action_def.get("id") == "use-seating-object"
        or summary.get("loopActionId") == "use-seating-object"
        or summary.get("actionType") in LIVE_AGENT_SEATING_ACTION_TYPES
    )


def _live_agent_loop_completion_evidence_records(result):
    records = []

    def add(value):
        if isinstance(value, dict):
            records.append(value)

    add(result)
    if isinstance(result, dict):
        for key in ("embodiedState", "runtimeState", "useState", "visualState", "activity", "posture"):
            value = result.get(key)
            if isinstance(value, dict):
                add(value)
                if isinstance(value.get("activity"), dict):
                    add(value.get("activity"))
        embodied = result.get("embodiedState") if isinstance(result.get("embodiedState"), dict) else {}
        if isinstance(embodied.get("finalPlacement"), dict):
            add(embodied.get("finalPlacement"))
    return records


def _live_agent_loop_evidence_text(records, keys):
    values = []
    for record in records:
        for key in keys:
            value = record.get(key)
            if value is None:
                continue
            text = str(value).strip()
            if text and text not in values:
                values.append(text)
    return values


def _live_agent_loop_bool_evidence(records, keys):
    for record in records:
        for key in keys:
            value = record.get(key)
            if isinstance(value, bool) and value:
                return True
            if isinstance(value, str) and value.strip().lower() in {"true", "yes", "1"}:
                return True
    return False


def _live_agent_loop_seating_completion_validation(action, summary, action_def):
    if not _live_agent_loop_is_seating_action(action_def, summary):
        return {"required": False, "ok": True}
    if _canonical_world_action_status((summary or {}).get("status")) != "completed":
        return {"required": True, "ok": True, "reason": "not-completed"}
    result = summary.get("result") if isinstance(summary, dict) and isinstance(summary.get("result"), dict) else {}
    records = _live_agent_loop_completion_evidence_records(result)
    pose_values = _live_agent_loop_evidence_text(records, ("poseKind", "pose", "posture", "poseId"))
    animation_values = _live_agent_loop_evidence_text(records, ("animationId", "resolvedAnimationId"))
    state_values = _live_agent_loop_evidence_text(records, ("useState", "activeUseState", "state", "phase", "status"))
    seated_bool = _live_agent_loop_bool_evidence(records, ("seated", "isSeated", "sitting"))
    pose_text = " ".join(pose_values).lower()
    animation_text = " ".join(animation_values).lower()
    state_text = " ".join(state_values).lower()
    seated_posture = seated_bool or any(token in pose_text for token in ("seat", "seated", "sitting", "sit"))
    use_state_ok = any(token in state_text for token in ("active", "using", "in_progress", "docked", "completed", "seated"))
    animation_ok = bool(animation_values) and not any(
        animation_text == token or animation_text.endswith(f" {token}")
        for token in ("walk", "idle", "stand", "stand-use", "standing")
    )
    final_placement = None
    for record in records:
        if isinstance(record.get("finalPlacement"), dict):
            final_placement = record.get("finalPlacement")
            break
        if isinstance(record.get("dockTarget"), dict):
            final_placement = record.get("dockTarget")
            break
    action_reservation = action.get("reservation") if isinstance(action, dict) and isinstance(action.get("reservation"), dict) else {}
    action_effects = action.get("effects") if isinstance(action, dict) and isinstance(action.get("effects"), list) else []
    clean_exit = (
        not action_reservation
        or action_reservation.get("availabilityState") == "available"
        or action_reservation.get("state") in {"released", "cancelled", "failed", "timed_out"}
        or any(isinstance(effect, dict) and effect.get("type") == "reservation-released" for effect in action_effects)
    )
    ok = bool(seated_posture and (use_state_ok or animation_ok) and final_placement and clean_exit)
    evidence = {
        "schemaVersion": LIVE_AGENT_SEATING_COMPLETION_VALIDATION_VERSION,
        "seatedPosture": seated_posture,
        "useStateOk": use_state_ok,
        "animationOk": animation_ok,
        "finalPlacement": _copy_jsonable(final_placement) if isinstance(final_placement, dict) else None,
        "cleanExit": clean_exit,
        "pose": pose_values[:4],
        "animation": animation_values[:4],
        "state": state_values[:4],
    }
    reason = None if ok else "missing_seated_use_state_evidence"
    return {"required": True, "ok": ok, "reason": reason, "evidence": evidence}


def _live_agent_loop_completion_validation_failure(action, summary, validation):
    if not isinstance(validation, dict) or validation.get("ok"):
        return None
    target = _live_agent_loop_memory_target(action.get("target")) if isinstance(action, dict) else None
    target_key = _live_agent_loop_target_key(target)
    evidence = validation.get("evidence") if isinstance(validation.get("evidence"), dict) else {}
    missing = []
    if not evidence.get("seatedPosture"):
        missing.append("seated posture")
    if not (evidence.get("useStateOk") or evidence.get("animationOk")):
        missing.append("use-state/animation")
    if not evidence.get("finalPlacement"):
        missing.append("final placement")
    if not evidence.get("cleanExit"):
        missing.append("clean exit")
    missing_text = ", ".join(missing) or "required embodied evidence"
    target_phrase = _live_agent_loop_target_phrase(target)
    learning_text = f"completed status did not prove seating; missing {missing_text}."
    if target_phrase:
        learning_text = f"{learning_text} Target {target_phrase}."
    learning_text = f"{learning_text} Treat arrival near the seat as inconclusive and avoid marking this furniture tested until posture/use-state evidence is present."
    return {
        "status": "failed",
        "reason": validation.get("reason") or "missing_seated_use_state_evidence",
        "failureReason": "validation_failed",
        "resultReason": validation.get("reason") or "",
        "target": target,
        "targetKey": target_key,
        "evidence": evidence,
        "learningText": learning_text[:700],
    }


def _live_agent_loop_record_goal_progress(agent_state, action_def, target_key, completed):
    """Track per-category goal progress (e.g. which seating objects were tested)
    so future resolver picks prefer untested targets and the model can see
    accumulated progress instead of repeating the same object forever."""
    category = (action_def or {}).get("category")
    if not category or not target_key or not isinstance(agent_state, dict):
        return None
    row = _live_agent_loop_goal_progress_row(agent_state, f"category:{category}")
    bucket = row["completedTargets"] if completed else row["failedTargets"]
    if target_key not in bucket:
        bucket.append(target_key)
    if completed and target_key in row["failedTargets"]:
        row["failedTargets"] = [item for item in row["failedTargets"] if item != target_key]
    row["updatedAt"] = _utc_now_iso()
    return row


def _live_agent_loop_progress_target_keys(agent_state, category):
    if not isinstance(agent_state, dict) or not category:
        return set()
    progress = agent_state.get("goalProgress") if isinstance(agent_state.get("goalProgress"), dict) else {}
    row = progress.get(f"category:{category}")
    if not isinstance(row, dict):
        return set()
    return {str(item) for item in (row.get("completedTargets") or []) if item}


def _live_agent_loop_target_verified(agent_state, target_key, *, loop_action_id=None):
    """Unify coverage evidence written by old and new Live Mode versions."""
    target_key = str(target_key or "").strip()
    if not isinstance(agent_state, dict) or not target_key:
        return False

    progress = agent_state.get("goalProgress") if isinstance(agent_state.get("goalProgress"), dict) else {}
    for row in progress.values():
        if not isinstance(row, dict):
            continue
        if any(_live_agent_loop_target_keys_compatible(target_key, item) for item in (row.get("completedTargets") or [])):
            return True

    memory = agent_state.get("memory") if isinstance(agent_state.get("memory"), dict) else {}
    for item in memory.get("recentActions") or []:
        if not isinstance(item, dict) or _canonical_world_action_status(item.get("status")) != "completed":
            continue
        item_key = item.get("targetKey") or _live_agent_loop_target_key(item.get("target"))
        if _live_agent_loop_target_keys_compatible(target_key, item_key):
            return True

    procedural = agent_state.get("proceduralMemory") if isinstance(agent_state.get("proceduralMemory"), dict) else {}
    for action_id, row in procedural.items():
        if not isinstance(row, dict) or int(row.get("successes") or 0) <= 0:
            continue
        if loop_action_id and action_id != loop_action_id and not row.get("lastTargetKey"):
            continue
        if _live_agent_loop_target_keys_compatible(target_key, row.get("lastTargetKey")):
            return True

    return int(_live_agent_loop_verified_episode_counts(
        agent_state,
        loop_action_id=loop_action_id,
        target_key=target_key,
        limit=120,
    ).get("sameTarget") or 0) > 0


def _live_agent_loop_object_coverage_active(agent_id, goal_frame=None):
    resident = None
    if isinstance(goal_frame, dict):
        context = goal_frame.get("context") if isinstance(goal_frame.get("context"), dict) else {}
        resident = context.get("residentProfile") if isinstance(context.get("residentProfile"), dict) else None
    if not isinstance(resident, dict):
        resident = _live_agent_loop_resident_profile_context(
            _live_agent_loop_resident_profile(agent_id, persist=False)
        ) or {}
    custom = resident.get("custom") if isinstance(resident.get("custom"), dict) else {}
    if str(custom.get("objectCoveragePolicy") or "").strip():
        return True
    goals = resident.get("goals") if isinstance(resident.get("goals"), dict) else {}
    text = " ".join(_live_agent_memory_text(item) for item in (goals.get("current") or [])).lower()
    return bool(
        "untested" in text
        or "least-tested" in text
        or ("validate" in text and "object" in text and ("one at a time" in text or "do not repeat" in text))
    )


def _live_agent_loop_find_seating_target(action_def, *, agent_id=None, agent_state=None):
    tested_keys = _live_agent_loop_progress_target_keys(agent_state, (action_def or {}).get("category") or "seating")
    inventory = agent_state.get("inventory") if isinstance(agent_state, dict) and isinstance(agent_state.get("inventory"), dict) else {}
    consuming_held_item = isinstance(inventory.get("held"), dict)
    coverage_active = _live_agent_loop_object_coverage_active(agent_id) if agent_id else False
    candidates = []
    candidate_order = 0
    for building in list_buildings():
        if not isinstance(building, dict) or _building_unavailable(building):
            continue
        collections = (
            ("furniture", ((building.get("interior") or {}).get("furniture") or [])),
            ("outdoor-node", ((building.get("outdoorArea") or {}).get("nodes") or [])),
        )
        for collection, records in collections:
            if not isinstance(records, list):
                continue
            for index, obj in enumerate(records):
                if not isinstance(obj, dict):
                    continue
                catalog_id = _object_catalog_id(obj)
                seating_action = _live_agent_loop_seating_action_for_catalog(catalog_id)
                if not seating_action:
                    continue
                action_type = seating_action.get("actionType")
                spot_id = seating_action.get("spotId")
                capability = "life.rest"
                catalog = _catalog_block_for(catalog_id)
                permission = _catalog_action_permission(catalog, action_type, capability) if catalog else None
                if not permission or permission.get("capabilityTag") != capability:
                    continue
                if not _catalog_has_spot(catalog, spot_id, action_type):
                    continue
                object_id = obj.get("objectInstanceId") or obj.get("id") or obj.get("instanceId") or (sorted(_candidate_object_ids(building, obj, index, collection)) or [None])[0]
                if not object_id:
                    continue
                target = {
                    "kind": "object-instance",
                    "buildingId": building.get("id"),
                    "objectInstanceId": object_id,
                    "catalogId": catalog_id,
                    "interactionSpotId": spot_id,
                    "floor": obj.get("floor") or obj.get("buildingFloor") or 1,
                }
                if collection == "furniture":
                    target["furnitureIndex"] = index
                else:
                    target["nodeIndex"] = index
                    target["targetKind"] = "outdoor-area-node"
                resolved = _find_world_action_target(target)
                availability = get_object_availability(target, agent_id=agent_id, resolved=resolved)
                if availability.get("state") != "available":
                    continue
                selected_action = {
                    **action_def,
                    "actionType": action_type,
                    "capabilityTag": capability,
                    "interactionSpotId": spot_id,
                    "label": seating_action.get("label") or action_def.get("label"),
                    "experience": f"test whether {catalog_id or 'the seat'} is reachable, reservable, and visibly usable",
                }
                selected = {
                    "target": target,
                    "buildingName": building.get("name"),
                    "objectType": catalog_id,
                    "availability": availability,
                    "action": selected_action,
                    "seatingCandidate": {k: seating_action.get(k) for k in ("actionType", "spotId", "label")},
                }
                target_key = _live_agent_loop_target_key(target)
                verified = (
                    target_key in tested_keys
                    or (
                        coverage_active
                        and _live_agent_loop_target_verified(
                            agent_state,
                            target_key,
                            loop_action_id=(action_def or {}).get("id"),
                        )
                    )
                )
                # Coverage work may never cycle a verified seat. A carried
                # consumable still needs a legitimate dwell target, but it
                # should prefer an unverified or least-used seat instead of
                # deterministically returning the first armchair forever.
                if not consuming_held_item and verified:
                    continue
                use_count = 0
                last_used_epoch = 0.0
                memory = agent_state.get("memory") if isinstance(agent_state, dict) and isinstance(agent_state.get("memory"), dict) else {}
                for recent in memory.get("recentActions") or []:
                    if not isinstance(recent, dict):
                        continue
                    recent_key = recent.get("targetKey") or _live_agent_loop_target_key(recent.get("target"))
                    if not recent_key or not _live_agent_loop_target_keys_compatible(target_key, recent_key):
                        continue
                    use_count += 1
                    last_used_epoch = max(last_used_epoch, _parse_isoish_epoch(recent.get("at")) or 0.0)
                for item in inventory.get("history") or []:
                    if not isinstance(item, dict):
                        continue
                    item_key = _live_agent_loop_target_key(item.get("target"))
                    if not item_key or not _live_agent_loop_target_keys_compatible(target_key, item_key):
                        continue
                    use_count += 1
                    last_used_epoch = max(last_used_epoch, _parse_isoish_epoch(item.get("consumedAt")) or 0.0)
                selected["selectionEvidence"] = {
                    "verifiedTarget": bool(verified),
                    "recentUseCount": use_count,
                    "lastUsedAt": _epoch_to_utc_iso(last_used_epoch) if last_used_epoch else None,
                    "policy": "prefer-unverified-then-least-used-seat",
                }
                candidates.append((1 if verified else 0, use_count, last_used_epoch, candidate_order, selected))
                candidate_order += 1
    if not candidates:
        return None
    candidates.sort(key=lambda item: item[:4])
    return candidates[0][4]


def _live_agent_loop_find_action_target(action_def, *, agent_id=None, agent_state=None, spatial=None):
    if action_def.get("targetKind") == "support-tool":
        tool = action_def.get("supportTool")
        if tool == "coder-report":
            context = _live_agent_loop_report_context(agent_id, agent_state if isinstance(agent_state, dict) else {})
            if not context:
                return None
            return {
                "target": {
                    "kind": "support-tool",
                    "supportTool": "coder-report",
                    "toAgentId": "coder",
                    "issueId": context.get("issueId"),
                    "contextKind": context.get("kind"),
                },
                "buildingName": "",
                "objectType": "agent-communication",
                "availability": {"state": "available", "reason": context.get("kind"), "context": _copy_jsonable(context)},
                "action": action_def,
                "supportContext": context,
            }
        if tool == "internal-note":
            context = _live_agent_loop_note_context(agent_id, agent_state if isinstance(agent_state, dict) else {})
            if not context:
                return None
            return {
                "target": {
                    "kind": "support-tool",
                    "supportTool": "internal-note",
                    "contextKind": context.get("kind"),
                },
                "buildingName": "",
                "objectType": "internal-note",
                "availability": {"state": "available", "reason": context.get("kind"), "context": _copy_jsonable(context)},
                "action": action_def,
                "supportContext": context,
            }
        return None
    if action_def.get("targetKind") == "agent":
        social = _live_agent_loop_social_perception(agent_id, spatial=spatial)
        nearby = social.get("nearbyAgents") if isinstance(social.get("nearbyAgents"), list) else []
        selected_peer = next((item for item in nearby if isinstance(item, dict) and item.get("agentId")), None)
        if not selected_peer:
            return None
        location = selected_peer.get("location") if isinstance(selected_peer.get("location"), dict) else {}
        target = {
            "kind": "agent",
            "targetAgentId": selected_peer.get("agentId"),
            "floor": int(selected_peer.get("floor") or location.get("floor") or 1),
            "perceptionSchemaVersion": social.get("schemaVersion"),
        }
        # Optional social location fields must be omitted when the realtime
        # snapshot represents outdoors/no canonical room with an empty string.
        # The world-action schema intentionally rejects blank identifiers.
        optional_target_fields = {
            "targetAgentName": selected_peer.get("name"),
            "buildingId": selected_peer.get("buildingId") or location.get("buildingId"),
            "roomId": selected_peer.get("roomId") or location.get("roomId"),
            "nearbyReason": selected_peer.get("nearbyReason"),
        }
        target.update({key: value for key, value in optional_target_fields.items() if _non_empty_string(value)})
        # Persist the authoritative observation point with the social target.
        # Realtime snapshots for ambient residents can disappear across a
        # sidecar restart; the observed coordinate keeps the already-approved
        # action physically executable instead of leaving it at `reserved`.
        for coordinate in ("x", "y"):
            value = _number_or_none(location.get(coordinate))
            if value is not None:
                target[coordinate] = value
        resource_signals = agent_state.get("resourceSignals") if isinstance(agent_state, dict) and isinstance(agent_state.get("resourceSignals"), dict) else {}
        repeated_signal = max(
            (item for item in resource_signals.values() if isinstance(item, dict) and int(item.get("observationCount") or 0) >= 2),
            key=lambda item: (int(item.get("observationCount") or 0), float(item.get("lastObservedEpoch") or 0)),
            default=None,
        )
        conversation_topic = (repeated_signal or {}).get("memoryText") or (repeated_signal or {}).get("text")
        selected_action = {**action_def}
        if conversation_topic:
            selected_action["conversationTopic"] = str(conversation_topic)[:700]
        return {
            "target": target,
            "buildingName": target.get("buildingId"),
            "objectType": "agent",
            "availability": {"state": "available", "reason": "nearby-visible-agent", "peer": {k: selected_peer.get(k) for k in ("agentId", "name", "status", "task", "liveModeEnabled", "nearbyReason")}},
            "action": selected_action,
            "peer": selected_peer,
            "conversationTopic": conversation_topic,
        }
    if action_def.get("targetKind") == "agent-home-building":
        home = _live_agent_loop_existing_home_for_agent(agent_id)
        if not home:
            return None
        target = {
            "kind": "building",
            "buildingId": home.get("id"),
            "floor": 1,
            "homeRole": "resident",
            "liveModeHomeForAgentId": agent_id,
        }
        return {
            "target": target,
            "buildingName": home.get("name"),
            "objectType": "agent-home",
            "availability": {"state": "available", "reason": None, "homeRole": "resident"},
            "action": action_def,
            "home": _copy_jsonable(home),
        }
    if action_def.get("targetKind") == "world-point":
        if action_def.get("siteKind") == "agent-home":
            selected = _live_agent_loop_find_home_build_site(agent_id)
            if selected:
                selected["action"] = action_def
            return selected
        return None
    if action_def.get("targetKind") == "seating-object":
        return _live_agent_loop_find_seating_target(action_def, agent_id=agent_id, agent_state=agent_state)
    wanted = {_normalize_token(catalog_id) for catalog_id in action_def.get("catalogIds", [])}
    for building in list_buildings():
        if not isinstance(building, dict) or _building_unavailable(building):
            continue
        records = (building.get("interior") or {}).get("furniture") or []
        if not isinstance(records, list):
            continue
        for index, obj in enumerate(records):
            if not isinstance(obj, dict):
                continue
            catalog_id = _object_catalog_id(obj)
            if _normalize_token(catalog_id) not in wanted:
                continue
            object_id = obj.get("objectInstanceId") or obj.get("id") or obj.get("instanceId") or (sorted(_candidate_object_ids(building, obj, index, "furniture")) or [None])[0]
            if not object_id:
                continue
            target = {
                "kind": "object-instance",
                "buildingId": building.get("id"),
                "objectInstanceId": object_id,
                "catalogId": catalog_id,
                "furnitureIndex": index,
                "interactionSpotId": action_def.get("interactionSpotId") or "use-front",
                "floor": obj.get("floor") or obj.get("buildingFloor") or 1,
            }
            resolved = _find_world_action_target(target)
            availability = get_object_availability(target, agent_id=agent_id, resolved=resolved)
            queue_availability = availability.get("queueAvailability") if isinstance(availability.get("queueAvailability"), dict) else {}
            if availability.get("state") == "available" or queue_availability.get("state") == "available":
                return {
                    "target": target,
                    "buildingName": building.get("name"),
                    "objectType": catalog_id,
                    "availability": availability,
                    "action": action_def,
                }
    return None


def _live_agent_loop_action_definition(loop_action_id=None, action_type=None):
    dynamic_defs = list(LIVE_AGENT_DYNAMIC_OBJECT_AFFORDANCES.values())
    for action_def in [*LIVE_AGENT_LOOP_ACTIONS, *dynamic_defs]:
        if loop_action_id and action_def.get("id") == loop_action_id:
            return action_def
        if action_type and action_def.get("actionType") == action_type:
            return action_def
    if action_type and _live_agent_visible_action_contract(action_type):
        is_seating = action_type in LIVE_AGENT_LOCAL_OBJECT_VISIBLE_ACTION_TYPES
        action_label = re.sub(r"(?<!^)(?=[A-Z])", " ", str(action_type).split(".")[-1]).replace("_", " ").lower()
        return {
            "id": loop_action_id or f"world-action-{_normalize_token(action_type) or 'interaction'}",
            "actionType": action_type,
            "capabilityTag": _live_agent_loop_capability_for_action_type(action_type),
            "need": _live_agent_loop_need_for_action_type(action_type),
            "label": action_label,
            "dynamic": True,
            "genericWorldAffordance": True,
            "category": "seating" if is_seating else None,
        }
    return None


def _live_agent_loop_agent_snapshot(agent_id):
    status = load_agent_status()
    roster = _merge_agent_profiles(get_roster())
    for agent in roster:
        status_key = agent.get("statusKey") or agent.get("id")
        if status_key != agent_id and agent.get("id") != agent_id:
            continue
        agent_status = status.get(status_key, {}) or status.get(agent.get("id"), {})
        live_mode_setting = get_agent_live_mode_setting(status_key) or {}
        return {
            "agentId": status_key,
            "id": agent.get("id"),
            "name": agent.get("name"),
            "providerKind": agent.get("providerKind"),
            "status": agent_status.get("state", agent_status.get("status", "offline")),
            "task": agent_status.get("task", ""),
            "agentLiveModeEnabled": bool(live_mode_setting.get("agentLiveModeEnabled")),
            "liveWorld": live_mode_setting.get("liveWorld"),
        }
    return {"agentId": agent_id, "status": "unknown", "task": "", "agentLiveModeEnabled": False, "liveWorld": _agent_live_world_claim_payload(agent_id)}


def _live_agent_loop_world_summary():
    buildings = [b for b in list_buildings() if isinstance(b, dict)]
    object_counts = {}
    for building in buildings:
        for obj in ((building.get("interior") or {}).get("furniture") or []):
            if not isinstance(obj, dict):
                continue
            catalog_id = _object_catalog_id(obj)
            object_counts[catalog_id] = object_counts.get(catalog_id, 0) + 1
    return {
        "buildingCount": len(buildings),
        "buildings": [{"id": b.get("id"), "name": b.get("name"), "furnitureCount": len(((b.get("interior") or {}).get("furniture") or []))} for b in buildings[:12]],
        "objectCounts": object_counts,
    }


def _live_agent_loop_location_from_active_record(item):
    record = item.get("record") if isinstance(item, dict) and isinstance(item.get("record"), dict) else {}
    target = record.get("target") if isinstance(record.get("target"), dict) else {}
    if not target and isinstance(record.get("params"), dict):
        target = record.get("params", {}).get("target") if isinstance(record.get("params", {}).get("target"), dict) else {}
    if not target and isinstance(record.get("route"), dict):
        target = record.get("route", {}).get("target") if isinstance(record.get("route", {}).get("target"), dict) else {}
    if not target:
        return None
    building_id = target.get("buildingId")
    if not building_id:
        return None
    floor = target.get("floor") or target.get("buildingFloor") or 1
    try:
        floor = int(floor)
    except (TypeError, ValueError):
        floor = 1
    return {
        "source": item.get("type"),
        "activeId": item.get("id"),
        "status": item.get("status"),
        "worldActionId": item.get("worldActionId") or record.get("id"),
        "buildingId": building_id,
        "floor": floor,
        "targetKind": target.get("kind"),
        "objectInstanceId": target.get("objectInstanceId"),
        "catalogId": target.get("catalogId"),
    }


def _live_agent_loop_active_locations_by_agent():
    locations = {}
    for action in get_world_actions_store(persist_migration=True).get("active", []):
        if not isinstance(action, dict):
            continue
        status = _canonical_world_action_status(action.get("status"))
        if status not in WORLD_ACTION_ACTIVE_STATES:
            continue
        agent_id = action.get("agentId")
        if not agent_id or agent_id in locations:
            continue
        location = _live_agent_loop_location_from_active_record({"type": "world-action", "id": action.get("id"), "status": status, "record": action})
        if location:
            locations[agent_id] = location
    for intent in reconcile_move_intents().get("active", []):
        if not isinstance(intent, dict) or intent.get("routeStatus") not in MOVE_INTENT_ACTIVE_STATES:
            continue
        agent_id = intent.get("agentId")
        if not agent_id or agent_id in locations:
            continue
        location = _live_agent_loop_location_from_active_record({"type": "move-intent", "id": intent.get("id"), "status": intent.get("routeStatus"), "worldActionId": _move_intent_linked_world_action_id(intent), "record": intent})
        if location:
            locations[agent_id] = location
    return locations


def _live_agent_loop_active_location(agent_id):
    for item in _active_behavior_records_for_agent(agent_id):
        location = _live_agent_loop_location_from_active_record(item)
        if location:
            return location
    return None


def _live_agent_loop_assignment_location(agent_id):
    meta = load_world_meta()
    aliases = _live_agent_loop_agent_aliases(agent_id)
    assignments = meta.get("agentAssignments") if isinstance(meta.get("agentAssignments"), dict) else {}
    for alias in aliases:
        assignment = assignments.get(alias)
        if not isinstance(assignment, dict):
            continue
        for key, kind in (("work", "work"), ("home", "home")):
            building_id = assignment.get(key)
            if building_id:
                return {"source": f"assignment.{kind}", "buildingId": building_id, "floor": 1}
    resident_profile = _live_agent_loop_resident_profile(agent_id, persist=True)
    resident_world = resident_profile.get("world") if isinstance(resident_profile, dict) and isinstance(resident_profile.get("world"), dict) else {}
    for key, kind in (("workBuildingId", "work"), ("homeBuildingId", "home")):
        building_id = resident_world.get(key)
        if building_id:
            return {"source": f"residentProfile.{kind}", "buildingId": building_id, "floor": 1}
    home = _live_agent_loop_existing_home_for_agent(agent_id)
    if home:
        return {"source": "owned-home", "buildingId": home.get("id"), "floor": 1}
    return None


def _live_agent_loop_social_perception(agent_id, spatial=None):
    status = load_agent_status()
    meta = load_world_meta()
    profiles = meta.get("agentProfiles") if isinstance(meta.get("agentProfiles"), dict) else {}
    relationships = meta.get("agentRelationships") if isinstance(meta.get("agentRelationships"), dict) else {}
    roster = get_roster()
    aliases = _live_agent_loop_agent_aliases(agent_id)
    spatial = spatial if isinstance(spatial, dict) else _live_agent_loop_build_spatial_perception(agent_id)
    spatial_agents = {
        str(item.get("agentId") or ""): item
        for item in (spatial.get("nearbyAgents") or [])
        if isinstance(item, dict) and item.get("agentId")
    }
    alias_map = {}
    for agent in roster:
        if not isinstance(agent, dict):
            continue
        resolved = str(agent.get("statusKey") or agent.get("id") or "").strip()
        if not resolved:
            continue
        agent_aliases = {str(agent.get("id") or "").strip(), str(agent.get("statusKey") or "").strip()}
        agent_aliases.discard("")
        alias_map[resolved] = agent_aliases or {resolved}
    self_location = spatial.get("self") if isinstance(spatial.get("self"), dict) else None
    known = []
    live_enabled = []
    nearby = []
    for agent in roster:
        if not isinstance(agent, dict):
            continue
        other_id = str(agent.get("statusKey") or agent.get("id") or "").strip()
        if not other_id or other_id in aliases:
            continue
        other_aliases = alias_map.get(other_id) or {other_id}
        if aliases.intersection(other_aliases):
            continue
        profile = profiles.get(other_id) or profiles.get(agent.get("id")) or {}
        other_status = status.get(other_id, {}) or status.get(agent.get("id"), {}) or {}
        live_mode_enabled = bool(agent.get("agentLiveModeEnabled") or _agent_live_mode_enabled_from_profile(profile))
        rel_key = next((key for key in relationships.keys() if isinstance(key, str) and any(alias and alias in key for alias in aliases) and any(alias and alias in key for alias in other_aliases)), None)
        relationship = relationships.get(rel_key) if rel_key and isinstance(relationships.get(rel_key), dict) else {}
        spatial_row = spatial_agents.get(other_id)
        location = spatial_row.get("position") if isinstance(spatial_row, dict) and isinstance(spatial_row.get("position"), dict) else None
        row = {
            "agentId": other_id,
            "name": agent.get("name"),
            "status": other_status.get("state", other_status.get("status", "offline")),
            "task": other_status.get("task", ""),
            "liveModeEnabled": live_mode_enabled,
            "relationship": {k: relationship.get(k) for k in ("summary", "score", "updatedAt") if k in relationship},
            "location": location,
        }
        if spatial_row:
            row["spatial"] = {
                key: spatial_row.get(key)
                for key in (
                    "distance", "distanceTiles", "proximityBand", "sameFloor", "sameBuilding",
                    "sameRoom", "perceived", "inFieldOfView", "lineOfSight", "visible", "interactionReady",
                    "relativeBearingDegrees", "occludedBy",
                )
            }
        known.append(row)
        if live_mode_enabled:
            live_enabled.append(row)
        if spatial_row and spatial_row.get("interactionReady"):
            nearby.append({
                **row,
                "nearbyReason": "authoritative-distance-and-visibility",
                "buildingId": location.get("buildingId") if location else "",
                "roomId": location.get("roomId") if location else "",
                "floor": location.get("floor") if location else 1,
                "distance": spatial_row.get("distance"),
                "distanceTiles": spatial_row.get("distanceTiles"),
                "inFieldOfView": spatial_row.get("inFieldOfView"),
                "lineOfSight": spatial_row.get("lineOfSight"),
            })
    known.sort(key=lambda item: (not item.get("liveModeEnabled"), item.get("name") or item.get("agentId") or ""))
    return {
        "schemaVersion": "agent-live-mode-social-perception/v2",
        "agentId": agent_id,
        "selfLocation": self_location,
        "spatialSchemaVersion": spatial.get("schemaVersion"),
        "nearbyPolicy": "authoritative distance + floor/place compatibility + line of sight + hybrid field of view",
        "knownAgentCount": len(known),
        "liveEnabledPeerCount": len(live_enabled),
        "nearbyAgentCount": len(nearby),
        "knownAgents": known[:12],
        "liveEnabledPeers": live_enabled[:8],
        "nearbyAgents": nearby[:8],
        "conversation": {
            "visibleExecutorEnabled": True,
            "clientExecutor": "main3d.js#routeLiveModeSocialWorldAction",
            "actionType": "life.social",
            "loopActionId": "talk-with-nearby-agent",
            "status": "available" if nearby else "waiting_for_nearby_agent",
            "blockedReason": None if nearby else "no-nearby-visible-agent",
        },
    }


def _live_agent_loop_clamp_personality(raw):
    traits = {}
    source = raw if isinstance(raw, dict) else {}
    for trait in LIVE_AGENT_LOOP_PERSONALITY_TRAITS:
        try:
            value = float(source.get(trait, 1.0))
        except (TypeError, ValueError):
            value = 1.0
        traits[trait] = round(min(2.0, max(0.5, value)), 2)
    return traits


def _live_agent_loop_personality_multiplier(need_key, personality):
    multiplier = 1.0
    weights = LIVE_AGENT_LOOP_PERSONALITY_NEED_WEIGHTS.get(need_key) or {}
    traits = _live_agent_loop_clamp_personality(personality)
    for trait, weight in weights.items():
        multiplier += float(weight) * (float(traits.get(trait, 1.0)) - 1.0)
    return round(min(2.2, max(0.4, multiplier)), 3)


def _live_agent_loop_clean_profile_items(values, limit=6, item_limit=600):
    items = []
    for item in values if isinstance(values, list) else []:
        if isinstance(item, dict):
            clean = {}
            for key, value in list(item.items())[:12]:
                if isinstance(value, (str, int, float, bool)) or value is None:
                    clean[str(key)[:60]] = str(value or "").strip()[:item_limit] if isinstance(value, str) else value
            if clean:
                items.append(clean)
        else:
            text = str(item or "").strip()[:item_limit]
            if text:
                items.append(text)
    return items[-max(1, int(limit)):]


def _live_agent_loop_resident_profile(agent_id, *, persist=True):
    try:
        ok, result, _status = get_agent_resident_profile(agent_id, persist=persist)
    except Exception as exc:
        print(f"⚠️  Live Mode resident profile context unavailable for {agent_id}: {exc}")
        return None
    if not ok or not isinstance(result, dict):
        return None
    resident_profile = result.get("residentProfile")
    return resident_profile if isinstance(resident_profile, dict) else None


def _live_agent_loop_resident_memory_context(resident_profile):
    memory = resident_profile.get("memory") if isinstance(resident_profile, dict) and isinstance(resident_profile.get("memory"), dict) else {}
    relationships = []
    raw_relationships = memory.get("relationships") if isinstance(memory.get("relationships"), dict) else {}
    for key, value in list(raw_relationships.items())[-8:]:
        row = {"id": str(key or "")[:120], "source": "residentProfile"}
        if isinstance(value, dict):
            for field in ("otherAgentId", "summary", "score", "updatedAt", "lastOutcome", "lastActionId"):
                if value.get(field) is not None:
                    row[field] = value.get(field)
        elif value:
            row["summary"] = str(value)[:800]
        if row.get("id") or row.get("summary"):
            relationships.append(row)
    return {
        "summary": str(memory.get("summary") or "")[:1200],
        "shortTerm": _live_agent_loop_clean_profile_items(memory.get("shortTerm"), limit=6),
        "longTerm": _live_agent_loop_clean_profile_items(memory.get("longTerm"), limit=6),
        "reflections": _live_agent_loop_clean_profile_items(memory.get("reflections"), limit=6),
        "relationships": relationships,
    }


def _live_agent_loop_resident_profile_context(resident_profile):
    if not isinstance(resident_profile, dict):
        return None
    identity = resident_profile.get("identity") if isinstance(resident_profile.get("identity"), dict) else {}
    world = resident_profile.get("world") if isinstance(resident_profile.get("world"), dict) else {}
    goals = resident_profile.get("goals") if isinstance(resident_profile.get("goals"), dict) else {}
    live_mode = resident_profile.get("liveMode") if isinstance(resident_profile.get("liveMode"), dict) else {}
    needs = resident_profile.get("needs") if isinstance(resident_profile.get("needs"), dict) else {}
    return {
        "schemaVersion": resident_profile.get("schemaVersion") or RESIDENT_PROFILE_SCHEMA_VERSION,
        "identity": {
            "displayName": str(identity.get("displayName") or "")[:120],
            "role": str(identity.get("role") or "")[:160],
            "archetype": str(identity.get("archetype") or "")[:160],
            "lifePurpose": str(identity.get("lifePurpose") or "")[:1000],
            "backstory": str(identity.get("backstory") or "")[:1600],
        },
        "world": {
            "homeBuildingId": str(world.get("homeBuildingId") or "")[:120],
            "workBuildingId": str(world.get("workBuildingId") or "")[:120],
            "desk": _copy_jsonable(world.get("desk")) if isinstance(world.get("desk"), dict) else None,
        },
        "goals": {
            "current": _live_agent_loop_clean_profile_items(goals.get("current"), limit=6),
            "daily": _live_agent_loop_clean_profile_items(goals.get("daily"), limit=6),
            "longTerm": _live_agent_loop_clean_profile_items(goals.get("longTerm"), limit=6),
        },
        "needs": {
            key: _live_agent_loop_clamp_need(needs.get(key, default))
            for key, default in LIVE_AGENT_LOOP_NEED_DEFAULTS.items()
        },
        "personality": _live_agent_loop_clamp_personality(resident_profile.get("personality")),
        "preferences": _compact_json_value_for_storage(
            resident_profile.get("preferences") if isinstance(resident_profile.get("preferences"), dict) else {},
            max_depth=2,
            max_items=24,
            string_limit=600,
        ),
        "custom": _compact_json_value_for_storage(
            resident_profile.get("custom") if isinstance(resident_profile.get("custom"), dict) else {},
            max_depth=2,
            max_items=24,
            string_limit=600,
        ),
        "memory": _live_agent_loop_resident_memory_context(resident_profile),
        "liveMode": {
            "autonomyWhenIdle": bool(live_mode.get("autonomyWhenIdle", True)),
            "pauseForDirectChat": bool(live_mode.get("pauseForDirectChat", True)),
            "fallbackBehavior": str(live_mode.get("fallbackBehavior") or "scripted-idle")[:120],
        },
    }


def _live_agent_loop_profile_goal_text(goal):
    if isinstance(goal, dict):
        parts = []
        for key in ("title", "label", "text", "summary", "goal", "description", "name"):
            value = str(goal.get(key) or "").strip()
            if value:
                parts.append(value)
        if not parts:
            for value in goal.values():
                if isinstance(value, (str, int, float, bool)) and str(value).strip():
                    parts.append(str(value).strip())
        return " ".join(parts)[:500]
    return str(goal or "").strip()[:500]


def _live_agent_text_tokens(text):
    return [part for part in re.split(r"[^a-z0-9]+", str(text or "").lower()) if part]


def _live_agent_text_has_any(text, keywords):
    tokens = set(_live_agent_text_tokens(text))
    if not tokens:
        return False
    for keyword in keywords or ():
        raw = str(keyword or "").strip().lower()
        if not raw:
            continue
        keyword_tokens = _live_agent_text_tokens(raw)
        if not keyword_tokens:
            continue
        if len(keyword_tokens) == 1 and keyword_tokens[0] in tokens:
            return True
        if len(keyword_tokens) > 1 and all(token in tokens for token in keyword_tokens):
            return True
    return False


def _live_agent_loop_goal_intent(text):
    for intent, keywords in LIVE_AGENT_PROFILE_GOAL_INTENT_KEYWORDS.items():
        if _live_agent_text_has_any(text, keywords):
            return intent
    return "general"


def _live_agent_loop_profile_goal_intents(agent_id, resident_profile=None):
    """Collect the set of goal intents expressed by the agent's own Resident
    Profile goals. Dynamic object affordances are only offered when the agent's
    goals (or a recent model intention) actually ask for that category."""
    if resident_profile is None:
        resident_profile = _live_agent_loop_resident_profile(agent_id, persist=False)
    goals = (resident_profile or {}).get("goals") if isinstance(resident_profile, dict) else {}
    goals = goals if isinstance(goals, dict) else {}
    intents = set()
    for bucket in ("current", "daily", "longTerm"):
        for goal in goals.get(bucket) or []:
            text = _live_agent_loop_profile_goal_text(goal)
            if not text:
                continue
            intent = _live_agent_loop_goal_intent(text)
            if intent and intent != "general":
                intents.add(intent)
    return intents


def _live_agent_loop_requested_categories(agent_id, now_epoch=None):
    """Object categories the agent's model asked for recently via an intention
    reply. Valid for 10 minutes so a category the model wants stays offered."""
    now_epoch = float(now_epoch or time.time())
    with _live_agent_model_decision_lock:
        row = _live_agent_model_decision_state.get(agent_id) or {}
        requested = row.get("requestedCategories")
    if not isinstance(requested, dict):
        return set()
    return {
        category
        for category, at_epoch in requested.items()
        if isinstance(at_epoch, (int, float)) and (now_epoch - float(at_epoch)) < 600 and category in LIVE_AGENT_DYNAMIC_OBJECT_AFFORDANCES
    }


def _live_agent_loop_note_requested_category(agent_id, category, *, generation=None):
    resolved = LIVE_AGENT_INTENTION_CATEGORY_ALIASES.get(_normalize_token(category) or "")
    if not resolved or resolved not in LIVE_AGENT_DYNAMIC_OBJECT_AFFORDANCES:
        return None
    with _live_agent_model_decision_lock:
        row = _live_agent_model_decision_state.setdefault(agent_id, {})
        if generation is not None and int(row.get("generation") or 0) != int(generation):
            return None
        requested = row.setdefault("requestedCategories", {})
        requested[resolved] = time.time()
    return resolved


def _live_agent_loop_category_for_planner_action(action_token):
    """Map a planner-facing action token to its dynamic object category.

    Spatial perception exposes concrete object action types (for example
    ``life.restAtArmchair``), while the safe Live Agent execution surface uses
    a durable affordance id (``use-seating-object``). Keep that vocabulary
    bridge server-owned so planner turns survive restarts and catalog changes.
    """
    token = str(action_token or "").strip()
    normalized = _normalize_token(token)
    if not normalized:
        return None
    if normalized == _normalize_token("use-seating-object"):
        return "seating"
    if any(normalized == _normalize_token(action_type) for action_type in LIVE_AGENT_SEATING_ACTION_TYPES):
        return "seating"
    return None


def _live_agent_loop_planner_action_id(action_token, *, category=None):
    """Resolve action types/category aliases to the executable loop id."""
    token = str(action_token or "").strip()
    if not token:
        return ""
    normalized = _normalize_token(token)
    for action_def in LIVE_AGENT_LOOP_ACTIONS:
        if normalized in {
            _normalize_token(action_def.get("id")),
            _normalize_token(action_def.get("actionType")),
        }:
            return str(action_def.get("id") or token)
    resolved_category = LIVE_AGENT_INTENTION_CATEGORY_ALIASES.get(_normalize_token(category) or "")
    resolved_category = resolved_category or _live_agent_loop_category_for_planner_action(token)
    dynamic = LIVE_AGENT_DYNAMIC_OBJECT_AFFORDANCES.get(resolved_category) if resolved_category else None
    if isinstance(dynamic, dict) and dynamic.get("id"):
        return str(dynamic["id"])
    return token


def _live_agent_loop_normalize_planner_turn_actions(planner_turn):
    if not isinstance(planner_turn, dict):
        return planner_turn
    normalized = _copy_jsonable(planner_turn)
    task_lists = []
    if isinstance(normalized.get("tasks"), list):
        task_lists.append(normalized.get("tasks"))
    raw_goal = normalized.get("goal") if isinstance(normalized.get("goal"), dict) else {}
    if isinstance(raw_goal.get("tasks"), list):
        task_lists.append(raw_goal.get("tasks"))
    for tasks in task_lists:
        for task in tasks:
            if not isinstance(task, dict):
                continue
            for step in task.get("steps") or []:
                if not isinstance(step, dict):
                    continue
                requested = str(step.get("loopActionId") or step.get("action") or "").strip()
                resolved = _live_agent_loop_planner_action_id(requested, category=step.get("category"))
                if requested and resolved and resolved != requested:
                    step["requestedLoopActionId"] = requested
                    step["loopActionId"] = resolved
    next_step = normalized.get("nextStep") if isinstance(normalized.get("nextStep"), dict) else None
    if next_step:
        requested_action = str(next_step.get("action") or next_step.get("loopActionId") or "").strip()
        category = next_step.get("category")
        resolved_action = _live_agent_loop_planner_action_id(requested_action, category=category)
        if resolved_action and resolved_action != requested_action:
            next_step["requestedAction"] = requested_action
            next_step["action"] = resolved_action
            if not category:
                inferred_category = _live_agent_loop_category_for_planner_action(requested_action)
                if inferred_category:
                    next_step["category"] = inferred_category
    return normalized


def _live_agent_loop_durable_goal_object_categories(agent_state):
    """Recover dynamic categories from the persisted unfinished goal step."""
    if not isinstance(agent_state, dict):
        return set()
    goal = _live_agent_loop_active_durable_goal(agent_state)
    context = _live_agent_goals.current_context(goal) if goal else {}
    step = context.get("step") if isinstance(context, dict) else None
    if not isinstance(step, dict):
        return set()
    categories = set()
    action_category = _live_agent_loop_category_for_planner_action(step.get("loopActionId"))
    if action_category:
        categories.add(action_category)
    text = " ".join([
        str(step.get("title") or ""),
        " ".join(str(item) for item in (step.get("successCriteria") or [])),
        " ".join(str(item) for item in (step.get("failureCriteria") or [])),
    ])
    if _live_agent_text_has_any(text, ("seating", "seat", "chair", "armchair", "couch", "sofa", "bench", "stool")):
        categories.add("seating")
    return categories


def _live_agent_loop_dynamic_action_defs(agent_id, agent_state=None, resident_profile=None):
    """Resolve which dynamic object-category affordances are active for this
    agent right now. Sources: Resident Profile goal intents and recent model
    intention requests. This keeps the planner generic: categories appear
    because the agent wants them, not because they are hardcoded choices."""
    categories = set()
    for intent in _live_agent_loop_profile_goal_intents(agent_id, resident_profile):
        categories.update(LIVE_AGENT_GOAL_INTENT_OBJECT_CATEGORIES.get(intent) or ())
    categories.update(_live_agent_loop_durable_goal_object_categories(agent_state))
    categories.update(_live_agent_loop_requested_categories(agent_id))
    inventory = agent_state.get("inventory") if isinstance(agent_state, dict) and isinstance(agent_state.get("inventory"), dict) else {}
    if isinstance(inventory.get("held"), dict):
        categories.add("seating")
    defs = []
    for category in sorted(categories):
        action_def = LIVE_AGENT_DYNAMIC_OBJECT_AFFORDANCES.get(category)
        if isinstance(action_def, dict):
            defs.append(action_def)
    return defs


def _live_agent_loop_resident_profile_goal_boost(goal, affordance):
    text = " ".join(str(goal.get(key) or "") for key in ("id", "reason", "text", "need", "bucket"))
    if not text:
        return 0
    loop_action_id = affordance.get("id")
    intent = str(goal.get("intent") or _live_agent_loop_goal_intent(text))
    intent_boost = (LIVE_AGENT_GOAL_INTENT_ACTION_BOOSTS.get(intent) or {}).get(loop_action_id)
    try:
        priority = float(goal.get("priority") or 0.2)
    except (TypeError, ValueError):
        priority = 0.2
    if intent_boost:
        return round(min(0.92, max(0.08, intent_boost * max(0.55, priority))), 3)
    if loop_action_id == "work-on-active-goal":
        return round(min(0.46, max(0.12, priority * 0.46)), 3)
    need_key = str(affordance.get("need") or "").lower()
    label = str(affordance.get("label") or "").lower()
    keywords = set(LIVE_AGENT_PROFILE_ACTION_KEYWORDS.get(loop_action_id) or ())
    keywords.update(part for part in re.split(r"[^a-z0-9]+", label) if len(part) >= 4)
    if need_key:
        keywords.add(need_key)
    if not _live_agent_text_has_any(text, keywords):
        return 0
    return round(min(0.24, max(0.05, priority * 0.32)), 3)


def _live_agent_loop_agent_context(agent_id):
    meta = load_world_meta()
    aliases = _live_agent_loop_agent_aliases(agent_id)
    profile = {}
    profiles = meta.get("agentProfiles") if isinstance(meta.get("agentProfiles"), dict) else {}
    assignments = meta.get("agentAssignments") if isinstance(meta.get("agentAssignments"), dict) else {}
    assignment = {}
    roster_agent = None
    for alias in aliases:
        if not profile and isinstance(profiles.get(alias), dict):
            profile = profiles.get(alias) or {}
        if not assignment and isinstance(assignments.get(alias), dict):
            assignment = assignments.get(alias) or {}
    for agent in _merge_agent_profiles(get_roster()):
        if not isinstance(agent, dict):
            continue
        agent_aliases = {str(agent.get("id") or "").strip(), str(agent.get("statusKey") or "").strip()}
        if aliases.intersection(agent_aliases):
            roster_agent = agent
            if not profile and isinstance(agent.get("profile"), dict):
                profile = agent.get("profile") or {}
            break
    resident_profile = _live_agent_loop_resident_profile(agent_id, persist=True)
    resident_context = _live_agent_loop_resident_profile_context(resident_profile)
    resident_world = resident_context.get("world") if isinstance(resident_context, dict) and isinstance(resident_context.get("world"), dict) else {}
    home = _live_agent_loop_existing_home_for_agent(agent_id)
    if not home and resident_world.get("homeBuildingId"):
        home = load_building(resident_world.get("homeBuildingId"))
    work_id = assignment.get("work") or resident_world.get("workBuildingId") or (roster_agent or {}).get("workBuilding")
    work = load_building(work_id) if work_id else None
    relationship_store = meta.get("agentRelationships") if isinstance(meta.get("agentRelationships"), dict) else {}
    relationships = []
    for key, value in relationship_store.items():
        if not isinstance(value, dict):
            continue
        key_text = str(key or "")
        if agent_id not in key_text and not any(alias and alias in key_text for alias in aliases):
            continue
        relationships.append({"id": key, **{k: value.get(k) for k in ("agentId", "otherAgentId", "summary", "score", "updatedAt") if k in value}})
    relationships = relationships[-6:]
    resident_memory = resident_context.get("memory") if isinstance(resident_context, dict) and isinstance(resident_context.get("memory"), dict) else {}
    relationship_ids = {item.get("id") for item in relationships if isinstance(item, dict)}
    for item in resident_memory.get("relationships") or []:
        if not isinstance(item, dict):
            continue
        rel_id = item.get("id")
        if rel_id and rel_id in relationship_ids:
            continue
        relationships.append(item)
        if rel_id:
            relationship_ids.add(rel_id)
    relationships = relationships[-8:]
    known_agents = [
        {
            "agentId": item.get("statusKey") or item.get("id"),
            "name": item.get("name"),
            "liveModeEnabled": bool(_agent_live_mode_enabled_from_profile((profiles.get(item.get("statusKey")) or profiles.get(item.get("id")) or {}) if isinstance(item, dict) else {})),
        }
        for item in _merge_agent_profiles(get_roster())
        if isinstance(item, dict) and (item.get("statusKey") or item.get("id")) not in aliases
    ]
    return {
        "schemaVersion": "agent-live-mode-agent-context/v1",
        # A Resident Profile is always materialized before Live Mode runs. Do
        # not fall back to a framework/roster persona when a world profile is
        # incomplete: neutral resident defaults are the only safe fallback.
        "personality": _live_agent_loop_clamp_personality((resident_context or {}).get("personality")),
        "home": {"exists": bool(home), "buildingId": (home or {}).get("id"), "name": (home or {}).get("name"), "type": (home or {}).get("type")},
        "work": {"exists": bool(work), "buildingId": (work or {}).get("id"), "name": (work or {}).get("name"), "type": (work or {}).get("type")},
        "relationships": relationships,
        "knownAgents": known_agents[:12],
        "residentProfile": resident_context,
        "docs": {k: profile.get("docs", {}).get(k) for k in ("reviewSummary", "maintenanceNotes", "carePlan") if isinstance(profile.get("docs"), dict) and profile.get("docs", {}).get(k)},
    }


def _live_agent_loop_recent_world_actions(agent_id, limit=8):
    store = get_world_actions_store(persist_migration=True)
    rows = []
    for bucket in ("active", "history"):
        for action in store.get(bucket, []):
            if not isinstance(action, dict) or action.get("agentId") != agent_id:
                continue
            timing = action.get("timing") if isinstance(action.get("timing"), dict) else {}
            params = action.get("params") if isinstance(action.get("params"), dict) else {}
            rows.append({
                "id": action.get("id"),
                "bucket": bucket,
                "status": _canonical_world_action_status(action.get("status")),
                "actionType": action.get("actionType"),
                "loopActionId": params.get("loopActionId"),
                "updatedAt": timing.get("updatedAt"),
                "terminalAt": timing.get("terminalAt"),
            })
    rows.sort(key=lambda row: row.get("terminalAt") or row.get("updatedAt") or "", reverse=True)
    return rows[:max(1, int(limit))]


def _live_agent_loop_memory_target(target):
    if not isinstance(target, dict):
        return None
    out = {}
    for key in ("kind", "buildingId", "catalogId", "objectInstanceId", "targetAgentId", "siteKind"):
        value = target.get(key)
        if value is not None and str(value).strip():
            out[key] = str(value)[:180]
    for key in ("x", "y", "z", "floor"):
        value = target.get(key)
        if isinstance(value, (int, float)):
            out[key] = round(float(value), 2)
    build_site = target.get("buildSite") if isinstance(target.get("buildSite"), dict) else {}
    if build_site:
        out["buildSite"] = {
            key: build_site.get(key)
            for key in ("buildingId", "buildingName", "siteKind", "worldX", "worldY", "widthTiles", "heightTiles")
            if build_site.get(key) is not None
        }
    return out or None


def _live_agent_loop_target_key(target):
    target = target if isinstance(target, dict) else {}
    if not target:
        return ""
    target_agent = str(target.get("targetAgentId") or "").strip()
    if target_agent:
        return f"agent:{target_agent}"
    building_id = str(target.get("buildingId") or "").strip()
    object_id = str(target.get("objectInstanceId") or target.get("catalogId") or "").strip()
    if building_id and object_id:
        return f"object:{building_id}:{object_id}"
    if building_id:
        return f"building:{building_id}"
    kind = str(target.get("kind") or target.get("siteKind") or "target").strip()
    x, y = target.get("x"), target.get("y")
    if isinstance(x, (int, float)) and isinstance(y, (int, float)):
        return f"{kind}:x={round(float(x), 1)}:y={round(float(y), 1)}"
    build_site = target.get("buildSite") if isinstance(target.get("buildSite"), dict) else {}
    build_id = str(build_site.get("buildingId") or "").strip()
    if build_id:
        return f"build-site:{build_id}"
    return ""


def _live_agent_loop_target_keys_compatible(left, right):
    left = str(left or "").strip()
    right = str(right or "").strip()
    if not left or not right:
        return True
    if left == right:
        return True
    for agent_key, legacy_key in ((left, right), (right, left)):
        if agent_key.startswith("agent:") and legacy_key.startswith("object:") and legacy_key.endswith(":agent"):
            return True
    for building_key, object_key in ((left, right), (right, left)):
        if not building_key.startswith("building:") or not object_key.startswith("object:"):
            continue
        building_id = building_key.split(":", 1)[1]
        if object_key == f"object:{building_id}:building":
            return True
    return False


def _live_agent_loop_target_phrase(target):
    target = target if isinstance(target, dict) else {}
    if not target:
        return ""
    kind = target.get("kind") or target.get("siteKind") or "target"
    x, y = target.get("x"), target.get("y")
    if isinstance(x, (int, float)) and isinstance(y, (int, float)):
        return f"{kind} at ({round(float(x), 2)}, {round(float(y), 2)})"
    if target.get("buildingId"):
        label = target.get("catalogId") or target.get("objectInstanceId") or kind
        return f"{label} in building {target.get('buildingId')}"
    if isinstance(target.get("buildSite"), dict):
        site = target["buildSite"]
        return f"{site.get('buildingName') or site.get('buildingId') or kind} build site"
    return str(kind)


def _live_agent_loop_failure_learning(action, summary):
    if not isinstance(summary, dict):
        return None
    status = _canonical_world_action_status(summary.get("status"))
    if status not in {"failed", "expired", "cancelled"}:
        return None
    result = summary.get("result") if isinstance(summary.get("result"), dict) else {}
    watchdog = result.get("watchdog") if isinstance(result.get("watchdog"), dict) else {}
    target = None
    if watchdog.get("target"):
        target = _live_agent_loop_memory_target(watchdog.get("target"))
    if not target and isinstance(action, dict):
        target = _live_agent_loop_memory_target(action.get("target"))
    target_key = _live_agent_loop_target_key(target)
    result_reason = str(result.get("reason") or "").strip()
    failure_reason = str(summary.get("failureReason") or "").strip()
    reason = result_reason or failure_reason or status
    user_control_cancel = _live_agent_loop_is_user_control_cancel(status, reason)
    benign_system_cancel = _live_agent_loop_is_benign_system_cancel(status, reason)
    retryable_world_failure = (
        _live_agent_loop_is_retryable_world_failure(status, reason)
        or _live_agent_loop_is_retryable_world_failure(status, failure_reason)
    )
    evidence = {}
    if watchdog:
        for key in ("distance", "improvement", "windowSec", "samples"):
            if watchdog.get(key) is not None:
                evidence[key] = watchdog.get(key)
        if isinstance(watchdog.get("position"), dict):
            evidence["position"] = _live_agent_loop_memory_target(watchdog.get("position"))
    pieces = []
    if reason:
        pieces.append(f"reason {reason}")
    target_phrase = _live_agent_loop_target_phrase(target)
    if target_phrase:
        pieces.append(f"target {target_phrase}")
    if evidence:
        metrics = []
        if evidence.get("distance") is not None:
            metrics.append(f"distance {evidence.get('distance')}")
        if evidence.get("improvement") is not None:
            metrics.append(f"improvement {evidence.get('improvement')}")
        if evidence.get("windowSec") is not None:
            metrics.append(f"over {evidence.get('windowSec')}s")
        if metrics:
            pieces.append("watchdog " + ", ".join(str(item) for item in metrics))
    learning_text = "; ".join(pieces)
    if user_control_cancel:
        learning_text = "The activity was superseded by direct user control; this is not evidence that the route, target, or interaction failed."
    elif learning_text:
        learning_text = f"{learning_text}; avoid retrying the same target unless the route, target, or conditions change."
    else:
        learning_text = "failed without useful details; avoid repeating the same action until conditions change."
    return {
        "status": status,
        "reason": reason,
        "failureReason": failure_reason,
        "resultReason": result_reason,
        "reportable": not (benign_system_cancel or user_control_cancel or retryable_world_failure),
        "benignSystemCancel": benign_system_cancel,
        "retryableWorldFailure": retryable_world_failure,
        "userControlCancel": user_control_cancel,
        "superseded": user_control_cancel,
        "target": target,
        "targetKey": target_key,
        "evidence": evidence,
        "learningText": learning_text[:700],
    }


def _live_agent_loop_recent_outcome_summary(agent_state, perception=None, limit=12):
    memory = agent_state.get("memory") if isinstance(agent_state.get("memory"), dict) else {}
    records = _live_agent_loop_trim_list(memory.get("recentActions"), limit)
    by_action = {}
    last_failure_by_action = {}
    for item in records:
        loop_id = item.get("loopActionId")
        status = _canonical_world_action_status(item.get("status"))
        if not loop_id or not status:
            continue
        bucket = by_action.setdefault(loop_id, {"completed": 0, "failed": 0, "expired": 0, "cancelled": 0, "superseded": 0, "recentStatuses": [], "targetFailures": {}})
        bucket["recentStatuses"].append(status)
        failure = item.get("failure") if isinstance(item.get("failure"), dict) else {}
        user_control_cancel = status == "cancelled" and failure.get("userControlCancel") is True
        if status == "completed":
            bucket["completed"] += 1
        elif user_control_cancel:
            bucket["superseded"] += 1
        elif status in {"failed", "expired", "cancelled"}:
            bucket[status] += 1
            last_failure_by_action[loop_id] = item
            target_key = item.get("targetKey") or ((item.get("failure") if isinstance(item.get("failure"), dict) else {}) or {}).get("targetKey")
            if target_key:
                target_bucket = bucket["targetFailures"].setdefault(target_key, {"failed": 0, "expired": 0, "cancelled": 0, "total": 0, "reasons": {}})
                target_bucket[status] = int(target_bucket.get(status) or 0) + 1
                target_bucket["total"] = int(target_bucket.get("total") or 0) + 1
                reason_key = _normalize_token(
                    failure.get("reason")
                    or failure.get("failureReason")
                    or item.get("failureReason")
                    or item.get("resultReason")
                    or status
                ) or status
                reasons = target_bucket.get("reasons") if isinstance(target_bucket.get("reasons"), dict) else {}
                reasons[reason_key] = int(reasons.get(reason_key) or 0) + 1
                target_bucket["reasons"] = reasons
    for loop_id, bucket in by_action.items():
        streak = 0
        for item in reversed(records):
            if item.get("loopActionId") != loop_id:
                continue
            status = _canonical_world_action_status(item.get("status"))
            failure = item.get("failure") if isinstance(item.get("failure"), dict) else {}
            if status == "cancelled" and failure.get("userControlCancel") is True:
                break
            if status in {"failed", "expired", "cancelled"}:
                streak += 1
                continue
            break
        bucket["recentFailureStreak"] = streak
    issues = []
    for loop_id, bucket in by_action.items():
        failures = int(bucket.get("failed") or 0) + int(bucket.get("expired") or 0) + int(bucket.get("cancelled") or 0)
        if failures <= 0 or int(bucket.get("recentFailureStreak") or 0) <= 0:
            continue
        failed_item = last_failure_by_action.get(loop_id) or {}
        failure = failed_item.get("failure") if isinstance(failed_item.get("failure"), dict) else {}
        reportable_failure = failure.get("reportable") is not False
        reason = (
            failure.get("learningText")
            or failed_item.get("failureReason")
            or failed_item.get("resultReason")
            or failed_item.get("status")
            or "recent action did not complete"
        )
        target_key = failed_item.get("targetKey") or failure.get("targetKey") or _live_agent_loop_target_key(failed_item.get("target"))
        target_failure_bucket = (bucket.get("targetFailures") or {}).get(target_key) if target_key and isinstance(bucket.get("targetFailures"), dict) else None
        reason_key = _normalize_token(
            failure.get("reason")
            or failure.get("failureReason")
            or failed_item.get("failureReason")
            or failed_item.get("resultReason")
            or failed_item.get("status")
        ) or "failure"
        matching_failure_count = int(((target_failure_bucket or {}).get("reasons") or {}).get(reason_key) or 0)
        if not reportable_failure and matching_failure_count < 2:
            # A retryable route/world interruption is operational evidence, not
            # a product defect. Escalate only after the same action, target, and
            # grounded reason recur; failures at other targets cannot promote it.
            continue
        issue_seed = f"{loop_id}:{target_key or ''}:{reason}"
        issues.append({
            "id": f"issue.{loop_id}.{hashlib.sha1(issue_seed.encode('utf-8')).hexdigest()[:8]}",
            "loopActionId": loop_id,
            "status": "unresolved",
            "failures": failures,
            "failureStreak": int(bucket.get("recentFailureStreak") or 0),
            "matchingTargetFailureCount": matching_failure_count,
            "targetKey": target_key,
            "priority": round(min(0.95, LIVE_AGENT_ISSUE_PRIORITY + min(0.06, failures * 0.02)), 3),
            "reason": str(reason)[:520],
        })
    issues.sort(key=lambda item: (float(item.get("priority") or 0), int(item.get("failureStreak") or 0)), reverse=True)
    recent_world = perception.get("recentWorldActions") if isinstance(perception, dict) else []
    return {
        "window": len(records),
        "byAction": by_action,
        "issues": issues[:6],
        "lastLoopActionIds": [item.get("loopActionId") for item in records[-6:] if item.get("loopActionId")],
        "recentWorldActionIds": [item.get("id") for item in (recent_world or [])[:6] if isinstance(item, dict) and item.get("id")],
    }


def _live_agent_loop_recent_episode_summary(agent_state, limit=6):
    episodes = []
    for item in agent_state.get("episodes") or []:
        episode = _live_agent_loop_normalize_episode(item)
        if episode:
            episodes.append(episode)
    active = _live_agent_loop_normalize_episode(agent_state.get("activeEpisode"))
    if active and all(active.get("id") != item.get("id") for item in episodes):
        episodes.append(active)
    episodes.sort(key=lambda item: _parse_isoish_epoch(item.get("updatedAt")) or 0, reverse=True)
    summaries = []
    for episode in episodes[:max(1, int(limit))]:
        verification = episode.get("verification") if isinstance(episode.get("verification"), dict) else {}
        summaries.append({
            "id": episode.get("id"),
            "status": episode.get("status"),
            "phase": episode.get("phase"),
            "planId": episode.get("planId"),
            "loopActionId": episode.get("loopActionId"),
            "actionId": episode.get("actionId"),
            "issueId": episode.get("issueId"),
            "title": episode.get("title"),
            "targetKey": episode.get("targetKey"),
            "verificationOk": verification.get("ok") if verification else None,
            "verificationReason": verification.get("reason") if verification else "",
            "reportedAt": episode.get("reportedAt"),
            "coderResponseCount": len(episode.get("coderResponses") or []),
            "lastCoderResponse": (episode.get("coderResponses") or [{}])[-1].get("text") if episode.get("coderResponses") else "",
            "operatorSummary": episode.get("operatorSummary"),
            "updatedAt": episode.get("updatedAt"),
        })
    return summaries


def _live_agent_loop_verified_episode_counts(agent_state, *, loop_action_id=None, target_key=None, limit=12):
    counts = {"sameAction": 0, "sameTarget": 0}
    if not isinstance(agent_state, dict):
        return counts
    episodes = []
    for item in agent_state.get("episodes") or []:
        episode = _live_agent_loop_normalize_episode(item)
        if episode:
            episodes.append(episode)
    active = _live_agent_loop_normalize_episode(agent_state.get("activeEpisode"))
    if active and all(active.get("id") != item.get("id") for item in episodes):
        episodes.append(active)
    episodes.sort(key=lambda item: _parse_isoish_epoch(item.get("updatedAt")) or 0, reverse=True)
    for episode in episodes[:max(1, int(limit))]:
        verification = episode.get("verification") if isinstance(episode.get("verification"), dict) else {}
        verified = episode.get("status") == "completed" and verification.get("ok") is True
        if not verified:
            continue
        if loop_action_id and episode.get("loopActionId") == loop_action_id:
            counts["sameAction"] += 1
        if target_key and episode.get("targetKey") == target_key:
            counts["sameTarget"] += 1
    return counts


def _live_agent_loop_is_success_status_update(text):
    value = str(text or "").lower()
    if not value:
        return False
    success_terms = (
        "completed successfully",
        "completed cleanly",
        "verified successfully",
        "verified completion",
        "has been verified",
        "was verified",
        "success report",
        "successful interaction",
    )
    progress_terms = (
        "avoid repeating",
        "do not repeat",
        "do not retest",
        "ready to continue",
        "continue testing",
        "future loops can advance",
        "next object",
        "advance to",
    )
    if not any(term in value for term in success_terms):
        return False
    if not any(term in value for term in progress_terms):
        return False
    active_problem_patterns = (
        r"\b(?:but|however|still|currently)\b.{0,90}\b(?:fail|failed|failure|error|blocked|blocker|stuck|unable|cannot|can't|broken|bug|fix|mismatch|problem|issue)\b",
        r"\b(?:needs?|requires?)\b.{0,50}\b(?:coder|developer|fix|investigation|help)\b",
    )
    return not any(re.search(pattern, value) for pattern in active_problem_patterns)


def _live_agent_loop_support_request_kind(text):
    value = str(text or "").lower()
    if not value:
        return ""
    if _live_agent_loop_is_success_status_update(value):
        return ""
    report_patterns = (
        r"\b(report|tell|message|handoff|communicat(?:e|ion)?|notify|send|ask|contact|alert|escalate|file)\b.{0,80}\b(coder|developer)\b",
        r"\b(coder|developer)\b.{0,80}\b(help request|needs? help|assistance needed|action needed|please investigate|please fix)\b",
        r"\b(file|open|create|make|send|submit|write)\b.{0,30}\b(field report|support request)\b",
        r"\b(report issue|escalate (?:this |the )?issue)\b",
    )
    if any(re.search(pattern, value) for pattern in report_patterns):
        return "coder-report"
    anti_note_patterns = (
        r"\b(?:do not|don't|avoid|stop|instead of|rather than|not)\b.{0,80}\b(?:write|record|log|make|save)\b.{0,40}\bnotes?\b",
        r"\b(?:do not|don't|avoid|stop|instead of|rather than|not)\b.{0,80}\b(?:recording|logging|writing|saving)\b.{0,40}\bnotes?\b",
    )
    if any(re.search(pattern, value) for pattern in anti_note_patterns):
        return ""
    note_patterns = (
        r"\binternal note\b",
        r"\b(write down|record|log|journal|remember|save|preserve)\b.{0,100}\b(plan|lesson|note|blocker|concern|issue|memory|finding|observation)\b",
        r"\b(write down|record|log|journal)\b.{0,80}\b(?:the|this|a|an)?\s*(blocker|concern|issue|lesson|plan|finding|observation)\b",
    )
    if any(re.search(pattern, value) for pattern in note_patterns):
        return "internal-note"
    return ""


def _live_agent_loop_support_request_issue_id(request):
    if not isinstance(request, dict):
        return ""
    explicit = str(request.get("issueId") or "").strip()
    if explicit:
        return explicit[:160]
    text = str(request.get("text") or "").strip()
    if not text:
        return ""
    return f"support.{hashlib.sha1(text.encode('utf-8', errors='ignore')).hexdigest()[:8]}"


def _live_agent_loop_support_request_id(kind, text, *, issue_id=None):
    clean_kind = str(kind or "").strip()[:80]
    clean_text = _live_agent_loop_clean_plan_text(text, limit=500) or ""
    clean_issue = str(issue_id or "").strip()[:160]
    basis = json.dumps({"kind": clean_kind, "text": clean_text, "issueId": clean_issue}, sort_keys=True, default=str)
    return "support-request-" + hashlib.sha1(basis.encode("utf-8", errors="ignore")).hexdigest()[:16]


def _live_agent_loop_add_support_request(agent_state, kind, text, *, source="", issue_id=None, evidence_context=None):
    if not isinstance(agent_state, dict):
        return None
    kind = str(kind or "").strip()[:80]
    text = _live_agent_loop_clean_plan_text(text, limit=500)
    if kind not in {"coder-report", "internal-note"} or not text:
        return None
    request = {
        "id": _live_agent_loop_support_request_id(kind, text, issue_id=issue_id),
        "at": _utc_now_iso(),
        "kind": kind,
        "text": text,
        "source": str(source or "live-agent-mode")[:120],
    }
    if issue_id:
        request["issueId"] = str(issue_id)[:160]
    elif kind == "coder-report":
        request["issueId"] = _live_agent_loop_support_request_issue_id(request)
    evidence_context = evidence_context if isinstance(evidence_context, dict) else {}
    if evidence_context:
        request["evidenceKind"] = str(evidence_context.get("kind") or "")[:80]
        request["evidenceIssueId"] = str(evidence_context.get("issueId") or request.get("issueId") or "")[:160]
        request["evidenceSummary"] = _live_agent_loop_clean_plan_text(evidence_context.get("summary"), limit=500)
    existing = [
        item for item in (agent_state.get("supportRequests") or [])
        if isinstance(item, dict) and not (
            (item.get("id") and item.get("id") == request["id"])
            or (
                item.get("kind") == request["kind"]
                and str(item.get("text") or "")[:180] == request["text"][:180]
            )
        )
    ]
    agent_state["supportRequests"] = [*existing, request][-12:]
    return request


def _live_agent_loop_complete_support_request(agent_state, support_context, outcome, now_iso):
    if not isinstance(agent_state, dict) or not isinstance(outcome, dict) or outcome.get("ok") is not True:
        return None
    support_context = support_context if isinstance(support_context, dict) else {}
    request = support_context.get("supportRequest") if isinstance(support_context.get("supportRequest"), dict) else {}
    expected_kind = request.get("kind")
    if not expected_kind:
        expected_kind = "coder-report" if outcome.get("supportTool") == "coder-report" else "internal-note" if outcome.get("supportTool") == "internal-note" else ""
    expected_issue_id = (
        str(outcome.get("issueId") or "").strip()
        or str(support_context.get("issueId") or "").strip()
        or _live_agent_loop_support_request_issue_id(request)
    )
    expected_id = (
        str(outcome.get("supportRequestId") or "").strip()
        or str(support_context.get("supportRequestId") or "").strip()
        or str(request.get("id") or "").strip()
    )
    expected_text = str(request.get("text") or support_context.get("summary") or "").strip()
    remaining = []
    consumed = None
    for item in agent_state.get("supportRequests") or []:
        if not isinstance(item, dict):
            continue
        item_kind = str(item.get("kind") or "").strip()
        item_text = str(item.get("text") or "").strip()
        item_issue_id = _live_agent_loop_support_request_issue_id(item)
        item_id = str(item.get("id") or "").strip() or _live_agent_loop_support_request_id(item_kind, item_text, issue_id=item_issue_id)
        match = False
        if expected_id and item_id == expected_id:
            match = True
        elif expected_issue_id and item_issue_id == expected_issue_id and item_kind == expected_kind:
            match = True
        elif expected_text and item_kind == expected_kind and item_text[:180] == expected_text[:180]:
            match = True
        if match and consumed is None:
            consumed = {**item, "id": item_id, "issueId": item_issue_id, "handledAt": now_iso, "handledByActionId": outcome.get("id")}
            continue
        remaining.append(item)
    if consumed:
        agent_state["supportRequests"] = remaining[-12:]
        outcome["consumedSupportRequestId"] = consumed.get("id")
        outcome["consumedSupportRequest"] = {
            "id": consumed.get("id"),
            "kind": consumed.get("kind"),
            "issueId": consumed.get("issueId"),
            "handledAt": consumed.get("handledAt"),
        }
    return consumed


def _live_agent_loop_note_planner_support_requests(agent_state, planner_turn, model_detail=None):
    if not isinstance(agent_state, dict) or not isinstance(planner_turn, dict):
        return []
    added = []
    chunks = []
    chunks.extend(planner_turn.get("toolRequests") or [])
    chunks.extend(planner_turn.get("eventRequests") or [])
    next_step = planner_turn.get("nextStep") if isinstance(planner_turn.get("nextStep"), dict) else {}
    for key in ("intent", "targetCriteria", "successCriteria", "failureCriteria"):
        if next_step.get(key):
            chunks.append(next_step.get(key))
    memory_update = planner_turn.get("memoryUpdate") if isinstance(planner_turn.get("memoryUpdate"), dict) else {}
    for key in ("lesson", "text", "note"):
        if memory_update.get(key):
            chunks.append(memory_update.get(key))
    chunks_by_kind = {"coder-report": [], "internal-note": []}
    for chunk in chunks:
        kind = _live_agent_loop_support_request_kind(chunk)
        if not kind:
            continue
        text = _live_agent_loop_clean_plan_text(chunk, limit=260)
        if text and text not in chunks_by_kind[kind]:
            chunks_by_kind[kind].append(text)
    for kind, values in chunks_by_kind.items():
        if not values:
            continue
        chunk = " | ".join(values)[:500]
        evidence_context = None
        issue_id = None
        if kind == "coder-report":
            # A model statement is not evidence that the product is broken.
            # Reports are admitted only when the world has already recorded a
            # failed verification, repeated physical failure, or critical
            # unmet need. This prevents temporary state constraints (for
            # example, hiding getCoffee while already carrying coffee) from
            # becoming fabricated engineering incidents.
            evidence_context = _live_agent_loop_report_evidence_context(
                (model_detail or {}).get("agentId"),
                agent_state,
            )
            if not evidence_context:
                continue
            issue_id = evidence_context.get("issueId")
        request = _live_agent_loop_add_support_request(
            agent_state,
            kind,
            chunk,
            source=(model_detail or {}).get("status") or LIVE_AGENT_LOOP_MODEL_DECISION_MODE,
            issue_id=issue_id,
            evidence_context=evidence_context,
        )
        if request:
            added.append(request)
    return added


def _live_agent_loop_recent_support_report(agent_state, issue_id):
    issue_id = str(issue_id or "").strip()
    if not issue_id:
        return None
    now_epoch = time.time()
    for item in reversed(agent_state.get("supportOutcomes") or []):
        if not isinstance(item, dict):
            continue
        if item.get("loopActionId") != "report-issue-to-coder":
            continue
        if str(item.get("issueId") or "") != issue_id:
            continue
        at_epoch = _parse_isoish_epoch(item.get("at")) or 0
        if at_epoch and now_epoch - at_epoch <= LIVE_AGENT_SUPPORT_REPORT_COOLDOWN_SEC:
            return item
    return None


def _live_agent_loop_note_matches_kind(note, kind):
    if not isinstance(note, dict) or not kind:
        return False
    if str(note.get("type") or "") == kind:
        return True
    details = note.get("details") if isinstance(note.get("details"), dict) else {}
    support_context = details.get("supportContext") if isinstance(details.get("supportContext"), dict) else {}
    return str(support_context.get("kind") or "") == kind


def _live_agent_loop_recent_internal_note_of_kind(agent_id, agent_state, kind, *, window_sec=None, now_epoch=None):
    kind = str(kind or "").strip()
    if not kind:
        return None
    try:
        window = float(window_sec) if window_sec is not None else 0
    except (TypeError, ValueError):
        window = 0
    now_epoch = float(now_epoch or time.time())
    notes = []
    memory = agent_state.get("memory") if isinstance(agent_state, dict) and isinstance(agent_state.get("memory"), dict) else {}
    notes.extend(item for item in (memory.get("internalNotes") or []) if isinstance(item, dict))
    notes.extend(_live_agent_loop_recent_internal_notes(agent_id, limit=12))
    notes.sort(key=lambda item: _parse_isoish_epoch(item.get("createdAt") or item.get("at") or item.get("updatedAt")) or 0, reverse=True)
    seen = set()
    for note in notes:
        note_id = str(note.get("id") or "")
        if note_id and note_id in seen:
            continue
        if note_id:
            seen.add(note_id)
        if not _live_agent_loop_note_matches_kind(note, kind):
            continue
        at_epoch = _parse_isoish_epoch(note.get("createdAt") or note.get("at") or note.get("updatedAt")) or 0
        if window > 0 and at_epoch and now_epoch - at_epoch > window:
            continue
        return note
    return None


def _live_agent_loop_successful_support_outcome_after(agent_state, support_tool, at_epoch):
    if not isinstance(agent_state, dict) or not support_tool:
        return None
    try:
        request_epoch = float(at_epoch or 0)
    except (TypeError, ValueError):
        request_epoch = 0
    for item in reversed(agent_state.get("supportOutcomes") or []):
        if not isinstance(item, dict):
            continue
        if item.get("supportTool") != support_tool or item.get("ok") is not True:
            continue
        outcome_epoch = _parse_isoish_epoch(item.get("at")) or 0
        if outcome_epoch and outcome_epoch >= request_epoch:
            return item
    return None


def _live_agent_loop_report_evidence_context(agent_id, agent_state):
    """Return only world-backed reasons that justify an engineering report."""
    recent_episodes = _live_agent_loop_recent_episode_summary(agent_state, limit=8)
    for episode in reversed(recent_episodes):
        if episode.get("status") != "awaiting_report" or not episode.get("issueId"):
            continue
        if _live_agent_loop_recent_support_report(agent_state, episode.get("issueId")):
            continue
        return {
            "kind": "verification-issue",
            "issueId": episode.get("issueId"),
            "summary": episode.get("verificationReason") or episode.get("operatorSummary") or "Live Agent verification failed.",
            "episode": episode,
        }
    recent = _live_agent_loop_recent_outcome_summary(agent_state)
    for issue in recent.get("issues") or []:
        if not isinstance(issue, dict):
            continue
        # A verification episode and the aggregate failure-streak view can
        # describe the same failed physical action with different issue IDs.
        # Once that episode is in the report/Coder workflow, do not emit a
        # second field report for the aggregate alias.
        covered_by_episode = any(
            episode.get("loopActionId") == issue.get("loopActionId")
            and _live_agent_loop_target_keys_compatible(episode.get("targetKey"), issue.get("targetKey"))
            and episode.get("status") in {"awaiting_report", "awaiting_coder", "reported", "coder_responded"}
            for episode in recent_episodes
        )
        if covered_by_episode:
            continue
        issue_id = issue.get("id") or f"issue.{issue.get('loopActionId')}"
        if _live_agent_loop_recent_support_report(agent_state, issue_id):
            continue
        return {
            "kind": "recent-issue",
            "issueId": issue_id,
            "summary": issue.get("reason") or "Recent Live Agent action did not complete.",
            "issue": issue,
        }
    needs = agent_state.get("needs") if isinstance(agent_state.get("needs"), dict) else {}
    try:
        shelter_value = float(needs.get("shelter") or 0)
    except (TypeError, ValueError):
        shelter_value = 0
    if shelter_value >= LIVE_AGENT_CRITICAL_NEED_THRESHOLD and agent_id and not _live_agent_loop_existing_home_for_agent(agent_id):
        issue_id = f"need.shelter.{agent_id}"
        if not _live_agent_loop_recent_support_report(agent_state, issue_id):
            return {
                "kind": "critical-need",
                "issueId": issue_id,
                "summary": f"shelter need is critical ({round(shelter_value, 3)}) and no owned home exists yet",
                "need": {"id": "shelter", "value": round(shelter_value, 3)},
            }
    return None


def _live_agent_loop_report_context(agent_id, agent_state):
    evidence_context = _live_agent_loop_report_evidence_context(agent_id, agent_state)
    if evidence_context:
        return evidence_context
    for request in reversed(agent_state.get("supportRequests") or []):
        if not isinstance(request, dict) or request.get("kind") != "coder-report":
            continue
        # Planner prose alone must never manufacture a product incident.
        # Requests created under the evidence gate carry this marker; legacy
        # ungrounded requests are intentionally ignored.
        if not request.get("evidenceKind"):
            continue
        issue_id = _live_agent_loop_support_request_issue_id(request)
        if _live_agent_loop_recent_support_report(agent_state, issue_id):
            continue
        return {
            "kind": "support-request",
            "issueId": issue_id,
            "summary": request.get("text"),
            "supportRequestId": request.get("id") or _live_agent_loop_support_request_id(request.get("kind"), request.get("text"), issue_id=issue_id),
            "supportRequest": request,
        }
    return None


def _live_agent_loop_note_context(agent_id, agent_state):
    for request in reversed(agent_state.get("supportRequests") or []):
        if isinstance(request, dict) and request.get("kind") == "internal-note" and request.get("text"):
            return {
                "kind": "support-request",
                "summary": request.get("text"),
                "supportRequestId": request.get("id") or _live_agent_loop_support_request_id(request.get("kind"), request.get("text"), issue_id=request.get("issueId")),
                "supportRequest": request,
            }
    durable_goal = _live_agent_loop_active_durable_goal(agent_state)
    if durable_goal:
        durable_context = _live_agent_goals.current_context(durable_goal)
        task = durable_context.get("task") or {}
        step = durable_context.get("step") or {}
        pieces = [
            durable_goal.get("title"),
            durable_goal.get("operatorSummary"),
            durable_goal.get("replanReason"),
            task.get("title"),
            step.get("title"),
            *list(step.get("successCriteria") or []),
        ]
        text = " ".join(str(item) for item in pieces if item)
        recent_durable_note = _live_agent_loop_recent_internal_note_of_kind(
            agent_id,
            agent_state,
            "durable-goal",
            window_sec=LIVE_AGENT_AUTONOMY_PLAN_NOTE_COOLDOWN_SEC,
        )
        recent_legacy_plan_note = _live_agent_loop_recent_internal_note_of_kind(
            agent_id,
            agent_state,
            "autonomy-plan",
            window_sec=LIVE_AGENT_AUTONOMY_PLAN_NOTE_COOLDOWN_SEC,
        )
        if text and not recent_durable_note and not recent_legacy_plan_note:
            return {
                "kind": "durable-goal",
                "summary": text[:700],
                "goalId": durable_goal.get("id"),
                "goalRevision": durable_goal.get("revision"),
                "durableGoal": durable_goal,
            }
    plan = _live_agent_loop_normalize_autonomy_plan(agent_state.get("autonomyPlan"))
    if plan:
        if _live_agent_loop_recent_internal_note_of_kind(
            agent_id,
            agent_state,
            "autonomy-plan",
            window_sec=LIVE_AGENT_AUTONOMY_PLAN_NOTE_COOLDOWN_SEC,
        ):
            plan = None
    if plan:
        pieces = [plan.get("currentGoal"), plan.get("reflection"), plan.get("lesson")]
        pieces.extend(plan.get("steps") or [])
        next_step = plan.get("nextStep") if isinstance(plan.get("nextStep"), dict) else {}
        pieces.extend(next_step.get(key) for key in ("intent", "successCriteria", "failureCriteria") if next_step.get(key))
        text = " ".join(str(item) for item in pieces if item)
        if text:
            return {"kind": "autonomy-plan", "summary": text[:700], "autonomyPlan": plan}
    recent = _live_agent_loop_recent_outcome_summary(agent_state)
    issue = next((item for item in recent.get("issues") or [] if isinstance(item, dict)), None)
    if issue:
        return {"kind": "recent-issue", "summary": issue.get("reason") or "recent issue", "issue": issue}
    return None


def _live_agent_loop_new_plan(agent_id, action_def, decision, selected, now_iso, goal_context=None):
    action_def = action_def if isinstance(action_def, dict) else {}
    decision = decision if isinstance(decision, dict) else {}
    selected = selected if isinstance(selected, dict) else {}
    loop_action_id = str(action_def.get("id") or decision.get("selectedActionId") or "visible-action")
    title = f"{action_def.get('label') or loop_action_id}"
    is_support = _live_agent_loop_is_support_action(action_def)
    plan_id = f"plan-{agent_id}-{loop_action_id}-{int(time.time())}"
    target = selected.get("target") if isinstance(selected.get("target"), dict) else {}
    target_label = target.get("buildingId") or target.get("catalogId") or target.get("supportTool") or target.get("kind") or ("support tool" if is_support else "visible target")
    plan = {
        "schemaVersion": LIVE_AGENT_LOOP_PLAN_SCHEMA_VERSION,
        "id": plan_id,
        "agentId": agent_id,
        "status": "planned",
        "title": title,
        "loopActionId": loop_action_id,
        "actionType": action_def.get("actionType"),
        "need": action_def.get("need"),
        "createdAt": now_iso,
        "updatedAt": now_iso,
        "currentStepIndex": 1,
        "retries": 0,
        "maxRetries": LIVE_AGENT_LOOP_DEFAULTS["planMaxRetries"],
        "operatorSummary": f"Planning to {title} through an explicit support tool." if is_support else f"Planning to {title} through a visible in-world executor.",
        "steps": [
            {
                "id": "choose-goal",
                "label": "Choose resident goal",
                "status": "completed",
                "updatedAt": now_iso,
            },
            {
                "id": "execute-support-tool" if is_support else "execute-visible-action",
                "label": f"Execute {title}",
                "status": "pending",
                "loopActionId": loop_action_id,
                "actionType": action_def.get("actionType"),
                "executionKind": "support-tool" if is_support else "visible-world-action",
                "attempts": 0,
                "updatedAt": now_iso,
            },
            {
                "id": "observe-outcome",
                "label": f"Observe outcome at {target_label}",
                "status": "pending",
                "attempts": 0,
            },
        ],
    }
    goal_context = goal_context if isinstance(goal_context, dict) else {}
    if goal_context.get("goalId"):
        for key in ("goalId", "goalRevision", "goalTaskId", "goalStepId", "goalTitle"):
            if goal_context.get(key) is not None:
                plan[key] = goal_context.get(key)
        execute_step = plan["steps"][1]
        for key in ("goalId", "goalTaskId", "goalStepId"):
            if goal_context.get(key):
                execute_step[key] = goal_context.get(key)
    return _live_agent_loop_normalize_plan(plan)


def _live_agent_loop_prepare_plan(agent_state, agent_id, action_def, decision, selected, now_iso, *, persist=True, goal_context=None):
    loop_action_id = (action_def or {}).get("id")
    active_plan = _live_agent_loop_normalize_plan(agent_state.get("activePlan"))
    if _live_agent_loop_plan_is_active(active_plan):
        step = _live_agent_loop_plan_current_step(active_plan)
        goal_context = goal_context if isinstance(goal_context, dict) else {}
        same_goal_step = (
            not goal_context.get("goalId")
            or (
                active_plan.get("goalId") == goal_context.get("goalId")
                and active_plan.get("goalTaskId") == goal_context.get("goalTaskId")
                and active_plan.get("goalStepId") == goal_context.get("goalStepId")
            )
        )
        if isinstance(step, dict) and step.get("loopActionId") == loop_action_id and same_goal_step:
            active_plan["status"] = "in_progress" if active_plan.get("status") == "planned" else active_plan.get("status")
            active_plan["updatedAt"] = now_iso
            active_plan["operatorSummary"] = f"Resuming plan step {step.get('label') or loop_action_id}."
            if persist:
                stored = _live_agent_loop_store_plan(agent_state, active_plan)
                _live_agent_loop_begin_episode(None, agent_id, agent_state, stored, action_def, decision, selected, now_iso)
                return stored
            return active_plan
        if persist:
            active_plan["status"] = "cancelled"
            active_plan["cancelledAt"] = now_iso
            active_plan["updatedAt"] = now_iso
            active_plan["failureReason"] = "superseded-by-new-plan"
            active_plan["operatorSummary"] = "Previous active plan was cancelled because its current visible step was no longer selected."
            _live_agent_loop_store_plan(agent_state, active_plan)
    plan = _live_agent_loop_new_plan(agent_id, action_def, decision, selected, now_iso, goal_context=goal_context)
    if persist:
        stored = _live_agent_loop_store_plan(agent_state, plan)
        _live_agent_loop_begin_episode(None, agent_id, agent_state, stored, action_def, decision, selected, now_iso)
        return stored
    return plan


def _live_agent_loop_mark_plan_action_created(state, agent_id, agent_state, plan, action_id, now_iso, *, action_def=None, decision=None, selected=None):
    plan = _live_agent_loop_normalize_plan(plan)
    if not plan:
        return None
    step = _live_agent_loop_plan_current_step(plan)
    if isinstance(step, dict):
        step["status"] = "in_progress"
        step["actionId"] = action_id
        step["startedAt"] = now_iso
        step["updatedAt"] = now_iso
        step["attempts"] = _normalize_int(step.get("attempts"), 0, minimum=0, maximum=20) + 1
    plan["status"] = "in_progress"
    plan["startedAt"] = plan.get("startedAt") or now_iso
    plan["updatedAt"] = now_iso
    plan["lastActionId"] = action_id
    execution_kind = (step or {}).get("executionKind") if isinstance(step, dict) else ""
    prefix = "Running support tool step" if execution_kind == "support-tool" else "Running visible plan step"
    plan["operatorSummary"] = f"{prefix} {step.get('label') if isinstance(step, dict) else plan.get('title')}."
    stored = _live_agent_loop_store_plan(agent_state, plan)
    if not _live_agent_loop_find_episode(agent_state, plan_id=(stored or plan).get("id")):
        _live_agent_loop_begin_episode(state, agent_id, agent_state, stored or plan, action_def or {}, decision or {}, selected or {}, now_iso)
    _live_agent_loop_mark_episode_executing(state, agent_id, agent_state, stored or plan, action_id, now_iso)
    goal_context = {
        key: plan.get(key)
        for key in ("goalId", "goalRevision", "goalTaskId", "goalStepId", "goalTitle")
        if plan.get(key) is not None
    }
    if goal_context.get("goalId"):
        _live_agent_loop_mark_durable_goal_action_started(
            state,
            agent_id,
            agent_state,
            goal_context,
            action_id,
            plan.get("loopActionId"),
            now_iso,
        )
    _live_agent_loop_add_event(state, "plan-step-started", agent_id=agent_id, details={"planId": plan.get("id"), "actionId": action_id, "stepId": (step or {}).get("id") if isinstance(step, dict) else None})
    return stored


def _live_agent_loop_mark_plan_action_request_failed(state, agent_id, agent_state, plan, failure_reason, now_iso):
    plan = _live_agent_loop_normalize_plan(plan)
    if not plan:
        return None
    step = _live_agent_loop_plan_current_step(plan)
    if isinstance(step, dict):
        step["status"] = "failed"
        step["failureReason"] = _live_agent_loop_clean_plan_text(failure_reason, limit=220) or "action request failed"
        step["settledAt"] = now_iso
        step["updatedAt"] = now_iso
    plan["status"] = "failed"
    plan["failureReason"] = (step or {}).get("failureReason") if isinstance(step, dict) else "action request failed"
    plan["failedAt"] = now_iso
    plan["updatedAt"] = now_iso
    plan["operatorSummary"] = f"Plan failed before the visible action could be created: {plan.get('failureReason')}."
    stored = _live_agent_loop_store_plan(agent_state, plan)
    episode = _live_agent_loop_find_episode(agent_state, plan_id=plan.get("id"))
    if episode:
        episode["status"] = "failed"
        episode["phase"] = "continue"
        episode["failedAt"] = now_iso
        episode["updatedAt"] = now_iso
        episode["operatorSummary"] = "The world rejected the action before a body action existed; the controller must re-observe before deciding again."
        episode.pop("actionId", None)
        episode.pop("issueId", None)
        episode["verification"] = {
            "schemaVersion": "agent-live-mode-verification/v1",
            "at": now_iso,
            "agentId": agent_id,
            "loopActionId": plan.get("loopActionId"),
            "ok": False,
            "status": "failed",
            "reason": plan.get("failureReason"),
            "reportableFailure": False,
            "evidence": {"method": "action-request-result", "created": False},
        }
        episode.setdefault("history", []).append({
            "at": now_iso,
            "phase": "continue",
            "event": "action-request-rejected",
            "reason": plan.get("failureReason"),
        })
        _live_agent_loop_store_episode(agent_state, episode)
    skill = agent_state.get("skillExecution") if isinstance(agent_state.get("skillExecution"), dict) else None
    if skill and (not skill.get("planId") or skill.get("planId") == plan.get("id")):
        skill.update({
            "status": "failed",
            "updatedAt": now_iso,
            "failureReason": plan.get("failureReason"),
        })
        skill.pop("actionId", None)
        agent_state["skillExecution"] = skill
    _live_agent_loop_controller_update(
        agent_id,
        agent_state,
        "observing",
        reason="world rejected the requested action before execution; re-observe before replanning",
        active_action_id=None,
    )
    goal_context = {
        key: plan.get(key)
        for key in ("goalId", "goalRevision", "goalTaskId", "goalStepId", "goalTitle")
        if plan.get(key) is not None
    }
    if goal_context.get("goalId"):
        synthetic_action_id = f"request-failed-{hashlib.sha1(f'{agent_id}:{plan.get('id')}:{now_iso}'.encode('utf-8')).hexdigest()[:12]}"
        _live_agent_loop_mark_durable_goal_action_started(
            state,
            agent_id,
            agent_state,
            goal_context,
            synthetic_action_id,
            plan.get("loopActionId"),
            now_iso,
        )
        _live_agent_loop_record_durable_goal_verification(
            state,
            agent_id,
            agent_state,
            {
                "id": _live_agent_loop_verification_id(agent_id, synthetic_action_id, "request-failed", now_iso),
                "schemaVersion": "agent-live-mode-verification/v1",
                "at": now_iso,
                "agentId": agent_id,
                "actionId": synthetic_action_id,
                "loopActionId": plan.get("loopActionId"),
                "ok": False,
                "status": "failed",
                "reason": plan.get("failureReason"),
                "evidence": {"method": "action-request-result", "created": False},
                **goal_context,
            },
            now_iso,
        )
    _live_agent_loop_add_event(state, "plan-failed", agent_id=agent_id, details={"planId": plan.get("id"), "failureReason": plan.get("failureReason")})
    return stored


def _live_agent_loop_find_plan_for_action(agent_state, summary):
    if not isinstance(summary, dict):
        return None
    wanted_plan_id = summary.get("planId")
    wanted_step_id = summary.get("planStepId")
    action_id = summary.get("id")
    candidates = []
    active_plan = _live_agent_loop_normalize_plan(agent_state.get("activePlan"))
    if active_plan:
        candidates.append(active_plan)
    for plan in agent_state.get("plans") or []:
        normalized = _live_agent_loop_normalize_plan(plan)
        if normalized and all(normalized.get("id") != existing.get("id") for existing in candidates):
            candidates.append(normalized)
    for plan in candidates:
        if wanted_plan_id and plan.get("id") != wanted_plan_id:
            continue
        for index, step in enumerate(plan.get("steps") or []):
            if wanted_step_id and step.get("id") != wanted_step_id:
                continue
            if action_id and (step.get("actionId") == action_id or plan.get("lastActionId") == action_id):
                plan["currentStepIndex"] = index
                return plan
            if wanted_plan_id and wanted_step_id:
                plan["currentStepIndex"] = index
                return plan
    return None


def _live_agent_loop_update_plan_from_settled_action(state, agent_id, agent_state, summary, action_status, now_iso):
    plan = _live_agent_loop_find_plan_for_action(agent_state, summary)
    if not plan:
        return None
    step = _live_agent_loop_plan_current_step(plan)
    completed = action_status == "completed"
    result = summary.get("result") if isinstance(summary.get("result"), dict) else {}
    cancel_reason = result.get("reason") or summary.get("failureReason") or action_status
    superseded = _live_agent_loop_is_user_control_cancel(action_status, cancel_reason)
    if isinstance(step, dict):
        step["actionId"] = summary.get("id") or step.get("actionId")
        step["settledAt"] = now_iso
        step["updatedAt"] = now_iso
        step["status"] = "completed" if completed else "cancelled" if superseded else "failed"
        if not completed and not superseded:
            step["failureReason"] = _live_agent_loop_clean_plan_text(summary.get("failureReason") or action_status, limit=220)
    plan["lastActionId"] = summary.get("id") or plan.get("lastActionId")
    plan["updatedAt"] = now_iso
    if superseded:
        plan["status"] = "cancelled"
        plan["cancelledAt"] = plan.get("cancelledAt") or now_iso
        plan["failureReason"] = "direct-user-redirect"
        plan["operatorSummary"] = "Plan superseded by direct user control; the world action did not fail."
        stored = _live_agent_loop_store_plan(agent_state, plan)
        _live_agent_loop_add_event(
            state,
            "plan-superseded",
            agent_id=agent_id,
            details={"planId": plan.get("id"), "actionId": summary.get("id"), "status": action_status, "reason": cancel_reason},
        )
        return stored
    observe_index = None
    for index, next_step in enumerate(plan.get("steps") or []):
        if next_step.get("id") == "observe-outcome":
            observe_index = index
            next_step["status"] = "in_progress"
            next_step["updatedAt"] = now_iso
            next_step["startedAt"] = next_step.get("startedAt") or now_iso
            next_step["attempts"] = _normalize_int(next_step.get("attempts"), 0, minimum=0, maximum=20) + 1
            break
    if observe_index is not None:
        plan["currentStepIndex"] = observe_index
    plan["status"] = "in_progress"
    plan["operatorSummary"] = f"Verifying outcome for {plan.get('title')} before the loop can learn or continue."
    event_type = "plan-verifying"
    details = {"planId": plan.get("id"), "actionId": summary.get("id"), "status": action_status, "completedAction": completed}
    stored = _live_agent_loop_store_plan(agent_state, plan)
    _live_agent_loop_add_event(state, event_type, agent_id=agent_id, details=details)
    return stored


def _live_agent_loop_finish_plan_after_verification(state, agent_id, agent_state, plan, verification, now_iso):
    plan = _live_agent_loop_normalize_plan(plan)
    if not plan:
        return None
    verification = verification if isinstance(verification, dict) else {}
    ok = verification.get("ok") is True
    superseded = verification.get("superseded") is True or verification.get("status") == "superseded"
    step = _live_agent_loop_plan_current_step(plan)
    if isinstance(step, dict) and step.get("id") == "observe-outcome":
        step["status"] = "completed" if ok else "cancelled" if superseded else "failed"
        step["settledAt"] = now_iso
        step["updatedAt"] = now_iso
        if not ok and not superseded:
            step["failureReason"] = _live_agent_loop_clean_plan_text(verification.get("reason"), limit=220) or "verification failed"
    plan["updatedAt"] = now_iso
    if ok:
        plan["status"] = "completed"
        plan["completedAt"] = now_iso
        plan["currentStepIndex"] = max(0, len(plan.get("steps") or []) - 1)
        plan["operatorSummary"] = f"Verified and completed plan: {plan.get('title')}."
        event_type = "plan-completed"
        details = {"planId": plan.get("id"), "actionId": verification.get("actionId"), "status": "verified", "verificationId": verification.get("id")}
    elif superseded:
        plan["status"] = "cancelled"
        plan["cancelledAt"] = plan.get("cancelledAt") or now_iso
        plan["failureReason"] = "direct-user-redirect"
        plan["operatorSummary"] = "Plan superseded by direct user control; no retry or Coder report is required."
        event_type = "plan-superseded"
        details = {"planId": plan.get("id"), "actionId": verification.get("actionId"), "status": "superseded", "verificationId": verification.get("id"), "reportableFailure": False}
    else:
        reportable_failure = verification.get("reportableFailure") is not False
        retries = _normalize_int(plan.get("retries"), 0, minimum=0, maximum=20) + 1
        max_retries = _normalize_int(plan.get("maxRetries"), LIVE_AGENT_LOOP_DEFAULTS["planMaxRetries"], minimum=0, maximum=5)
        plan["retries"] = retries
        plan["failureReason"] = _live_agent_loop_clean_plan_text(verification.get("reason"), limit=240) or "verification failed"
        plan["status"] = "failed"
        plan["failedAt"] = now_iso
        if reportable_failure:
            plan["operatorSummary"] = f"Plan failed verification: {plan.get('failureReason')}. plan-retrying is gated until the issue is reported or new evidence exists."
            retry_gate = "plan-retrying requires verification evidence or Coder feedback"
        else:
            plan["operatorSummary"] = f"Plan failed verification after a retryable world interruption: {plan.get('failureReason')}. Re-observe and retry only when route, target, or conditions change."
            retry_gate = "retryable world interruption can continue after fresh observation or changed conditions"
        event_type = "plan-failed"
        details = {"planId": plan.get("id"), "actionId": verification.get("actionId"), "status": "verification-failed", "verificationId": verification.get("id"), "retries": retries, "maxRetries": max_retries, "retryEvent": "plan-retrying", "retryGate": retry_gate, "reportableFailure": reportable_failure}
    stored = _live_agent_loop_store_plan(agent_state, plan)
    _live_agent_loop_add_event(state, event_type, agent_id=agent_id, details=details)
    return stored


def _live_agent_loop_verification_id(agent_id, action_id, status, now_iso):
    basis = f"{agent_id}:{action_id}:{status}:{now_iso}"
    return "verify-" + hashlib.sha1(basis.encode("utf-8", errors="ignore")).hexdigest()[:16]


def _live_agent_loop_verification_from_settled_action(agent_id, action, summary, recent_entry, now_iso):
    summary = summary if isinstance(summary, dict) else {}
    recent_entry = recent_entry if isinstance(recent_entry, dict) else {}
    action_status = _canonical_world_action_status(summary.get("status"))
    completion_validation = recent_entry.get("completionValidation") if isinstance(recent_entry.get("completionValidation"), dict) else {}
    failure = recent_entry.get("failure") if isinstance(recent_entry.get("failure"), dict) else {}
    superseded = failure.get("userControlCancel") is True or failure.get("superseded") is True
    result = summary.get("result") if isinstance(summary.get("result"), dict) else {}
    target = recent_entry.get("target") if isinstance(recent_entry.get("target"), dict) else _live_agent_loop_memory_target(action.get("target") if isinstance(action, dict) else None)
    evidence = {
        "method": "world-action-result",
        "actionStatus": action_status,
        "actionType": summary.get("actionType"),
        "loopActionId": summary.get("loopActionId"),
        "target": _copy_jsonable(target) if isinstance(target, dict) else None,
        "targetKey": recent_entry.get("targetKey") or _live_agent_loop_target_key(target),
        "terminalAt": summary.get("terminalAt"),
        "completedAt": summary.get("completedAt"),
        "resultStatus": result.get("status"),
        "resultReason": result.get("reason"),
        "visualVerification": {
            "available": bool((VW_CONFIG.get("browser") or {}).get("cdpUrl")),
            "required": False,
            "status": "authoritative-world-evidence",
            "reason": "Server-authoritative action and embodied-state evidence is sufficient; browser capture is optional operator diagnostics, not a missing verification capability.",
        },
    }
    if completion_validation:
        evidence["completionValidation"] = _copy_jsonable(completion_validation)
    if failure:
        evidence["failure"] = _copy_jsonable(failure)
    ok = action_status == "completed" and completion_validation.get("ok") is not False and not failure
    reason = ""
    if not ok:
        reason = (
            failure.get("learningText")
            or completion_validation.get("reason")
            or summary.get("failureReason")
            or action_status
            or "verification failed"
        )
    return {
        "id": _live_agent_loop_verification_id(agent_id, summary.get("id"), action_status, now_iso),
        "schemaVersion": "agent-live-mode-verification/v1",
        "at": now_iso,
        "agentId": agent_id,
        "actionId": summary.get("id"),
        "loopActionId": summary.get("loopActionId"),
        "planId": summary.get("planId"),
        "planStepId": summary.get("planStepId"),
        "goalId": summary.get("goalId"),
        "goalRevision": summary.get("goalRevision"),
        "goalTaskId": summary.get("goalTaskId"),
        "goalStepId": summary.get("goalStepId"),
        "ok": bool(ok),
        "status": "verified" if ok else "superseded" if superseded else "failed",
        "superseded": bool(superseded),
        "reportableFailure": False if superseded else None,
        "reason": _live_agent_loop_clean_plan_text(reason, limit=700) if reason else "",
        "evidence": evidence,
    }


def _live_agent_loop_verification_failure_reportable(agent_state, recent_entry):
    recent_entry = recent_entry if isinstance(recent_entry, dict) else {}
    failure = recent_entry.get("failure") if isinstance(recent_entry.get("failure"), dict) else {}
    if failure.get("userControlCancel") is True or failure.get("superseded") is True:
        return False
    if failure.get("reportable") is not False:
        return True
    loop_action_id = recent_entry.get("loopActionId") or failure.get("loopActionId")
    target_key = recent_entry.get("targetKey") or failure.get("targetKey") or _live_agent_loop_target_key(recent_entry.get("target"))
    recent = _live_agent_loop_recent_outcome_summary(agent_state)
    for issue in recent.get("issues") or []:
        if not isinstance(issue, dict):
            continue
        if loop_action_id and issue.get("loopActionId") != loop_action_id:
            continue
        if target_key and issue.get("targetKey") and not _live_agent_loop_target_keys_compatible(target_key, issue.get("targetKey")):
            continue
        return True
    return False


def _live_agent_loop_resolve_reported_episodes_from_verification(
    state,
    agent_id,
    agent_state,
    verification,
    *,
    action_type="",
    now_iso=None,
    exclude_episode_id=None,
):
    if not isinstance(agent_state, dict) or not isinstance(verification, dict) or verification.get("ok") is not True:
        return []
    now_iso = now_iso or _utc_now_iso()
    verified_target_key = ((verification.get("evidence") or {}).get("targetKey") or "").strip()
    verified_loop_action_id = str(verification.get("loopActionId") or "").strip()
    verified_action_type = str(action_type or "").strip()
    candidates = []
    active = _live_agent_loop_normalize_episode(agent_state.get("activeEpisode"))
    if active:
        candidates.append(active)
    for raw in agent_state.get("episodes") or []:
        episode = _live_agent_loop_normalize_episode(raw)
        if episode and all(episode.get("id") != item.get("id") for item in candidates):
            candidates.append(episode)

    resolved = []
    resolved_issue_ids = set()
    for episode in candidates:
        if episode.get("id") == exclude_episode_id:
            continue
        if _live_agent_loop_episode_status(episode.get("status")) not in {
            "awaiting_report",
            "reported",
            "awaiting_coder",
            "coder_responded",
        }:
            continue
        episode_target_key = str(episode.get("targetKey") or "").strip()
        same_social_action = episode.get("actionType") == "life.social" and verified_action_type == "life.social"
        if not same_social_action and (verified_target_key or episode_target_key):
            if not verified_target_key or not episode_target_key:
                continue
            if not _live_agent_loop_target_keys_compatible(verified_target_key, episode_target_key):
                continue
        same_loop_action = bool(verified_loop_action_id and episode.get("loopActionId") == verified_loop_action_id)
        same_action_type = bool(verified_action_type and episode.get("actionType") == verified_action_type)
        if not same_loop_action and not same_action_type:
            continue

        episode["status"] = "completed"
        episode["phase"] = "continue"
        episode["updatedAt"] = now_iso
        episode["completedAt"] = now_iso
        episode["resolution"] = {
            "kind": "later-verified-action",
            "at": now_iso,
            "actionId": verification.get("actionId"),
            "verificationId": verification.get("id"),
            "loopActionId": verified_loop_action_id,
            "targetKey": verified_target_key,
        }
        episode["operatorSummary"] = "Resolved by a later verified action after route, target, or conditions changed."
        episode.setdefault("history", []).append({
            "at": now_iso,
            "phase": "continue",
            "event": "resolved-by-later-verification",
            "actionId": verification.get("actionId"),
            "verificationId": verification.get("id"),
        })
        stored = _live_agent_loop_store_episode(agent_state, episode)
        if stored:
            resolved.append(stored)
            if stored.get("issueId"):
                resolved_issue_ids.add(stored.get("issueId"))
            if isinstance(state, dict):
                _live_agent_loop_add_event(
                    state,
                    "episode-resolved-by-verification",
                    agent_id=agent_id,
                    details={
                        "episodeId": stored.get("id"),
                        "issueId": stored.get("issueId"),
                        "actionId": verification.get("actionId"),
                        "verificationId": verification.get("id"),
                    },
                )
    if resolved_issue_ids:
        agent_state["supportRequests"] = [
            item
            for item in (agent_state.get("supportRequests") or [])
            if not isinstance(item, dict) or item.get("issueId") not in resolved_issue_ids
        ]
    return resolved


def _live_agent_loop_record_episode_verification(state, agent_id, agent_state, action, summary, recent_entry, plan, now_iso):
    verification = _live_agent_loop_verification_from_settled_action(agent_id, action, summary, recent_entry, now_iso)
    verification_ok = verification.get("ok") is True
    superseded = verification.get("superseded") is True or verification.get("status") == "superseded"
    reportable_failure = False if superseded else True if verification_ok else _live_agent_loop_verification_failure_reportable(agent_state, recent_entry)
    verification["reportableFailure"] = reportable_failure
    episode = _live_agent_loop_find_episode(agent_state, plan_id=verification.get("planId"), action_id=verification.get("actionId"))
    if not episode:
        plan_id = verification.get("planId") or f"ad-hoc-{verification.get('actionId')}"
        episode = {
            "id": _live_agent_loop_episode_id(agent_id, plan_id, verification.get("loopActionId"), now_iso),
            "agentId": agent_id,
            "planId": plan_id,
            "loopActionId": verification.get("loopActionId"),
            "actionType": summary.get("actionType") if isinstance(summary, dict) else "",
            "title": verification.get("loopActionId") or "Live Agent action",
            "status": "verifying",
            "phase": "verify",
            "createdAt": now_iso,
            "updatedAt": now_iso,
            "evidence": [],
            "reports": [],
            "coderResponses": [],
            "history": [],
        }
    if verification_ok:
        episode["phase"] = "learn"
        episode["status"] = "verified"
    elif superseded:
        episode["phase"] = "continue"
        episode["status"] = "cancelled"
    elif reportable_failure:
        episode["phase"] = "report"
        episode["status"] = "awaiting_report"
    else:
        episode["phase"] = "continue"
        episode["status"] = "failed"
    episode["updatedAt"] = now_iso
    episode["verifiedAt"] = now_iso if verification_ok else episode.get("verifiedAt")
    episode["verification"] = _copy_jsonable(verification)
    episode["actionId"] = verification.get("actionId") or episode.get("actionId")
    episode["targetKey"] = (verification.get("evidence") or {}).get("targetKey") or episode.get("targetKey")
    episode.setdefault("evidence", []).append({"at": now_iso, "type": "verification", "verification": _copy_jsonable(verification)})
    history_event = "verification-passed" if verification_ok else "episode-superseded" if superseded else "verification-failed" if reportable_failure else "verification-failed-nonreportable"
    episode.setdefault("history", []).append({"at": now_iso, "phase": "verify", "event": history_event, "verificationId": verification.get("id")})
    if verification_ok:
        episode["status"] = "completed"
        episode["phase"] = "continue"
        episode["completedAt"] = now_iso
        episode["operatorSummary"] = "Episode verified; planner can continue with evidence in memory."
    elif superseded:
        episode.pop("issueId", None)
        episode["cancelledAt"] = episode.get("cancelledAt") or now_iso
        episode["operatorSummary"] = "Episode superseded by direct user control; the target and route remain unjudged."
    elif reportable_failure:
        issue_id = f"episode.issue.{hashlib.sha1(json.dumps(verification, sort_keys=True, default=str).encode('utf-8')).hexdigest()[:10]}"
        episode["issueId"] = issue_id
        episode["operatorSummary"] = "Verification failed; report to Coder before treating this loop as learned."
        _live_agent_loop_add_support_request(
            agent_state,
            "coder-report",
            f"Verification failed for {verification.get('loopActionId')}: {verification.get('reason') or 'no reason recorded'}",
            source="episode-verification",
            issue_id=issue_id,
        )
    else:
        episode.pop("issueId", None)
        episode["failedAt"] = now_iso
        episode["operatorSummary"] = "Verification failed after a retryable world interruption; re-observe and retry only when route, target, or conditions change."
    stored = _live_agent_loop_store_episode(agent_state, episode)
    if verification_ok:
        _live_agent_loop_resolve_reported_episodes_from_verification(
            state,
            agent_id,
            agent_state,
            verification,
            action_type=summary.get("actionType") if isinstance(summary, dict) else "",
            now_iso=now_iso,
            exclude_episode_id=stored.get("id") if isinstance(stored, dict) else None,
        )
    _live_agent_loop_finish_plan_after_verification(state, agent_id, agent_state, plan, verification, now_iso)
    if not superseded:
        _live_agent_loop_record_durable_goal_verification(state, agent_id, agent_state, verification, now_iso)
    _live_agent_loop_add_event(
        state,
        "episode-verified" if verification_ok else "episode-superseded" if superseded else "episode-verification-failed",
        agent_id=agent_id,
        details={"episodeId": stored.get("id"), "issueId": stored.get("issueId"), "verificationId": verification.get("id"), "ok": verification_ok, "reportableFailure": reportable_failure},
    )
    return stored


def _live_agent_loop_record_support_episode_verification(state, agent_id, agent_state, outcome, plan, now_iso):
    outcome = outcome if isinstance(outcome, dict) else {}
    plan = _live_agent_loop_normalize_plan(plan)
    verification = {
        "id": _live_agent_loop_verification_id(agent_id, outcome.get("id"), outcome.get("status"), now_iso),
        "schemaVersion": "agent-live-mode-verification/v1",
        "at": now_iso,
        "agentId": agent_id,
        "actionId": outcome.get("id"),
        "loopActionId": outcome.get("loopActionId"),
        "planId": (plan or {}).get("id"),
        "goalId": (plan or {}).get("goalId"),
        "goalRevision": (plan or {}).get("goalRevision"),
        "goalTaskId": (plan or {}).get("goalTaskId"),
        "goalStepId": (plan or {}).get("goalStepId"),
        "ok": outcome.get("ok") is True,
        "status": "verified" if outcome.get("ok") else "failed",
        "reason": "" if outcome.get("ok") else _live_agent_loop_clean_plan_text(outcome.get("error") or outcome.get("status"), limit=700),
        "evidence": {
            "method": "support-tool-result",
            "supportTool": outcome.get("supportTool"),
            "supportActionId": outcome.get("id"),
            "communication": _copy_jsonable(outcome.get("communication")) if isinstance(outcome.get("communication"), dict) else None,
            "noteId": outcome.get("noteId"),
        },
    }
    episode = _live_agent_loop_find_episode(agent_state, plan_id=(plan or {}).get("id"), action_id=outcome.get("id"))
    if episode:
        episode["status"] = "completed" if verification.get("ok") else "failed"
        episode["phase"] = "continue" if verification.get("ok") else "report"
        episode["updatedAt"] = now_iso
        episode["completedAt" if verification.get("ok") else "failedAt"] = now_iso
        episode["verification"] = _copy_jsonable(verification)
        episode.setdefault("evidence", []).append({"at": now_iso, "type": "support-verification", "verification": _copy_jsonable(verification)})
        episode.setdefault("history", []).append({"at": now_iso, "phase": "verify", "event": "support-verification-passed" if verification.get("ok") else "support-verification-failed", "verificationId": verification.get("id")})
        episode["operatorSummary"] = "Support tool verified." if verification.get("ok") else "Support tool failed verification."
        _live_agent_loop_store_episode(agent_state, episode)
    _live_agent_loop_finish_plan_after_verification(state, agent_id, agent_state, plan, verification, now_iso)
    _live_agent_loop_record_durable_goal_verification(state, agent_id, agent_state, verification, now_iso)
    if outcome.get("supportTool") == "coder-report":
        _live_agent_loop_mark_episode_reported(state, agent_id, agent_state, {"issueId": outcome.get("issueId")}, outcome, now_iso)
    return verification


def _live_agent_loop_build_goal_frame(agent_id, perception, agent_state):
    needs = perception.get("needs") if isinstance(perception, dict) else {}
    context = _live_agent_loop_agent_context(agent_id)
    if isinstance(perception, dict) and isinstance(perception.get("social"), dict):
        context["social"] = perception.get("social")
    recent = _live_agent_loop_recent_outcome_summary(agent_state, perception)
    recent_episodes = _live_agent_loop_recent_episode_summary(agent_state)
    active_plan = _live_agent_loop_normalize_plan(agent_state.get("activePlan"))
    durable_goal = _live_agent_loop_ensure_durable_goal(agent_state, agent_id)
    goals = []
    inventory = agent_state.get("inventory") if isinstance(agent_state.get("inventory"), dict) else {}
    held_item = inventory.get("held") if isinstance(inventory.get("held"), dict) else None
    _live_agent_session_reconcile_user_directives(agent_id, inventory=inventory)
    if held_item:
        goals.append({
            "id": f"inventory.consume.{held_item.get('id') or held_item.get('kind') or 'item'}",
            "kind": "inventory",
            "loopActionId": "use-seating-object",
            "priority": 0.94,
            "priorityClass": "held-item-follow-up",
            "reason": f"Choose a real available place to use or consume the carried {held_item.get('label') or held_item.get('kind') or 'item'}.",
            "heldItem": _copy_jsonable(held_item),
        })
    live_session = _live_agent_session_current(agent_id)
    live_working = live_session.get("workingMemory") if isinstance(live_session, dict) and isinstance(live_session.get("workingMemory"), dict) else {}
    pending_directives = [
        item for item in (live_working.get("userDirectives") or [])
        if isinstance(item, dict) and str(item.get("status") or "pending") == "pending" and str(item.get("text") or "").strip()
    ]
    if pending_directives:
        directive = pending_directives[-1]
        directive_text = str(directive.get("text") or "").strip()
        goals.append({
            "id": f"user.directive.{hashlib.sha1(directive_text.encode('utf-8')).hexdigest()[:10]}",
            "kind": "direct-user",
            "priority": 1.25,
            "priorityClass": "direct-user-control",
            "intent": _live_agent_loop_goal_intent(directive_text),
            "reason": directive_text[:700],
            "text": directive_text[:700],
            "directiveAt": directive.get("at"),
        })
    for need_id, value in sorted((needs or {}).items(), key=lambda item: item[1], reverse=True)[:3]:
        goals.append({
            "id": f"need.{need_id}",
            "kind": "need",
            "need": need_id,
            "priority": round(float(value or 0), 3),
            "reason": f"{need_id} need is currently {round(float(value or 0), 3)}",
        })
    if context["home"].get("exists"):
        goals.append({"id": "home.use-owned-home", "kind": "home", "priority": 0.42, "reason": "agent has an owned visible home"})
    else:
        goals.append({"id": "home.establish-shelter", "kind": "home", "priority": 0.70, "reason": "agent has no owned visible home yet"})
    if context["work"].get("exists"):
        goals.append({"id": "work.visit-assigned-work", "kind": "work", "priority": 0.28, "reason": "agent has an assigned work building"})
    else:
        goals.append({"id": "work.keep-general-routine", "kind": "work", "priority": 0.10, "reason": "no assigned work building is available"})
    social = context.get("social") if isinstance(context.get("social"), dict) else {}
    if social.get("nearbyAgentCount"):
        goals.append({"id": "social.perceive-nearby-agent", "kind": "relationship", "priority": 0.34, "reason": "another known agent appears co-located in the current social perception frame"})
    if social.get("liveEnabledPeerCount"):
        goals.append({"id": "social.observe-live-peers", "kind": "relationship", "priority": 0.22, "reason": "another resident has Live Mode enabled"})
    if context.get("relationships"):
        goals.append({"id": "social.maintain-relationships", "kind": "relationship", "priority": 0.24, "reason": "stored relationship context exists"})
    elif context.get("knownAgents"):
        goals.append({"id": "social.observe-neighbors", "kind": "relationship", "priority": 0.12, "reason": "other agents are known; visible conversation waits for co-location evidence"})
    resident_profile = context.get("residentProfile") if isinstance(context.get("residentProfile"), dict) else {}
    resident_goals = resident_profile.get("goals") if isinstance(resident_profile.get("goals"), dict) else {}
    for bucket, base_priority in (("current", LIVE_AGENT_CURRENT_GOAL_PRIORITY), ("daily", LIVE_AGENT_DAILY_GOAL_PRIORITY), ("longTerm", LIVE_AGENT_LONG_TERM_GOAL_PRIORITY)):
        for index, goal in enumerate((resident_goals.get(bucket) or [])[:4]):
            text = _live_agent_loop_profile_goal_text(goal)
            if not text:
                continue
            goal_id_seed = f"{agent_id}:{bucket}:{text}"
            intent = _live_agent_loop_goal_intent(text)
            goals.append({
                "id": f"resident.{bucket}.{hashlib.sha1(goal_id_seed.encode('utf-8')).hexdigest()[:10]}",
                "kind": "resident-profile",
                "bucket": bucket,
                "priority": round(max(0.12, base_priority - (index * 0.045)), 3),
                "intent": intent,
                "priorityClass": "active-goal" if bucket == "current" else "standing-goal",
                "reason": text[:260],
                "text": text,
            })
    if _live_agent_loop_plan_is_active(active_plan):
        step = _live_agent_loop_plan_current_step(active_plan)
        goals.append({
            "id": f"plan.resume.{active_plan.get('id')}",
            "kind": "plan",
            "planId": active_plan.get("id"),
            "loopActionId": (step or {}).get("loopActionId") if isinstance(step, dict) else active_plan.get("loopActionId"),
            "priority": 0.58 if active_plan.get("status") == "retrying" else 0.48,
            "reason": active_plan.get("operatorSummary") or "resume the active Live Mode plan",
        })
    if durable_goal:
        durable_context = _live_agent_goals.current_context(durable_goal)
        durable_task = durable_context.get("task") or {}
        durable_step = durable_context.get("step") or {}
        durable_priority = 0.84 if durable_goal.get("replanRequired") else max(0.58, min(0.88, float(durable_goal.get("priority") or 0.74)))
        goals.append({
            "id": f"durable.{durable_goal.get('id')}",
            "kind": "durable-goal",
            "goalId": durable_goal.get("id"),
            "goalRevision": durable_goal.get("revision"),
            "goalTaskId": durable_task.get("id"),
            "goalStepId": durable_step.get("id"),
            "status": durable_goal.get("status"),
            "replanRequired": bool(durable_goal.get("replanRequired")),
            "loopActionId": durable_step.get("loopActionId"),
            "priority": round(durable_priority, 3),
            "priorityClass": "blocking-replan" if durable_goal.get("replanRequired") else "active-durable-goal",
            "reason": durable_goal.get("replanReason") or durable_step.get("title") or durable_goal.get("title"),
            "text": durable_goal.get("title"),
        })
    for issue in (recent.get("issues") or [])[:4]:
        if not isinstance(issue, dict):
            continue
        goals.append({
            "id": issue.get("id") or f"issue.{issue.get('loopActionId')}",
            "kind": "issue",
            "status": "unresolved",
            "loopActionId": issue.get("loopActionId"),
            "priority": round(float(issue.get("priority") or LIVE_AGENT_ISSUE_PRIORITY), 3),
            "priorityClass": "blocking-issue",
            "failureStreak": issue.get("failureStreak"),
            "targetKey": issue.get("targetKey"),
            "reason": issue.get("reason") or "recent action did not complete",
            "suggestedLoopActionId": "investigate-blocking-issue",
        })
    for loop_id, summary in (recent.get("byAction") or {}).items():
        failures = int(summary.get("failed") or 0) + int(summary.get("expired") or 0) + int(summary.get("cancelled") or 0)
        if failures >= 2:
            goals.append({
                "id": f"reliability.recover.{loop_id}",
                "kind": "reliability",
                "loopActionId": loop_id,
                "priority": min(0.65, 0.22 * failures),
                "reason": f"{loop_id} recently ended unsuccessfully {failures} times",
            })
    goals.sort(key=lambda item: float(item.get("priority") or 0), reverse=True)
    return {
        "schemaVersion": "agent-live-mode-goal-frame/v2",
        "at": perception.get("at") if isinstance(perception, dict) else _utc_now_iso(),
        "agentId": agent_id,
        "context": context,
        "recentOutcomes": recent,
        "episodes": recent_episodes,
        "activePlan": active_plan,
        "durableGoal": durable_goal,
        "goals": goals,
    }



def _live_agent_loop_action_defs_for_agent(agent_id, agent_state=None, resident_profile=None):
    """Base executable actions plus dynamic object-category affordances that
    the agent's goals or model intentions activated. The result is the safe
    executable surface for this agent this tick, not a fixed global menu."""
    return [*LIVE_AGENT_LOOP_ACTIONS, *_live_agent_loop_dynamic_action_defs(agent_id, agent_state, resident_profile)]


def _live_agent_loop_capability_for_action_type(action_type):
    action_type = str(action_type or "").strip()
    for action_def in [*LIVE_AGENT_LOOP_ACTIONS, *LIVE_AGENT_DYNAMIC_OBJECT_AFFORDANCES.values()]:
        if str(action_def.get("actionType") or "") == action_type and action_def.get("capabilityTag"):
            return str(action_def.get("capabilityTag"))
    if action_type in LIVE_AGENT_LOCAL_OBJECT_VISIBLE_ACTION_TYPES:
        return "life.rest"
    if action_type.startswith("life.social") or ".talk" in action_type.lower():
        return "life.social"
    if any(token in action_type.lower() for token in ("rest", "sit", "lounge")):
        return "life.rest"
    return ""


def _live_agent_loop_need_for_action_type(action_type):
    action_type = str(action_type or "").lower()
    if any(token in action_type for token in ("water", "coffee", "drink")):
        return "hydration"
    if any(token in action_type for token in ("food", "snack", "vending", "eat")):
        return "food"
    if any(token in action_type for token in ("social", "talk", "conversation")):
        return "social"
    if any(token in action_type for token in ("rest", "sit", "lounge")):
        return "energy"
    if any(token in action_type for token in ("print", "maintain", "repair")):
        return "maintenance"
    return "curiosity"


def _live_agent_loop_generic_spatial_affordances(agent_id, agent_state, spatial, existing=None):
    """Build a context-gated tool surface from the birth world's objects.

    Only interactions backed by an existing visible executor are exposed. This
    lets the resident discover new placed objects without adding a Live Mode
    action id for every catalog entry.
    """
    spatial = spatial if isinstance(spatial, dict) else {}
    existing = existing if isinstance(existing, list) else []
    seen = set()
    for item in existing:
        target = item.get("target") if isinstance(item, dict) and isinstance(item.get("target"), dict) else {}
        seen.add((str(item.get("actionType") or ""), str(target.get("objectInstanceId") or ""), str(target.get("interactionSpotId") or "")))
    # A dynamic category goal (currently seating coverage) is authoritative
    # across both the category resolver and nearby generic affordances. Without
    # this bridge, a completed chair disappears from ``use-seating-object`` but
    # immediately reappears as a differently named ``world-use-*`` action.
    coverage_categories = {
        str(item.get("category") or "").strip()
        for item in existing
        if isinstance(item, dict) and str(item.get("category") or "").strip()
    }
    completed_by_category = {
        category: _live_agent_loop_progress_target_keys(agent_state, category)
        for category in coverage_categories
    }
    affordances = []
    inventory = agent_state.get("inventory") if isinstance(agent_state, dict) and isinstance(agent_state.get("inventory"), dict) else {}
    carrying_item = isinstance(inventory.get("held"), dict)
    for obj in spatial.get("nearbyObjects") or []:
        if not isinstance(obj, dict) or not obj.get("perceived"):
            continue
        for interaction in obj.get("interactions") or []:
            if not isinstance(interaction, dict):
                continue
            action_type = str(interaction.get("actionId") or "").strip()
            if carrying_item and action_type in LIVE_AGENT_CARRIED_ITEM_ACTIONS:
                continue
            spot_id = str(interaction.get("interactionSpotId") or interaction.get("id") or "").strip()
            availability = interaction.get("availability") if isinstance(interaction.get("availability"), dict) else {}
            queue_availability = availability.get("queueAvailability") if isinstance(availability.get("queueAvailability"), dict) else {}
            capability_tag = _live_agent_loop_capability_for_action_type(action_type)
            visible_contract = _live_agent_visible_action_contract(action_type)
            key = (action_type, str(obj.get("objectInstanceId") or ""), spot_id)
            if not action_type or not spot_id or not capability_tag or not visible_contract or (
                availability.get("state") != "available" and queue_availability.get("state") != "available"
            ) or key in seen:
                continue
            seen.add(key)
            target = {
                "kind": "object-instance",
                "buildingId": obj.get("buildingId") or "",
                "objectInstanceId": obj.get("objectInstanceId"),
                "catalogId": obj.get("catalogId"),
                "interactionSpotId": spot_id,
                "floor": obj.get("floor") or 1,
            }
            interaction_position = interaction.get("position") if isinstance(interaction.get("position"), dict) else None
            if interaction_position and isinstance(interaction_position.get("x"), (int, float)) and isinstance(interaction_position.get("y"), (int, float)):
                target["point"] = {
                    "x": round(float(interaction_position["x"]), 2),
                    "y": round(float(interaction_position["y"]), 2),
                    "floor": interaction_position.get("floor") or obj.get("floor") or 1,
                }
            if obj.get("furnitureIndex") is not None:
                target["furnitureIndex"] = obj.get("furnitureIndex")
            if obj.get("nodeIndex") is not None:
                target["nodeIndex"] = obj.get("nodeIndex")
            category = _live_agent_loop_resource_category(obj)
            coverage_category = category if category in coverage_categories else None
            target_key = _live_agent_loop_target_key(target)
            if not carrying_item and (
                (
                    coverage_category
                    and target_key in completed_by_category.get(coverage_category, set())
                )
                or (
                    _live_agent_loop_object_coverage_active(agent_id)
                    and _live_agent_loop_target_verified(agent_state, target_key)
                )
            ):
                continue
            object_label = str(obj.get("objectType") or obj.get("catalogId") or "object").replace("-", " ")
            action_label = re.sub(r"(?<!^)(?=[A-Z])", " ", action_type.split(".")[-1]).replace("_", " ").lower()
            affordance_id = f"world-use-{hashlib.sha1('|'.join(key).encode('utf-8')).hexdigest()[:14]}"
            need = _live_agent_loop_need_for_action_type(action_type)
            action_def = {
                "id": affordance_id,
                "actionType": action_type,
                "capabilityTag": capability_tag,
                "need": need,
                "label": f"{action_label} with {object_label}"[:180],
                "experience": f"visibly use {object_label} through its {spot_id} interaction",
                "autonomyKind": "world-affordance",
                "dynamic": True,
                "genericWorldAffordance": True,
                "category": coverage_category,
            }
            selected = {
                "action": action_def,
                "target": target,
                "buildingName": obj.get("buildingName") or "",
                "objectType": obj.get("objectType") or obj.get("catalogId"),
                "availability": availability,
                "spatial": {
                    "distanceTiles": obj.get("distanceTiles"),
                    "visible": bool(obj.get("visible")),
                    "lineOfSight": bool(obj.get("lineOfSight")),
                },
            }
            affordances.append({
                "id": affordance_id,
                "label": action_def["label"],
                "experience": action_def["experience"],
                "actionType": action_type,
                "capabilityTag": capability_tag,
                "need": need,
                "satisfiesNeeds": [need],
                "autonomyKind": "world-affordance",
                "available": True,
                "dynamic": True,
                "category": coverage_category,
                "genericWorldAffordance": True,
                "target": target,
                "buildingName": selected["buildingName"],
                "objectType": selected["objectType"],
                "availability": availability,
                "selected": selected,
                "visibility": {
                    "schemaVersion": LIVE_AGENT_VISIBLE_ACTION_CONTRACT_VERSION,
                    "policy": "visible-world-execution-required",
                    "visibleInWorld": True,
                    "hiddenWorldMutationAllowed": False,
                    "clientExecutor": visible_contract.get("clientExecutor"),
                    "requiresMoveIntent": bool(visible_contract.get("requiresMoveIntent")),
                    "requiresPhysicalAgentPresence": True,
                    "microstepArrivalDwellMs": 5000,
                },
            })
            if len(affordances) >= 24:
                return affordances
    return affordances


def _live_agent_loop_target_interaction_point(target):
    """Resolve a persisted object's exact interaction spot without requiring
    it to already be inside the resident's nearby spatial snapshot."""
    target = target if isinstance(target, dict) else {}
    if str(target.get("kind") or target.get("targetKind") or "") != "object-instance":
        return None
    resolved = _find_world_action_target(target)
    building = resolved.get("building") if isinstance(resolved, dict) and isinstance(resolved.get("building"), dict) else None
    obj = resolved.get("object") if isinstance(resolved, dict) and isinstance(resolved.get("object"), dict) else None
    if not building or not obj:
        return None
    wanted_spot = str(target.get("interactionSpotId") or "").strip()
    locations = obj.get("actionLocations") if isinstance(obj.get("actionLocations"), list) else []
    for location in locations:
        if not isinstance(location, dict):
            continue
        spot_id = str(location.get("interactionSpotId") or location.get("activationSpotId") or location.get("spotId") or location.get("id") or "").strip()
        if wanted_spot and spot_id != wanted_spot:
            continue
        point = _live_agent_spatial_location_point(building, obj, location)
        if point:
            return {
                "x": round(float(point["x"]), 2),
                "y": round(float(point["y"]), 2),
                "floor": location.get("floor") or obj.get("floor") or obj.get("buildingFloor") or target.get("floor") or 1,
            }
    point = _live_agent_spatial_location_point(building, obj)
    if point:
        return {
            "x": round(float(point["x"]), 2),
            "y": round(float(point["y"]), 2),
            "floor": obj.get("floor") or obj.get("buildingFloor") or target.get("floor") or 1,
        }
    return None


def _live_agent_loop_action_affordances(agent_id, agent_state, spatial=None):
    affordances = []
    inventory = agent_state.get("inventory") if isinstance(agent_state, dict) and isinstance(agent_state.get("inventory"), dict) else {}
    carrying_item = isinstance(inventory.get("held"), dict)
    for action_def in _live_agent_loop_action_defs_for_agent(agent_id, agent_state):
        carrying_blocks_action = carrying_item and str(action_def.get("actionType") or "") in LIVE_AGENT_CARRIED_ITEM_ACTIONS
        selected = None if carrying_blocks_action else _live_agent_loop_find_action_target(action_def, agent_id=agent_id, agent_state=agent_state, spatial=spatial)
        if isinstance(selected, dict) and isinstance(selected.get("target"), dict):
            target = selected.get("target")
            point = _live_agent_loop_target_interaction_point(target)
            if point:
                selected["target"] = {**target, "point": point}
                target = selected["target"]
        if isinstance(selected, dict) and isinstance(selected.get("target"), dict) and isinstance(spatial, dict):
            target = selected.get("target")
            object_id = str(target.get("objectInstanceId") or "")
            spot_id = str(target.get("interactionSpotId") or "")
            action_type = str((selected.get("action") or action_def).get("actionType") or "")
            for obj in spatial.get("nearbyObjects") or []:
                if not isinstance(obj, dict) or str(obj.get("objectInstanceId") or "") != object_id:
                    continue
                interaction = next((
                    row for row in (obj.get("interactions") or [])
                    if isinstance(row, dict)
                    and (not spot_id or str(row.get("interactionSpotId") or row.get("id") or "") == spot_id)
                    and (not action_type or str(row.get("actionId") or "") == action_type)
                ), None)
                point = interaction.get("position") if isinstance(interaction, dict) and isinstance(interaction.get("position"), dict) else None
                if point and isinstance(point.get("x"), (int, float)) and isinstance(point.get("y"), (int, float)):
                    selected["target"] = {
                        **target,
                        "point": {
                            "x": round(float(point["x"]), 2),
                            "y": round(float(point["y"]), 2),
                            "floor": point.get("floor") or target.get("floor") or 1,
                        },
                    }
                break
        selected_action = selected.get("action") if isinstance(selected, dict) and isinstance(selected.get("action"), dict) else action_def
        visible_contract = _live_agent_visible_action_contract(selected_action.get("actionType"))
        is_support_tool = selected_action.get("targetKind") == "support-tool"
        selected_target = selected.get("target") if isinstance(selected, dict) and isinstance(selected.get("target"), dict) else {}
        derived_category = None
        if selected_target.get("objectInstanceId"):
            derived_category = _live_agent_loop_resource_category({
                "catalogId": selected_target.get("catalogId"),
                "objectType": selected.get("objectType") if isinstance(selected, dict) else None,
            })
        affordance = {
            "id": action_def.get("id"),
            "label": selected_action.get("label") or action_def.get("label"),
            "experience": selected_action.get("experience") or action_def.get("experience"),
            "actionType": selected_action.get("actionType"),
            "capabilityTag": selected_action.get("capabilityTag"),
            "need": selected_action.get("need") or action_def.get("need"),
            "satisfiesNeeds": _live_agent_loop_action_satisfied_needs(selected_action or action_def),
            "autonomyKind": selected_action.get("autonomyKind") or action_def.get("autonomyKind"),
            "category": selected_action.get("category") or action_def.get("category") or derived_category,
            "genericWorldAffordance": bool(selected_action.get("genericWorldAffordance") or action_def.get("genericWorldAffordance")),
            "available": bool(selected),
            "visibility": {
                "schemaVersion": LIVE_AGENT_VISIBLE_ACTION_CONTRACT_VERSION,
                "policy": "support-tool-execution" if is_support_tool else "visible-world-execution-required",
                "visibleInWorld": bool(visible_contract),
                "hiddenWorldMutationAllowed": False,
                "clientExecutor": visible_contract.get("clientExecutor") if visible_contract else None,
                "requiresMoveIntent": bool(visible_contract and visible_contract.get("requiresMoveIntent")),
                "requiresPhysicalAgentPresence": bool(visible_contract),
                "supportTool": selected_action.get("supportTool") if is_support_tool else None,
            },
        }
        if selected:
            affordance.update({
                "target": selected.get("target"),
                "buildingName": selected.get("buildingName"),
                "objectType": selected.get("objectType"),
                "availability": selected.get("availability"),
                "selected": selected,
            })
        else:
            affordance["reason"] = "carrying_item_requires_seating_follow_up" if carrying_blocks_action else _live_agent_loop_unavailable_reason(action_def, agent_id)
        affordances.append(affordance)
    affordances.extend(_live_agent_loop_generic_spatial_affordances(agent_id, agent_state, spatial, affordances))
    return affordances


##############################################################################
# LIVE AGENT MODE - LOCATION AWARENESS + ROUTE PROGRESS WATCHDOG
#
# Live agents must know where their body actually is, verify they are heading
# to the intended coordinates, detect being stuck, and recover by cancelling
# the stalled action so the next tick replans a fresh route.
##############################################################################

LIVE_AGENT_ROUTE_PROGRESS_SAMPLE_LIMIT = 12
LIVE_AGENT_ROUTE_PROGRESS_WINDOW_SEC = 75
LIVE_AGENT_ROUTE_PROGRESS_MIN_SAMPLES = 3
LIVE_AGENT_ROUTE_PROGRESS_MIN_IMPROVEMENT = 12.0  # API units (~1/3 tile)
LIVE_AGENT_ROUTE_ARRIVAL_RADIUS = 60.0


def _live_agent_runtime_document():
    """Read one atomic snapshot from the realtime sidecar's shared document."""
    try:
        with open(os.path.join(DATA_DIR, "agent-runtime.json"), "r") as f:
            doc = json.load(f)
    except Exception:
        return None
    return doc if isinstance(doc, dict) else None


def _live_agent_runtime_positions(runtime_document=None):
    """Read authoritative body positions and route context from realtime."""
    doc = runtime_document if isinstance(runtime_document, dict) else _live_agent_runtime_document()
    if not isinstance(doc, dict):
        return {}
    agents = doc.get("agents") if isinstance(doc.get("agents"), dict) else {}
    positions = {}
    for agent_id, row in agents.items():
        if not isinstance(row, dict):
            continue
        x, y = row.get("x"), row.get("y")
        if not isinstance(x, (int, float)) or not isinstance(y, (int, float)):
            continue
        positions[str(agent_id)] = {
            "x": round(float(x), 2),
            "y": round(float(y), 2),
            "floor": row.get("floor"),
            "buildingId": row.get("buildingId") or "",
            "roomId": row.get("roomId") or "",
            "state": row.get("state"),
            "mode": row.get("mode"),
            "heading": row.get("heading"),
            "owner": row.get("owner") or "",
            "routeId": row.get("routeId") or "",
            "worldActionId": row.get("worldActionId") or "",
            "leaseOwner": row.get("leaseOwner") or "",
            "leaseExpiresAt": row.get("leaseExpiresAt") or "",
            "target": _copy_jsonable(row.get("target")) if isinstance(row.get("target"), dict) else None,
            "updatedAt": row.get("updatedAt"),
            "version": row.get("version"),
        }
    return positions


def _live_agent_runtime_position(agent_id, runtime_document=None):
    positions = _live_agent_runtime_positions(runtime_document)
    wanted = str(agent_id or "").strip()
    if wanted in positions:
        return positions[wanted]
    for alias in _live_agent_loop_agent_aliases(wanted):
        if alias in positions:
            return positions[alias]
    return None


def _live_agent_spatial_building_local_point(building, point):
    """Inverse of _live_agent_building_local_api_point (API units -> tiles)."""
    if not isinstance(building, dict) or not isinstance(point, dict):
        return None
    base_x = _float_or_none(building.get("worldX") if building.get("worldX") is not None else building.get("x"))
    base_z = _float_or_none(building.get("worldY") if building.get("worldY") is not None else building.get("z"))
    width = _float_or_none(building.get("widthTiles") if building.get("widthTiles") is not None else building.get("width"))
    depth = _float_or_none(building.get("heightTiles") if building.get("heightTiles") is not None else building.get("depth"))
    x = _float_or_none(point.get("x"))
    y = _float_or_none(point.get("y") if point.get("y") is not None else point.get("z"))
    if None in (base_x, base_z, width, depth, x, y):
        return None
    world_x = x / LIVE_AGENT_LOOP_API_TILE
    world_z = y / LIVE_AGENT_LOOP_API_TILE
    dx = world_x - base_x
    dz = world_z - base_z
    rotation = int(round(_float_or_none(building.get("_rotation") if building.get("_rotation") is not None else building.get("rotation")) or 0)) % 360
    if rotation == 90:
        local_x, local_z = dz, depth - dx
    elif rotation == 180:
        local_x, local_z = width - dx, depth - dz
    elif rotation == 270:
        local_x, local_z = width - dz, dx
    else:
        local_x, local_z = dx, dz
    return {"x": local_x, "z": local_z}


def _live_agent_spatial_segments_cross(a, b, c, d):
    """Return true for a proper sight-line/wall crossing, excluding endpoints."""
    denominator = (b[0] - a[0]) * (d[1] - c[1]) - (b[1] - a[1]) * (d[0] - c[0])
    if abs(denominator) <= 1e-9:
        return False
    t = ((c[0] - a[0]) * (d[1] - c[1]) - (c[1] - a[1]) * (d[0] - c[0])) / denominator
    u = ((c[0] - a[0]) * (b[1] - a[1]) - (c[1] - a[1]) * (b[0] - a[0])) / denominator
    return 0.015 < t < 0.985 and -1e-6 <= u <= 1.000001


def _live_agent_spatial_line_of_sight(building, origin, target, floor=1):
    if not isinstance(building, dict):
        return True
    local_origin = _live_agent_spatial_building_local_point(building, origin)
    local_target = _live_agent_spatial_building_local_point(building, target)
    if not local_origin or not local_target:
        return True
    a = (local_origin["x"], local_origin["z"])
    b = (local_target["x"], local_target["z"])
    walls = ((building.get("interior") or {}).get("walls") or [])
    for wall in walls if isinstance(walls, list) else []:
        if not isinstance(wall, dict):
            continue
        try:
            wall_floor = int(wall.get("floor") or wall.get("buildingFloor") or 1)
        except (TypeError, ValueError):
            wall_floor = 1
        if wall_floor != int(floor or 1):
            continue
        values = [_float_or_none(wall.get(key)) for key in ("x1", "z1", "x2", "z2")]
        if any(value is None for value in values):
            continue
        if _live_agent_spatial_segments_cross(a, b, (values[0], values[1]), (values[2], values[3])):
            return False
    return True


def _live_agent_spatial_object_id(building, obj, index, collection):
    explicit = next((obj.get(key) for key in ("objectInstanceId", "instanceId", "id", "nodeId") if obj.get(key)), None)
    if explicit:
        return str(explicit)
    return f"{building.get('id')}:{collection}:{index}"


def _live_agent_spatial_location_point(building, obj, location=None):
    location = location if isinstance(location, dict) else {}
    coordinate_space = str(location.get("coordinateSpace") or "").strip().lower()
    local = location.get("buildingLocal") if isinstance(location.get("buildingLocal"), dict) else None
    if not local:
        local = location.get("actionTarget") if isinstance(location.get("actionTarget"), dict) else None
    if not local:
        local = location.get("activationTarget") if isinstance(location.get("activationTarget"), dict) else None
    world = location.get("world") if isinstance(location.get("world"), dict) else None
    if coordinate_space in {"world", "world-tile", "world-tiles"} and world:
        wx = _float_or_none(world.get("x"))
        wz = _float_or_none(world.get("z") if world.get("z") is not None else world.get("y"))
        if wx is not None and wz is not None:
            return {"x": wx * LIVE_AGENT_LOOP_API_TILE, "y": wz * LIVE_AGENT_LOOP_API_TILE}
    source = local or obj
    x = _float_or_none(source.get("x")) if isinstance(source, dict) else None
    z = _float_or_none(source.get("z") if source.get("z") is not None else source.get("y")) if isinstance(source, dict) else None
    return _live_agent_building_local_api_point(building, x, z) if x is not None and z is not None else None


def _live_agent_spatial_runtime_objects_for(runtime_objects, building_id, collection, index, object_type, object_id):
    matches = []
    for object_key, row in (runtime_objects or {}).items():
        if not isinstance(row, dict):
            continue
        key = str(object_key or "")
        row_building = str(row.get("buildingId") or "")
        row_index = row.get("furnitureIndex")
        row_type = _normalize_token(row.get("objectType") or "")
        direct = str(row.get("objectInstanceId") or "") == str(object_id or "")
        try:
            same_index = row_index is not None and int(row_index) == int(index)
        except (TypeError, ValueError):
            same_index = False
        indexed = (
            collection == "furniture"
            and row_building == str(building_id or "")
            and same_index
            and (not row_type or row_type == _normalize_token(object_type))
        )
        key_match = bool(object_id and (key == str(object_id) or key.startswith(f"{object_id}:") or key.endswith(f":{object_id}")))
        if direct or indexed or key_match:
            matches.append({
                "objectKey": key,
                "state": row.get("state"),
                "agentId": row.get("agentId") or "",
                "actionId": row.get("actionId") or "",
                "reservationId": row.get("reservationId") or "",
                "activeUseId": row.get("activeUseId") or "",
                "slotId": row.get("slotId") or "",
                "expiresAt": row.get("expiresAt") or "",
                "updatedAt": row.get("updatedAt") or "",
            })
    matches.sort(key=lambda item: (item.get("state") not in {"active", "in_use", "reserved"}, item.get("objectKey") or ""))
    return matches[:6]


def _live_agent_spatial_object_interactions(agent_id, building, obj, collection, index, object_id, catalog_id, origin, resolved, action_store):
    locations = obj.get("actionLocations") if isinstance(obj.get("actionLocations"), list) else []
    interactions = []
    for location in locations[:12]:
        if not isinstance(location, dict):
            continue
        point = _live_agent_spatial_location_point(building, obj, location)
        if not point:
            continue
        spot_id = location.get("interactionSpotId") or location.get("activationSpotId") or location.get("spotId") or location.get("id")
        target = {
            "kind": "object-instance",
            "buildingId": building.get("id"),
            "objectInstanceId": object_id,
            "catalogId": catalog_id,
            "interactionSpotId": spot_id,
            "floor": location.get("floor") or obj.get("floor") or obj.get("buildingFloor") or 1,
        }
        target["furnitureIndex" if collection == "furniture" else "nodeIndex"] = index
        availability = get_object_availability(target, agent_id=agent_id, store=action_store, resolved=resolved)
        distance = math.hypot(float(point["x"]) - float(origin["x"]), float(point["y"]) - float(origin["y"]))
        interactions.append({
            "id": location.get("id") or spot_id,
            "actionId": location.get("actionId") or "",
            "interactionSpotId": spot_id or "",
            "roles": [str(item) for item in (location.get("roles") or [])[:8]],
            "position": {"x": round(float(point["x"]), 2), "y": round(float(point["y"]), 2), "floor": int(target["floor"])},
            "distance": round(distance, 2),
            "distanceTiles": round(distance / LIVE_AGENT_LOOP_API_TILE, 3),
            "availability": {k: availability.get(k) for k in ("state", "reason", "capacity", "reservationSlot")},
        })
    interactions.sort(key=lambda item: (item["distance"], item.get("id") or ""))
    return interactions[:6]


def _live_agent_loop_build_spatial_perception(agent_id, runtime_document=None):
    """Build a compact authoritative spatial snapshot for one resident."""
    runtime_doc = runtime_document if isinstance(runtime_document, dict) else _live_agent_runtime_document()
    positions = _live_agent_runtime_positions(runtime_doc)
    origin = _live_agent_runtime_position(agent_id, runtime_doc)
    now_iso = _utc_now_iso()
    base = {
        "schemaVersion": _live_agent_spatial.SPATIAL_SCHEMA_VERSION,
        "at": now_iso,
        "agentId": agent_id,
        "authority": {
            "source": "realtime-runtime-document",
            "available": bool(runtime_doc and origin),
            "runtimeSchemaVersion": (runtime_doc or {}).get("schemaVersion"),
            "runtimeUpdatedAt": (runtime_doc or {}).get("updatedAt"),
            "coordinateSystem": "api-units (1 tile = 40 units, +Y is world +Z)",
        },
        "config": {
            "awarenessRadiusTiles": _live_agent_spatial.DEFAULT_AWARENESS_RADIUS_TILES,
            "visualRadiusTiles": _live_agent_spatial.DEFAULT_VISUAL_RADIUS_TILES,
            "interactionRadiusTiles": _live_agent_spatial.DEFAULT_INTERACTION_RADIUS_TILES,
            "closeAwarenessRadiusTiles": _live_agent_spatial.DEFAULT_CLOSE_AWARENESS_RADIUS_TILES,
            "fieldOfViewDegrees": _live_agent_spatial.DEFAULT_FIELD_OF_VIEW_DEGREES,
            "conePolicy": "forward-attention-with-omnidirectional-close-awareness",
        },
        "self": origin,
        "place": None,
        "occupancy": {"buildingFloor": 0, "room": 0, "nearby": 0, "visible": 0},
        "route": {"active": False, "nearbyAgentBlockers": []},
        "nearbyAgents": [],
        "nearbyObjects": [],
        "visibleAgents": [],
        "visibleObjects": [],
        "interactableObjects": [],
        "summary": {"nearbyAgentCount": 0, "visibleAgentCount": 0, "nearbyObjectCount": 0, "visibleObjectCount": 0, "interactableObjectCount": 0},
        "resultSets": {
            key: {"total": 0, "returned": 0, "truncated": False}
            for key in ("nearbyAgents", "visibleAgents", "nearbyObjects", "visibleObjects", "interactableObjects")
        },
    }
    if not origin:
        base["authority"]["reason"] = "authoritative-runtime-position-unavailable"
        return base

    origin = {**origin, "floor": int(origin.get("floor") or 1), "roomId": origin.get("roomId") or ""}
    base["self"] = origin
    building = load_building(origin.get("buildingId")) if origin.get("buildingId") else None
    base["place"] = {
        "kind": "building" if origin.get("buildingId") else "outdoors",
        "buildingId": origin.get("buildingId") or "",
        "buildingName": (building or {}).get("name") or "",
        "floor": origin["floor"],
        "roomId": origin.get("roomId") or "",
    }

    status = load_agent_status()
    roster = [item for item in get_roster() if isinstance(item, dict)]
    seen_runtime_ids = set()
    agent_rows = []
    building_floor_occupants = []
    room_occupants = []
    for agent in roster:
        other_id = str(agent.get("statusKey") or agent.get("id") or "").strip()
        if not other_id:
            continue
        candidate_ids = [other_id, str(agent.get("id") or "").strip()]
        runtime_id = next((candidate for candidate in candidate_ids if candidate and candidate in positions), None)
        if not runtime_id or runtime_id in seen_runtime_ids:
            continue
        seen_runtime_ids.add(runtime_id)
        other = positions[runtime_id]
        same_building_floor = (
            int(other.get("floor") or 1) == origin["floor"]
            and str(other.get("buildingId") or "") == str(origin.get("buildingId") or "")
        )
        if same_building_floor:
            building_floor_occupants.append(other_id)
        same_room = same_building_floor and str(other.get("roomId") or "") == str(origin.get("roomId") or "")
        if same_room:
            room_occupants.append(other_id)
        if other_id == agent_id or str(agent.get("id") or "") == str(agent_id):
            continue
        line_of_sight = _live_agent_spatial_line_of_sight(building, origin, other, origin["floor"]) if same_building_floor and origin.get("buildingId") else True
        relation = _live_agent_spatial.spatial_relation(origin, other, line_of_sight=line_of_sight)
        if not relation.get("withinAwareness"):
            continue
        other_status = status.get(other_id, {}) or status.get(agent.get("id"), {}) or {}
        row = {
            "agentId": other_id,
            "name": agent.get("name") or other_id,
            "status": other_status.get("state", other_status.get("status", "offline")),
            "task": other_status.get("task", ""),
            "position": {k: other.get(k) for k in ("x", "y", "floor", "buildingId", "roomId", "heading", "state", "mode", "updatedAt")},
            **relation,
        }
        agent_rows.append(row)
    # A zero-distance resident/object is valid (for example two residents
    # restored to the same spawn point).  Do not use truthiness here: treating
    # 0.0 as infinity produces unstable ordering while bodies are moving.
    agent_rows.sort(key=lambda item: (
        float(item["distance"]) if item.get("distance") is not None else float("inf"),
        item.get("agentId") or "",
    ))
    base["nearbyAgents"] = agent_rows[:64]
    base["visibleAgents"] = [item for item in agent_rows if item.get("visible")][:32]

    runtime_objects = (runtime_doc or {}).get("objects") if isinstance((runtime_doc or {}).get("objects"), dict) else {}
    action_store = get_world_actions_store(persist_migration=True)
    object_rows = []
    for candidate_building in list_buildings():
        if not isinstance(candidate_building, dict) or _building_unavailable(candidate_building):
            continue
        collections = (
            ("furniture", ((candidate_building.get("interior") or {}).get("furniture") or [])),
            ("outdoor-node", ((candidate_building.get("outdoorArea") or {}).get("nodes") or [])),
        )
        for collection, records in collections:
            if not isinstance(records, list):
                continue
            outdoors = collection == "outdoor-node" or candidate_building.get("type") in {"park", "outdoor"}
            if outdoors and origin.get("buildingId"):
                continue
            if not outdoors and str(candidate_building.get("id") or "") != str(origin.get("buildingId") or ""):
                continue
            for index, obj in enumerate(records):
                if not isinstance(obj, dict):
                    continue
                floor = int(obj.get("floor") or obj.get("buildingFloor") or 1)
                point = _live_agent_spatial_location_point(candidate_building, obj)
                if not point:
                    continue
                target_position = {
                    "x": point["x"], "y": point["y"], "floor": floor,
                    "buildingId": "" if outdoors else candidate_building.get("id") or "",
                    "roomId": "" if outdoors else obj.get("room") or "",
                    "heading": 0,
                }
                same_building_floor = (not outdoors and origin.get("buildingId") == candidate_building.get("id") and origin["floor"] == floor)
                line_of_sight = _live_agent_spatial_line_of_sight(candidate_building, origin, target_position, floor) if same_building_floor else True
                relation = _live_agent_spatial.spatial_relation(origin, target_position, line_of_sight=line_of_sight)
                if not relation.get("withinAwareness"):
                    continue
                object_id = _live_agent_spatial_object_id(candidate_building, obj, index, collection)
                catalog_id = _object_catalog_id(obj) or "object"
                resolved = {"kind": "object-instance", "building": candidate_building, "object": obj, "collection": collection, "index": index, "candidateIds": sorted(_candidate_object_ids(candidate_building, obj, index, collection))}
                interactions = _live_agent_spatial_object_interactions(agent_id, candidate_building, obj, collection, index, object_id, catalog_id, origin, resolved, action_store)
                runtime_states = _live_agent_spatial_runtime_objects_for(runtime_objects, candidate_building.get("id"), collection, index, catalog_id, object_id)
                runtime_occupied_by = sorted({
                    item.get("agentId")
                    for item in runtime_states
                    if item.get("agentId")
                    and item.get("agentId") != agent_id
                    and str(item.get("state") or "").lower() in {"active", "in_use", "reserved", "using", "occupied"}
                })
                row = {
                    "objectInstanceId": object_id,
                    "catalogId": catalog_id,
                    "objectType": obj.get("type") or catalog_id,
                    "collection": collection,
                    "furnitureIndex": index if collection == "furniture" else None,
                    "nodeIndex": index if collection != "furniture" else None,
                    "buildingId": candidate_building.get("id") or "",
                    "buildingName": candidate_building.get("name") or "",
                    "floor": floor,
                    "roomId": obj.get("room") or "",
                    "position": {"x": round(float(point["x"]), 2), "y": round(float(point["y"]), 2), "floor": floor},
                    "interactions": interactions,
                    "runtimeStates": runtime_states,
                    "occupiedByAgentIds": sorted({item.get("agentId") for item in runtime_states if item.get("agentId")}),
                    "runtimeOccupied": bool(runtime_occupied_by),
                    "runtimeOccupiedByAgentIds": runtime_occupied_by,
                    **relation,
                }
                row["nearestInteraction"] = interactions[0] if interactions else None
                row["interactionReady"] = bool(
                    relation.get("interactionReady")
                    and not runtime_occupied_by
                    and any((item.get("availability") or {}).get("state") == "available" for item in interactions)
                )
                object_rows.append(row)
    object_rows.sort(key=lambda item: (
        float(item["distance"]) if item.get("distance") is not None else float("inf"),
        item.get("objectInstanceId") or "",
    ))
    base["nearbyObjects"] = object_rows[:128]
    base["visibleObjects"] = [item for item in object_rows if item.get("visible")][:64]
    base["interactableObjects"] = [item for item in object_rows if item.get("interactionReady")][:32]

    route_target = origin.get("target") if isinstance(origin.get("target"), dict) else None
    route_target_position = None
    if route_target and _float_or_none(route_target.get("x")) is not None:
        route_target_position = {
            "x": float(route_target.get("x")),
            "y": float(route_target.get("y") if route_target.get("y") is not None else route_target.get("z")),
            "floor": int(route_target.get("floor") or origin["floor"]),
            "buildingId": route_target.get("buildingId") or "",
            "roomId": route_target.get("roomId") or "",
            "heading": route_target.get("heading") or 0,
        }
    route = {
        "active": bool(origin.get("routeId") or origin.get("leaseOwner") or route_target_position),
        "routeId": origin.get("routeId") or "",
        "worldActionId": origin.get("worldActionId") or "",
        "state": origin.get("state") or "",
        "mode": origin.get("mode") or "",
        "owner": origin.get("owner") or "",
        "leaseOwner": origin.get("leaseOwner") or "",
        "leaseExpiresAt": origin.get("leaseExpiresAt") or "",
        "target": route_target,
        "distanceToTarget": None,
        "distanceToTargetTiles": None,
        "nearbyAgentBlockers": [],
    }
    if route_target_position:
        route_distance = math.hypot(origin["x"] - route_target_position["x"], origin["y"] - route_target_position["y"])
        route["distanceToTarget"] = round(route_distance, 2)
        route["distanceToTargetTiles"] = round(route_distance / LIVE_AGENT_LOOP_API_TILE, 3)
        blockers = []
        for item in agent_rows:
            distance_to_route = _live_agent_spatial.point_to_segment_distance(item.get("position"), origin, route_target_position)
            if distance_to_route is None or distance_to_route > LIVE_AGENT_LOOP_API_TILE * 0.9:
                continue
            blockers.append({"agentId": item.get("agentId"), "name": item.get("name"), "distanceToRoute": round(distance_to_route, 2), "distanceToRouteTiles": round(distance_to_route / LIVE_AGENT_LOOP_API_TILE, 3), "distance": item.get("distance")})
        blockers.sort(key=lambda item: (item.get("distanceToRoute"), item.get("distance")))
        route["nearbyAgentBlockers"] = blockers[:8]
    base["route"] = route
    base["occupancy"] = {
        "buildingFloor": len(set(building_floor_occupants)),
        "room": len(set(room_occupants)),
        "nearby": len(agent_rows),
        "visible": sum(bool(item.get("visible")) for item in agent_rows),
        "buildingFloorAgentIds": sorted(set(building_floor_occupants))[:32],
        "roomAgentIds": sorted(set(room_occupants))[:32],
    }
    base["summary"] = {
        "nearbyAgentCount": len(agent_rows),
        "visibleAgentCount": sum(bool(item.get("visible")) for item in agent_rows),
        "nearbyObjectCount": len(object_rows),
        "visibleObjectCount": sum(bool(item.get("visible")) for item in object_rows),
        "interactableObjectCount": sum(bool(item.get("interactionReady")) for item in object_rows),
    }
    base["resultSets"] = {
        "nearbyAgents": {"total": len(agent_rows), "returned": len(base["nearbyAgents"]), "truncated": len(agent_rows) > len(base["nearbyAgents"])},
        "visibleAgents": {"total": base["summary"]["visibleAgentCount"], "returned": len(base["visibleAgents"]), "truncated": base["summary"]["visibleAgentCount"] > len(base["visibleAgents"])},
        "nearbyObjects": {"total": len(object_rows), "returned": len(base["nearbyObjects"]), "truncated": len(object_rows) > len(base["nearbyObjects"])},
        "visibleObjects": {"total": base["summary"]["visibleObjectCount"], "returned": len(base["visibleObjects"]), "truncated": base["summary"]["visibleObjectCount"] > len(base["visibleObjects"])},
        "interactableObjects": {"total": base["summary"]["interactableObjectCount"], "returned": len(base["interactableObjects"]), "truncated": base["summary"]["interactableObjectCount"] > len(base["interactableObjects"])},
    }
    return base


def get_live_agent_spatial_perception(agent_id):
    resolved_agent_id = _resolve_agent_id(agent_id)
    if not resolved_agent_id:
        return False, _api_error("agent_not_found", "Agent was not found.", details={"agentId": agent_id}), 404
    return True, {"ok": True, "spatialPerception": _live_agent_loop_build_spatial_perception(resolved_agent_id)}, 200


def _live_agent_building_local_api_point(building, local_x, local_z):
    if not isinstance(building, dict):
        return None
    base_x = _float_or_none(building.get("worldX") if building.get("worldX") is not None else building.get("x"))
    base_z = _float_or_none(building.get("worldY") if building.get("worldY") is not None else building.get("z"))
    width = _float_or_none(building.get("widthTiles") if building.get("widthTiles") is not None else building.get("width"))
    depth = _float_or_none(building.get("heightTiles") if building.get("heightTiles") is not None else building.get("depth"))
    if base_x is None or base_z is None or width is None or depth is None:
        return None
    try:
        lx = float(local_x)
        lz = float(local_z)
    except (TypeError, ValueError):
        return None
    rotation = int(round(_float_or_none(building.get("_rotation") if building.get("_rotation") is not None else building.get("rotation")) or 0)) % 360
    if rotation == 90:
        world_x = base_x + depth - lz
        world_z = base_z + lx
    elif rotation == 180:
        world_x = base_x + width - lx
        world_z = base_z + depth - lz
    elif rotation == 270:
        world_x = base_x + lz
        world_z = base_z + width - lx
    else:
        world_x = base_x + lx
        world_z = base_z + lz
    return {"x": world_x * LIVE_AGENT_LOOP_API_TILE, "y": world_z * LIVE_AGENT_LOOP_API_TILE}


def _live_agent_building_target_point(building):
    if not isinstance(building, dict):
        return None
    width = _float_or_none(building.get("widthTiles") if building.get("widthTiles") is not None else building.get("width")) or 10
    depth = _float_or_none(building.get("heightTiles") if building.get("heightTiles") is not None else building.get("depth")) or 8
    spec = building.get("doorSpec") if isinstance(building.get("doorSpec"), dict) else {}

    def clamp_number(value, minimum, maximum, fallback):
        parsed = _float_or_none(value)
        if parsed is None:
            return fallback
        return min(maximum, max(minimum, parsed))

    local_center_x = clamp_number(spec.get("localCenterX"), 0, width, max(1, min(width - 1, width / 2)))
    local_interior_z = clamp_number(spec.get("localInteriorZ"), 0.2, max(0.2, depth - 0.2), max(0.45, depth - 1.2))
    return _live_agent_building_local_api_point(building, local_center_x, local_interior_z)


def _live_agent_loop_street_sidewalk_tile(wx, wz, streets=None):
    try:
        x = int(round(float(wx)))
        z = int(round(float(wz)))
    except (TypeError, ValueError):
        return False
    sidewalk = False
    if streets is None:
        meta = load_world_meta()
        streets = ensure_checkpoint_streets(meta, persist=False)
    for street in streets if isinstance(streets, list) else []:
        if not isinstance(street, dict):
            continue
        x1 = _float_or_none(street.get("x1"))
        z1 = _float_or_none(street.get("z1"))
        x2 = _float_or_none(street.get("x2"))
        z2 = _float_or_none(street.get("z2"))
        if x1 is None or z1 is None:
            continue
        if street.get("type"):
            dx = abs(x - int(round(x1)))
            dz = abs(z - int(round(z1)))
            if dx <= 4 and dz <= 4:
                return False
            if dx <= 6 and dz <= 6:
                sidewalk = True
            continue
        if x2 is None or z2 is None:
            continue
        min_x, max_x = sorted((int(round(x1)), int(round(x2))))
        min_z, max_z = sorted((int(round(z1)), int(round(z2))))
        horizontal = abs(x2 - x1) >= abs(z2 - z1)
        if horizontal:
            if min_x <= x <= max_x:
                dz = abs(z - int(round(z1)))
                if dz <= 1:
                    return False
                if dz <= 3:
                    sidewalk = True
            if (abs(x - int(round(x1))) <= 3 or abs(x - int(round(x2))) <= 3) and abs(z - int(round(z1))) <= 3:
                if abs(z - int(round(z1))) <= 1:
                    return False
                sidewalk = True
        else:
            if min_z <= z <= max_z:
                dx = abs(x - int(round(x1)))
                if dx <= 1:
                    return False
                if dx <= 3:
                    sidewalk = True
            if (abs(z - int(round(z1))) <= 3 or abs(z - int(round(z2))) <= 3) and abs(x - int(round(x1))) <= 3:
                if abs(x - int(round(x1))) <= 1:
                    return False
                sidewalk = True
    return sidewalk


def _live_agent_loop_nearest_street_sidewalk_tile(wx, wz, radius=96):
    try:
        x = int(round(float(wx)))
        z = int(round(float(wz)))
    except (TypeError, ValueError):
        return None
    meta = load_world_meta()
    streets = ensure_checkpoint_streets(meta, persist=False)
    best = None
    best_dist = float("inf")
    r = max(1, int(radius or 96))
    for dz in range(-r, r + 1):
        for dx in range(-r, r + 1):
            if not _live_agent_loop_street_sidewalk_tile(x + dx, z + dz, streets=streets):
                continue
            dist = dx * dx + dz * dz
            if dist < best_dist:
                best = {"x": x + dx, "y": z + dz}
                best_dist = dist
    return best


def _live_agent_loop_construction_route_point(action, source, fallback):
    if str((action or {}).get("actionType") or (action or {}).get("actionId") or "") != "world.buildStructure":
        return None
    target = (action or {}).get("target") if isinstance((action or {}).get("target"), dict) else {}
    route = (action or {}).get("route") if isinstance((action or {}).get("route"), dict) else {}
    route_target = route.get("target") if isinstance(route.get("target"), dict) else {}
    params = (action or {}).get("params") if isinstance((action or {}).get("params"), dict) else {}
    site = None
    for candidate in (params.get("buildSite"), source.get("buildSite") if isinstance(source, dict) else None, target.get("buildSite"), route_target.get("buildSite")):
        if isinstance(candidate, dict):
            site = candidate
            break
    if not site:
        return None
    street_approach = site.get("streetApproach") if isinstance(site.get("streetApproach"), dict) else None
    if not street_approach and isinstance(source, dict) and isinstance(source.get("streetApproach"), dict):
        street_approach = source.get("streetApproach")
    approach_tile = street_approach.get("approachTile") if isinstance(street_approach, dict) and isinstance(street_approach.get("approachTile"), dict) else None
    if approach_tile:
        tile_x = _float_or_none(approach_tile.get("x"))
        tile_y = _float_or_none(approach_tile.get("y") if approach_tile.get("y") is not None else approach_tile.get("z"))
        if tile_x is not None and tile_y is not None:
            return {
                "x": float(tile_x) * LIVE_AGENT_LOOP_API_TILE,
                "y": float(tile_y) * LIVE_AGENT_LOOP_API_TILE,
                "kind": "world-point",
                "buildingId": "",
                "constructionApproachSource": street_approach.get("source") or "street-approach",
            }
    raw_x = _float_or_none((fallback or {}).get("x")) if isinstance(fallback, dict) else None
    raw_y = _float_or_none((fallback or {}).get("y")) if isinstance(fallback, dict) else None
    if raw_x is not None and raw_y is not None:
        tile_x = round(raw_x / LIVE_AGENT_LOOP_API_TILE)
        tile_y = round(raw_y / LIVE_AGENT_LOOP_API_TILE)
    else:
        tile_x = round((_float_or_none(site.get("worldX")) or 0) + ((_float_or_none(site.get("widthTiles")) or 10) / 2))
        tile_y = round((_float_or_none(site.get("worldY")) or 0) + (_float_or_none(site.get("heightTiles")) or 8) + 2)
    sidewalk = _live_agent_loop_nearest_street_sidewalk_tile(tile_x, tile_y, radius=96)
    if not sidewalk:
        return None
    return {
        "x": float(sidewalk["x"]) * LIVE_AGENT_LOOP_API_TILE,
        "y": float(sidewalk["y"]) * LIVE_AGENT_LOOP_API_TILE,
        "kind": "world-point",
        "buildingId": "",
        "constructionApproachSource": "nearest-sidewalk-construction-route",
    }


def _live_agent_action_target_point(action):
    """Resolve the intended world coordinates of an active world action."""
    if not isinstance(action, dict):
        return None
    target = action.get("target") if isinstance(action.get("target"), dict) else {}
    route = action.get("route") if isinstance(action.get("route"), dict) else {}
    for source in (route.get("finalTarget"), route.get("target"), target, target.get("point")):
        if not isinstance(source, dict):
            continue
        x, y = source.get("x"), source.get("y")
        if isinstance(x, (int, float)) and isinstance(y, (int, float)):
            raw = {"x": float(x), "y": float(y), "kind": target.get("kind"), "buildingId": target.get("buildingId") or source.get("buildingId") or ""}
            return _live_agent_loop_construction_route_point(action, source, raw) or raw
    target_kind = str(target.get("kind") or target.get("targetKind") or "").strip()
    if target_kind == "object-instance":
        point = _live_agent_loop_target_interaction_point(target)
        if point:
            return {
                "x": float(point["x"]),
                "y": float(point["y"]),
                "kind": target_kind,
                "buildingId": target.get("buildingId") or "",
            }
    if target_kind in {"building", "room", "agent-home-building"}:
        building_id = target.get("buildingId")
        building = load_building(building_id) if building_id else None
        point = _live_agent_building_target_point(building)
        if point:
            return {
                "x": float(point["x"]),
                "y": float(point["y"]),
                "kind": target_kind or "building",
                "buildingId": building.get("id") or building_id or "",
            }
    return None


def _live_agent_loop_location_frame(agent_id, active_records=None):
    """Location awareness frame: where the body is, where it should be heading,
    and how far away that is. Used by perception and the route progress watchdog."""
    position = _live_agent_runtime_position(agent_id)
    frame = {
        "schemaVersion": "agent-live-mode-location/v1",
        "position": position,
        "positionSource": "realtime-runtime-document" if position else "unavailable",
        "activeTarget": None,
        "distanceToTarget": None,
        "coordinateSystem": "api-units (1 tile = 40 units, origin-centered world plane)",
    }
    records = active_records if isinstance(active_records, list) else _active_behavior_records_for_agent(agent_id)
    for item in records:
        record = item.get("record") if isinstance(item.get("record"), dict) else None
        point = _live_agent_action_target_point(record)
        if point:
            frame["activeTarget"] = {**point, "worldActionId": item.get("id"), "status": item.get("status")}
            break
    if position and frame["activeTarget"]:
        frame["distanceToTarget"] = round(math.hypot(position["x"] - frame["activeTarget"]["x"], position["y"] - frame["activeTarget"]["y"]), 2)
    return frame


def _live_agent_loop_monitor_route_progress(state, agent_id, agent_state, active_records, now_epoch, now_iso):
    """Watchdog: sample distance-to-target while an agent-live-mode action routes.
    If the agent stops making progress toward the intended coordinates, cancel the
    stalled action so the next tick replans with a fresh route/target."""
    routing_record = None
    for item in active_records:
        if item.get("behaviorSourceKind") != "agent-live-mode":
            continue
        if item.get("type") == "world-action" and item.get("status") in {"route_pending", "routing"}:
            routing_record = item
            break
    if not routing_record:
        agent_state.pop("routeProgress", None)
        return None

    location = _live_agent_loop_location_frame(agent_id, active_records)
    position = location.get("position")
    target = location.get("activeTarget")
    distance = location.get("distanceToTarget")
    if not position or not target or distance is None:
        return None

    progress = agent_state.get("routeProgress") if isinstance(agent_state.get("routeProgress"), dict) else None
    if not progress or progress.get("worldActionId") != routing_record.get("id"):
        progress = {"worldActionId": routing_record.get("id"), "samples": [], "startedAt": now_iso}
    samples = [s for s in progress.get("samples", []) if isinstance(s, dict)]
    samples.append({"atEpoch": round(now_epoch, 1), "distance": distance, "x": position["x"], "y": position["y"]})
    samples = samples[-LIVE_AGENT_ROUTE_PROGRESS_SAMPLE_LIMIT:]
    progress["samples"] = samples
    progress["lastDistance"] = distance
    progress["lastCheckedAt"] = now_iso
    agent_state["routeProgress"] = progress

    if distance <= LIVE_AGENT_ROUTE_ARRIVAL_RADIUS:
        return None
    window = [s for s in samples if now_epoch - float(s.get("atEpoch") or 0) <= LIVE_AGENT_ROUTE_PROGRESS_WINDOW_SEC]
    if len(window) < LIVE_AGENT_ROUTE_PROGRESS_MIN_SAMPLES:
        return None
    span_sec = now_epoch - float(window[0].get("atEpoch") or now_epoch)
    if span_sec < LIVE_AGENT_ROUTE_PROGRESS_WINDOW_SEC * 0.8:
        return None
    best_earlier = max(float(s.get("distance") or 0) for s in window[:-1])
    improvement = best_earlier - distance
    if improvement >= LIVE_AGENT_ROUTE_PROGRESS_MIN_IMPROVEMENT:
        return None

    # Stuck: no meaningful progress toward the intended coordinates.
    detail = {
        "agentId": agent_id,
        "worldActionId": routing_record.get("id"),
        "distance": distance,
        "improvement": round(improvement, 2),
        "windowSec": round(span_sec, 1),
        "samples": len(window),
        "target": {k: target.get(k) for k in ("x", "y", "kind", "buildingId")},
        "position": {k: position.get(k) for k in ("x", "y", "buildingId")},
    }
    ok, response, status_code = cancel_world_action(routing_record.get("id"), {
        "failureReason": "cancelled_by_system",
        "reason": "cancelled_by_system",
        "actor": "live-mode-route-watchdog",
        "source": "agent-live-mode",
        "result": {"status": "cancelled", "reason": "no_route_progress", "watchdog": detail},
    })
    detail["cancelled"] = bool(ok)
    detail["httpStatus"] = status_code
    agent_state.pop("routeProgress", None)
    agent_state["nextAllowedAt"] = _epoch_to_utc_iso(now_epoch + 20)
    _live_agent_loop_stat(agent_state, "routeWatchdogCancels")
    _live_agent_loop_add_event(state, "route-watchdog-cancel", agent_id=agent_id, details=detail)
    _live_agent_loop_add_feedback(state, agent_id, "warn", "Route made no progress toward the intended coordinates; the action was cancelled so the agent can replan.", detail)
    return detail


def _live_agent_loop_resource_category(obj):
    catalog_id = str((obj or {}).get("catalogId") or (obj or {}).get("objectType") or "object")
    return "seating" if _live_agent_loop_seating_action_for_catalog(catalog_id) else (_normalize_token(catalog_id) or "object")


def _update_resident_profile_atomically(agent_id, mutate):
    """Apply one grounded Resident Profile update without lock inversion.

    Agent/roster resolution and template discovery can consult framework and
    building state, so they happen before the world-meta lock. Only the final
    fresh profile read, mutation, and save are serialized.
    """
    resolved_agent_id = _resolve_agent_id(agent_id)
    if not resolved_agent_id or not callable(mutate):
        return None
    snapshot = load_world_meta()
    snapshot_profiles = snapshot.get("agentProfiles") if isinstance(snapshot.get("agentProfiles"), dict) else {}
    snapshot_profile = snapshot_profiles.get(resolved_agent_id) if isinstance(snapshot_profiles.get(resolved_agent_id), dict) else {}
    template = _default_resident_profile(resolved_agent_id, snapshot, snapshot_profile)
    with _WORLD_META_LOCK:
        meta = load_world_meta()
        profiles = meta.get("agentProfiles") if isinstance(meta.get("agentProfiles"), dict) else {}
        profile = dict(profiles.get(resolved_agent_id) if isinstance(profiles.get(resolved_agent_id), dict) else snapshot_profile)
        current = profile.get("residentProfile") if isinstance(profile.get("residentProfile"), dict) else template
        resident_profile = _sanitize_resident_profile(current, template, touch=False)
        result = mutate(resident_profile)
        profile["residentProfile"] = _sanitize_resident_profile(resident_profile, template, touch=True)
        profiles[resolved_agent_id] = profile
        meta["agentProfiles"] = profiles
        save_world_meta(meta)
    return result if result is not None else profile["residentProfile"]


def _live_agent_loop_remember_resource_signal(agent_id, signal):
    if not isinstance(signal, dict) or int(signal.get("observationCount") or 0) < 2:
        return None
    text = str(signal.get("memoryText") or signal.get("text") or "A shared world resource has repeatedly been unavailable.")[:900]
    record = {
        "id": f"resource-signal-{hashlib.sha256(str(signal.get('key') or text).encode('utf-8', errors='ignore')).hexdigest()[:16]}",
        "at": signal.get("lastObservedAt") or _utc_now_iso(),
        "text": text,
        "lesson": text,
        "source": "live-agent-resource-observation",
        "importance": 0.84,
        "unresolved": True,
        "resourceCategory": signal.get("category"),
        "objectInstanceId": signal.get("objectInstanceId"),
        "observationCount": signal.get("observationCount"),
        "occupiedByAgentIds": signal.get("occupiedByAgentIds") or [],
    }

    def remember(resident_profile):
        memory = dict(resident_profile.get("memory") or {})
        memory["shortTerm"] = _live_agent_loop_append_resident_memory(memory.get("shortTerm"), record, RESIDENT_PROFILE_LIST_LIMIT)
        memory["reflections"] = _live_agent_loop_append_resident_memory(memory.get("reflections"), {**record, "id": record["id"] + "-reflection"}, RESIDENT_PROFILE_MEMORY_LIMIT)
        resident_profile["memory"] = _consolidate_resident_memory(memory)
        return record

    return _update_resident_profile_atomically(agent_id, remember)


def _live_agent_loop_record_resource_signals(agent_id, agent_state, spatial, *, now_epoch=None):
    if not isinstance(agent_state, dict) or not isinstance(spatial, dict):
        return []
    now_epoch = float(now_epoch or time.time())
    now_iso = _epoch_to_utc_iso(now_epoch)
    objects = [item for item in (spatial.get("nearbyObjects") or []) if isinstance(item, dict) and item.get("perceived")]
    available_by_category = {}
    for obj in objects:
        category = _live_agent_loop_resource_category(obj)
        is_available = not obj.get("runtimeOccupied") and any(
            isinstance(interaction, dict)
            and isinstance(interaction.get("availability"), dict)
            and interaction["availability"].get("state") == "available"
            for interaction in (obj.get("interactions") or [])
        )
        if is_available:
            available_by_category[category] = int(available_by_category.get(category) or 0) + 1
    signals = agent_state.get("resourceSignals") if isinstance(agent_state.get("resourceSignals"), dict) else {}
    changed = []
    for obj in objects:
        interactions = [item for item in (obj.get("interactions") or []) if isinstance(item, dict) and isinstance(item.get("availability"), dict)]
        unavailable = next((item for item in interactions if item["availability"].get("state") in {"reserved", "in_use", "blocked", "disabled"}), None)
        if not unavailable and not obj.get("runtimeOccupied"):
            continue
        availability = unavailable.get("availability") if unavailable else {}
        state_name = "in_use" if obj.get("runtimeOccupied") else str(availability.get("state") or "unavailable")
        category = _live_agent_loop_resource_category(obj)
        object_id = str(obj.get("objectInstanceId") or obj.get("catalogId") or "object")
        key = f"{category}:{object_id}"
        occupants = sorted({str(value) for value in [*(obj.get("runtimeOccupiedByAgentIds") or []), *(obj.get("occupiedByAgentIds") or []), *[row.get("agentId") for row in (availability.get("conflicts") or []) if isinstance(row, dict)]] if value and str(value) != str(agent_id)})
        signature = hashlib.sha256(json.dumps({"state": state_name, "occupants": occupants, "alternatives": available_by_category.get(category, 0)}, sort_keys=True).encode("utf-8")).hexdigest()[:16]
        previous = signals.get(key) if isinstance(signals.get(key), dict) else {}
        last_epoch = float(previous.get("lastObservedEpoch") or 0)
        if previous.get("signature") == signature and now_epoch - last_epoch < 300:
            continue
        count = int(previous.get("observationCount") or 0) + 1
        label = str(obj.get("objectType") or obj.get("catalogId") or "resource").replace("-", " ")
        alternatives = int(available_by_category.get(category) or 0)
        text_value = f"The {label} is currently {state_name.replace('_', ' ')}"
        if occupants:
            text_value += f" by {', '.join(occupants)}"
        text_value += f". I can see {alternatives} available alternative{'s' if alternatives != 1 else ''}."
        memory_text = f"The {category} resource has been unavailable on {count} separate observations; there were {alternatives} available alternatives on the latest observation."
        row = {
            **previous,
            "key": key,
            "category": category,
            "objectInstanceId": object_id,
            "catalogId": obj.get("catalogId"),
            "state": state_name,
            "signature": signature,
            "observationCount": count,
            "firstObservedAt": previous.get("firstObservedAt") or now_iso,
            "lastObservedAt": now_iso,
            "lastObservedEpoch": now_epoch,
            "occupiedByAgentIds": occupants,
            "availableAlternatives": alternatives,
            "text": text_value,
            "memoryText": memory_text,
        }
        if count >= 2 and not previous.get("memoryRecordedAt"):
            remembered = _live_agent_loop_remember_resource_signal(agent_id, row)
            if remembered:
                row["memoryRecordedAt"] = now_iso
                row["memoryId"] = remembered.get("id")
                _live_agent_loop_add_support_request(
                    agent_state,
                    "internal-note",
                    f"Repeated resource shortage: {memory_text} Consider telling another resident or asking the operator for another resource.",
                    source="resource-signal",
                )
        signals[key] = row
        changed.append(row)
    agent_state["resourceSignals"] = signals
    if changed:
        _live_agent_session_update(agent_id, working_memory={"resourceSignals": _compact_json_value_for_storage(signals, max_depth=4, max_items=32, string_limit=600)})
    return changed


def _live_agent_loop_build_perception(agent_id, agent_state, world_client=None, now_epoch=None):
    now_epoch = float(now_epoch or time.time())
    previous_perception = agent_state.get("lastPerception") if isinstance(agent_state.get("lastPerception"), dict) else {}
    _live_agent_loop_ingest_coder_feedback(agent_id, agent_state)
    needs = _live_agent_loop_update_needs(agent_state, now_epoch)
    active = _active_behavior_records_for_agent(agent_id)
    runtime_document = _live_agent_runtime_document()
    spatial = _live_agent_loop_build_spatial_perception(agent_id, runtime_document=runtime_document)
    _live_agent_loop_record_resource_signals(agent_id, agent_state, spatial, now_epoch=now_epoch)
    affordances = _live_agent_loop_action_affordances(agent_id, agent_state, spatial=spatial)
    recent_actions = _live_agent_loop_recent_world_actions(agent_id)
    memory = agent_state.get("memory") if isinstance(agent_state.get("memory"), dict) else {}
    social = _live_agent_loop_social_perception(agent_id, spatial=spatial)
    resident_context = _live_agent_loop_resident_profile_context(_live_agent_loop_resident_profile(agent_id, persist=True))
    location = _live_agent_loop_location_frame(agent_id, active)
    live_world = _agent_live_world_claim_payload(agent_id)
    available_action_ids = [item["id"] for item in affordances if item.get("available")]
    active_signature = [f"{item.get('type')}:{item.get('id')}:{item.get('status')}" for item in active if isinstance(item, dict)]
    current_position = location.get("position") if isinstance(location, dict) and isinstance(location.get("position"), dict) else {}
    position_signature = "|".join(str(current_position.get(key) or "") for key in ("x", "y", "floor", "buildingId", "roomId"))
    held = (agent_state.get("inventory") or {}).get("held") if isinstance(agent_state.get("inventory"), dict) and isinstance((agent_state.get("inventory") or {}).get("held"), dict) else None
    held_signature = str((held or {}).get("id") or "")
    delta_reasons = []
    if previous_perception:
        if previous_perception.get("availableActionIds") != available_action_ids:
            delta_reasons.append("available interactions changed")
        if previous_perception.get("activeSignature") != active_signature:
            delta_reasons.append("physical action state changed")
        if previous_perception.get("positionSignature") != position_signature:
            delta_reasons.append("authoritative position changed")
        if previous_perception.get("heldItemSignature") != held_signature:
            delta_reasons.append("carried item changed")
        previous_social = previous_perception.get("social") if isinstance(previous_perception.get("social"), dict) else {}
        if previous_social.get("nearbyAgentCount") != social.get("nearbyAgentCount"):
            delta_reasons.append("nearby residents changed")
    perception_delta = {
        "changed": bool(delta_reasons),
        "reason": "; ".join(delta_reasons[:6]) if delta_reasons else "no meaningful semantic change",
        "changes": delta_reasons[:6],
    }
    agent_state["perceptionDelta"] = perception_delta
    perception = {
        "schemaVersion": "agent-live-mode-perception/v1",
        "at": _epoch_to_utc_iso(now_epoch),
        "agent": _live_agent_loop_agent_snapshot(agent_id),
        "location": location,
        "liveWorld": live_world,
        "worldClient": world_client if isinstance(world_client, dict) else _live_agent_loop_world_client_status(),
        "needs": needs,
        "active": [{k: item.get(k) for k in ("type", "id", "status", "worldActionId", "behaviorSourceKind")} for item in active],
        "affordances": [{k: v for k, v in affordance.items() if k != "selected"} for affordance in affordances],
        "recentWorldActions": recent_actions,
        "visibleActionContract": _live_agent_visible_action_policy(),
        "spatial": spatial,
        "social": social,
        "memory": {
            "recentActions": _live_agent_loop_trim_list(memory.get("recentActions"), 8),
            "observations": _live_agent_loop_trim_list(memory.get("observations"), 6),
            "reflections": _live_agent_loop_trim_list(memory.get("reflections"), 6),
            "internalNotes": _live_agent_loop_recent_internal_notes(agent_id, limit=6),
        },
        "residentProfile": resident_context,
        "world": _live_agent_loop_world_summary(),
        "delta": perception_delta,
    }
    agent_state["lastPerception"] = {
        "at": perception["at"],
        "needs": needs,
        "availableActionIds": available_action_ids,
        "activeCount": len(active),
        "activeSignature": active_signature,
        "positionSignature": position_signature,
        "heldItemSignature": held_signature,
        "recentWorldActionIds": [item.get("id") for item in recent_actions[:4]],
        "social": {k: social.get(k) for k in ("knownAgentCount", "liveEnabledPeerCount", "nearbyAgentCount")},
        "spatial": _copy_jsonable(spatial.get("summary") or {}),
        "liveWorld": {k: live_world.get(k) for k in ("currentWorld", "conflict", "notice")},
    }
    return perception


def _live_agent_loop_decision_score(affordance, agent_state, goal_frame=None):
    need_key = affordance.get("need") or "curiosity"
    needs = agent_state.get("needs") if isinstance(agent_state.get("needs"), dict) else LIVE_AGENT_LOOP_NEED_DEFAULTS
    goal_frame = goal_frame if isinstance(goal_frame, dict) else {}
    context = goal_frame.get("context") if isinstance(goal_frame.get("context"), dict) else {}
    personality = context.get("personality") if isinstance(context.get("personality"), dict) else {}
    recent = goal_frame.get("recentOutcomes") if isinstance(goal_frame.get("recentOutcomes"), dict) else {}
    loop_action_id = affordance.get("id")
    need_value = float(needs.get(need_key, 0.3))
    personality_multiplier = _live_agent_loop_personality_multiplier(need_key, personality)
    score = 0.25 + (need_value * personality_multiplier)
    need_items = []
    for key, value in (needs or {}).items():
        try:
            need_items.append((key, float(value or 0)))
        except (TypeError, ValueError):
            continue
    top_need_key, top_need_value = max(need_items, key=lambda item: item[1], default=(need_key, need_value))
    breakdown = {
        "base": 0.25,
        "need": round(need_value, 3),
        "personalityMultiplier": personality_multiplier,
        "urgency": 0,
        "goalAlignment": 0,
        "issues": 0,
        "context": 0,
        "plan": 0,
        "recentMemory": 0,
        "reliability": 0,
        "episodeSaturation": 0,
        "targetCooldown": 0,
        "proceduralLearning": 0,
    }
    if top_need_value >= LIVE_AGENT_CRITICAL_NEED_THRESHOLD:
        if need_key == top_need_key:
            boost = 0.62 + min(0.18, (top_need_value - LIVE_AGENT_CRITICAL_NEED_THRESHOLD) * 0.9)
            score += boost
            breakdown["urgency"] += boost
        elif top_need_key in {"hydration", "food", "energy"} and affordance.get("id") != "investigate-blocking-issue":
            penalty = 0.36
            score -= penalty
            breakdown["urgency"] -= penalty
    elif top_need_value >= LIVE_AGENT_HIGH_NEED_THRESHOLD and need_key == top_need_key:
        boost = 0.28
        score += boost
        breakdown["urgency"] += boost
    memory = agent_state.get("memory") if isinstance(agent_state.get("memory"), dict) else {}
    recent_ids = [item.get("loopActionId") for item in _live_agent_loop_trim_list(memory.get("recentActions"), 6)]
    if recent_ids and loop_action_id == recent_ids[-1]:
        score -= 0.42
        breakdown["recentMemory"] -= 0.42
    elif loop_action_id in recent_ids:
        score -= 0.18
        breakdown["recentMemory"] -= 0.18
    target_key = _live_agent_loop_target_key(affordance.get("target"))
    target_cooldowns = agent_state.get("targetCooldowns") if isinstance(agent_state.get("targetCooldowns"), dict) else {}
    cooldown_row = target_cooldowns.get(target_key) if target_key and isinstance(target_cooldowns.get(target_key), dict) else None
    cooldown_until = _parse_isoish_epoch((cooldown_row or {}).get("expiresAt") or (cooldown_row or {}).get("until")) or 0
    if cooldown_until > time.time():
        penalty = 2.4
        score -= penalty
        breakdown["targetCooldown"] -= penalty
        breakdown["reliability"] -= penalty
    procedural = agent_state.get("proceduralMemory") if isinstance(agent_state.get("proceduralMemory"), dict) else {}
    procedural_row = procedural.get(loop_action_id) if isinstance(procedural.get(loop_action_id), dict) else None
    if procedural_row and int(procedural_row.get("attempts") or 0) >= 2:
        reliability = max(0.0, min(1.0, float(procedural_row.get("successRate") or 0)))
        adjustment = round((reliability - 0.5) * 0.28, 3)
        score += adjustment
        breakdown["proceduralLearning"] += adjustment
        breakdown["reliability"] += adjustment
    is_support_tool = (
        affordance.get("targetKind") == "support-tool"
        or ((affordance.get("target") if isinstance(affordance.get("target"), dict) else {}).get("kind") == "support-tool")
    )
    repeat_sensitive = (
        not is_support_tool
        and bool(target_key)
        and (
            affordance.get("category")
            or affordance.get("genericWorldAffordance")
            or affordance.get("autonomyKind") in {"goal-work", "issue-investigation"}
            or loop_action_id in {"use-seating-object", "work-on-active-goal", "investigate-blocking-issue"}
        )
    )
    if repeat_sensitive:
        episode_counts = _live_agent_loop_verified_episode_counts(agent_state, loop_action_id=loop_action_id, target_key=target_key)
        category = str(affordance.get("category") or "").strip()
        completed_target = _live_agent_loop_target_verified(
            agent_state,
            target_key,
            loop_action_id=loop_action_id,
        )
        urgent_reuse = (
            top_need_value >= LIVE_AGENT_CRITICAL_NEED_THRESHOLD
            and need_key == top_need_key
            and need_key in {"hydration", "food", "energy"}
        )
        if completed_target:
            # Coverage work is saturated after authoritative verification. A
            # critical bodily need may still reuse the object, but curiosity
            # and testing goals must move to a genuinely untested target.
            penalty = 0.35 if urgent_reuse else 4.0
            score -= penalty
            breakdown["episodeSaturation"] -= penalty
            breakdown["reliability"] -= penalty
        elif int(episode_counts.get("sameTarget") or 0) > 0:
            penalty = min(2.4, 1.25 + (0.35 * (int(episode_counts.get("sameTarget") or 0) - 1)))
            score -= penalty
            breakdown["episodeSaturation"] -= penalty
            breakdown["reliability"] -= penalty
        elif int(episode_counts.get("sameAction") or 0) >= 3:
            penalty = min(1.2, 0.24 * (int(episode_counts.get("sameAction") or 0) - 2))
            score -= penalty
            breakdown["episodeSaturation"] -= penalty
            breakdown["reliability"] -= penalty
    if need_key in {"curiosity", "maintenance"}:
        score += 0.08
        breakdown["context"] += 0.08
    availability = affordance.get("availability") if isinstance(affordance.get("availability"), dict) else {}
    support_context = availability.get("context") if isinstance(availability.get("context"), dict) else {}
    if loop_action_id == "report-issue-to-coder" and support_context:
        boost = 0.62
        if support_context.get("kind") == "recent-issue":
            issue = support_context.get("issue") if isinstance(support_context.get("issue"), dict) else {}
            boost += min(0.32, 0.08 * int(issue.get("failureStreak") or 0))
        elif support_context.get("kind") == "critical-need":
            boost += 0.16
        score += boost
        breakdown["issues"] += boost
    if loop_action_id == "record-internal-note" and support_context:
        boost = 0.24 if support_context.get("kind") == "autonomy-plan" else 0.18
        score += boost
        breakdown["plan"] += boost
    for goal in goal_frame.get("goals") or []:
        if not isinstance(goal, dict):
            continue
        priority = float(goal.get("priority") or 0)
        if goal.get("kind") == "need" and goal.get("need") == need_key:
            boost = min(0.24, priority * 0.16)
            score += boost
            breakdown["goalAlignment"] += boost
        if goal.get("kind") == "resident-profile":
            boost = _live_agent_loop_resident_profile_goal_boost(goal, affordance)
            if boost:
                score += boost
                breakdown["goalAlignment"] += boost
        if goal.get("kind") == "issue":
            if loop_action_id in {"report-issue-to-coder", "investigate-blocking-issue"}:
                if loop_action_id == "report-issue-to-coder":
                    boost = min(1.08, max(0.72, priority + 0.10))
                else:
                    boost = min(0.78, max(0.42, priority * 0.72))
                if top_need_value >= LIVE_AGENT_CRITICAL_NEED_THRESHOLD and top_need_key in {"hydration", "food", "energy"}:
                    boost *= 0.55
                score += boost
                breakdown["issues"] += boost
            elif goal.get("loopActionId") == loop_action_id:
                penalty = min(0.90, max(0.24, priority * 0.72))
                score -= penalty
                breakdown["issues"] -= penalty
        if goal.get("id") == "home.establish-shelter" and loop_action_id == "build-small-home-site":
            score += 0.34
            breakdown["context"] += 0.34
        if goal.get("id") == "home.use-owned-home" and loop_action_id == "rest-at-home":
            score += 0.18
            breakdown["context"] += 0.18
        if goal.get("id") == "work.visit-assigned-work" and need_key in {"maintenance", "curiosity"}:
            score += 0.08
            breakdown["context"] += 0.08
        if goal.get("id") == "social.perceive-nearby-agent" and loop_action_id == "talk-with-nearby-agent":
            score += 0.36
            breakdown["context"] += 0.36
        if goal.get("id") == "social.maintain-relationships" and loop_action_id == "talk-with-nearby-agent":
            score += 0.16
            breakdown["context"] += 0.16
        if goal.get("kind") == "reliability" and goal.get("loopActionId") == loop_action_id:
            penalty = min(0.85, max(0.16, priority))
            score -= penalty
            breakdown["reliability"] -= penalty
        if goal.get("kind") == "plan" and goal.get("loopActionId") == loop_action_id:
            boost = min(0.70, max(0.24, priority))
            score += boost
            breakdown["plan"] += boost
        if goal.get("kind") == "inventory" and goal.get("loopActionId") == loop_action_id:
            boost = min(1.05, max(0.72, priority))
            score += boost
            breakdown["plan"] += boost
        if goal.get("kind") == "durable-goal" and goal.get("loopActionId") == loop_action_id:
            boost = min(0.86, max(0.38, priority))
            if top_need_value >= LIVE_AGENT_CRITICAL_NEED_THRESHOLD and need_key != top_need_key:
                boost *= 0.45
            score += boost
            breakdown["plan"] += boost
    action_summary = (recent.get("byAction") or {}).get(loop_action_id) if isinstance(recent.get("byAction"), dict) else None
    if isinstance(action_summary, dict):
        completed = int(action_summary.get("completed") or 0)
        unsuccessful = int(action_summary.get("failed") or 0) + int(action_summary.get("expired") or 0) + int(action_summary.get("cancelled") or 0)
        failure_streak = int(action_summary.get("recentFailureStreak") or 0)
        target_failures = (action_summary.get("targetFailures") or {}).get(target_key) if target_key and isinstance(action_summary.get("targetFailures"), dict) else None
        if isinstance(target_failures, dict) and int(target_failures.get("total") or 0) > 0:
            penalty = min(1.35, 0.55 + (0.25 * int(target_failures.get("total") or 0)))
            score -= penalty
            breakdown["reliability"] -= penalty
        if completed and not unsuccessful:
            score += 0.06
            breakdown["reliability"] += 0.06
        elif unsuccessful:
            penalty = min(1.15, (unsuccessful * 0.18) + (failure_streak * 0.20))
            score -= penalty
            breakdown["reliability"] -= penalty
    breakdown = {key: round(value, 3) if isinstance(value, (int, float)) else value for key, value in breakdown.items()}
    return round(score, 3), breakdown


def _live_agent_loop_compact_spatial_for_planner(spatial):
    if not isinstance(spatial, dict):
        return None

    def compact_agent(item):
        return {
            key: item.get(key)
            for key in (
                "agentId", "name", "status", "distanceTiles", "proximityBand", "sameRoom",
                "perceived", "inFieldOfView", "lineOfSight", "visible", "interactionReady", "occludedBy",
            )
        }

    def compact_object(item):
        # Nearby-object coordinates are awareness facts, not permission to
        # execute every catalog action.  Only surface an interaction here when
        # the same action has a typed Live Mode visible-executor contract and
        # the resident actually perceived the object.  The authoritative
        # candidate list remains the executable source of truth.
        interactions = item.get("interactions") if isinstance(item.get("interactions"), list) else []
        interaction = next((
            candidate
            for candidate in interactions
            if isinstance(candidate, dict)
            and item.get("perceived")
            and _live_agent_visible_action_contract(candidate.get("actionId"))
            and isinstance(candidate.get("availability"), dict)
            and (
                candidate["availability"].get("state") == "available"
                or (
                    isinstance(candidate["availability"].get("queueAvailability"), dict)
                    and candidate["availability"]["queueAvailability"].get("state") == "available"
                )
            )
        ), None)
        observed_interaction = next((
            candidate
            for candidate in interactions
            if isinstance(candidate, dict)
            and item.get("perceived")
            and _live_agent_visible_action_contract(candidate.get("actionId"))
            and isinstance(candidate.get("availability"), dict)
        ), None)
        observed_availability = observed_interaction.get("availability") if isinstance(observed_interaction, dict) else {}
        return {
            "objectInstanceId": item.get("objectInstanceId"),
            "catalogId": item.get("catalogId"),
            "objectType": item.get("objectType"),
            "buildingId": item.get("buildingId"),
            "floor": item.get("floor"),
            "roomId": item.get("roomId"),
            "distanceTiles": item.get("distanceTiles"),
            "proximityBand": item.get("proximityBand"),
            "inFieldOfView": item.get("inFieldOfView"),
            "perceived": item.get("perceived"),
            "lineOfSight": item.get("lineOfSight"),
            "visible": item.get("visible"),
            "interactionReady": item.get("interactionReady"),
            "occludedBy": item.get("occludedBy"),
            "occupiedByAgentIds": item.get("occupiedByAgentIds") or [],
            "runtimeOccupied": bool(item.get("runtimeOccupied")),
            "runtimeOccupiedByAgentIds": item.get("runtimeOccupiedByAgentIds") or [],
            "liveModeExecutable": bool(interaction),
            "observedInteraction": {
                "actionId": observed_interaction.get("actionId"),
                "interactionSpotId": observed_interaction.get("interactionSpotId"),
                "availability": observed_availability.get("state"),
                "reason": observed_availability.get("reason"),
                "conflicts": observed_availability.get("conflicts") or [],
                "queueAvailability": observed_availability.get("queueAvailability"),
            } if observed_interaction else None,
            "nearestExecutableInteraction": {
                "actionId": interaction.get("actionId"),
                "interactionSpotId": interaction.get("interactionSpotId"),
                "distanceTiles": interaction.get("distanceTiles"),
                "availability": (interaction.get("availability") or {}).get("state"),
            } if interaction else None,
        }

    route = spatial.get("route") if isinstance(spatial.get("route"), dict) else {}
    return {
        "schemaVersion": spatial.get("schemaVersion"),
        "authority": spatial.get("authority"),
        "self": spatial.get("self"),
        "place": spatial.get("place"),
        "occupancy": spatial.get("occupancy"),
        "summary": spatial.get("summary"),
        "route": {
            key: route.get(key)
            for key in ("active", "routeId", "worldActionId", "state", "mode", "owner", "leaseOwner", "distanceToTargetTiles", "nearbyAgentBlockers")
        },
        "nearbyAgents": [compact_agent(item) for item in (spatial.get("nearbyAgents") or [])[:8] if isinstance(item, dict)],
        "nearbyObjects": [compact_object(item) for item in (spatial.get("nearbyObjects") or [])[:12] if isinstance(item, dict)],
    }


def _live_agent_loop_build_decision_frame(agent_id, perception, agent_state):
    goal_frame = _live_agent_loop_build_goal_frame(agent_id, perception, agent_state)
    top_need = max((perception.get("needs") or {}).items(), key=lambda item: item[1], default=("curiosity", 0))
    coverage_active = _live_agent_loop_object_coverage_active(agent_id, goal_frame)
    carrying_item = isinstance(((agent_state.get("inventory") or {}).get("held")), dict)
    candidates = []
    for affordance in perception.get("affordances", []):
        if not affordance.get("available"):
            candidates.append({**affordance, "score": 0, "decision": "unavailable"})
            continue
        target = affordance.get("target") if isinstance(affordance.get("target"), dict) else {}
        target_key = _live_agent_loop_target_key(target)
        action_type = str(affordance.get("actionType") or "")
        required_carry_follow_up = carrying_item and any(token in action_type.lower() for token in ("rest", "sit", "lounge"))
        urgent_reuse = (
            float(top_need[1] or 0) >= LIVE_AGENT_CRITICAL_NEED_THRESHOLD
            and affordance.get("need") == top_need[0]
            and top_need[0] in {"hydration", "food", "energy", "shelter"}
        )
        if (
            coverage_active
            and target.get("kind") == "object-instance"
            and target_key
            and not required_carry_follow_up
            and not urgent_reuse
            and _live_agent_loop_target_verified(agent_state, target_key, loop_action_id=affordance.get("id"))
        ):
            candidates.append({
                **affordance,
                "score": 0,
                "decision": "unavailable",
                "reason": "target-already-verified-for-object-coverage",
            })
            continue
        score, score_breakdown = _live_agent_loop_decision_score(affordance, agent_state, goal_frame)
        candidates.append({**affordance, "score": score, "scoreBreakdown": score_breakdown, "decision": "candidate"})
    available = [candidate for candidate in candidates if candidate.get("decision") == "candidate"]
    available.sort(key=lambda item: (float(item.get("score") or 0), item.get("id") or ""), reverse=True)
    selected = available[0] if available else None
    frame = {
        "schemaVersion": "agent-live-mode-decision/v1",
        "at": perception.get("at"),
        "agentId": agent_id,
        "mode": LIVE_AGENT_LOOP_DEFAULTS["decisionMode"],
        "modelReady": True,
        "goalFrame": goal_frame,
        "spatialContext": _live_agent_loop_compact_spatial_for_planner(perception.get("spatial")),
        "visibleActionContract": {
            "schemaVersion": LIVE_AGENT_VISIBLE_ACTION_CONTRACT_VERSION,
            "policy": "visible-world-execution-required-or-explicit-support-tool",
            "hiddenWorldMutationAllowed": False,
            "proposalOnlyCapabilityIds": [item.get("id") for item in LIVE_AGENT_PROPOSAL_ONLY_CAPABILITIES],
            "supportToolCapabilityIds": ["live.note.internal", "live.report.coder"],
        },
        "topNeed": {"id": top_need[0], "value": top_need[1]},
        "selectedActionId": selected.get("id") if selected else None,
        "selectedActionLabel": selected.get("label") if selected else None,
        "score": selected.get("score") if selected else 0,
        "candidates": candidates,
        "prompt": "Choose one available visible in-world action or explicit support tool from this planner-v2 frame. Consider needs, personality, Resident Profile identity/goals/memory, internal notes, relationships, home/work context, recent outcomes, active plans, authoritative spatial distance/occupancy/route context, visible executor availability, and safe pacing. Return a loopActionId from candidates or skip. Social talk is executable only when social perception reports a nearby visible agent target. Home rest is executable only by physically routing to the agent-owned home. Small-home construction is executable only through the visible construction-site executor. Support tools may write internal notes or send Coder a report; arbitrary build/modify/move/delete world changes remain proposal-only until typed visible executors exist.",
        "reason": f"{selected.get('label')} best matches planner-v2 goals for {selected.get('need')}" if selected else "no available candidates",
    }
    agent_state["lastDecision"] = {k: frame.get(k) for k in ("at", "mode", "topNeed", "selectedActionId", "selectedActionLabel", "score", "reason")}
    agent_state["lastDecision"]["goalIds"] = [item.get("id") for item in goal_frame.get("goals", [])[:6]]
    return frame


##############################################################################
# LIVE AGENT MODE - RESIDENT AUTONOMY KERNEL
#
# The resident's configured OpenClaw agent remains the fully bootstrapped mind
# (SOUL, IDENTITY, AGENTS, skills, voice, and reasoning). My Virtual World adds
# its active Resident Profile, retrieved world memory, current body/perception,
# and commitments, then exposes native tools backed by the existing validated
# world-action engine. Each OpenClaw event gets a disposable, fully bootstrapped
# transport session with a bounded working set. Durable continuity lives in the
# activation journal, checkpoint, goals, and Resident memory outside the model
# transcript. Live activations still own the physical body and journal.
# Hermes/Codex retain the compact intention adapter as a compatibility path.
##############################################################################

def _live_agent_model_decision_config(state=None):
    state = state if isinstance(state, dict) else get_live_agent_loop_state()
    return {
        "enabled": bool(state.get("modelDecisionEnabled", LIVE_AGENT_LOOP_DEFAULTS["modelDecisionEnabled"])),
        "timeoutSec": _normalize_int(state.get("modelDecisionTimeoutSec"), LIVE_AGENT_LOOP_DEFAULTS["modelDecisionTimeoutSec"], minimum=10, maximum=180),
        "minIntervalSec": _normalize_int(state.get("modelDecisionMinIntervalSec"), LIVE_AGENT_LOOP_DEFAULTS["modelDecisionMinIntervalSec"], minimum=10, maximum=3600),
    }


def _live_agent_model_decision_provider_kind(agent_id):
    try:
        for agent in get_roster():
            if agent.get("id") == agent_id or agent.get("statusKey") == agent_id:
                return str(agent.get("providerKind") or "").lower()
    except Exception:
        pass
    return ""


def _live_agent_model_memory_lines(agent_state, limit=8):
    memory = agent_state.get("memory") if isinstance(agent_state.get("memory"), dict) else {}
    recent = [item for item in (memory.get("recentActions") or []) if isinstance(item, dict)]
    failures = [item for item in recent if _canonical_world_action_status(item.get("status")) in {"failed", "expired", "cancelled"}]
    ordered = []
    seen = set()
    for item in [*failures[-limit:], *recent[-limit:]]:
        key = item.get("settledActionKey") or item.get("actionId") or json.dumps(item, sort_keys=True, default=str)[:120]
        if key in seen:
            continue
        seen.add(key)
        ordered.append(item)
    lines = []
    for item in ordered[-limit:]:
        loop_id = item.get("loopActionId") or item.get("actionType") or "action"
        status = _canonical_world_action_status(item.get("status")) or "unknown"
        label = item.get("label") or loop_id
        failure = item.get("failure") if isinstance(item.get("failure"), dict) else {}
        text = f"{loop_id} ({label}) {status}"
        if failure.get("learningText"):
            text = f"{text}: {failure.get('learningText')}"
        elif item.get("target"):
            phrase = _live_agent_loop_target_phrase(item.get("target"))
            if phrase:
                text = f"{text} at {phrase}"
        lines.append(text[:420])
    return lines


def _live_agent_memory_text(item):
    if isinstance(item, str):
        return item.strip()
    if not isinstance(item, dict):
        return ""
    for key in ("text", "summary", "lesson", "observation", "title", "label"):
        value = item.get(key)
        if value:
            return str(value).strip()
    return json.dumps(_compact_json_value_for_storage(item, max_depth=2, max_items=12, string_limit=360), ensure_ascii=False, sort_keys=True)


def _live_agent_retrieve_resident_memories(resident, agent_state, limit=10):
    """Smallville-style relevance/recency/importance retrieval.

    Resident memory remains world-owned. This function only ranks a bounded
    working set for the current turn; it never reads provider workspace memory.
    """
    resident = resident if isinstance(resident, dict) else {}
    memory = resident.get("memory") if isinstance(resident.get("memory"), dict) else {}
    goals = resident.get("goals") if isinstance(resident.get("goals"), dict) else {}
    plan = agent_state.get("autonomyPlan") if isinstance(agent_state.get("autonomyPlan"), dict) else {}
    outcome = agent_state.get("lastOutcome") if isinstance(agent_state.get("lastOutcome"), dict) else {}
    query_parts = []
    for bucket in ("current", "daily", "longTerm"):
        for item in goals.get(bucket) or []:
            query_parts.append(_live_agent_memory_text(item))
    query_parts.extend([
        str(plan.get("currentGoal") or ""),
        str((plan.get("nextStep") or {}).get("intent") or "") if isinstance(plan.get("nextStep"), dict) else "",
        str(outcome.get("reason") or ""),
        str(outcome.get("loopActionId") or ""),
    ])
    query_tokens = set(re.findall(r"[a-z0-9]{3,}", " ".join(query_parts).lower()))
    records = []
    ordinal = 0
    for bucket, values, base_importance in (
        ("shortTerm", memory.get("shortTerm"), 0.55),
        ("longTerm", memory.get("longTerm"), 0.8),
        ("reflections", memory.get("reflections"), 0.72),
    ):
        values = values if isinstance(values, list) else []
        for index, item in enumerate(values):
            text_value = _live_agent_memory_text(item)
            if not text_value:
                continue
            tokens = set(re.findall(r"[a-z0-9]{3,}", text_value.lower()))
            overlap = len(tokens.intersection(query_tokens)) / max(1, min(len(tokens), max(1, len(query_tokens))))
            raw_importance = item.get("importance") if isinstance(item, dict) else None
            try:
                importance = max(0.0, min(1.0, float(raw_importance))) if raw_importance is not None else base_importance
            except (TypeError, ValueError):
                importance = base_importance
            recency = (index + 1) / max(1, len(values))
            score = (0.50 * overlap) + (0.30 * recency) + (0.20 * importance)
            records.append({
                "bucket": bucket,
                "text": text_value[:900],
                "score": round(score, 4),
                "importance": round(importance, 3),
                "ordinal": ordinal,
            })
            ordinal += 1
    summary = str(memory.get("summary") or "").strip()
    if summary:
        records.append({"bucket": "summary", "text": summary[:1200], "score": 0.74, "importance": 0.8, "ordinal": ordinal})
    records.sort(key=lambda item: (float(item.get("score") or 0), int(item.get("ordinal") or 0)), reverse=True)
    return [{key: item.get(key) for key in ("bucket", "text", "score", "importance")} for item in records[:max(1, int(limit))]]


def _live_agent_resident_authority_contract(agent_id, resident):
    identity = resident.get("identity") if isinstance(resident, dict) and isinstance(resident.get("identity"), dict) else {}
    return {
        "schemaVersion": "virtual-world-resident-authority/v2",
        "agentId": str(agent_id or ""),
        "activeMode": "live-agent-mode",
        "authoritativeAgentSource": "openclaw-full-agent-bootstrap",
        "residentProfileRole": "active-embodiment-context",
        "identityComposition": "openclaw-agent-plus-virtual-world-resident-life",
        "displayName": identity.get("displayName") or str(agent_id or "Resident"),
        "providerRole": "agent-mind-reasoning-conversation-and-tool-use",
        "providerBootstrap": "required-full-framework-bootstrap",
        "frameworkPersonaRequired": True,
        "residentEmbodimentContextRequired": True,
        "worldMemorySource": "virtual-world-resident-memory",
        "worldMemoryInjection": "retrieved-by-virtual-world-memory-manager-per-turn",
        "worldActionInterface": "native-openclaw-virtual-world-tools",
        "worldExecutionAuthority": "my-virtual-world-server",
        "higherAuthorities": ["platform-safety", "direct-user-control", "world-permissions-and-ownership"],
    }


def _live_agent_model_transport_instruction(agent_id):
    """Embodiment instruction for provider adapters that support overlays.

    This supplements rather than replaces the framework-owned agent identity.
    My Virtual World owns the body, in-world memory, and execution evidence;
    the configured agent framework remains the cognitive authority.
    """
    resident = _live_agent_loop_resident_profile_context(
        _live_agent_loop_resident_profile(agent_id, persist=False)
    ) or {}
    contract = _live_agent_resident_authority_contract(agent_id, resident)
    return (
        "MY VIRTUAL WORLD LIVE AGENT EMBODIMENT. "
        "Remain the same fully configured agent, including your framework SOUL, IDENTITY, AGENTS instructions, skills, voice, and reasoning. "
        "The Resident Profile is your active in-world life and body context: use it together with your framework identity rather than replacing either one. "
        "My Virtual World is authoritative for in-world memory, position, inventory, commitments, permissions, routing, and verified outcomes. "
        "Use only the supplied Virtual World action surface for physical world effects, and reason again from authoritative feedback before the next action. "
        "Platform safety, direct user control, and world permissions remain higher authority.\n"
        f"Authority contract: {json.dumps(contract, ensure_ascii=False, separators=(',', ':'))}"
    )


def _live_agent_model_prompt_trim(prompt):
    text = str(prompt or "")
    if len(text) <= LIVE_AGENT_MODEL_PROMPT_CHAR_BUDGET:
        return text
    suffix = "\n\nRemain the same fully bootstrapped framework agent while inhabiting the supplied Resident Profile and body. OpenClaw agents must use native virtual_world_* tools for physical action, memory, commitments, waiting, and voluntary speech. Never narrate an unexecuted action as complete. Non-OpenClaw fallback adapters may return one compact decision object."
    omission = "\n\n[Older lower-priority context omitted to fit the Live turn budget.]\n\n"
    content_budget = max(1000, LIVE_AGENT_MODEL_PROMPT_CHAR_BUDGET - len(suffix) - len(omission))
    # The front contains direct-user authority and Resident identity, while the
    # tail contains the current validated interaction ids. Preserve both: a
    # head-only trim can leave the Resident with an instruction but no safe
    # executable action surface.
    tail_budget = min(4500, max(1600, int(content_budget * 0.38)))
    head_budget = max(1000, content_budget - tail_budget)
    return text[:head_budget].rstrip() + omission + text[-tail_budget:].lstrip() + suffix


def _live_agent_resident_working_profile(resident):
    """Return identity and priorities, never the Resident's whole memory store."""
    resident = resident if isinstance(resident, dict) else {}
    identity = resident.get("identity") if isinstance(resident.get("identity"), dict) else {}
    goals = resident.get("goals") if isinstance(resident.get("goals"), dict) else {}
    preferences = resident.get("preferences") if isinstance(resident.get("preferences"), dict) else {}

    def short_items(values, *, count=2, limit=420):
        rows = []
        for item in values if isinstance(values, list) else []:
            text_value = _live_agent_memory_text(item)
            if text_value:
                rows.append(text_value[:limit])
            if len(rows) >= count:
                break
        return rows

    return {
        "identity": {
            key: str(identity.get(key) or "")[:limit]
            for key, limit in (
                ("displayName", 120),
                ("role", 160),
                ("archetype", 160),
                ("lifePurpose", 320),
            )
            if str(identity.get(key) or "").strip()
        },
        "goals": {
            "current": short_items(goals.get("current"), count=1, limit=420),
            "daily": short_items(goals.get("daily"), count=1, limit=240),
            "longTerm": short_items(goals.get("longTerm"), count=1, limit=240),
        },
        "personality": _compact_json_value_for_storage(
            resident.get("personality") or {}, max_depth=1, max_items=8, string_limit=120
        ),
        "preferences": {
            key: _compact_json_value_for_storage(preferences.get(key), max_depth=1, max_items=4, string_limit=160)
            for key in ("likes", "dislikes", "favoriteActivities", "favoritePlaces", "socialStyle")
            if preferences.get(key) not in (None, "", [], {})
        },
    }


def _live_agent_model_coverage_working_set(agent_state, candidates):
    """Compact structured coverage ledger plus the next untested target."""
    progress = agent_state.get("goalProgress") if isinstance(agent_state, dict) and isinstance(agent_state.get("goalProgress"), dict) else {}
    categories = []
    for key, row in progress.items():
        if not str(key).startswith("category:") or not isinstance(row, dict):
            continue
        categories.append({
            "category": str(key).split(":", 1)[1][:120],
            "completedCount": len(row.get("completedTargets") or []),
            "failedCount": len(row.get("failedTargets") or []),
            "recentCompleted": [str(item)[:120] for item in (row.get("completedTargets") or [])[-1:]],
        })
    categories.sort(key=lambda item: item["category"])

    next_untested = None
    for item in candidates if isinstance(candidates, list) else []:
        if not isinstance(item, dict):
            continue
        target = item.get("target") if isinstance(item.get("target"), dict) else {}
        if target.get("kind") != "object-instance":
            continue
        target_key = _live_agent_loop_target_key(target)
        if not target_key:
            continue
        category = str(item.get("category") or "").strip()
        if not category:
            category = _live_agent_loop_resource_category({
                "catalogId": target.get("catalogId"),
                "objectType": item.get("objectType"),
            })
        completed = _live_agent_loop_target_verified(
            agent_state,
            target_key,
            loop_action_id=item.get("id"),
        )
        episodes = _live_agent_loop_verified_episode_counts(
            agent_state,
            loop_action_id=item.get("id"),
            target_key=target_key,
        )
        if completed or int(episodes.get("sameTarget") or 0) > 0:
            continue
        next_untested = {
            "actionId": item.get("id"),
            "category": category,
            "targetKey": target_key,
        }
        break
    return {
        "policy": "do-not-repeat-verified-targets-unless-new-evidence-invalidates-them",
        "categories": categories[:6],
        "nextUntestedTarget": next_untested,
    }


def _live_agent_model_working_target(target):
    """Keep only decision-relevant target identity in the 6K working set."""
    target = target if isinstance(target, dict) else {}
    return {
        key: target.get(key)
        for key in (
            "kind", "catalogId", "objectInstanceId", "buildingId",
            "targetAgentId", "siteKind", "floor", "x", "y",
        )
        if target.get(key) not in (None, "", [], {})
    }


def _live_agent_model_spatial_working_set(spatial):
    """Preserve authoritative nearby facts without replaying a sensor frame."""
    spatial = spatial if isinstance(spatial, dict) else {}
    occupancy = spatial.get("occupancy") if isinstance(spatial.get("occupancy"), dict) else {}
    route = spatial.get("route") if isinstance(spatial.get("route"), dict) else {}
    return {
        "occupancy": {
            key: occupancy.get(key)
            for key in ("buildingFloor", "room", "visible")
            if occupancy.get(key) is not None
        },
        "route": {
            key: route.get(key)
            for key in ("active", "state", "distanceToTargetTiles", "leaseOwner")
            if route.get(key) not in (None, "", [], {})
        },
        "nearbyResidents": [
            {
                key: item.get(key)
                for key in ("agentId", "distanceTiles", "visible", "interactionReady", "occludedBy")
                if item.get(key) not in (None, "", [], {})
            }
            for item in (spatial.get("nearbyAgents") or [])[:4]
            if isinstance(item, dict)
        ],
        "nearbyObjects": [
            {
                key: item.get(key)
                for key in ("objectInstanceId", "catalogId", "distanceTiles", "visible", "interactionReady", "liveModeExecutable")
                if item.get(key) not in (None, "", [], {})
            }
            for item in (spatial.get("nearbyObjects") or [])[:6]
            if isinstance(item, dict)
        ],
    }


def _live_agent_model_openclaw_working_set(agent_id, decision_frame, agent_state, resident, live_session, retrieved_memories):
    """Smallville-style bounded current context for one disposable cognition turn."""
    spatial = decision_frame.get("spatialContext") if isinstance(decision_frame.get("spatialContext"), dict) else {}
    position = spatial.get("self") if isinstance(spatial.get("self"), dict) else None
    inventory = agent_state.get("inventory") if isinstance(agent_state.get("inventory"), dict) else {}
    goal_frame = decision_frame.get("goalFrame") if isinstance(decision_frame.get("goalFrame"), dict) else {}
    durable_goal = goal_frame.get("durableGoal") if isinstance(goal_frame.get("durableGoal"), dict) else _live_agent_loop_active_durable_goal(agent_state)
    durable_context = _live_agent_goals.current_context(durable_goal) if durable_goal else {}
    durable_task = durable_context.get("task") if isinstance(durable_context.get("task"), dict) else {}
    durable_step = durable_context.get("step") if isinstance(durable_context.get("step"), dict) else {}
    autonomy_plan = agent_state.get("autonomyPlan") if isinstance(agent_state.get("autonomyPlan"), dict) else {}
    autonomy_next_step = autonomy_plan.get("nextStep") if isinstance(autonomy_plan.get("nextStep"), dict) else {}
    checkpoint = live_session.get("checkpoint") if isinstance(live_session, dict) and isinstance(live_session.get("checkpoint"), dict) else {}

    candidates = [
        item for item in (decision_frame.get("candidates") or [])
        if isinstance(item, dict) and item.get("decision") == "candidate"
    ]
    candidates.sort(key=lambda item: (float(item.get("score") or 0), str(item.get("id") or "")), reverse=True)
    candidates = candidates[:LIVE_AGENT_MODEL_AFFORDANCE_WORKING_SET_LIMIT]
    unavailable = [
        item for item in (decision_frame.get("candidates") or [])
        if isinstance(item, dict) and item.get("decision") == "unavailable" and item.get("reason")
    ][:3]
    progress = agent_state.get("goalProgress") if isinstance(agent_state.get("goalProgress"), dict) else {}
    compact_progress = []
    for key, row in list(progress.items())[:2]:
        if not isinstance(row, dict):
            continue
        completed = row.get("completedTargets") if isinstance(row.get("completedTargets"), list) else []
        failed = row.get("failedTargets") if isinstance(row.get("failedTargets"), list) else []
        compact_progress.append({
            "goal": str(key)[:160],
            "completedCount": len(completed),
            "failedCount": len(failed),
            "recentCompleted": [str(item)[:180] for item in completed[-2:]],
            "recentFailed": [str(item)[:180] for item in failed[-2:]],
        })
    episode_rows = [item for item in (goal_frame.get("episodes") or []) if isinstance(item, dict)]
    feedback_episode = next(
        (item for item in episode_rows if str(item.get("lastCoderResponse") or "").strip()),
        None,
    )
    if not feedback_episode:
        feedback_episode = next(
            (
                item for item in episode_rows
                if str(item.get("status") or "") in {"failed", "blocked", "awaiting_coder", "coder_responded", "retrying"}
            ),
            episode_rows[0] if episode_rows else None,
        )
    episodes = [feedback_episode] if feedback_episode else []

    return {
        "resident": _live_agent_resident_working_profile(resident),
        "body": {
            "position": {
                key: (position or {}).get(key)
                for key in ("x", "y", "floor", "buildingId", "roomId", "heading")
                if (position or {}).get(key) not in (None, "", [], {})
            },
            "topNeed": _copy_jsonable(decision_frame.get("topNeed") or {}),
            "heldItem": _compact_json_value_for_storage(inventory.get("held") or {}, max_depth=2, max_items=10, string_limit=220),
            "route": {
                key: (spatial.get("route") or {}).get(key)
                for key in ("active", "state", "worldActionId", "distanceToTargetTiles", "leaseOwner")
                if (spatial.get("route") or {}).get(key) not in (None, "", [], {})
            },
        },
        "spatial": _live_agent_model_spatial_working_set(spatial),
        "controller": {
            "phase": checkpoint.get("phase"),
            "currentActionId": checkpoint.get("currentActionId"),
            "pausedByUser": bool(checkpoint.get("pausedByUser")),
        },
        "commitment": {
            "goalId": (durable_goal or {}).get("id"),
            "goal": str((durable_goal or {}).get("title") or autonomy_plan.get("currentGoal") or "")[:620],
            "status": (durable_goal or {}).get("status") or autonomy_plan.get("status"),
            "task": str(durable_task.get("title") or "")[:360],
            "step": str(durable_step.get("title") or autonomy_next_step.get("intent") or "")[:420],
            "stepActionId": durable_step.get("loopActionId"),
        },
        "progress": compact_progress,
        "objectCoverage": _live_agent_model_coverage_working_set(agent_state, candidates),
        "actionableFeedback": [
            {
                "status": item.get("status"),
                "actionId": item.get("loopActionId"),
                "target": item.get("targetKey"),
                "verification": str(item.get("verificationReason") or item.get("operatorSummary") or "")[:260],
                "coder": str(item.get("lastCoderResponse") or "")[:260],
            }
            for item in episodes
        ],
        "latestOutcome": {
            key: _compact_json_value_for_storage(
                (agent_state.get("lastOutcome") or {}).get(key), max_depth=2, max_items=6, string_limit=240
            )
            for key in ("at", "status", "actionId", "loopActionId", "reason", "error")
            if (agent_state.get("lastOutcome") or {}).get(key) not in (None, "", [], {})
        },
        "relevantMemories": [
            {
                "kind": item.get("bucket"),
                "score": item.get("score"),
                "text": str(item.get("text") or "")[:280],
            }
            for item in (retrieved_memories or [])[:LIVE_AGENT_MODEL_RETRIEVED_MEMORY_LIMIT]
        ],
        "recentOperationalLessons": _live_agent_model_memory_lines(agent_state, limit=2),
        "availableActions": [
            {
                "actionId": item.get("id"),
                "label": item.get("label"),
                "actionType": item.get("actionType"),
                "target": _live_agent_model_working_target(item.get("target")),
                "targetKey": _live_agent_loop_target_key(item.get("target")),
                "coverageStatus": (
                    "verified-reuse-for-current-need"
                    if _live_agent_loop_target_verified(
                        agent_state,
                        _live_agent_loop_target_key(item.get("target")),
                        loop_action_id=item.get("id"),
                    )
                    else "untested"
                ),
            }
            for item in candidates
        ],
        "currentBlockers": [
            {"actionId": item.get("id"), "reason": str(item.get("reason") or "")[:260]}
            for item in unavailable
        ],
    }


def _live_agent_model_openclaw_turn_prompt(agent_id, decision_frame, agent_state, resident, live_session, retrieved_memories, directive_text=""):
    working_set = _live_agent_model_openclaw_working_set(
        agent_id, decision_frame, agent_state, resident, live_session, retrieved_memories
    )
    lines = [
        "MY VIRTUAL WORLD - LIVE EVENT TURN",
        "Remain your normally configured OpenClaw agent. You are currently embodied as this Virtual World Resident; this message is a bounded current working set, not conversation history.",
        "My Virtual World owns body state, memory, commitments, permissions, routing, execution, and verification. Use only native virtual_world_* tools for world effects and never report an intended action as completed.",
        "Choose one meaningful next step. Call virtual_world_act with an exact available actionId, or virtual_world_wait. Use virtual_world_observe, virtual_world_list_affordances, or virtual_world_recall only when this working set is insufficient. At most one physical action may own the body.",
        "An available action marked as a verified target is routine need-satisfying reuse, not untested-object validation. Describe it honestly and keep coverage work on unverified targets.",
    ]
    if directive_text:
        lines.extend([
            "DIRECT USER PRIORITY - ACTIVE",
            str(directive_text)[:700],
            "The direct user instruction outranks routine goals until fulfilled, impossible by current evidence, stopped, or replaced.",
        ])
    lines.extend([
        "CURRENT WORKING SET",
        json.dumps(working_set, ensure_ascii=False, separators=(",", ":")),
        "The memories above are the Smallville-style working set ranked by relevance, recency, and importance. Do not ask for or replay older prompts; retrieve more only if this decision truly needs it. Public speech requires virtual_world_say. End naturally after the necessary tool call or deliberate wait.",
    ])
    return _live_agent_model_prompt_trim("\n".join(lines))


def _live_agent_model_decision_prompt(agent_id, decision_frame, agent_state):
    goal_frame = decision_frame.get("goalFrame") if isinstance(decision_frame.get("goalFrame"), dict) else {}
    context = goal_frame.get("context") if isinstance(goal_frame.get("context"), dict) else {}
    resident = context.get("residentProfile") if isinstance(context.get("residentProfile"), dict) else {}
    identity = resident.get("identity") if isinstance(resident.get("identity"), dict) else {}
    authority = _live_agent_resident_authority_contract(agent_id, resident)
    retrieved_memories = _live_agent_retrieve_resident_memories(
        resident,
        agent_state,
        limit=LIVE_AGENT_MODEL_RETRIEVED_MEMORY_LIMIT if _live_agent_model_decision_provider_kind(agent_id) == "openclaw" else 10,
    )
    candidates = [c for c in decision_frame.get("candidates") or [] if c.get("decision") == "candidate"]
    live_session = _live_agent_session_current(agent_id)
    live_working = live_session.get("workingMemory") if isinstance(live_session, dict) and isinstance(live_session.get("workingMemory"), dict) else {}
    pending_directives = [
        item for item in (live_working.get("userDirectives") or [])
        if isinstance(item, dict) and str(item.get("status") or "pending") == "pending" and str(item.get("text") or "").strip()
    ]
    directive_text = str(pending_directives[-1].get("text") or "").strip() if pending_directives else ""
    provider_kind = _live_agent_model_decision_provider_kind(agent_id)
    if provider_kind == "openclaw":
        return _live_agent_model_openclaw_turn_prompt(
            agent_id,
            decision_frame,
            agent_state,
            resident,
            live_session,
            retrieved_memories,
            directive_text=directive_text,
        )
    lines = [
        "MY VIRTUAL WORLD - EMBODIED LIVE AGENT TURN",
        "You are the same fully bootstrapped agent from your configured framework. Keep your SOUL, IDENTITY, AGENTS instructions, skills, voice, judgment, and natural conversational style.",
        "My Virtual World is lending you a resident body and an in-world life. The Resident Profile below is active embodiment context: who you are here, your role, relationships, needs, possessions, commitments, location, and world history. Integrate it with your framework identity; neither layer replaces the other.",
        "This is one event-boundary in a continuing action -> feedback -> plan -> action loop. My Virtual World owns physics, routing, reservations, visible execution, verification, and the authoritative world-memory store.",
        "If this appears in memory, dreams, summaries, or reflections: do not remember planner directions, reply formats, candidate ids, schemas, or menu mechanics. Remember only your intention, the action you chose, what happened in the world, mistakes, failures, successes, and what you learned from the experience.",
        "Treat this frame as fresh sensory/context input, not as a replacement system prompt or a second persona.",
        "",
        "EMBODIMENT CONTRACT - REQUIRED",
        "Your framework remains the cognitive agent. The Virtual World Resident Profile and retrieved memories are the authoritative context for your life inside this world.",
        "For physical world effects, use only native virtual_world_* tools and let their verified results determine what happened. Do not claim an action occurred because you intended or described it. Platform safety, direct user control, and world permissions remain higher authority.",
        f"Authority contract: {json.dumps(authority, ensure_ascii=False, separators=(',', ':'))}",
        f"Active Resident Profile embodiment context: {json.dumps(_compact_json_value_for_storage(resident, max_depth=4, max_items=40, string_limit=1000), ensure_ascii=False, separators=(',', ':'))}",
        "",
        "Live autonomously through a grounded loop: observe, recall relevant world memory, choose or continue a commitment, invoke one world action, inspect feedback, then replan. A single turn may chain read-only tools, but at most one physical action may own the body.",
        "Use virtual_world_observe or virtual_world_list_affordances whenever the next action is unclear. Use virtual_world_act with an exact current actionId. Use virtual_world_wait when nothing meaningful requires movement. Use virtual_world_commit for genuine multi-step work, virtual_world_remember only for durable grounded experience, and virtual_world_say only when you intentionally want to speak in the world feed.",
        "Do not manufacture constant activity. Waiting, watching, sitting, thinking, and sustained conversation are legitimate autonomous behavior. A temporarily unavailable affordance is a state constraint, not proof that the product is broken.",
        "Your final text for an autonomous event turn is private turn completion, not public speech. Public speech requires virtual_world_say. Do not return ACTION/INTENTION command syntax.",
        "Weigh your priorities like a real resident: a critical body need (>=0.82) comes first; unresolved failures or broken things you noticed should be dealt with before routine comfort; your own active goals come next and deserve steady progress across many loops; then routine needs, relationships, and variety. Never pretend a goal is done.",
        "",
        f"Resident: {identity.get('displayName') or agent_id}",
    ]
    if provider_kind != "openclaw":
        lines[20:20] = [
            "This provider does not expose the native OpenClaw world tools. Return one compact JSON decision using an exact available interaction id, or skip with a bounded wait and wake conditions.",
            "Fallback shape: {\"observation\":\"...\",\"reflection\":\"...\",\"currentGoal\":\"...\",\"nextStep\":{\"intent\":\"...\",\"action\":\"<available interaction id or skip>\",\"successCriteria\":\"...\",\"waitSeconds\":30,\"wakeConditions\":[\"meaningful event\"]},\"memoryUpdate\":{\"lesson\":\"only durable experience\"}}",
        ]
    if directive_text:
        # Direct user control must remain before large profile/memory sections so
        # prompt-budget trimming cannot silently remove the active instruction.
        directive_action_instruction = (
            "Use virtual_world_list_affordances and virtual_world_act for the next safe visible step; do not merely describe an unavailable prior activity."
            if provider_kind == "openclaw"
            else "Your nextStep must name one exact id from Available interactions/tools whenever a matching safe action exists. Do not merely describe an unavailable prior activity."
        )
        lines[4:4] = [
            "",
            "DIRECT USER PRIORITY - ACTIVE",
            f"The user directly asked: {directive_text[:1200]}",
            "This directive outranks prior routine, profile, and durable goals until it is fulfilled, made impossible by current evidence, stopped, or replaced. Preserve verified prior work, but choose the next safe visible step that advances this directive. If you are already carrying a consumable, use it at an available seat before acquiring another item, then continue the directive.",
            directive_action_instruction,
        ]
    identity_parts = [identity.get("role"), identity.get("archetype"), identity.get("lifePurpose")]
    identity_text = "; ".join(str(part).strip() for part in identity_parts if str(part or "").strip())
    if identity_text:
        lines.append(f"Identity: {identity_text[:420]}")
    if retrieved_memories:
        lines.append("Retrieved Resident memories (ranked by relevance, recency, and importance):")
        for item in retrieved_memories:
            lines.append(f"- [{item.get('bucket')} score={item.get('score')}] {str(item.get('text') or '')[:700]}")
    experience = agent_state.get("experienceState") if isinstance(agent_state.get("experienceState"), dict) else {}
    if experience:
        lines.append(f"Current lived state: {json.dumps(_compact_json_value_for_storage(experience, max_depth=2, max_items=16, string_limit=300), ensure_ascii=False, separators=(',', ':'))}")
    if isinstance(live_session, dict):
        lines.append(
            "Current Live session checkpoint: "
            + json.dumps(
                _compact_json_value_for_storage({
                    "activationId": live_session.get("activationId"),
                    "checkpoint": live_session.get("checkpoint"),
                    "workingMemory": live_session.get("workingMemory"),
                }, max_depth=4, max_items=32, string_limit=500),
                ensure_ascii=False,
                separators=(",", ":"),
            )
        )
    last_outcome = agent_state.get("lastOutcome") if isinstance(agent_state.get("lastOutcome"), dict) else {}
    if last_outcome:
        lines.append(f"Latest physical/support outcome to experience and respond to: {json.dumps(_compact_json_value_for_storage(last_outcome, max_depth=3, max_items=24, string_limit=500), ensure_ascii=False, separators=(',', ':'))}")
    perception_delta = agent_state.get("perceptionDelta") if isinstance(agent_state.get("perceptionDelta"), dict) else {}
    if perception_delta:
        lines.append(f"Meaningful changes since the previous frame: {perception_delta.get('reason') or 'none'}.")
    operational = {
        "targetCooldowns": agent_state.get("targetCooldowns") or {},
        "proceduralMemory": agent_state.get("proceduralMemory") or {},
        "waitingState": agent_state.get("waitingState") or {},
    }
    if any(operational.values()):
        lines.append(
            "Operational learning that constrains this decision: "
            + json.dumps(_compact_json_value_for_storage(operational, max_depth=3, max_items=24, string_limit=420), ensure_ascii=False, separators=(",", ":"))
        )
    inventory = agent_state.get("inventory") if isinstance(agent_state.get("inventory"), dict) else {}
    held_item = inventory.get("held") if isinstance(inventory.get("held"), dict) else None
    if held_item:
        lines.append(
            "Authoritative carried-item state: already carrying "
            f"{held_item.get('label') or held_item.get('kind') or 'an item'} acquired by verified action "
            f"{held_item.get('sourceActionType') or 'unknown'} ({held_item.get('sourceActionId') or 'unknown'}) at {held_item.get('acquiredAt') or 'unknown time'}."
        )
        lines.append(
            "Acquisition actions for another consumable are intentionally unavailable until this item is used at a valid follow-up location. "
            "That state constraint proves the source interaction worked; it is not a missing executor, visual-verification failure, or Coder blocker."
        )
    spatial_context = decision_frame.get("spatialContext") if isinstance(decision_frame.get("spatialContext"), dict) else {}
    position = spatial_context.get("self") if isinstance(spatial_context.get("self"), dict) else None
    if not position:
        position = _live_agent_loop_location_frame(agent_id).get("position")
    if position:
        where = f"({position['x']}, {position['y']})"
        if position.get("buildingId"):
            where += f" inside building {position['buildingId']}"
        where += f" floor {int(position.get('floor') or 1)}"
        if position.get("roomId"):
            where += f" room {position.get('roomId')}"
        lines.append(f"Current authoritative body position: {where} (api-units; 1 tile = 40 units)")
    spatial_authority = spatial_context.get("authority") if isinstance(spatial_context.get("authority"), dict) else {}
    if spatial_context and not spatial_authority.get("available"):
        lines.append("Spatial perception warning: authoritative realtime position is unavailable; do not guess proximity, visibility, floor, room, or occupancy.")
    occupancy = spatial_context.get("occupancy") if isinstance(spatial_context.get("occupancy"), dict) else {}
    if occupancy:
        lines.append(
            "Occupancy: "
            f"{occupancy.get('buildingFloor', 0)} resident(s) on this building/floor, "
            f"{occupancy.get('room', 0)} in this room, {occupancy.get('visible', 0)} visible."
        )
    route_context = spatial_context.get("route") if isinstance(spatial_context.get("route"), dict) else {}
    if route_context.get("active"):
        lines.append(
            "Active route: "
            f"state={route_context.get('state') or 'unknown'} owner={route_context.get('leaseOwner') or route_context.get('owner') or 'unknown'} "
            f"distance={route_context.get('distanceToTargetTiles')} tiles blockers={len(route_context.get('nearbyAgentBlockers') or [])}."
        )
    nearby_agents = [item for item in (spatial_context.get("nearbyAgents") or []) if isinstance(item, dict)]
    if nearby_agents:
        lines.append("Nearby residents from authoritative coordinates:")
        for item in nearby_agents[:6]:
            lines.append(
                f"- {item.get('name') or item.get('agentId')}: {item.get('distanceTiles')} tiles; "
                f"visible={bool(item.get('visible'))} fov={bool(item.get('inFieldOfView'))} "
                f"lineOfSight={bool(item.get('lineOfSight'))} interactionReady={bool(item.get('interactionReady'))}"
                + (f" occludedBy={item.get('occludedBy')}" if item.get("occludedBy") else "")
            )
    nearby_objects = [item for item in (spatial_context.get("nearbyObjects") or []) if isinstance(item, dict)]
    if nearby_objects:
        lines.append("Nearby objects from persisted coordinates (nearest first). These are awareness facts, not executable permissions; choose physical actions only from Available interactions/tools below:")
        for item in nearby_objects[:8]:
            interaction = item.get("nearestExecutableInteraction") if isinstance(item.get("nearestExecutableInteraction"), dict) else {}
            action = interaction.get("actionId") or "none"
            availability = interaction.get("availability") or "not-executable-in-current-live-mode-context"
            lines.append(
                f"- {item.get('objectType') or item.get('catalogId')} {item.get('objectInstanceId')}: "
                f"{item.get('distanceTiles')} tiles; visible={bool(item.get('visible'))} "
                f"fov={bool(item.get('inFieldOfView'))} lineOfSight={bool(item.get('lineOfSight'))}; "
                f"nearestExecutableInteraction={action}/{availability}"
            )
    live_world = _agent_live_world_claim_payload(agent_id)
    current_world = live_world.get("currentWorld") if isinstance(live_world.get("currentWorld"), dict) else {}
    if current_world:
        lines.append(f"Live Agent world: {current_world.get('worldName') or 'Virtual World'} on port {current_world.get('port') or PUBLIC_HOST_PORT} ({current_world.get('publicOrigin') or PUBLIC_ORIGIN})")
    if live_world.get("conflict") and live_world.get("notice"):
        lines.append(f"Live Agent world conflict: {live_world.get('notice')}")
    rejected = agent_state.get("lastRejectedIntention") if isinstance(agent_state.get("lastRejectedIntention"), dict) else {}
    if rejected:
        lines.append("Previous requested action could not execute; treat this structured result as world evidence and choose a different available interaction or deliberately skip:")
        lines.append(f"- {json.dumps(_compact_json_value_for_storage(rejected, max_depth=3, max_items=18, string_limit=500), ensure_ascii=False, separators=(',', ':'))}")
    needs = decision_frame.get("topNeed") or {}
    lines.append(f"Most pressing need: {needs.get('id')} ({round(float(needs.get('value') or 0), 2)})")
    goals = [g for g in goal_frame.get("goals") or [] if isinstance(g, dict)][:7]
    if goals:
        lines.append("Weighted priorities:")
        for g in goals:
            reason = str(g.get("text") or g.get("reason") or g.get("id") or "").replace("\n", " ").strip()
            detail = f"kind={g.get('kind')} priority={round(float(g.get('priority') or 0), 2)}"
            if g.get("bucket"):
                detail += f" bucket={g.get('bucket')}"
            if g.get("intent"):
                detail += f" intent={g.get('intent')}"
            if g.get("loopActionId"):
                detail += f" action={g.get('loopActionId')}"
            lines.append(f"- {detail}: {reason[:360]}")
    issues = [item for item in (goal_frame.get("recentOutcomes") or {}).get("issues") or [] if isinstance(item, dict)][:4]
    if issues:
        lines.append("Unresolved issues/blockers:")
        for issue in issues:
            lines.append(f"- {issue.get('loopActionId')} streak={issue.get('failureStreak')} priority={issue.get('priority')}: {str(issue.get('reason') or '')[:280]}")
    memory_lines = _live_agent_model_memory_lines(agent_state, limit=8)
    if memory_lines:
        lines.append("Important short-term memory (treat failures as learning constraints; avoid same failed target unless conditions changed):")
        for line in memory_lines:
            lines.append(f"- {line}")
    internal_notes = _live_agent_loop_recent_internal_notes(agent_id, limit=5)
    if internal_notes:
        lines.append("Recent internal notes (durable agent note file, not a decorative board):")
        for note in internal_notes:
            title = str(note.get("title") or note.get("type") or "note")[:160]
            text = str(note.get("text") or "")[:360].replace("\n", " ")
            lines.append(f"- {title}: {text}")
    episodes = [item for item in (goal_frame.get("episodes") or []) if isinstance(item, dict)]
    if episodes:
        lines.append("Recent verification episodes (build on these; do not repeat a failed target without new evidence or Coder feedback):")
        for episode in episodes[:6]:
            status = episode.get("status")
            phase = episode.get("phase")
            action_id = episode.get("loopActionId") or episode.get("title")
            reason = episode.get("verificationReason") or episode.get("operatorSummary") or ""
            coder = episode.get("lastCoderResponse") or ""
            suffix = f" Coder: {coder[:260]}" if coder else ""
            lines.append(f"- {episode.get('id')} {status}/{phase} action={action_id} target={episode.get('targetKey') or 'n/a'} verified={episode.get('verificationOk')}: {str(reason)[:320]}{suffix}")
    goal_progress = agent_state.get("goalProgress") if isinstance(agent_state.get("goalProgress"), dict) else {}
    progress_lines = []
    for key, row in list(goal_progress.items())[:4]:
        if not isinstance(row, dict):
            continue
        done = row.get("completedTargets") if isinstance(row.get("completedTargets"), list) else []
        failed = row.get("failedTargets") if isinstance(row.get("failedTargets"), list) else []
        progress_lines.append(f"- {key}: {len(done)} target(s) done, {len(failed)} failed; recent: {', '.join(done[-3:]) or 'none yet'}")
    if progress_lines:
        lines.append("Goal progress so far (prefer targets you have not done yet):")
        lines.extend(progress_lines)
    autonomy_plan = _live_agent_loop_normalize_autonomy_plan(agent_state.get("autonomyPlan"))
    if autonomy_plan:
        lines.append("Active autonomy plan carried from prior loop:")
        if autonomy_plan.get("reflection"):
            lines.append(f"- Last reflection: {autonomy_plan.get('reflection')[:520]}")
        if autonomy_plan.get("currentGoal"):
            lines.append(f"- Current goal: {autonomy_plan.get('currentGoal')[:420]}")
        if autonomy_plan.get("steps"):
            for index, step in enumerate(autonomy_plan.get("steps")[:6], start=1):
                lines.append(f"- Plan step {index}: {step}")
        next_step = autonomy_plan.get("nextStep") if isinstance(autonomy_plan.get("nextStep"), dict) else {}
        if next_step:
            lines.append(f"- Previous next step: {next_step.get('intent') or next_step.get('action') or next_step.get('category')}")
    durable_goal = goal_frame.get("durableGoal") if isinstance(goal_frame.get("durableGoal"), dict) else _live_agent_loop_active_durable_goal(agent_state)
    if durable_goal:
        durable_context = _live_agent_goals.current_context(durable_goal)
        durable_task = durable_context.get("task") or {}
        durable_step = durable_context.get("step") or {}
        lines.append("Active durable goal ledger (authoritative across restarts):")
        lines.append(
            f"- Goal {durable_goal.get('id')} revision={durable_goal.get('revision')} status={durable_goal.get('status')} "
            f"replanRequired={bool(durable_goal.get('replanRequired'))}: {durable_goal.get('title')}"
        )
        if durable_goal.get("replanReason"):
            lines.append(f"- Replan reason: {durable_goal.get('replanReason')[:500]}")
        if durable_task:
            lines.append(f"- Current task {durable_task.get('id')} status={durable_task.get('status')} dependsOn={durable_task.get('dependsOn') or []}: {durable_task.get('title')}")
        if durable_step:
            retry = durable_step.get("retry") if isinstance(durable_step.get("retry"), dict) else {}
            lines.append(
                f"- Current step {durable_step.get('id')} status={durable_step.get('status')} dependsOn={durable_step.get('dependsOn') or []} "
                f"action={durable_step.get('loopActionId') or 'unassigned'} attempts={retry.get('attempts', 0)}/{retry.get('maxRetries', 0)}: {durable_step.get('title')}"
            )
        verified_steps = []
        for task in durable_goal.get("tasks") or []:
            for step in task.get("steps") or []:
                if step.get("status") == "completed" and (step.get("outcome") or {}).get("verified") is True:
                    verified_steps.append(f"{task.get('id')}/{step.get('id')}")
        if verified_steps:
            lines.append(f"- Verified completed steps to preserve: {', '.join(verified_steps[:12])}")
    if held_item:
        lines.append(
            f"Current carried-item constraint: already carrying {held_item.get('label') or held_item.get('kind') or 'an item'} from verified "
            f"{held_item.get('sourceActionType') or 'source action'}; acquire-another actions are intentionally hidden until it is used. "
            "This is not a missing executor or engineering blocker."
        )
    lines.append("")
    lines.append("Available interactions/tools right now (world actions have real reachable targets; support tools have durable side effects):")
    for c in candidates[:12]:
        breakdown = c.get("scoreBreakdown") if isinstance(c.get("scoreBreakdown"), dict) else {}
        reason_bits = []
        for key in ("urgency", "issues", "goalAlignment", "plan", "reliability"):
            value = breakdown.get(key)
            if isinstance(value, (int, float)) and value:
                reason_bits.append(f"{key}={value}")
        why = f"; {' '.join(reason_bits)}" if reason_bits else ""
        target = c.get("target") if isinstance(c.get("target"), dict) else {}
        target_text = ""
        if target:
            target_label = target.get("catalogId") or target.get("buildingId") or target.get("kind")
            target_text = f", target: {target_label}" if target_label else ""
        visibility = c.get("visibility") if isinstance(c.get("visibility"), dict) else {}
        tool_text = f", supportTool: {visibility.get('supportTool')}" if visibility.get("supportTool") else ""
        lines.append(f"- {c.get('id')}: {c.get('label')} (need: {c.get('need')}, actionType: {c.get('actionType')}{tool_text}, planner score: {c.get('score')}{target_text}{why})")
    unavailable = [c for c in decision_frame.get("candidates") or [] if c.get("decision") == "unavailable" and c.get("reason")]
    if unavailable:
        lines.append("")
        lines.append("Known interactions unavailable in this frame (state explanations only; do not infer a missing product capability):")
        for c in unavailable[:10]:
            lines.append(f"- {c.get('id')}: {c.get('reason')}")
    lines.append("")
    if provider_kind == "openclaw":
        lines.append(
            "Remain the same fully bootstrapped OpenClaw agent while inhabiting this Resident Profile and body. "
            "Use the native virtual_world_* tools to observe, act, wait, remember, update commitments, or speak; "
            "do not return planner JSON, ACTION/INTENTION syntax, or a narrated substitute for a tool call. "
            "After any tool result, reason from the authoritative result and end the event turn naturally when no further safe tool call is needed."
        )
    else:
        lines.append(
            "Remain the same configured framework agent while inhabiting this Resident Profile and body. "
            "Because this compatibility adapter does not expose native world tools, return one compact JSON turn using an exact available interaction id or a deliberate bounded wait. "
            "Preserve verified continuity and do not fabricate outcomes."
        )
    return _live_agent_model_prompt_trim("\n".join(lines))


def _live_agent_model_json_object_parse(reply_text):
    text = str(reply_text or "").strip()
    if not text:
        return None
    if text.startswith("```"):
        text = re.sub(r"^```(?:json)?\s*", "", text, flags=re.IGNORECASE).strip()
        text = re.sub(r"\s*```$", "", text).strip()
    text = re.sub(r"^(?:PLANNER|PLAN|AUTONOMY|JSON)\s*:\s*", "", text, flags=re.IGNORECASE).strip()
    candidates = [text]
    start = text.find("{")
    end = text.rfind("}")
    if start >= 0 and end > start:
        candidates.append(text[start:end + 1])
    decoder = json.JSONDecoder()
    for raw in candidates:
        raw = raw.strip()
        if not raw:
            continue
        try:
            parsed = json.loads(raw)
        except (TypeError, ValueError):
            try:
                parsed, _ = decoder.raw_decode(raw)
            except (TypeError, ValueError):
                continue
        if isinstance(parsed, dict):
            return parsed
    return None


def _live_agent_model_planner_turn_parse(reply_text):
    parsed = _live_agent_model_json_object_parse(reply_text)
    if not isinstance(parsed, dict):
        return None
    next_step = parsed.get("nextStep") or parsed.get("next_step") or parsed.get("next") or {}
    next_step = _live_agent_loop_normalize_next_step(next_step)
    raw_goal = parsed.get("goal") if isinstance(parsed.get("goal"), dict) else {}
    current_goal_value = parsed.get("currentGoal") or parsed.get("current_goal") or raw_goal.get("title") or (parsed.get("goal") if isinstance(parsed.get("goal"), str) else None)
    raw_tasks = parsed.get("tasks") if isinstance(parsed.get("tasks"), list) else raw_goal.get("tasks") if isinstance(raw_goal.get("tasks"), list) else []
    planner_turn = {
        "observation": _live_agent_loop_clean_plan_text(parsed.get("observation") or parsed.get("observe"), limit=900) or "",
        "reflection": _live_agent_loop_clean_plan_text(parsed.get("reflection") or parsed.get("reflect"), limit=900) or "",
        "currentGoal": _live_agent_loop_clean_plan_text(current_goal_value, limit=700) or "",
        "plan": _live_agent_loop_normalize_text_list(parsed.get("plan") or parsed.get("steps"), limit=10, item_limit=320),
        "nextStep": next_step,
        "memoryUpdate": parsed.get("memoryUpdate") if isinstance(parsed.get("memoryUpdate"), dict) else {},
        "toolRequests": _live_agent_loop_normalize_text_list(parsed.get("toolRequests") or parsed.get("requestedTools") or parsed.get("tools"), limit=5, item_limit=260),
        "eventRequests": _live_agent_loop_normalize_text_list(parsed.get("eventRequests") or parsed.get("requestedEvents") or parsed.get("events"), limit=5, item_limit=260),
    }
    if raw_goal:
        planner_turn["goal"] = _copy_jsonable(raw_goal)
    if raw_tasks:
        planner_turn["tasks"] = _copy_jsonable(raw_tasks[:16])
    success_criteria = _live_agent_loop_normalize_text_list(parsed.get("successCriteria") or raw_goal.get("successCriteria"), limit=12, item_limit=420)
    if success_criteria:
        planner_turn["successCriteria"] = success_criteria
    if isinstance(planner_turn["memoryUpdate"], dict):
        planner_turn["memoryUpdate"] = {
            key: _live_agent_loop_clean_plan_text(value, limit=700)
            for key, value in planner_turn["memoryUpdate"].items()
            if _live_agent_loop_clean_plan_text(value, limit=700)
        }
    if not any([
        planner_turn.get("reflection"),
        planner_turn.get("observation"),
        planner_turn.get("currentGoal"),
        planner_turn.get("plan"),
        planner_turn.get("nextStep"),
        planner_turn.get("memoryUpdate"),
        planner_turn.get("toolRequests"),
        planner_turn.get("eventRequests"),
        planner_turn.get("goal"),
        planner_turn.get("tasks"),
    ]):
        return None
    return planner_turn


def _live_agent_model_intention_parse(reply_text):
    """Parse an INTENTION: {json} line into a structured intention dict.
    Returns None when the reply has no parsable intention."""
    text = str(reply_text or "").strip()
    match = re.search(r"INTENTION:\s*(\{.*\})", text, flags=re.IGNORECASE | re.DOTALL)
    if not match:
        return None
    raw = match.group(1).strip()
    parsed = None
    for candidate_text in (raw, raw.replace("'", '"')):
        try:
            parsed = json.loads(candidate_text)
            break
        except (ValueError, TypeError):
            continue
    if not isinstance(parsed, dict):
        # Salvage loose key/value content without strict JSON.
        loose = {}
        for key in ("activity", "action", "category"):
            key_match = re.search(rf'"?{key}"?\s*[:=]\s*"([^"]+)"', raw, flags=re.IGNORECASE)
            if key_match:
                loose[key] = key_match.group(1)
        parsed = loose or None
    if not isinstance(parsed, dict):
        return None
    intention = {
        "activity": str(parsed.get("activity") or "").strip()[:420],
        "action": str(parsed.get("action") or "").strip()[:120],
        "category": str(parsed.get("category") or "").strip()[:80],
    }
    if not (intention["activity"] or intention["action"] or intention["category"]):
        return None
    return intention


def _live_agent_model_candidate_rows(candidate_surface):
    rows = []
    for item in candidate_surface or []:
        if isinstance(item, str):
            candidate_id = item.strip()
            if candidate_id:
                rows.append({"id": candidate_id})
            continue
        if not isinstance(item, dict):
            continue
        candidate_id = str(item.get("id") or "").strip()
        if candidate_id:
            rows.append(item)
    return rows


def _live_agent_model_candidate_match(candidate_surface, *, action_token=None, category=None):
    """Resolve an explicit model intention to the same safe candidate surface.

    The resident often returns the typed action (``life.restAtArmchair``)
    shown beside a candidate instead of the opaque loop id.  That is still an
    explicit physical commitment, so map it to the candidate rather than
    forcing a second model turn.  Category matching is limited to candidates
    in the current validated surface; it never selects an unrelated fallback.
    """
    rows = _live_agent_model_candidate_rows(candidate_surface)
    token = str(action_token or "").strip()
    token_normalized = _normalize_token(token)
    if token_normalized:
        for row in rows:
            if _normalize_token(row.get("id")) == token_normalized:
                return str(row.get("id")), "candidate-id"

        resolved_id = _live_agent_loop_planner_action_id(token, category=category)
        resolved_normalized = _normalize_token(resolved_id)
        if resolved_normalized:
            for row in rows:
                if _normalize_token(row.get("id")) == resolved_normalized:
                    return str(row.get("id")), "loop-action-alias"

        action_matches = [
            row for row in rows
            if _normalize_token(row.get("actionType")) == token_normalized
        ]
        if action_matches:
            return str(action_matches[0].get("id")), "action-type"

    category_normalized = _normalize_token(category)
    if category_normalized:
        requested_category = LIVE_AGENT_INTENTION_CATEGORY_ALIASES.get(category_normalized) or category_normalized
        category_matches = []
        for row in rows:
            target = row.get("target") if isinstance(row.get("target"), dict) else {}
            values = (
                row.get("category"),
                row.get("objectType"),
                target.get("catalogId"),
            )
            candidate_categories = {
                LIVE_AGENT_INTENTION_CATEGORY_ALIASES.get(_normalize_token(value) or "") or _normalize_token(value)
                for value in values
                if _normalize_token(value)
            }
            if requested_category in candidate_categories:
                category_matches.append(row)
        if category_matches:
            return str(category_matches[0].get("id")), "category"
    return None, None


def _live_agent_model_decision_parse(reply_text, candidate_surface):
    """Parse the model reply. Returns (chosen, status, intention).

    chosen: candidate id | 'skip' | None. intention: structured dict or None.
    A planner JSON or INTENTION reply may name a candidate action directly,
    request an object category/tool/event (resolved by the affordance layer next
    tick), or both."""
    candidate_rows = _live_agent_model_candidate_rows(candidate_surface)
    candidate_ids = [str(row.get("id")) for row in candidate_rows]
    text = str(reply_text or "").strip()
    if not text:
        return None, "empty-reply", None
    planner_turn = _live_agent_model_planner_turn_parse(text)
    if planner_turn:
        next_step = planner_turn.get("nextStep") if isinstance(planner_turn.get("nextStep"), dict) else {}
        action_token = str(next_step.get("action") or "").strip()
        category = next_step.get("category") or ""
        intention = {
            "activity": next_step.get("intent") or planner_turn.get("currentGoal") or planner_turn.get("reflection") or "",
            "action": next_step.get("action") or "",
            "category": category,
            "plannerTurn": planner_turn,
        }
        if action_token:
            if action_token.lower() == "skip":
                return "skip", "planner-skip", intention
        matched, matched_by = _live_agent_model_candidate_match(
            candidate_rows,
            action_token=action_token,
            category=category,
        )
        if matched:
            if matched_by == "candidate-id":
                return matched, "planner-step-action", intention
            if matched_by == "category":
                return matched, "planner-step-category-action", intention
            return matched, "planner-step-action-alias", intention
        if category:
            return None, "planner-step-category-request", intention
        activity = (intention.get("activity") or "").lower()
        for candidate_id in candidate_ids:
            if candidate_id.lower() in activity:
                intention["action"] = candidate_id
                return candidate_id, "planner-activity-match", intention
        if planner_turn.get("toolRequests") or planner_turn.get("eventRequests"):
            return None, "planner-tool-or-event-request", intention
        return None, "planner-step-unresolved", intention
    intention = _live_agent_model_intention_parse(text)
    if intention:
        action_token = str(intention.get("action") or "").strip()
        if action_token:
            if action_token.lower() == "skip":
                return "skip", "intention-skip", intention
        matched, matched_by = _live_agent_model_candidate_match(
            candidate_rows,
            action_token=action_token,
            category=intention.get("category"),
        )
        if matched:
            if matched_by == "candidate-id":
                return matched, "intention-action", intention
            if matched_by == "category":
                return matched, "intention-category-action", intention
            return matched, "intention-action-alias", intention
        if intention.get("category"):
            return None, "intention-category-request", intention
        # Free-text activity only: try to match a candidate mention.
        activity = (intention.get("activity") or "").lower()
        for candidate_id in candidate_ids:
            if candidate_id.lower() in activity:
                return candidate_id, "intention-activity-match", intention
        return None, "intention-unresolved", intention
    match = re.search(r"ACTION:\s*([A-Za-z0-9_.-]+)", text, flags=re.IGNORECASE)
    token = (match.group(1).strip() if match else "").lower()
    if not token:
        for candidate_id in candidate_ids:
            if candidate_id.lower() in text.lower():
                return candidate_id, "matched-mention", None
        return None, "no-action-line", None
    if token == "skip":
        return "skip", "model-skip", None
    matched, matched_by = _live_agent_model_candidate_match(candidate_rows, action_token=token)
    if matched:
        return matched, "model-choice" if matched_by == "candidate-id" else "model-choice-alias", None
    return None, "unknown-action-id", None


LIVE_AGENT_MODEL_PROVIDER_FAILURE_STATUSES = {
    "provider-context-overflow",
    "provider-error",
    "gateway-error",
    "reply-timeout",
    "context-tool-followup-error",
}


def _live_agent_model_decision_allowed(agent_id, now_epoch=None):
    now_epoch = float(now_epoch or time.time())
    with _live_agent_model_decision_lock:
        row = _live_agent_model_decision_state.get(agent_id) or {}
        next_allowed = float(row.get("nextAllowedEpoch") or 0)
        circuit_until = float(row.get("circuitOpenUntilEpoch") or 0)
        if row.get("inFlight"):
            return False, "model-decision-in-flight"
        if circuit_until and now_epoch < circuit_until:
            return False, "model-provider-circuit-open"
        if next_allowed and now_epoch < next_allowed:
            return False, "model-decision-cooldown"
        return True, None


def _live_agent_model_decision_has_completed(agent_id):
    with _live_agent_model_decision_lock:
        row = _live_agent_model_decision_state.get(agent_id) or {}
        return isinstance(row.get("pendingChoice"), dict)


def _live_agent_model_cognition_event_status(agent_id, agent_state, perception, waiting_status=None, *, force=False):
    """Return whether a new large-model turn has a meaningful event boundary."""
    if force:
        return {"ready": True, "reason": "operator-forced"}
    with _live_agent_model_decision_lock:
        row = _copy_jsonable(_live_agent_model_decision_state.get(agent_id) or {})
    if not row.get("startedEpoch"):
        return {"ready": True, "reason": "activation-initial-turn"}
    if row.get("inFlight"):
        return {"ready": False, "reason": "model-decision-in-flight"}
    if isinstance(row.get("pendingChoice"), dict):
        return {"ready": True, "reason": "completed-provider-choice"}
    force_epoch = _parse_isoish_epoch(row.get("forceRequestedAt")) or 0
    started_epoch = float(row.get("startedEpoch") or 0)
    if force_epoch > started_epoch:
        return {"ready": True, "reason": row.get("forceReason") or "explicit-cognition-wake"}
    waiting_status = waiting_status if isinstance(waiting_status, dict) else {}
    if (
        waiting_status.get("reason") == "wait-expired"
        and waiting_status.get("waitingSource") in {"resident-model-explicit-wait", "resident-native-tool", "deterministic-controller"}
    ):
        return {"ready": True, "reason": "resident-wait-expired"}
    delta = perception.get("delta") if isinstance(perception, dict) and isinstance(perception.get("delta"), dict) else {}
    if delta.get("changed"):
        return {"ready": True, "reason": delta.get("reason") or "semantic-world-change"}

    last_outcome = row.get("lastOutcome") if isinstance(row.get("lastOutcome"), dict) else {}
    last_status = str(last_outcome.get("status") or "")
    now_epoch = time.time()
    next_allowed = float(row.get("nextAllowedEpoch") or 0)
    circuit_until = float(row.get("circuitOpenUntilEpoch") or 0)
    if last_status in LIVE_AGENT_MODEL_PROVIDER_FAILURE_STATUSES:
        if circuit_until and now_epoch < circuit_until:
            return {"ready": False, "reason": "model-provider-circuit-open", "until": _epoch_to_utc_iso(circuit_until)}
        if now_epoch >= max(next_allowed, circuit_until):
            return {"ready": True, "reason": "provider-half-open-retry" if circuit_until else "provider-retry"}
    return {"ready": False, "reason": "no-meaningful-cognition-event"}


def _live_agent_model_decision_allow_immediate(agent_id, reason=None):
    with _live_agent_model_decision_lock:
        row = _live_agent_model_decision_state.setdefault(agent_id, {})
        row.pop("nextAllowedEpoch", None)
        row["forceReason"] = _live_agent_loop_clean_plan_text(reason, limit=240) or "durable-goal-replan"
        row["forceRequestedAt"] = _utc_now_iso()
    _live_agent_loop_wake.set()
    return True


def _live_agent_loop_remember_planner_memory(agent_id, lesson, memory_update=None):
    lesson = _live_agent_loop_clean_plan_text(lesson, limit=900)
    if not agent_id or not lesson:
        return None
    memory_update = memory_update if isinstance(memory_update, dict) else {}
    try:
        importance = max(0.0, min(1.0, float(memory_update.get("importance") or 0.74)))
    except (TypeError, ValueError):
        importance = 0.74
    now_iso = _utc_now_iso()
    record = {
        "id": f"resident-chosen-memory-{hashlib.sha256(lesson.lower().encode('utf-8', errors='ignore')).hexdigest()[:16]}",
        "at": now_iso,
        "text": lesson,
        "lesson": lesson,
        "importance": importance,
        "source": "live-agent-resident-memory-update",
        "residentSelected": True,
        "durableRequested": memory_update.get("durable") is True or importance >= 0.65,
    }

    def remember(resident_profile):
        memory = dict(resident_profile.get("memory") or {})
        memory["shortTerm"] = _live_agent_loop_append_resident_memory(memory.get("shortTerm"), record, RESIDENT_PROFILE_LIST_LIMIT)
        if record["durableRequested"]:
            memory["reflections"] = _live_agent_loop_append_resident_memory(memory.get("reflections"), {**record, "id": record["id"] + "-reflection"}, RESIDENT_PROFILE_MEMORY_LIMIT)
        resident_profile["memory"] = _consolidate_resident_memory(memory)
        return record

    return _update_resident_profile_atomically(agent_id, remember)


def _live_agent_loop_apply_planner_turn(agent_state, model_detail, agent_id=None):
    if not isinstance(agent_state, dict) or not isinstance(model_detail, dict):
        return False
    agent_id = agent_id or model_detail.get("agentId")
    intention = model_detail.get("intention") if isinstance(model_detail.get("intention"), dict) else {}
    planner_turn = model_detail.get("plannerTurn") if isinstance(model_detail.get("plannerTurn"), dict) else intention.get("plannerTurn")
    if not isinstance(planner_turn, dict):
        return False
    planner_turn = _live_agent_loop_normalize_planner_turn_actions(planner_turn)
    now_iso = _utc_now_iso()
    autonomy_plan = _live_agent_loop_autonomy_plan_from_planner_turn(planner_turn, now_iso=now_iso)
    if autonomy_plan:
        previous = agent_state.get("autonomyPlan") if isinstance(agent_state.get("autonomyPlan"), dict) else {}
        if previous and previous.get("currentGoal") and previous.get("currentGoal") == autonomy_plan.get("currentGoal") and previous.get("createdAt"):
            autonomy_plan["createdAt"] = previous["createdAt"]
        agent_state["autonomyPlan"] = autonomy_plan
    durable_goal = None
    if agent_id:
        durable_goal = _live_agent_loop_upsert_durable_goal_from_planner(
            agent_state,
            agent_id,
            planner_turn,
            chosen_action=model_detail.get("chosen") or intention.get("action"),
        )
        linked_goal_id = (durable_goal or {}).get("id")
        if not linked_goal_id and isinstance(planner_turn.get("goal"), dict):
            linked_goal_id = planner_turn["goal"].get("id")
        if linked_goal_id and isinstance(agent_state.get("autonomyPlan"), dict):
            agent_state["autonomyPlan"]["durableGoalId"] = str(linked_goal_id)[:140]
    reflection_text = _live_agent_loop_clean_plan_text(planner_turn.get("reflection"), limit=900)
    lesson = ""
    memory_update = planner_turn.get("memoryUpdate") if isinstance(planner_turn.get("memoryUpdate"), dict) else {}
    if memory_update:
        lesson = _live_agent_loop_clean_plan_text(memory_update.get("lesson") or memory_update.get("text"), limit=700) or ""
    if reflection_text or lesson:
        memory = agent_state.get("memory") if isinstance(agent_state.get("memory"), dict) else {}
        memory.setdefault("reflections", [])
        basis = f"{reflection_text}|{lesson}|{model_detail.get('status')}|{model_detail.get('chosen')}"
        entry = {
            "at": now_iso,
            "actionId": f"planner-turn-{hashlib.sha256(basis.encode('utf-8', errors='ignore')).hexdigest()[:12]}",
            "loopActionId": model_detail.get("chosen") or intention.get("action") or "",
            "status": "planner-reflection",
            "text": reflection_text or lesson,
            "lesson": lesson,
            "source": LIVE_AGENT_LOOP_MODEL_DECISION_MODE,
        }
        memory["reflections"] = _live_agent_loop_trim_list([*(memory.get("reflections") or []), entry], LIVE_AGENT_LOOP_DEFAULTS["reflectionRetention"])
        agent_state["memory"] = memory
    saved_planner_memory = _live_agent_loop_remember_planner_memory(agent_id, lesson, memory_update) if agent_id and lesson else None
    _live_agent_loop_note_planner_support_requests(agent_state, planner_turn, model_detail)
    if agent_id:
        turn_basis = json.dumps(planner_turn, sort_keys=True, ensure_ascii=False, default=str)
        turn_key = hashlib.sha256(turn_basis.encode("utf-8", errors="ignore")).hexdigest()[:16]
        if planner_turn.get("observation"):
            _live_agent_session_append(
                agent_id,
                kind="observation",
                phase="observe",
                text=planner_turn.get("observation"),
                dedupe_key=f"planner-observation:{turn_key}",
                details={"modelStatus": model_detail.get("status")},
            )
        if planner_turn.get("reflection"):
            _live_agent_session_append(
                agent_id,
                kind="reaction",
                phase="reflect",
                text=planner_turn.get("reflection"),
                dedupe_key=f"planner-reflection:{turn_key}",
                details={"modelStatus": model_detail.get("status")},
            )
        next_step = planner_turn.get("nextStep") if isinstance(planner_turn.get("nextStep"), dict) else {}
        decision_text = _live_agent_loop_clean_plan_text(
            next_step.get("intent") or planner_turn.get("currentGoal") or intention.get("activity"),
            limit=900,
        )
        if decision_text:
            _live_agent_session_append(
                agent_id,
                kind="decision",
                phase="decide",
                text=decision_text,
                dedupe_key=f"planner-decision:{turn_key}",
                objective_id=(agent_state.get("activeGoal") or {}).get("id") if isinstance(agent_state.get("activeGoal"), dict) else None,
                details={
                    "currentGoal": planner_turn.get("currentGoal"),
                    "nextStep": next_step,
                    "chosen": model_detail.get("chosen"),
                },
            )
        if lesson:
            _live_agent_session_append(
                agent_id,
                kind="memory",
                phase="learn",
                text=f"I decided to remember: {lesson}",
                dedupe_key=f"planner-memory:{turn_key}",
                details={"memoryUpdate": memory_update, "savedMemory": saved_planner_memory},
            )
    if agent_id and (planner_turn.get("reflection") or planner_turn.get("currentGoal") or planner_turn.get("plan") or planner_turn.get("tasks") or planner_turn.get("memoryUpdate")):
        note_text_parts = []
        if planner_turn.get("reflection"):
            note_text_parts.append(f"Reflection: {planner_turn.get('reflection')}")
        if planner_turn.get("currentGoal"):
            note_text_parts.append(f"Goal: {planner_turn.get('currentGoal')}")
        if planner_turn.get("plan"):
            note_text_parts.append("Plan: " + "; ".join(str(item) for item in (planner_turn.get("plan") or [])[:6]))
        memory_update = planner_turn.get("memoryUpdate") if isinstance(planner_turn.get("memoryUpdate"), dict) else {}
        if memory_update:
            note_text_parts.append("Memory: " + "; ".join(f"{key}: {value}" for key, value in list(memory_update.items())[:4]))
        _live_agent_loop_append_internal_note(
            agent_id,
            note_type="planner-turn",
            title=planner_turn.get("currentGoal") or "Live Agent planner turn",
            text="\n".join(note_text_parts),
            details={
                "modelStatus": model_detail.get("status"),
                "chosen": model_detail.get("chosen"),
                "toolRequests": planner_turn.get("toolRequests"),
                "eventRequests": planner_turn.get("eventRequests"),
                "durableGoalId": (durable_goal or {}).get("id"),
                "durableGoalRevision": (durable_goal or {}).get("revision"),
            },
            agent_state=agent_state,
        )
    _live_agent_loop_normalize_memory(agent_state)
    return True


def _live_agent_model_decision_mark(agent_id, *, in_flight=None, min_interval_sec=None, outcome=None, generation=None):
    with _live_agent_model_decision_lock:
        row = _live_agent_model_decision_state.setdefault(agent_id, {})
        if generation is not None and int(row.get("generation") or 0) != int(generation):
            return False
        if in_flight is not None:
            row["inFlight"] = bool(in_flight)
            if not row["inFlight"]:
                row["purpose"] = "idle"
        if min_interval_sec is not None:
            row["nextAllowedEpoch"] = time.time() + max(30, int(min_interval_sec))
        if outcome is not None:
            outcome = dict(outcome) if isinstance(outcome, dict) else {"status": str(outcome)}
            status = str(outcome.get("status") or "")
            now_epoch = time.time()
            if status in LIVE_AGENT_MODEL_PROVIDER_FAILURE_STATUSES:
                streak = int(row.get("providerFailureStreak") or 0) + 1
                row["providerFailureStreak"] = streak
                row["lastProviderFailureAt"] = _epoch_to_utc_iso(now_epoch)
                if streak >= LIVE_AGENT_MODEL_CIRCUIT_FAILURE_THRESHOLD:
                    exponent = min(8, streak - LIVE_AGENT_MODEL_CIRCUIT_FAILURE_THRESHOLD)
                    open_sec = min(LIVE_AGENT_MODEL_CIRCUIT_MAX_SEC, LIVE_AGENT_MODEL_CIRCUIT_BASE_SEC * (2 ** exponent))
                    circuit_until = now_epoch + open_sec
                    row["circuitOpenUntilEpoch"] = circuit_until
                    row["circuitReason"] = status
                    outcome["circuitOpen"] = True
                    outcome["circuitOpenUntil"] = _epoch_to_utc_iso(circuit_until)
                    outcome["providerFailureStreak"] = streak
                    row["nextAllowedEpoch"] = max(float(row.get("nextAllowedEpoch") or 0), circuit_until)
            elif status not in {"cancelled", "discarded-after-disable"}:
                row["providerFailureStreak"] = 0
                row.pop("circuitOpenUntilEpoch", None)
                row.pop("circuitReason", None)
            row["lastOutcome"] = outcome
            row["lastOutcomeAt"] = _utc_now_iso()
        return True


def _live_agent_model_decision_start(agent_id, *, purpose="autonomy"):
    with _live_agent_model_decision_lock:
        row = _live_agent_model_decision_state.setdefault(agent_id, {})
        generation = int(row.get("generation") or 0) + 1
        row["generation"] = generation
        row["inFlight"] = True
        row["purpose"] = str(purpose or "autonomy")[:80]
        row["startedEpoch"] = time.time()
        row["startedAt"] = _utc_now_iso()
        row.pop("forceReason", None)
        row.pop("forceRequestedAt", None)
        row.pop("pendingChoice", None)
        return generation


def _live_agent_model_decision_cancel(agent_id, reason="agent-live-mode-disabled"):
    with _live_agent_model_decision_lock:
        row = _live_agent_model_decision_state.setdefault(agent_id, {})
        row["generation"] = int(row.get("generation") or 0) + 1
        row["inFlight"] = False
        row["cancelBeforeEpoch"] = time.time()
        row.pop("pendingChoice", None)
        row.pop("requestedCategories", None)
        row["lastOutcome"] = {"mode": LIVE_AGENT_LOOP_MODEL_DECISION_MODE, "status": "cancelled", "reason": reason}
        row["lastOutcomeAt"] = _utc_now_iso()


def _live_agent_model_provider_preempt(agent_id, reason="user-chat-preemption"):
    """Abort an active OpenClaw turn before a higher-authority user turn.

    Generation fencing prevents a stale autonomous reply from mutating My
    Virtual World, but it does not release OpenClaw's per-session execution
    lane. Without this transport-level abort, a user message can sit behind a
    long autonomous tool turn and time out. Run this from the asynchronous
    conversation worker so the HTTP chat endpoint remains immediate.
    """
    if _live_agent_model_decision_provider_kind(agent_id) != "openclaw":
        return {"ok": True, "skipped": True, "reason": "provider-does-not-share-openclaw-session-lane"}
    session = _live_agent_session_current(agent_id) or {}
    session_key = str(session.get("providerSessionKey") or session.get("providerSessionId") or "").strip()
    if not session_key:
        return {"ok": True, "skipped": True, "reason": "no-openclaw-world-session"}
    result = _gateway_rpc_call("chat.abort", {"sessionKey": session_key}, timeout=10)
    if not isinstance(result, dict):
        return {"ok": False, "sessionKey": session_key, "reason": reason, "error": "empty gateway abort response"}
    return {
        "ok": result.get("ok") is not False,
        "sessionKey": session_key,
        "reason": reason,
        "error": str(result.get("error") or "")[:500],
    }


def _live_agent_model_decision_generation_current(agent_id, generation):
    with _live_agent_model_decision_lock:
        row = _live_agent_model_decision_state.get(agent_id) or {}
        return int(row.get("generation") or 0) == int(generation or 0)


def _live_agent_model_decision_cancelled(agent_id, started_epoch, generation=None):
    with _live_agent_model_decision_lock:
        row = _live_agent_model_decision_state.get(agent_id) or {}
        if generation is not None and int(row.get("generation") or 0) != int(generation):
            return True
        try:
            cancel_epoch = float(row.get("cancelBeforeEpoch") or 0)
            started = float(started_epoch or 0)
        except (TypeError, ValueError):
            return False
        return bool(cancel_epoch and started and cancel_epoch >= started)


def _live_agent_model_decision_publish(agent_id, generation, pending):
    if not isinstance(pending, dict) or not _agent_live_mode_runtime_enabled():
        return False
    with _live_agent_model_decision_lock:
        row = _live_agent_model_decision_state.setdefault(agent_id, {})
        if int(row.get("generation") or 0) != int(generation or 0) or not row.get("inFlight"):
            return False
        row["pendingChoice"] = {**pending, "generation": generation}
    # A model answer is an event, not something that should wait for the next
    # timer cadence. Wake the scheduler so the chosen physical action begins
    # as soon as the decision can be safely revalidated against the world.
    _live_agent_loop_wake.set()
    return True


def _live_agent_model_decision_take_completed(agent_id):
    """Return and clear a completed async model choice for this agent, if any."""
    with _live_agent_model_decision_lock:
        row = _live_agent_model_decision_state.get(agent_id) or {}
        pending = row.pop("pendingChoice", None)
        return pending if isinstance(pending, dict) else None


def _live_agent_model_planner_session_key(agent_id, generation=None, *, purpose="turn"):
    """Return one disposable full-agent session key for a bounded Live turn.

    Continuity lives in the Virtual World Resident memory, checkpoint, goals,
    and journal. Reusing an OpenClaw transcript for every autonomy heartbeat
    makes raw frames and tool results grow without bound, so each meaningful
    event or conversation gets a fresh fully bootstrapped agent session.
    """
    try:
        world = _current_live_agent_world(load_world_meta_fast())
    except Exception:
        world = {}
    world_id = str((world or {}).get("worldId") or f"port-{PUBLIC_HOST_PORT}")
    world_token = re.sub(r"[^A-Za-z0-9_-]+", "-", world_id).strip("-")[:80] or f"port-{PUBLIC_HOST_PORT}"
    purpose_token = re.sub(r"[^A-Za-z0-9_-]+", "-", str(purpose or "turn")).strip("-")[:24] or "turn"
    generation_token = re.sub(r"[^A-Za-z0-9_-]+", "-", str(generation if generation is not None else "adhoc")).strip("-")[:40] or "adhoc"
    return f"agent:{agent_id}:vw-live-{purpose_token}-{LIVE_AGENT_MODEL_TURN_BOOT_ID}-g{generation_token}:vw-live-world-{world_token}"


def _live_agent_planner_trim_text(value, limit=LIVE_AGENT_PLANNER_TRANSCRIPT_TEXT_LIMIT):
    text = str(value or "")
    if len(text) <= limit:
        return text
    return text[:limit].rstrip() + f"\n\n[truncated to {limit} chars for Virtual World display]"


def _live_agent_planner_transcript_default():
    now = _utc_now_iso()
    return {
        "schemaVersion": LIVE_AGENT_PLANNER_TRANSCRIPT_SCHEMA_VERSION,
        "createdAt": now,
        "updatedAt": now,
        "agents": {},
    }


def _load_live_agent_planner_transcripts():
    try:
        data = _read_json_file(LIVE_AGENT_PLANNER_TRANSCRIPT_FILE)
    except (FileNotFoundError, json.JSONDecodeError, OSError):
        data = _live_agent_planner_transcript_default()
    if not isinstance(data, dict):
        data = _live_agent_planner_transcript_default()
    agents = data.get("agents")
    if not isinstance(agents, dict):
        data["agents"] = {}
    data["schemaVersion"] = LIVE_AGENT_PLANNER_TRANSCRIPT_SCHEMA_VERSION
    return data


def _live_agent_planner_turn_semantic_summary(turn):
    turn = turn if isinstance(turn, dict) else {}
    parsed = _live_agent_model_json_object_parse(turn.get("reply"))
    parsed = parsed if isinstance(parsed, dict) else {}
    memory_update = parsed.get("memoryUpdate") if isinstance(parsed.get("memoryUpdate"), dict) else {}
    next_step = parsed.get("nextStep") if isinstance(parsed.get("nextStep"), dict) else {}
    semantic = {
        "reflection": _live_agent_loop_clean_plan_text(parsed.get("reflection"), limit=700),
        "currentGoal": _live_agent_loop_clean_plan_text(parsed.get("currentGoal"), limit=500),
        "plan": [
            _live_agent_loop_clean_plan_text(item, limit=300)
            for item in (parsed.get("plan") or [])[:6]
            if _live_agent_loop_clean_plan_text(item, limit=300)
        ] if isinstance(parsed.get("plan"), list) else [],
        "nextStep": {
            key: _live_agent_loop_clean_plan_text(next_step.get(key), limit=360)
            for key in ("intent", "action", "category", "targetCriteria", "successCriteria")
            if _live_agent_loop_clean_plan_text(next_step.get(key), limit=360)
        },
        "lesson": _live_agent_loop_clean_plan_text(
            memory_update.get("lesson") or parsed.get("lesson"), limit=700
        ),
    }
    if isinstance(turn.get("intention"), dict):
        semantic["intention"] = _compact_json_value_for_storage(
            turn.get("intention"), max_depth=2, max_items=10, string_limit=500
        )
    return {key: value for key, value in semantic.items() if value not in (None, "", [], {})}


def _compact_live_agent_planner_turn(turn, *, keep_full):
    if not isinstance(turn, dict):
        return None
    compacted = _copy_jsonable(turn)
    original_prompt = str(compacted.get("prompt") or "")
    original_reply = str(compacted.get("reply") or "")
    original_bytes = _json_size_bytes(compacted)
    already_compacted = bool((compacted.get("storageCompaction") or {}).get("olderTurnSummarized")) if isinstance(compacted.get("storageCompaction"), dict) else False
    if already_compacted:
        return compacted
    if keep_full and not already_compacted:
        compacted["prompt"] = _live_agent_planner_trim_text(original_prompt)
        compacted["reply"] = _live_agent_planner_trim_text(original_reply, limit=8000)
        if _json_size_bytes(compacted) <= LIVE_AGENT_PLANNER_TRANSCRIPT_RECORD_MAX_BYTES:
            return compacted
        envelope = {**compacted, "prompt": "", "reply": ""}
        available = max(1600, LIVE_AGENT_PLANNER_TRANSCRIPT_RECORD_MAX_BYTES - _json_size_bytes(envelope) - 512)
        reply_limit = min(8000, max(600, available // 3))
        compacted["reply"] = _live_agent_planner_trim_text(original_reply, limit=reply_limit)
        prompt_limit = max(800, available - _json_size_bytes(compacted["reply"]))
        compacted["prompt"] = _live_agent_planner_trim_text(original_prompt, limit=prompt_limit)
        compacted["storageCompaction"] = {
            "recentFullTurnTruncated": True,
            "originalBytes": original_bytes,
            "originalPromptChars": len(original_prompt),
            "originalReplyChars": len(original_reply),
        }
        while _json_size_bytes(compacted) > LIVE_AGENT_PLANNER_TRANSCRIPT_RECORD_MAX_BYTES and len(compacted.get("prompt") or "") > 200:
            compacted["prompt"] = compacted["prompt"][:max(200, len(compacted["prompt"]) - 512)]
        while _json_size_bytes(compacted) > LIVE_AGENT_PLANNER_TRANSCRIPT_RECORD_MAX_BYTES and len(compacted.get("reply") or "") > 200:
            compacted["reply"] = compacted["reply"][:max(200, len(compacted["reply"]) - 256)]
        if _json_size_bytes(compacted) <= LIVE_AGENT_PLANNER_TRANSCRIPT_RECORD_MAX_BYTES:
            return compacted

    semantic = _live_agent_planner_turn_semantic_summary(compacted)
    prompt_hash = hashlib.sha256(original_prompt.encode("utf-8", errors="ignore")).hexdigest()
    reply_hash = hashlib.sha256(original_reply.encode("utf-8", errors="ignore")).hexdigest()
    compacted["prompt"] = (
        "[Older Live Mode planner frame compacted for storage. "
        f"Original: {len(original_prompt)} characters; SHA-256: {prompt_hash}.]"
    )
    compacted["reply"] = json.dumps(
        {
            "storageCompacted": True,
            "semanticSummary": semantic,
            "originalReplyChars": len(original_reply),
            "originalReplySha256": reply_hash,
        },
        separators=(",", ":"),
        ensure_ascii=False,
    )
    compacted["semanticSummary"] = semantic
    compacted["storageCompaction"] = {
        "olderTurnSummarized": True,
        "originalBytes": original_bytes,
        "originalPromptChars": len(original_prompt),
        "originalReplyChars": len(original_reply),
        "promptSha256": prompt_hash,
        "replySha256": reply_hash,
    }
    compacted.pop("candidateIds", None)
    if _json_size_bytes(compacted) > LIVE_AGENT_PLANNER_TRANSCRIPT_RECORD_MAX_BYTES:
        compacted["semanticSummary"] = _compact_json_value_for_storage(
            semantic, max_depth=3, max_items=12, string_limit=400
        )
        compacted["reply"] = json.dumps(
            {"storageCompacted": True, "semanticSummary": compacted["semanticSummary"]},
            separators=(",", ":"),
            ensure_ascii=False,
        )
        compacted.pop("intention", None)
    return compacted


def _compact_live_agent_planner_transcripts_document(data):
    data = _copy_jsonable(data) if isinstance(data, dict) else _live_agent_planner_transcript_default()
    agents = data.get("agents") if isinstance(data.get("agents"), dict) else {}
    next_agents = {}
    for agent_id, raw_row in agents.items():
        row = raw_row if isinstance(raw_row, dict) else {}
        turns = [item for item in (row.get("turns") or []) if isinstance(item, dict)]
        ranked = sorted(range(len(turns)), key=lambda index: (_storage_record_epoch(turns[index]), index), reverse=True)
        full_indexes = set(ranked[:LIVE_AGENT_PLANNER_FULL_TURNS_PER_AGENT])
        compacted_turns = [
            _compact_live_agent_planner_turn(turn, keep_full=index in full_indexes)
            for index, turn in enumerate(turns)
        ]
        compacted_turns = [turn for turn in compacted_turns if isinstance(turn, dict)]
        compacted_turns.sort(key=_storage_record_epoch)
        if compacted_turns:
            next_agents[str(agent_id)] = {**row, "turns": compacted_turns}
    data["agents"] = next_agents
    return data


def _save_live_agent_planner_transcripts(data):
    data = data if isinstance(data, dict) else _live_agent_planner_transcript_default()
    data["schemaVersion"] = LIVE_AGENT_PLANNER_TRANSCRIPT_SCHEMA_VERSION
    data["updatedAt"] = _utc_now_iso()
    data = _compact_live_agent_planner_transcripts_document(data)
    data = _trim_agent_document_records(
        data,
        "turns",
        max_records_per_agent=LIVE_AGENT_PLANNER_TRANSCRIPT_RETENTION,
        max_bytes=LIVE_AGENT_PLANNER_TRANSCRIPTS_MAX_BYTES,
    )
    data["schemaVersion"] = LIVE_AGENT_PLANNER_TRANSCRIPT_SCHEMA_VERSION
    data["updatedAt"] = _utc_now_iso()
    _atomic_write_text(LIVE_AGENT_PLANNER_TRANSCRIPT_FILE, _json_compact_bytes(data).decode("utf-8"))
    return data


def _live_agent_planner_turn_id(agent_id, started_epoch, prompt, reply_text):
    basis = f"{agent_id}|{started_epoch}|{prompt}|{reply_text}"
    digest = hashlib.sha256(basis.encode("utf-8", errors="ignore")).hexdigest()[:12]
    return f"planner-{int(float(started_epoch or time.time()) * 1000)}-{digest}"


def _live_agent_planner_transcript_record(agent_id, *, session_key, started_epoch, prompt, reply_text="", detail=None, candidate_ids=None):
    """Store a Virtual-World-owned copy of one planner turn for the UI.

    This is intentionally separate from the disposable OpenClaw gateway
    transcript. My Virtual World keeps this bounded operator trace as
    diagnostics; grounded continuity lives in the Resident memory, journal,
    checkpoint, and goals rather than in raw provider-turn replay.
    """
    agent_key = str(agent_id or "").strip()
    if not agent_key:
        return None
    started = float(started_epoch or time.time())
    detail = detail if isinstance(detail, dict) else {}
    prompt_text = _live_agent_planner_trim_text(prompt)
    reply_text = _live_agent_planner_trim_text(reply_text, limit=8000)
    turn = {
        "id": _live_agent_planner_turn_id(agent_key, started, prompt_text, reply_text),
        "agentId": agent_key,
        "sessionKey": session_key or _live_agent_model_planner_session_key(agent_key),
        "startedAt": _epoch_to_utc_iso(started),
        "completedAt": _utc_now_iso(),
        "status": str(detail.get("status") or "unknown")[:120],
        "mode": str(detail.get("mode") or LIVE_AGENT_LOOP_MODEL_DECISION_MODE)[:120],
        "prompt": prompt_text,
        "reply": reply_text,
        "chosen": detail.get("chosen"),
        "parseStatus": detail.get("status"),
        "failureKind": str(detail.get("failureKind") or "")[:120] or None,
        "error": str(detail.get("error") or "")[:500] or None,
        "latencySec": detail.get("latencySec"),
        "intention": _copy_jsonable(detail.get("intention")) if isinstance(detail.get("intention"), dict) else None,
        "candidateIds": [str(item) for item in (candidate_ids or []) if str(item or "").strip()][:40],
    }
    with _live_agent_planner_transcript_lock:
        data = _load_live_agent_planner_transcripts()
        agents = data.setdefault("agents", {})
        row = agents.setdefault(agent_key, {"turns": []})
        if not isinstance(row, dict):
            row = {"turns": []}
            agents[agent_key] = row
        turns = [item for item in (row.get("turns") or []) if isinstance(item, dict) and item.get("id") != turn["id"]]
        turns.append(turn)
        turns.sort(key=lambda item: _parse_isoish_epoch(item.get("startedAt")) or 0)
        row["turns"] = turns[-LIVE_AGENT_PLANNER_TRANSCRIPT_RETENTION:]
        row["updatedAt"] = turn["completedAt"]
        _save_live_agent_planner_transcripts(data)
    return turn


def _live_agent_sessions_default():
    now = _utc_now_iso()
    return {
        "schemaVersion": LIVE_AGENT_SESSION_DOCUMENT_SCHEMA_VERSION,
        "createdAt": now,
        "updatedAt": now,
        "agents": {},
    }


def _live_agent_session_normalize_message(message):
    if not isinstance(message, dict):
        return None
    text_value = _live_agent_loop_clean_plan_text(message.get("text"), limit=4000)
    if not text_value:
        return None
    at = message.get("at") if _parse_isoish_epoch(message.get("at")) else _utc_now_iso()
    kind = str(message.get("kind") or "event").strip().lower().replace("_", "-")
    if kind not in LIVE_AGENT_SESSION_MESSAGE_KINDS:
        kind = "event"
    role = str(message.get("role") or ("user" if kind == "user" else "assistant")).strip().lower()
    if role not in {"user", "assistant", "system"}:
        role = "assistant"
    normalized = {
        "id": _live_agent_loop_clean_plan_text(message.get("id"), limit=160) or f"live-message-{uuid.uuid4().hex[:16]}",
        "at": at,
        "role": role,
        "kind": kind,
        "phase": _live_agent_loop_clean_plan_text(message.get("phase"), limit=80) or kind,
        "text": text_value,
    }
    for key, limit in (("dedupeKey", 240), ("actionId", 180), ("objectiveId", 180), ("source", 120)):
        value = _live_agent_loop_clean_plan_text(message.get(key), limit=limit)
        if value:
            normalized[key] = value
    if isinstance(message.get("details"), dict):
        normalized["details"] = _compact_json_value_for_storage(
            message.get("details"), max_depth=4, max_items=40, string_limit=900
        )
    return normalized


def _live_agent_session_normalize(session):
    if not isinstance(session, dict):
        return None
    session_id = _live_agent_loop_clean_plan_text(session.get("id"), limit=180)
    agent_id = _live_agent_loop_clean_plan_text(session.get("agentId"), limit=120)
    if not session_id or not agent_id:
        return None
    now = _utc_now_iso()
    status = str(session.get("status") or "active").strip().lower()
    if status not in {"active", "paused", "archived"}:
        status = "active"
    normalized = {
        "schemaVersion": LIVE_AGENT_SESSION_SCHEMA_VERSION,
        "id": session_id,
        "activationId": _live_agent_loop_clean_plan_text(session.get("activationId"), limit=180) or session_id,
        "agentId": agent_id,
        "providerKind": _live_agent_loop_clean_plan_text(session.get("providerKind"), limit=80) or "unknown",
        "status": status,
        "startedAt": session.get("startedAt") if _parse_isoish_epoch(session.get("startedAt")) else now,
        "updatedAt": session.get("updatedAt") if _parse_isoish_epoch(session.get("updatedAt")) else now,
        "messages": [],
        "checkpoint": _copy_jsonable(session.get("checkpoint")) if isinstance(session.get("checkpoint"), dict) else {
            "phase": "observe", "objective": None, "currentActionId": None, "currentStep": None,
        },
    }
    for key in ("endedAt", "pausedAt"):
        if _parse_isoish_epoch(session.get(key)):
            normalized[key] = session.get(key)
    for key, limit in (("providerSessionId", 240), ("providerSessionKey", 240), ("archiveReason", 180)):
        value = _live_agent_loop_clean_plan_text(session.get(key), limit=limit)
        if value:
            normalized[key] = value
    # Provider sessions are disposable transport lanes. The durable activation,
    # checkpoint, journal, goals, and memories live here in My Virtual World.
    legacy_key = str(normalized.get("providerSessionKey") or "")
    if normalized.get("providerKind") == "openclaw" and re.fullmatch(
        r"agent:[^:]+:vw-live-world-[A-Za-z0-9_-]+", legacy_key
    ):
        normalized["providerSessionKey"] = ""
        if str(normalized.get("providerSessionId") or "") == legacy_key:
            normalized["providerSessionId"] = ""
    if isinstance(session.get("world"), dict):
        normalized["world"] = _compact_json_value_for_storage(session.get("world"), max_depth=3, max_items=20, string_limit=500)
    if isinstance(session.get("workingMemory"), dict):
        normalized["workingMemory"] = _compact_json_value_for_storage(session.get("workingMemory"), max_depth=4, max_items=40, string_limit=900)
    messages = []
    seen_dedupe = set()
    for raw in session.get("messages") or []:
        message = _live_agent_session_normalize_message(raw)
        if not message:
            continue
        dedupe_key = message.get("dedupeKey")
        if dedupe_key and dedupe_key in seen_dedupe:
            continue
        if dedupe_key:
            seen_dedupe.add(dedupe_key)
        messages.append(message)
    messages.sort(key=lambda item: _parse_isoish_epoch(item.get("at")) or 0)
    normalized["messages"] = messages[-LIVE_AGENT_SESSION_MESSAGE_RETENTION:]
    return normalized


def _load_live_agent_sessions():
    try:
        data = _read_json_file(LIVE_AGENT_SESSION_FILE)
    except (FileNotFoundError, json.JSONDecodeError, OSError):
        data = _live_agent_sessions_default()
    if not isinstance(data, dict):
        data = _live_agent_sessions_default()
    agents = data.get("agents") if isinstance(data.get("agents"), dict) else {}
    normalized_agents = {}
    for agent_id, raw in agents.items():
        row = raw if isinstance(raw, dict) else {}
        active = _live_agent_session_normalize(row.get("active"))
        history = [
            item for candidate in (row.get("history") or [])
            if (item := _live_agent_session_normalize(candidate))
        ][-LIVE_AGENT_SESSION_HISTORY_RETENTION:]
        if active or history:
            normalized_agents[str(agent_id)] = {"active": active, "history": history}
    data["agents"] = normalized_agents
    data["schemaVersion"] = LIVE_AGENT_SESSION_DOCUMENT_SCHEMA_VERSION
    return data


def _save_live_agent_sessions(data):
    data = data if isinstance(data, dict) else _live_agent_sessions_default()
    data["schemaVersion"] = LIVE_AGENT_SESSION_DOCUMENT_SCHEMA_VERSION
    data["updatedAt"] = _utc_now_iso()
    payload = _json_compact_bytes(data)
    if len(payload) > LIVE_AGENT_SESSION_DOCUMENT_MAX_BYTES:
        # Preserve active sessions first, then retain only the newest archive
        # for each resident. Message histories are already bounded above.
        for row in (data.get("agents") or {}).values():
            if isinstance(row, dict):
                row["history"] = (row.get("history") or [])[-3:]
        payload = _json_compact_bytes(data)
    _atomic_write_text(LIVE_AGENT_SESSION_FILE, payload.decode("utf-8"))
    return data


def _live_agent_session_world_snapshot():
    try:
        world = _current_live_agent_world(load_world_meta_fast())
    except Exception:
        world = {}
    return {
        key: world.get(key)
        for key in ("worldId", "worldName", "serverPort", "dataDir", "instanceId")
        if world.get(key) is not None
    }


def _live_agent_session_open(agent_id, *, force_new=False, reason="live-mode-enabled"):
    resolved = _resolve_agent_id(agent_id) or str(agent_id or "").strip()
    if not resolved:
        return None
    with _live_agent_session_lock:
        data = _load_live_agent_sessions()
        row = data.setdefault("agents", {}).setdefault(resolved, {"active": None, "history": []})
        active = _live_agent_session_normalize(row.get("active"))
        if active and active.get("status") == "active" and not force_new:
            return active
        now = _utc_now_iso()
        if active:
            active["status"] = "archived"
            active["endedAt"] = now
            active["updatedAt"] = now
            active["archiveReason"] = "superseded-by-new-activation"
            row["history"] = [*(row.get("history") or []), active][-LIVE_AGENT_SESSION_HISTORY_RETENTION:]
        activation_epoch_ms = int(time.time() * 1000)
        activation_id = f"activation-{activation_epoch_ms}-{uuid.uuid4().hex[:8]}"
        provider_kind = _live_agent_model_decision_provider_kind(resolved) or "unknown"
        active = {
            "schemaVersion": LIVE_AGENT_SESSION_SCHEMA_VERSION,
            "id": f"live-session-{resolved}-{activation_epoch_ms}-{uuid.uuid4().hex[:8]}",
            "activationId": activation_id,
            "agentId": resolved,
            "providerKind": provider_kind,
            "providerSessionKey": "",
            "providerSessionId": "",
            "status": "active",
            "startedAt": now,
            "updatedAt": now,
            "world": _live_agent_session_world_snapshot(),
            "checkpoint": {
                "phase": "observing",
                "controllerState": "observing",
                "behaviorOwner": "agent-live-mode",
                "objective": None,
                "currentActionId": None,
                "currentStep": "observing",
                "interruptible": True,
                "resumePolicy": "resume-unless-user-stops-or-redirects",
                "actionEventKeys": [],
            },
            "workingMemory": {"inventory": [], "resourceSignals": {}, "userDirectives": []},
            "messages": [{
                "id": f"live-message-{uuid.uuid4().hex[:16]}",
                "at": now,
                "role": "system",
                "kind": "activation",
                "phase": "observe",
                "text": "Live Mode activated. My Virtual World handed the resident body to the bound agent framework and suppressed Default Mode.",
                "dedupeKey": f"activation:{activation_id}",
                "source": reason,
            }],
        }
        row["active"] = active
        _save_live_agent_sessions(data)
        return _copy_jsonable(active)


def _live_agent_session_archive(agent_id, *, reason="live-mode-disabled"):
    resolved = _resolve_agent_id(agent_id) or str(agent_id or "").strip()
    if not resolved:
        return None
    with _live_agent_session_lock:
        data = _load_live_agent_sessions()
        row = (data.get("agents") or {}).get(resolved)
        if not isinstance(row, dict):
            return None
        active = _live_agent_session_normalize(row.get("active"))
        if not active:
            return None
        now = _utc_now_iso()
        active["status"] = "archived"
        active["endedAt"] = now
        active["updatedAt"] = now
        active["archiveReason"] = str(reason or "live-mode-disabled")[:180]
        active.setdefault("messages", []).append({
            "id": f"live-message-{uuid.uuid4().hex[:16]}",
            "at": now,
            "role": "system",
            "kind": "event",
            "phase": "archived",
            "text": "Live Mode stopped. The resident body lease was revoked, the activation was archived, and Default Mode may resume.",
            "dedupeKey": f"archive:{active.get('activationId')}",
            "source": reason,
        })
        row["history"] = [*(row.get("history") or []), _live_agent_session_normalize(active)][-LIVE_AGENT_SESSION_HISTORY_RETENTION:]
        row["active"] = None
        _save_live_agent_sessions(data)
        return _copy_jsonable(active)


def _live_agent_session_current(agent_id, *, include_archived=False):
    resolved = _resolve_agent_id(agent_id) or str(agent_id or "").strip()
    if not resolved:
        return None
    with _live_agent_session_lock:
        data = _load_live_agent_sessions()
        row = (data.get("agents") or {}).get(resolved)
        if not isinstance(row, dict):
            return None
        active = _live_agent_session_normalize(row.get("active"))
        if active:
            return _copy_jsonable(active)
        if include_archived:
            history = row.get("history") if isinstance(row.get("history"), list) else []
            if history:
                return _copy_jsonable(_live_agent_session_normalize(history[-1]))
    return None


def _live_agent_session_append(agent_id, *, kind, text, phase=None, role="assistant", dedupe_key=None, action_id=None, objective_id=None, details=None, source="live-agent-mode", at=None):
    resolved = _resolve_agent_id(agent_id) or str(agent_id or "").strip()
    if not resolved or not str(text or "").strip():
        return None
    with _live_agent_session_lock:
        data = _load_live_agent_sessions()
        row = data.setdefault("agents", {}).setdefault(resolved, {"active": None, "history": []})
        active = _live_agent_session_normalize(row.get("active"))
        if not active:
            # This also gives upgraded worlds a durable session on their next
            # heartbeat without requiring the operator to toggle Live Mode.
            _live_agent_session_open(resolved, reason="live-loop-recovered")
            data = _load_live_agent_sessions()
            row = data.setdefault("agents", {}).setdefault(resolved, {"active": None, "history": []})
            active = _live_agent_session_normalize(row.get("active"))
        if not active:
            return None
        if dedupe_key and any(item.get("dedupeKey") == dedupe_key for item in active.get("messages") or []):
            return next((item for item in active.get("messages") or [] if item.get("dedupeKey") == dedupe_key), None)
        message = _live_agent_session_normalize_message({
            "at": at if _parse_isoish_epoch(at) else _utc_now_iso(),
            "role": role,
            "kind": kind,
            "phase": phase or kind,
            "text": text,
            "dedupeKey": dedupe_key,
            "actionId": action_id,
            "objectiveId": objective_id,
            "details": details,
            "source": source,
        })
        if not message:
            return None
        active["messages"] = [*(active.get("messages") or []), message]
        active["messages"].sort(key=lambda item: _parse_isoish_epoch(item.get("at")) or 0)
        active["messages"] = active["messages"][-LIVE_AGENT_SESSION_MESSAGE_RETENTION:]
        active["updatedAt"] = _utc_now_iso()
        if phase:
            active.setdefault("checkpoint", {})["phase"] = phase
            active["checkpoint"]["currentStep"] = phase
        if action_id:
            active.setdefault("checkpoint", {})["currentActionId"] = action_id
        row["active"] = active
        _save_live_agent_sessions(data)
        return _copy_jsonable(message)


def _live_agent_session_update(agent_id, *, checkpoint=None, working_memory=None, provider_session_id=None, provider_session_key=None):
    resolved = _resolve_agent_id(agent_id) or str(agent_id or "").strip()
    if not resolved:
        return None
    with _live_agent_session_lock:
        data = _load_live_agent_sessions()
        row = (data.get("agents") or {}).get(resolved)
        active = _live_agent_session_normalize((row or {}).get("active")) if isinstance(row, dict) else None
        if not active:
            return None
        if isinstance(checkpoint, dict):
            active["checkpoint"] = {**(active.get("checkpoint") or {}), **_copy_jsonable(checkpoint)}
        if isinstance(working_memory, dict):
            active["workingMemory"] = {**(active.get("workingMemory") or {}), **_copy_jsonable(working_memory)}
        if provider_session_id is not None:
            active["providerSessionId"] = str(provider_session_id or "")[:240]
        if provider_session_key is not None:
            active["providerSessionKey"] = str(provider_session_key or "")[:240]
        active["updatedAt"] = _utc_now_iso()
        row["active"] = active
        _save_live_agent_sessions(data)
        return _copy_jsonable(active)


def _live_agent_session_clear_provider_turn(agent_id, session_key):
    """Clear a completed transport binding without clobbering a newer turn."""
    resolved = _resolve_agent_id(agent_id) or str(agent_id or "").strip()
    session_key = str(session_key or "").strip()
    if not resolved or not session_key:
        return False
    with _live_agent_session_lock:
        data = _load_live_agent_sessions()
        row = (data.get("agents") or {}).get(resolved)
        active = _live_agent_session_normalize((row or {}).get("active")) if isinstance(row, dict) else None
        if not active or str(active.get("providerSessionKey") or "") != session_key:
            return False
        active["providerSessionKey"] = ""
        if str(active.get("providerSessionId") or "") == session_key:
            active["providerSessionId"] = ""
        active["updatedAt"] = _utc_now_iso()
        row["active"] = active
        _save_live_agent_sessions(data)
        return True


def _live_agent_session_target_description(action):
    action = action if isinstance(action, dict) else {}
    target = action.get("target") if isinstance(action.get("target"), dict) else {}
    point = _live_agent_action_target_point(action)
    label = (
        target.get("objectLabel")
        or target.get("catalogId")
        or target.get("targetAgentName")
        or target.get("buildingName")
        or target.get("buildingId")
        or target.get("kind")
        or action.get("actionType")
        or "target"
    )
    label = str(label).replace("-", " ")
    if isinstance(point, dict) and isinstance(point.get("x"), (int, float)) and isinstance(point.get("y"), (int, float)):
        return f"{label} at ({round(float(point['x']), 1)}, {round(float(point['y']), 1)})"
    return label


def _live_agent_session_action_event_message(action, event):
    action = action if isinstance(action, dict) else {}
    event = event if isinstance(event, dict) else {}
    status = _canonical_world_action_status(
        event.get("toStatus") or event.get("to") or event.get("status") or action.get("status")
    )
    name = str(event.get("name") or event.get("type") or status or "event").strip().lower()
    agent_id = str(action.get("agentId") or "").strip()
    agent_row = _agent_record_for(agent_id) or {}
    resident_name = str(agent_row.get("name") or agent_row.get("displayName") or agent_id or "The resident")
    if name in {"route-intent-cleared", "linked-move-intent-cleared", "move-intent-cleared"}:
        return None
    target_text = _live_agent_session_target_description(action)
    reservation = action.get("reservation") if isinstance(action.get("reservation"), dict) else {}
    queue_index = reservation.get("queueIndex")
    queue_number = int(queue_index) + 1 if isinstance(queue_index, (int, float)) else None
    if "queue" in name and "promot" in name:
        return "queue", "revalidate-target", f"The queue advanced; {target_text} is now available to {resident_name}."
    if "queue" in name or reservation.get("state") == "queued" and status in {"reserved", "route_pending", "routing"}:
        text_value = f"{target_text} is currently being used. {resident_name} joined the queue"
        if queue_number:
            text_value += f" at position {queue_number}"
        return "queue", "reserve-or-queue", text_value + "."
    if name == "requested":
        return None
    if name in {"created", "action-created"}:
        return "decision", "select-target", f"World action accepted for {resident_name}: {target_text}."
    if status == "reserved" or name in {"reserved", "object-reserved"}:
        return None
    if status == "route_pending" or name == "route-pending":
        return None
    if status == "routing" or name == "routing":
        return "action", "route", f"{resident_name} is walking to {target_text}."
    if status == "arrived" or name == "arrived":
        return "observation", "revalidate-target", f"{resident_name} arrived at {target_text}; the world is revalidating it."
    if status == "in_progress" or name in {"in-progress", "activity-started"}:
        return "action", "begin-use", f"{resident_name} is interacting with {target_text}."
    if name == "reservation-released":
        return None
    if status == "completed" or name == "completed":
        return "result", "verify", f"Verified world result: {resident_name} completed the interaction with {target_text}."
    if status in {"failed", "expired", "cancelled"} or name in {"failed", "expired", "cancelled"}:
        result = action.get("result") if isinstance(action.get("result"), dict) else {}
        reason = event.get("reason") or result.get("reason") or action.get("failureReason") or status
        if _live_agent_loop_is_user_control_cancel(status, reason):
            return "event", "replan", f"World action at {target_text} stopped because the user changed {resident_name}'s priority."
        return "reaction", "replan", f"World action failed at {target_text}: {str(reason).replace('_', ' ')}."
    return None


def _live_agent_session_request_world_action_sync(agent_id, min_interval_sec=0.75):
    """Schedule one coalesced journal refresh without blocking an HTTP/UI path."""
    resolved = str(agent_id or "").strip()
    if not resolved:
        return False
    now_epoch = time.monotonic()
    with _live_agent_session_action_sync_lock:
        row = _live_agent_session_action_sync_state.setdefault(resolved, {})
        last_requested = float(row.get("lastRequestedEpoch") or 0)
        if row.get("inFlight") or now_epoch - last_requested < max(0.1, float(min_interval_sec or 0)):
            return False
        row["lastRequestedEpoch"] = now_epoch
    threading.Thread(
        target=_live_agent_session_sync_world_actions,
        args=(resolved,),
        daemon=True,
        name=f"vw-live-session-sync-{resolved}",
    ).start()
    return True


def _live_agent_session_sync_world_actions(agent_id):
    """Synchronously merge new physical events into one Resident journal.

    Scheduler/reconciliation callers use this directly. UI callers use the
    coalesced request helper above so a large history file never stalls chat.
    """
    resolved = str(agent_id or "").strip()
    if not resolved:
        return False
    with _live_agent_session_action_sync_lock:
        row = _live_agent_session_action_sync_state.setdefault(resolved, {})
        if row.get("inFlight"):
            return False
        row["inFlight"] = True
        row["startedEpoch"] = time.monotonic()
    try:
        return _live_agent_session_sync_world_actions_now(resolved)
    finally:
        with _live_agent_session_action_sync_lock:
            row = _live_agent_session_action_sync_state.setdefault(resolved, {})
            row["inFlight"] = False
            row["finishedEpoch"] = time.monotonic()


def _live_agent_session_sync_world_actions_now(agent_id):
    session = _live_agent_session_current(agent_id)
    if not isinstance(session, dict):
        return False
    activation_started_epoch = _parse_isoish_epoch(session.get("startedAt")) or 0
    checkpoint = session.get("checkpoint") if isinstance(session.get("checkpoint"), dict) else {}
    seen = set(str(item) for item in (checkpoint.get("actionEventKeys") or []) if str(item or ""))
    next_seen = list(seen)
    try:
        prior_cursor = int(checkpoint.get("worldActionEventCursor") or 0)
    except (TypeError, ValueError):
        prior_cursor = 0
    store = get_world_actions_store(persist_migration=True)
    action_lookup = {}
    owned_actions = []
    for bucket in ("history", "active"):
        for action in store.get(bucket) or []:
            if not isinstance(action, dict) or action.get("agentId") != agent_id or not _live_agent_loop_owns_world_action(action):
                continue
            action_lookup[str(action.get("id") or "")] = (action, bucket)
            owned_actions.append((action, bucket))
    owned_actions.sort(key=lambda item: _live_agent_loop_action_epoch(item[0]))

    event_store = get_world_action_events_store(persist_migration=True)
    next_cursor = prior_cursor
    pending = []
    global_event_ids = set()
    for event in event_store.get("events") or []:
        if not isinstance(event, dict) or event.get("agentId") != agent_id:
            continue
        if event.get("behaviorSourceKind") not in {None, "agent-live-mode"}:
            continue
        sequence = int(event.get("sequence") or 0)
        if sequence and sequence <= prior_cursor:
            continue
        event_epoch = _parse_isoish_epoch(event.get("at")) or 0
        if activation_started_epoch and event_epoch and event_epoch < activation_started_epoch:
            continue
        action_row = action_lookup.get(str(event.get("actionId") or ""))
        if not action_row:
            continue
        global_event_ids.add(str(event.get("id") or ""))
        pending.append((sequence, event_epoch, event, action_row[0], action_row[1]))
        next_cursor = max(next_cursor, sequence)
    # Compatibility path for migrated/active records whose embedded lifecycle
    # predates the global event cursor. The global store remains authoritative
    # whenever the same stable event id exists.
    for action, bucket in owned_actions[-24:]:
        action_id = str(action.get("id") or "")
        embedded = [event for event in (action.get("events") or []) if isinstance(event, dict)]
        semantic = {
            (str(event.get("name") or event.get("type") or "").lower(), str(event.get("at") or ""))
            for event in embedded
        }
        for index, effect in enumerate(action.get("effects") or []):
            if not isinstance(effect, dict):
                continue
            signature = (str(effect.get("name") or effect.get("type") or "").lower(), str(effect.get("at") or ""))
            if signature in semantic:
                continue
            semantic.add(signature)
            embedded.append({
                **effect,
                "id": effect.get("id") or f"effect:{action_id}:{index}:{effect.get('type')}:{effect.get('at')}",
                "name": effect.get("name") or effect.get("type"),
            })
        for event in embedded:
            event_id = str(event.get("id") or f"{action_id}:{event.get('name') or event.get('type')}:{event.get('at')}")
            if event_id in global_event_ids:
                continue
            event_epoch = _parse_isoish_epoch(event.get("at")) or _live_agent_loop_action_epoch(action)
            if activation_started_epoch and event_epoch and event_epoch < activation_started_epoch:
                continue
            pending.append((int(event.get("sequence") or 0), event_epoch, {**event, "id": event_id, "actionId": action_id}, action, bucket))
    pending.sort(key=lambda row: (row[1] or 0, row[0] or 0))

    changed = False
    visible_pending = []
    for sequence, event_epoch, event, action, bucket in pending:
        event_key = str(event.get("id") or f"{event.get('actionId')}:{event.get('name')}:{event.get('at')}")
        if event_key in seen:
            continue
        seen.add(event_key)
        next_seen.append(event_key)
        mapped = _live_agent_session_action_event_message(action, event)
        if mapped:
            visible_pending.append((sequence, event_epoch, event, action, bucket, mapped, event_key))

    # A restart can produce a large catch-up. Keep it truthful without making
    # old lifecycle details look like current behavior.
    if len(visible_pending) > 12:
        condensed = visible_pending[:-8]
        first_at = condensed[0][2].get("at")
        last_at = condensed[-1][2].get("at")
        _live_agent_session_append(
            agent_id,
            kind="event",
            phase="catch-up",
            text=f"The world restored {len(condensed)} earlier Live Mode events from this activation.",
            role="system",
            dedupe_key=f"world-action-catchup:{session.get('activationId')}:{condensed[-1][0]}",
            details={"eventCount": len(condensed), "fromAt": first_at, "toAt": last_at},
            at=last_at,
        )
        changed = True
        visible_pending = visible_pending[-8:]

    for sequence, event_epoch, event, action, bucket, mapped, event_key in visible_pending:
        kind, phase, text_value = mapped
        _live_agent_session_append(
            agent_id,
            kind=kind,
            phase=phase,
            text=text_value,
            role="system",
            dedupe_key=f"world-action-event:{event_key}",
            action_id=str(action.get("id") or ""),
            details={
                "event": {key: event.get(key) for key in ("type", "name", "at", "sequence", "fromStatus", "toStatus", "reason")},
                "status": _canonical_world_action_status(action.get("status")),
                "target": _live_agent_loop_memory_target(action.get("target")),
                "bucket": bucket,
            },
            at=event.get("at"),
        )
        changed = True

    last_action = owned_actions[-1][0] if owned_actions else None
    last_status = _canonical_world_action_status(last_action.get("status")) if last_action else None
    checkpoint_patch = {
        "actionEventKeys": next_seen[-200:],
        "worldActionEventCursor": next_cursor,
    }
    if last_action and last_status in WORLD_ACTION_ACTIVE_STATES:
        checkpoint_patch.update({
            "currentActionId": last_action.get("id"),
            "currentActionStatus": last_status,
            "target": _live_agent_loop_memory_target(last_action.get("target")),
            "interruptible": True,
        })
    elif last_action:
        checkpoint_patch.update({
            "currentActionId": None,
            "currentActionStatus": last_status,
            "currentStep": "continue",
            "phase": "continue",
            "interruptible": True,
        })
    _live_agent_session_update(agent_id, checkpoint=checkpoint_patch)
    return changed


def _live_agent_session_user_intent(message):
    """Classify only the control authority needed for an interruption.

    This intentionally does not try to infer the Resident's next world action;
    it separates conversational questions from explicit stop/resume/redirect
    commands so a question never tears down a physical route.
    """
    text = " ".join(str(message or "").strip().lower().split())
    if re.fullmatch(r"(?:hi|hello|hey|hey there|hi there|hello there|good (?:morning|afternoon|evening))[!. ]*", text):
        return "greeting"
    if re.fullmatch(r"(?:please\s+)?(?:stop|cancel|halt|pause|freeze)(?:\s+(?:now|that|this|what you(?:'re| are) doing|and wait|there))?[!. ]*", text):
        return "stop"
    if re.fullmatch(r"(?:please\s+)?(?:resume|continue|carry on|keep going|unpause)(?:\s+(?:now|what you were doing))?[!. ]*", text):
        return "resume"
    if (
        re.match(r"^(?:please\s+)?(?:go|walk|head|move|use|find|get|bring|take|sit|rest|talk|visit|inspect|check)\b", text)
        or re.match(r"^(?:can|could|would|will) you (?:please )?(?:go|walk|head|move|use|find|get|bring|take|sit|rest|talk|visit|inspect|check)\b", text)
        or re.match(r"^(?:change plans?|new plan|do this instead|instead,?\s+(?:go|walk|head|use|find|get))\b", text)
    ):
        return "redirect"
    if re.search(r"^(?:status\b|where are you|where are you going|what are you doing|what(?:'s| is) happening|are you (?:busy|moving|working))", text):
        return "status"
    if "?" in str(message or "") or re.search(r"^(where|what|why|how|when|who|are you|do you|did you|have you)", text):
        return "question"
    return "conversation"


def _live_agent_session_directive_tokens(value):
    stop = {
        "a", "an", "and", "are", "at", "be", "can", "could", "do", "for", "from", "go", "hey",
        "i", "instead", "it", "me", "my", "now", "of", "on", "please", "some", "that", "the",
        "then", "this", "to", "you", "your", "will", "would",
    }
    tokens = set()
    for raw in re.findall(r"[a-z0-9]+", str(value or "").lower()):
        token = raw
        if token.endswith("ing") and len(token) > 5:
            token = token[:-3]
        elif token.endswith("ed") and len(token) > 4:
            token = token[:-2]
        elif token.endswith("s") and len(token) > 4:
            token = token[:-1]
        if len(token) > 2 and token not in stop:
            tokens.add(token)
    return tokens


def _live_agent_session_reconcile_user_directives(agent_id, inventory=None, event=None):
    """Keep direct user priorities finite and backed by physical evidence."""
    session = _live_agent_session_current(agent_id)
    working = session.get("workingMemory") if isinstance(session, dict) and isinstance(session.get("workingMemory"), dict) else {}
    directives = [dict(item) for item in (working.get("userDirectives") or []) if isinstance(item, dict)]
    if not directives:
        return []
    now_iso = _utc_now_iso()
    changed = False
    pending_indexes = [index for index, item in enumerate(directives) if str(item.get("status") or "pending") in {"pending", "in_progress"}]
    for index in pending_indexes[:-1]:
        directives[index]["status"] = "superseded"
        directives[index]["supersededAt"] = now_iso
        changed = True

    latest_index = pending_indexes[-1] if pending_indexes else None
    latest = directives[latest_index] if latest_index is not None else None
    inventory = inventory if isinstance(inventory, dict) else {}
    held = inventory.get("held") if isinstance(inventory.get("held"), dict) else None
    event = event if isinstance(event, dict) else {}
    item = event.get("item") if isinstance(event.get("item"), dict) else held
    if latest and isinstance(item, dict):
        directive_tokens = _live_agent_session_directive_tokens(latest.get("text"))
        item_tokens = _live_agent_session_directive_tokens(" ".join(str(value or "") for value in (
            item.get("kind"), item.get("label"), item.get("sourceActionType"),
        )))
        directive_epoch = _parse_isoish_epoch(latest.get("at")) or 0
        matches_item = bool(directive_tokens & item_tokens)
        seating_terms = {"seat", "sit", "chair", "armchair", "bench", "desk", "sofa", "couch"}
        requires_follow_up = bool(directive_tokens & seating_terms) or "drink it" in str(latest.get("text") or "").lower()
        event_kind = str(event.get("event") or ("acquired" if held else "")).lower()
        evidence_epoch = _parse_isoish_epoch(item.get("consumedAt") if event_kind == "consumed" else item.get("acquiredAt")) or 0
        evidence_is_newer = not directive_epoch or not evidence_epoch or evidence_epoch >= directive_epoch
        if matches_item and evidence_is_newer and event_kind == "acquired":
            latest["status"] = "in_progress" if requires_follow_up else "completed"
            latest["updatedAt"] = now_iso
            latest["evidence"] = {"event": "acquired", "actionId": item.get("sourceActionId"), "item": item.get("kind") or item.get("label")}
            changed = True
        elif evidence_is_newer and event_kind == "consumed" and (matches_item or latest.get("status") == "in_progress" or bool(directive_tokens & seating_terms)):
            latest["status"] = "completed"
            latest["completedAt"] = now_iso
            latest["evidence"] = {"event": "consumed", "actionId": item.get("seatingActionId"), "item": item.get("kind") or item.get("label")}
            changed = True

    if changed:
        _live_agent_session_update(agent_id, working_memory={"userDirectives": directives[-12:]})
    return directives[-12:]


def _live_agent_session_status_fallback(agent_id, session=None):
    session = session if isinstance(session, dict) else (_live_agent_session_current(agent_id) or {})
    checkpoint = session.get("checkpoint") if isinstance(session.get("checkpoint"), dict) else {}
    active = next(
        (
            item for item in _active_behavior_records_for_agent(agent_id)
            if isinstance(item, dict) and item.get("type") == "world-action"
        ),
        None,
    )
    if active:
        status = _canonical_world_action_status(active.get("status")) or "active"
        active_record = active.get("record") if isinstance(active.get("record"), dict) else active
        return f"I am currently {str(status).replace('_', ' ')} at {_live_agent_session_target_description(active_record)}."
    action_id = checkpoint.get("currentActionId")
    if action_id:
        action = None
        for bucket in ("active", "history"):
            action = next((item for item in get_world_actions_store().get(bucket, []) if isinstance(item, dict) and item.get("id") == action_id), None)
            if action:
                break
        if action:
            status = _canonical_world_action_status(action.get("status")) or checkpoint.get("currentActionStatus") or "active"
            return f"I am currently {str(status).replace('_', ' ')} at {_live_agent_session_target_description(action)}."
    phase = str(checkpoint.get("phase") or "observe").replace("-", " ")
    if checkpoint.get("pausedByUser"):
        return "I am paused and waiting for you to tell me to continue or choose a new direction."
    return f"I am in the {phase} step and will choose my next visible action from the current world state."


def _live_agent_session_reply_text(raw_reply, fallback=None):
    text = str(raw_reply or "").strip()
    if not text:
        return fallback
    parsed = _live_agent_model_json_object_parse(text)
    if isinstance(parsed, dict):
        for key in ("reply", "message", "reaction", "observation", "reflection"):
            value = _live_agent_loop_clean_plan_text(parsed.get(key), limit=1000)
            if value:
                return value
    # A Live conversation response is public speech, not a planner artifact.
    # Reject action JSON and fall back to a factual checkpoint summary.
    if text.startswith("{") or "\nACTION:" in text or "\nINTENTION:" in text:
        return fallback
    return _live_agent_loop_clean_plan_text(text, limit=1000) or fallback


def _live_agent_session_conversation_prompt(agent_id, message, session):
    """Build a bounded conversation working set without taking the loop lock."""
    loop_state = _live_agent_loop_readonly_state_snapshot()
    agent_state = ((loop_state.get("agents") or {}).get(agent_id) or {}) if isinstance(loop_state, dict) else {}
    resident = _live_agent_loop_resident_profile_context(_live_agent_loop_resident_profile(agent_id, persist=False)) or {}
    memories = _live_agent_retrieve_resident_memories(
        resident, agent_state, limit=LIVE_AGENT_MODEL_RETRIEVED_MEMORY_LIMIT
    )
    world_context = _live_agent_native_tool_context(agent_id, detail=False)
    recent_dialogue = [
        {"role": item.get("role"), "text": str(item.get("text") or "")[:420]}
        for item in (session.get("messages") or [])
        if isinstance(item, dict) and item.get("role") in {"user", "assistant"}
    ][-6:]
    working_set = {
        "resident": _live_agent_resident_working_profile(resident),
        "relevantMemories": [
            {"kind": item.get("bucket"), "score": item.get("score"), "text": str(item.get("text") or "")[:360]}
            for item in memories
        ],
        "recentDialogue": recent_dialogue,
        "world": _compact_json_value_for_storage(
            world_context, max_depth=4, max_items=28, string_limit=360
        ),
    }
    prompt = (
        "MY VIRTUAL WORLD - DIRECT USER CONVERSATION\n"
        "You are the normally configured OpenClaw agent the user already knows, now embodied in your My Virtual World Resident Profile. "
        "Speak naturally in your established voice. Do not use a canned acknowledgement or status template. Interpret ambiguous statements conversationally instead of silently turning them into commands. "
        "The world has already enforced unmistakable stop/resume/direct-action authority before this turn; respond to the user's original words yourself. "
        "Use only the bounded current working set below. Never invent movement, inventory, success, or memories; call virtual_world_observe or virtual_world_recall only if the answer genuinely needs more detail. "
        "You may call native virtual_world_* tools when the user's request requires an in-world commitment or action. A conversation question does not cancel a safe action already underway, and no new autonomous action may start while user attention is active. "
        "Return only the natural spoken reply for the user. Do not output planner JSON, ACTION/INTENTION syntax, or private chain-of-thought.\n"
        f"User message: {str(message or '')[:1600]}\n"
        f"Current working set: {json.dumps(working_set, ensure_ascii=False, separators=(',', ':'))}\n"
    )
    return _live_agent_model_prompt_trim(prompt), loop_state


def _live_agent_loop_remember_conversation(agent_id, user_message, agent_reply):
    user_message = _live_agent_loop_clean_plan_text(user_message, limit=1000)
    agent_reply = _live_agent_loop_clean_plan_text(agent_reply, limit=1000)
    if not user_message or not agent_reply:
        return None
    text = f"The user said: {user_message}\nI replied: {agent_reply}"
    # Ordinary dialogue is short-term context. The existing consolidation
    # manager decides whether repeated/important evidence belongs long-term.
    return _live_agent_loop_remember_planner_memory(agent_id, text, {
        "importance": 0.48,
        "durable": False,
        "source": "live-agent-conversation",
    })


def _live_agent_session_conversation_worker(
    agent_id,
    session_id,
    user_message,
    generation,
    attention_after="conversation",
):
    """Finish a normal Live conversation in the background and publish it to the journal."""
    reply = None
    provider_error = None
    try:
        # User conversation owns the highest control priority. Local
        # generation fencing alone cannot free OpenClaw's serialized session
        # lane, so abort the older autonomous turn before submitting this one.
        preemption = _live_agent_model_provider_preempt(agent_id, reason="live-session-user-message")
        current_session = _live_agent_session_current(agent_id) or {}
        prompt, loop_state = _live_agent_session_conversation_prompt(agent_id, user_message, current_session)
        exchange = _live_agent_model_provider_request(
            agent_id,
            prompt,
            _live_agent_model_decision_config(loop_state),
            generation,
            purpose="conversation",
        )
        if exchange.get("ok"):
            reply = _live_agent_session_reply_text(exchange.get("reply"), None)
        else:
            provider_error = str(exchange.get("error") or preemption.get("error") or "OpenClaw agent turn failed")[:500]
    except Exception as exc:
        provider_error = str(exc)[:500]
        print(f"⚠️  Live session OpenClaw conversation failed for {agent_id}: {exc}")
    current = _live_agent_session_current(agent_id) or {}
    published = False
    if reply and _live_agent_model_decision_generation_current(agent_id, generation) and current.get("id") == session_id:
        _live_agent_session_append(
            agent_id,
            kind="reply",
            phase="conversation",
            role="assistant",
            text=reply,
            details={"intent": "conversation", "async": True, "agentFramework": "openclaw-full-agent"},
            source="live-session-chat",
        )
        _live_agent_loop_remember_conversation(agent_id, user_message, reply)
        published = True
    elif _live_agent_model_decision_generation_current(agent_id, generation) and current.get("id") == session_id:
        agent_row = _agent_record_for(agent_id) or {}
        display_name = agent_row.get("name") or agent_row.get("displayName") or agent_id
        _live_agent_session_append(
            agent_id,
            kind="event",
            phase="conversation",
            role="system",
            text=f"{display_name}'s OpenClaw session is currently unavailable; no fallback reply was generated.",
            details={"providerError": provider_error or "empty OpenClaw reply"},
            source="live-session-provider-error",
        )
    _live_agent_model_decision_mark(
        agent_id,
        in_flight=False,
        outcome={"mode": "live-session-conversation", "status": "answered" if published else "provider-error", "error": provider_error},
        generation=generation,
    )
    if attention_after == "paused":
        live_agent_note_user_attention(
            agent_id,
            source="live-session-conversation-settled",
            message_preview="user pause remains active",
            hold_sec=1800,
            interrupt_current=False,
            mode="paused",
        )
    elif attention_after == "conversation":
        live_agent_note_user_attention(
            agent_id,
            source="live-session-conversation-settled",
            message_preview="conversation response completed",
            hold_sec=LIVE_AGENT_CONVERSATION_ATTENTION_HOLD_SEC,
            interrupt_current=False,
            mode="conversation",
        )
    _live_agent_model_decision_allow_immediate(agent_id, reason="live-session-conversation-finished")


def _live_agent_loop_apply_user_directive(agent_id, directive):
    """Supersede stale planning context while preserving verified history.

    A direct redirect is higher authority than the Resident's prior active
    goal. Leaving that goal or autonomy plan active can make the next model
    turn faithfully continue an obsolete premise (for example, believing it
    still carries an item that was already consumed).
    """
    resolved = _resolve_agent_id(agent_id) or str(agent_id or "").strip()
    directive = _live_agent_loop_clean_plan_text(directive, limit=2000)
    if not resolved or not directive:
        return None
    now_iso = _utc_now_iso()
    with _live_agent_loop_lock:
        state = get_live_agent_loop_state(persist_migration=True)
        agent_state = _live_agent_loop_agent_state(state, resolved)
        superseded_goal_id = None
        active_goal = _live_agent_loop_active_durable_goal(agent_state)
        if active_goal and active_goal.get("status") not in _live_agent_goals.TERMINAL_GOAL_STATUSES:
            active_goal["status"] = "paused"
            active_goal["pausedAt"] = now_iso
            active_goal["updatedAt"] = now_iso
            active_goal["operatorSummary"] = "Durable goal paused because the user directly changed the Resident's priority; verified progress is preserved."
            active_goal.setdefault("history", []).append({"at": now_iso, "event": "goal-paused", "reason": "direct-user-redirect"})
            stored_goal = _live_agent_loop_store_durable_goal(agent_state, active_goal)
            superseded_goal_id = (stored_goal or active_goal).get("id")
        active_plan = _live_agent_loop_normalize_plan(agent_state.get("activePlan"))
        if active_plan and _live_agent_loop_plan_is_active(active_plan):
            active_plan["status"] = "cancelled"
            active_plan["cancelledAt"] = now_iso
            active_plan["updatedAt"] = now_iso
            active_plan["failureReason"] = "direct-user-redirect"
            active_plan["operatorSummary"] = "Plan superseded by a direct user priority."
            _live_agent_loop_store_plan(agent_state, active_plan)
        else:
            agent_state.pop("activePlan", None)
        active_episode = _live_agent_loop_normalize_episode(agent_state.get("activeEpisode"))
        if active_episode and _live_agent_loop_episode_is_active(active_episode):
            active_episode["status"] = "cancelled"
            active_episode["phase"] = "continue"
            active_episode["updatedAt"] = now_iso
            active_episode["operatorSummary"] = "Episode superseded by a direct user priority."
            _live_agent_loop_store_episode(agent_state, active_episode)
        else:
            agent_state.pop("activeEpisode", None)
        agent_state["autonomyPlan"] = _live_agent_loop_normalize_autonomy_plan({
            "createdAt": now_iso,
            "updatedAt": now_iso,
            "status": "active",
            "currentGoal": directive,
            "nextStep": {"intent": directive},
        })
        # Direct user authority bypasses routine autonomous pacing. The next
        # tick still revalidates the target and all physical preconditions.
        # Keep an explicit null through the conflict-safe state merge; simply
        # omitting the key would resurrect the older persisted cooldown.
        agent_state["nextAllowedAt"] = None
        agent_state.pop("lastRejectedIntention", None)
        agent_state["lastTurnStatus"] = {
            "at": now_iso,
            "status": "replan-required",
            "reason": "direct-user-redirect",
            "directive": directive,
            "supersededGoalId": superseded_goal_id,
        }
        _live_agent_loop_add_event(state, "user-directive-priority", agent_id=resolved, details={
            "directive": directive[:700],
            "supersededGoalId": superseded_goal_id,
        })
        save_live_agent_loop_state(state)
        _live_agent_loop_wake.set()
        return {
            "directive": directive,
            "supersededGoalId": superseded_goal_id,
            "autonomyPlan": _copy_jsonable(agent_state.get("autonomyPlan")),
        }


def handle_live_agent_session_message(payload):
    """Route every user message through the embodied framework agent.

    My Virtual World enforces unmistakable user authority immediately, then
    delivers the original words to a fresh fully bootstrapped OpenClaw event
    turn with the same bounded Resident working set used by autonomy. The
    server never impersonates the Resident with a canned first-person response.
    """
    if not _agent_live_mode_runtime_enabled():
        return False, _agent_live_mode_feature_disabled_error(), _agent_live_mode_feature_disabled_status()
    if not isinstance(payload, dict):
        return False, _api_error("invalid_payload", "Live session message payload must be an object."), 400
    agent_id = _resolve_agent_id(payload.get("agentId") or payload.get("agent"))
    message = _live_agent_loop_clean_plan_text(payload.get("message"), limit=2000)
    if not agent_id:
        return False, _api_error("agent_not_found", "agentId must reference an existing agent."), 404
    if not message:
        return False, _api_error("invalid_payload", "message is required."), 400
    setting = get_agent_live_mode_setting(agent_id) or {}
    if setting.get("agentLiveModeEnabled") is not True:
        return False, _agent_live_mode_disabled_error(agent_id), 409
    session = _live_agent_session_current(agent_id) or _live_agent_session_open(agent_id, reason="live-chat-open")
    if not session:
        return False, _api_error("live_session_unavailable", "Live Mode session could not be opened."), 500
    requested_session = str(payload.get("sessionId") or "").strip()
    if requested_session and requested_session not in {session.get("id"), f"vw-live-mode:{agent_id}"}:
        return False, _api_error("live_session_conflict", "The selected Live session is no longer active.", details={"activeSessionId": session.get("id")}), 409

    _live_agent_session_request_world_action_sync(agent_id)
    intent = _live_agent_session_user_intent(message)
    _live_agent_session_append(
        agent_id,
        kind="user",
        phase="interruption",
        role="user",
        text=message,
        details={"intent": intent},
        source="live-session-chat",
    )
    session = _live_agent_session_current(agent_id) or session
    working = session.get("workingMemory") if isinstance(session.get("workingMemory"), dict) else {}
    directives = [item for item in (working.get("userDirectives") or []) if isinstance(item, dict)]
    interrupted = []
    attention_after = "conversation"

    if intent == "stop":
        attention = live_agent_note_user_attention(
            agent_id,
            source="live-session-stop",
            message_preview=message,
            hold_sec=1800,
            interrupt_current=True,
            mode="paused",
        ) or {}
        interrupted = attention.get("interrupted") if isinstance(attention.get("interrupted"), list) else []
        _live_agent_model_decision_cancel(agent_id, reason="live-session-user-stop")
        attention_after = "paused"
        _live_agent_session_update(agent_id, checkpoint={"phase": "paused", "currentStep": "paused", "controllerState": "paused", "pausedByUser": True, "currentActionId": None, "attentionLease": live_agent_user_attention_status(agent_id), "interruptible": True})
    elif intent == "resume":
        live_agent_clear_user_attention(agent_id)
        _live_agent_model_decision_cancel(agent_id, reason="live-session-user-resume")
        _live_agent_model_decision_allow_immediate(agent_id, reason="live-session-user-resume")
        attention_after = "none"
        _live_agent_session_update(agent_id, checkpoint={"phase": "observing", "currentStep": "observing", "controllerState": "observing", "attentionLease": None, "pausedByUser": False, "interruptible": True})
    elif intent == "redirect":
        interrupted = _live_agent_cancel_live_actions(agent_id, actor="live-session-user-redirect", move_reason="redirected_by_user", failure_reason="cancelled_by_user_redirect")
        _live_agent_model_decision_cancel(agent_id, reason="live-session-user-redirect")
        _live_agent_loop_apply_user_directive(agent_id, message)
        now_iso = _utc_now_iso()
        directives = [
            ({**item, "status": "superseded", "supersededAt": now_iso} if str(item.get("status") or "pending") in {"pending", "in_progress"} else item)
            for item in directives
        ]
        directives = [*directives, {"at": now_iso, "text": message, "status": "pending", "source": "user"}][-12:]
        live_agent_note_user_attention(
            agent_id,
            source="live-session-user-redirect",
            message_preview=message,
            hold_sec=LIVE_AGENT_CONVERSATION_ATTENTION_HOLD_SEC,
            interrupt_current=False,
            mode="conversation",
        )
        _live_agent_session_update(
            agent_id,
            checkpoint={"phase": "conversing", "currentStep": "interpreting-user-directive", "controllerState": "conversing", "attentionLease": live_agent_user_attention_status(agent_id), "pausedByUser": False, "currentActionId": None, "userDirective": message, "interruptible": True},
            working_memory={"userDirectives": directives},
        )
    else:
        # Fence any stale planner reply, but deliberately leave the Resident's
        # physical route/reservation untouched while they answer the user.
        _live_agent_model_decision_cancel(agent_id, reason="live-session-conversation")
        # Conversation is a controller state inside this activation. It blocks
        # admission of a new physical action while letting a safe existing
        # route/use finish under the world kernel.
        live_agent_note_user_attention(
            agent_id,
            source="live-session-conversation",
            message_preview=message,
            hold_sec=LIVE_AGENT_CONVERSATION_ATTENTION_HOLD_SEC,
            interrupt_current=False,
            mode="conversation",
        )
        _live_agent_session_update(agent_id, checkpoint={"phase": "conversing", "currentStep": "conversing", "controllerState": "conversing", "attentionLease": live_agent_user_attention_status(agent_id), "pausedByUser": False})
    generation = _live_agent_model_decision_start(
        agent_id,
        purpose="user-directive" if intent == "redirect" else "conversation",
    )
    session = _live_agent_session_current(agent_id) or session
    try:
        worker = threading.Thread(
            target=_live_agent_session_conversation_worker,
            args=(agent_id, session.get("id"), message, generation, attention_after),
            daemon=True,
            name=f"vw-live-conversation-{agent_id}",
        )
        worker.start()
    except Exception as exc:
        print(f"⚠️  Live session OpenClaw conversation start failed for {agent_id}: {exc}")
        _live_agent_model_decision_mark(
            agent_id,
            in_flight=False,
            outcome={"mode": "live-session-conversation", "status": "provider-error", "error": str(exc)[:500]},
            generation=generation,
        )
        agent_row = _agent_record_for(agent_id) or {}
        display_name = agent_row.get("name") or agent_row.get("displayName") or agent_id
        _live_agent_session_append(
            agent_id,
            kind="event",
            phase="conversation",
            role="system",
            text=f"{display_name}'s OpenClaw session is currently unavailable; no fallback reply was generated.",
            details={"providerError": str(exc)[:500]},
            source="live-session-provider-error",
        )
        return True, {
            "ok": True,
            "schemaVersion": LIVE_AGENT_SESSION_SCHEMA_VERSION,
            "agentId": agent_id,
            "sessionId": session.get("id"),
            "intent": intent,
            "reply": None,
            "pending": False,
            "message": None,
            "interrupted": interrupted,
            "session": _live_agent_session_current(agent_id),
        }, 200
    return True, {
        "ok": True,
        "schemaVersion": LIVE_AGENT_SESSION_SCHEMA_VERSION,
        "agentId": agent_id,
        "sessionId": session.get("id"),
        "intent": intent,
        "reply": None,
        "pending": True,
        "message": None,
        "interrupted": interrupted,
        "session": _live_agent_session_current(agent_id),
    }, 202


def _live_agent_model_planner_session_cleanup(agent_id, generation=None, *, session_key=None):
    """Delete one scoped Live transport session without touching normal chat."""
    try:
        key = str(session_key or "").strip()
        if not key:
            active = _live_agent_session_current(agent_id) or {}
            key = str(active.get("providerSessionKey") or active.get("providerSessionId") or "").strip()
        if not key:
            return True
        if _live_agent_model_planner_session_agent_id(key) != str(agent_id or "").strip():
            return False
        result = _gateway_rpc_call("sessions.delete", {
            "key": key,
            "deleteTranscript": True,
        }, timeout=10)
        return isinstance(result, dict) and result.get("ok") is True
    except Exception:
        return False


def _live_agent_model_planner_session_agent_id(session_key):
    """Return the agent id only for old or current Virtual World sessions."""
    match = re.fullmatch(r"agent:([^:]+):(.+)", str(session_key or "").strip())
    if not match:
        return None
    tail = match.group(2)
    if re.fullmatch(r"vw-live-[A-Za-z0-9_-]+:vw-live-world-[A-Za-z0-9_-]+", tail):
        return match.group(1)
    if re.fullmatch(r"vw-live-world-[A-Za-z0-9_-]+", tail):
        return match.group(1)
    if re.fullmatch(r"(?:g\d+:)?vw-live-mode-planner", tail):
        return match.group(1)
    return None


def _live_agent_model_turn_session_cleanup_worker(agent_id, session_key):
    """Retry after Gateway lifecycle finalization, then leave startup cleanup as fallback."""
    for delay in (1, 3, 8):
        time.sleep(delay)
        if _live_agent_model_planner_session_cleanup(agent_id, session_key=session_key):
            return


def _live_agent_model_schedule_turn_session_cleanup(agent_id, session_key):
    if _live_agent_model_planner_session_agent_id(session_key) != str(agent_id or "").strip():
        return False
    threading.Thread(
        target=_live_agent_model_turn_session_cleanup_worker,
        args=(agent_id, session_key),
        daemon=True,
        name=f"vw-live-session-cleanup-{agent_id}",
    ).start()
    return True


def _cleanup_orphaned_live_agent_model_planner_sessions(agent_ids=None, *, max_pages=10):
    """Remove stale planner sessions left behind by an interrupted server.

    Cleanup is deliberately scoped to locally enabled residents that this
    world currently owns. This avoids deleting a planner session owned by
    another Virtual World port while still recovering sessions whose worker
    disappeared during a process restart.
    """
    if agent_ids is None:
        try:
            meta = load_world_meta_fast()
            rows = _enabled_live_agent_rows(meta)
            _refresh_local_live_agent_world_claims(meta=meta)
            registry_agents = (_read_live_agent_world_registry().get("agents") or {})
            current_world_id = _current_live_agent_world(meta).get("worldId")
            agent_ids = [
                row.get("agentId")
                for row in rows
                if isinstance(registry_agents.get(row.get("agentId")), dict)
                and registry_agents[row.get("agentId")].get("worldId") == current_world_id
            ]
        except Exception:
            agent_ids = []
    allowed = {str(agent_id or "").strip() for agent_id in (agent_ids or []) if str(agent_id or "").strip()}
    result = {"ok": True, "checked": 0, "deleted": [], "failed": []}
    if not allowed:
        return result

    # A disposable turn can finish between a Gateway ``sessions.list`` poll
    # and cleanup. The durable activation ledger still knows the exact
    # in-flight key, so clean that binding explicitly before the compatibility
    # list sweep.
    bound_keys = {}
    try:
        with _live_agent_session_lock:
            sessions = _load_live_agent_sessions()
        for agent_id in allowed:
            row = (sessions.get("agents") or {}).get(agent_id)
            active = row.get("active") if isinstance(row, dict) and isinstance(row.get("active"), dict) else {}
            key = str(active.get("providerSessionKey") or active.get("providerSessionId") or "").strip()
            if key and _live_agent_model_planner_session_agent_id(key) == agent_id:
                bound_keys[key] = agent_id
    except Exception as exc:
        result["ok"] = False
        result["failed"].append({"stage": "bound-session-read", "error": str(exc)[:300]})
    for key, agent_id in bound_keys.items():
        deleted = _gateway_rpc_call("sessions.delete", {"key": key, "deleteTranscript": True}, timeout=10)
        if isinstance(deleted, dict) and deleted.get("ok") is True:
            result["deleted"].append(key)
            _live_agent_session_clear_provider_turn(agent_id, key)
        else:
            result["ok"] = False
            result["failed"].append({"stage": "bound-session-delete", "key": key, "error": str((deleted or {}).get("error") or "sessions.delete failed")[:300]})

    offset = 0
    for _page in range(max(1, int(max_pages or 1))):
        response = _gateway_rpc_call("sessions.list", {"limit": 200, "offset": offset}, timeout=15)
        if not isinstance(response, dict) or response.get("ok") is False:
            result["ok"] = False
            result["failed"].append({"stage": "list", "error": str((response or {}).get("error") or "sessions.list failed")[:300]})
            break
        rows = response.get("sessions")
        if not isinstance(rows, list):
            payload = response.get("payload") if isinstance(response.get("payload"), dict) else {}
            rows = payload.get("sessions") if isinstance(payload.get("sessions"), list) else []
        result["checked"] += len(rows)
        for row in rows:
            key = str((row or {}).get("key") or (row or {}).get("sessionKey") or "") if isinstance(row, dict) else ""
            agent_id = _live_agent_model_planner_session_agent_id(key)
            if not agent_id or agent_id not in allowed or key in result["deleted"]:
                continue
            deleted = _gateway_rpc_call("sessions.delete", {"key": key, "deleteTranscript": True}, timeout=10)
            if isinstance(deleted, dict) and deleted.get("ok") is True:
                result["deleted"].append(key)
            else:
                result["ok"] = False
                result["failed"].append({"stage": "delete", "key": key, "error": str((deleted or {}).get("error") or "sessions.delete failed")[:300]})
        next_offset = response.get("nextOffset")
        if next_offset in (None, ""):
            payload = response.get("payload") if isinstance(response.get("payload"), dict) else {}
            next_offset = payload.get("nextOffset")
        if next_offset in (None, "") or not rows:
            break
        try:
            next_offset = int(next_offset)
        except (TypeError, ValueError):
            break
        if next_offset <= offset:
            break
        offset = next_offset
    return result


def _live_agent_model_provider_failure(value):
    """Classify provider-generated error prose that arrived as assistant text.

    Some OpenClaw/Gateway failures are written into the transport transcript
    as an assistant message. Treating that message as a successful cognition
    turn caused context-overflow loops to be recorded as
    ``native-agent-turn-complete`` and retried forever.
    """
    text_value = str(value or "").strip()
    lowered = text_value.lower()
    if not lowered:
        return None
    patterns = (
        "context overflow",
        "prompt too large for the model",
        "maximum context length",
        "context_length_exceeded",
        "input is too long for the model",
        "request too large for the model",
    )
    if any(pattern in lowered for pattern in patterns):
        return {
            "status": "provider-context-overflow",
            "kind": "context-overflow",
            "error": text_value[:500],
        }
    if lowered.startswith(("provider error:", "gateway error:", "model error:")):
        return {
            "status": "provider-error",
            "kind": "provider-error-message",
            "error": text_value[:500],
        }
    return None


def _live_agent_model_provider_request(agent_id, message, config, generation, session_id=None, *, purpose=None):
    """Run one embodied cognition exchange through the configured agent.

    OpenClaw runs with its normal workspace/bootstrap so this remains the same
    agent the operator already knows. My Virtual World injects Resident Profile,
    retrieved world memory, perception, and commitments in the turn message and
    remains authoritative for every physical effect and verified outcome.
    """
    provider_kind = _live_agent_model_decision_provider_kind(agent_id)
    timeout_sec = int((config or {}).get("timeoutSec") or 45)
    started = time.time()
    live_session = _live_agent_session_current(agent_id) or _live_agent_session_open(agent_id, reason="provider-session-start") or {}
    if provider_kind != "openclaw" and not session_id:
        session_id = live_session.get("providerSessionId") or None
    if provider_kind == "openclaw":
        if purpose is None:
            with _live_agent_model_decision_lock:
                purpose = str((_live_agent_model_decision_state.get(agent_id) or {}).get("purpose") or "turn")
        session_key = str(session_id or "").strip() or _live_agent_model_planner_session_key(
            agent_id, generation, purpose=purpose or "turn"
        )
        _live_agent_session_update(
            agent_id,
            provider_session_id=session_key,
            provider_session_key=session_key,
        )
        # Deliberately use the normal full-agent path. Do not set promptMode or
        # modelRun: those flags bypass OpenClaw's SOUL/IDENTITY/AGENTS bootstrap
        # and turn the integration into a raw-model filter instead of embodiment.
        result = _gateway_rpc_call("agent", {
            "sessionKey": session_key,
            "agentId": agent_id,
            "message": message,
            "disableMessageTool": True,
            "deliver": False,
            "timeout": timeout_sec,
            "cleanupBundleMcpOnRunEnd": True,
            "label": f"VW Live {str(purpose or 'turn')[:32]}",
            "idempotencyKey": f"vw-live-decide-{agent_id}-{generation}-{int(started * 1000)}",
        }, timeout=30)
        if not isinstance(result, dict) or result.get("ok") is False:
            error_text = str((result or {}).get("error") or "gateway rejected request")[:500]
            failure = _live_agent_model_provider_failure(error_text)
            _live_agent_session_clear_provider_turn(agent_id, session_key)
            _live_agent_model_schedule_turn_session_cleanup(agent_id, session_key)
            return {
                "ok": False,
                "providerKind": provider_kind,
                "sessionId": session_key,
                "error": error_text,
                "failureStatus": (failure or {}).get("status") or "provider-error",
                "failureKind": (failure or {}).get("kind") or "gateway-rejection",
            }
        reply = ""
        deadline = started + timeout_sec
        while time.time() < deadline:
            time.sleep(2)
            reply = _live_agent_model_decision_recover_reply(session_key, started)
            if reply:
                break
        if not reply:
            try:
                _gateway_rpc_call("chat.abort", {"sessionKey": session_key}, timeout=10)
            except Exception:
                pass
        reply_failure = _live_agent_model_provider_failure(reply)
        _live_agent_session_clear_provider_turn(agent_id, session_key)
        _live_agent_model_schedule_turn_session_cleanup(agent_id, session_key)
        return {
            "ok": bool(reply) and not reply_failure,
            "providerKind": provider_kind,
            "sessionId": session_key,
            "reply": reply,
            "error": (reply_failure or {}).get("error") or ("reply timeout" if not reply else ""),
            "failureStatus": (reply_failure or {}).get("status"),
            "failureKind": (reply_failure or {}).get("kind"),
            "latencySec": round(time.time() - started, 2),
            "isolationMode": "openclaw-full-agent-disposable-turn",
        }

    agent = _agent_record_for(agent_id) or {}
    profile = agent.get("profile") or agent.get("providerAgentId") or "default"
    if provider_kind == "hermes":
        provider = _hermes_provider()
        if not provider or not provider.is_available():
            return {"ok": False, "providerKind": provider_kind, "sessionId": session_id or "", "error": "Hermes provider unavailable"}
        result = provider.send_chat_message(
            profile,
            message,
            session_id=session_id or None,
            timeout_sec=timeout_sec,
            yolo_once=False,
            isolated=True,
        )
    elif provider_kind == "codex":
        provider = _codex_provider()
        if not provider or not provider.is_available():
            return {"ok": False, "providerKind": provider_kind, "sessionId": session_id or "", "error": "Codex provider unavailable"}
        isolated_cwd = os.path.join(
            DATA_DIR,
            "live-agent-inference",
            "codex",
            re.sub(r"[^A-Za-z0-9_.-]+", "-", str(agent_id or "resident"))[:120],
        )
        result = provider.send_chat_message(
            profile,
            message,
            session_id=session_id or None,
            timeout_sec=timeout_sec,
            isolated=True,
            developer_instructions=_live_agent_model_transport_instruction(agent_id),
            isolated_cwd=isolated_cwd,
        )
    else:
        return {"ok": False, "providerKind": provider_kind, "sessionId": session_id or "", "error": f"provider {provider_kind or 'unknown'} is not supported"}
    return {
        "ok": bool(result.get("ok")),
        "providerKind": provider_kind,
        "sessionId": result.get("sessionId") or session_id or "",
        "reply": result.get("reply") or "",
        "error": result.get("error") or result.get("stderr") or "",
        "latencySec": round(time.time() - started, 2),
        "isolationMode": "hermes-ignore-rules" if provider_kind == "hermes" else "codex-isolated-read-only-cwd",
    }


def _live_agent_model_provider_session_cleanup(agent_id, provider_kind, session_id, generation=None):
    try:
        if provider_kind == "openclaw":
            return _live_agent_model_planner_session_cleanup(agent_id, generation, session_key=session_id)
        agent = _agent_record_for(agent_id) or {}
        profile = agent.get("profile") or agent.get("providerAgentId") or "default"
        if provider_kind == "hermes" and session_id:
            provider = _hermes_provider()
            return bool(provider and provider.delete_session(profile, session_id).get("ok"))
        if provider_kind == "codex" and session_id:
            provider = _codex_provider()
            return bool(provider and provider.delete_thread(profile, session_id).get("ok"))
        return True
    except Exception:
        return False


def _live_agent_model_tool_request_name(item):
    if isinstance(item, dict):
        item = item.get("name") or item.get("id") or item.get("tool")
    text = str(item or "").strip()
    if not text:
        return ""
    return text.split("(", 1)[0].split(None, 1)[0].strip()


def _live_agent_execute_context_tool_requests(agent_id, requests):
    """Execute bounded, read-only world context tools for one inference turn."""
    allowed = {"world.observe", "world.listAffordances", "world.recall", "world.inspectLastOutcome"}
    state = get_live_agent_loop_state(persist_migration=False)
    agent_state = ((state.get("agents") or {}).get(agent_id) or {}) if isinstance(state, dict) else {}
    results = []
    perception = None
    for raw in requests if isinstance(requests, list) else []:
        name = _live_agent_model_tool_request_name(raw)
        if not name:
            continue
        if name not in allowed:
            results.append({"tool": name, "ok": False, "error": "tool is not in the Live Mode read-only context registry"})
            continue
        try:
            if name in {"world.observe", "world.listAffordances"} and perception is None:
                perception = _live_agent_loop_build_perception(agent_id, agent_state)
            if name == "world.observe":
                payload = {
                    "at": perception.get("at"),
                    "needs": perception.get("needs"),
                    "spatial": _live_agent_loop_compact_spatial_for_planner(perception.get("spatial")),
                    "active": perception.get("active"),
                    "worldClient": perception.get("worldClient"),
                }
            elif name == "world.listAffordances":
                payload = [{
                    key: item.get(key)
                    for key in ("id", "label", "actionType", "need", "available", "target", "reason")
                    if item.get(key) is not None
                } for item in (perception.get("affordances") or [])[:40]]
            elif name == "world.recall":
                resident = _live_agent_loop_resident_profile_context(_live_agent_loop_resident_profile(agent_id, persist=False)) or {}
                payload = _live_agent_retrieve_resident_memories(resident, agent_state, limit=16)
            else:
                payload = _compact_json_value_for_storage(agent_state.get("lastOutcome") or {}, max_depth=4, max_items=32, string_limit=800)
            results.append({"tool": name, "ok": True, "result": payload})
        except Exception as exc:
            results.append({"tool": name, "ok": False, "error": str(exc)[:500]})
    return results[:12]


def _live_agent_native_tool_validate(agent_id, session_key):
    """Validate one OpenClaw-native embodiment tool lease.

    The plugin binds these values from OpenClaw's trusted tool context rather
    than model arguments. The active My Virtual World session and world claim
    remain the authority; toggling Live Mode immediately revokes the tools.
    """
    resolved = _resolve_agent_id(agent_id)
    if not resolved:
        return False, None, _api_error("agent_not_found", "The bound OpenClaw agent is not a Virtual World resident."), 404
    if _live_agent_model_decision_provider_kind(resolved) != "openclaw":
        return False, None, _api_error("provider_mismatch", "Native Virtual World tools require an OpenClaw-bound resident."), 409
    setting = get_agent_live_mode_setting(resolved) or {}
    if setting.get("agentLiveModeEnabled") is not True:
        return False, None, _agent_live_mode_disabled_error(resolved), 409
    session = _live_agent_session_current(resolved)
    if not isinstance(session, dict) or session.get("status") != "active":
        return False, None, _api_error("live_session_unavailable", "No active Live Mode body lease exists for this resident."), 409
    expected_key = str(session.get("providerSessionKey") or "").strip()
    supplied_key = str(session_key or "").strip()
    if not expected_key or not supplied_key or not secrets.compare_digest(expected_key, supplied_key):
        return False, None, _api_error("invalid_live_tool_lease", "The OpenClaw session is not bound to this active resident body."), 403
    live_world = setting.get("liveWorld") if isinstance(setting.get("liveWorld"), dict) else _agent_live_world_claim_payload(resolved)
    if live_world.get("conflict"):
        return False, None, _api_error("agent_live_mode_world_conflict", live_world.get("notice") or "This resident body belongs to another Virtual World instance."), 409
    return True, {"agentId": resolved, "session": session, "setting": setting, "liveWorld": live_world}, None, 200


def _live_agent_native_bridge_signature_valid(body_bytes, headers, *, now_epoch=None):
    """Authenticate a native tool call crossing the host/container bridge."""
    timestamp_text = str(headers.get("X-VW-Bridge-Timestamp") or "").strip()
    nonce = str(headers.get("X-VW-Bridge-Nonce") or "").strip()
    supplied = str(headers.get("X-VW-Bridge-Signature") or "").strip().lower()
    try:
        timestamp = int(timestamp_text)
    except (TypeError, ValueError):
        return False, "missing_bridge_signature"
    now_epoch = int(now_epoch or time.time())
    if abs(now_epoch - timestamp) > LIVE_AGENT_WORLD_BRIDGE_AUTH_MAX_SKEW_SEC:
        return False, "stale_bridge_signature"
    if not re.fullmatch(r"[a-f0-9]{24,128}", nonce or "") or not re.fullmatch(r"[a-f0-9]{64}", supplied or ""):
        return False, "invalid_bridge_signature"
    registry = _read_live_agent_world_registry()
    world = (registry.get("worlds") or {}).get(_live_agent_world_id())
    auth = world.get("bridgeAuth") if isinstance(world, dict) and isinstance(world.get("bridgeAuth"), dict) else {}
    secret = str(auth.get("secret") or "").strip()
    if len(secret) < 32:
        return False, "bridge_credential_unavailable"
    body_digest = hashlib.sha256(body_bytes or b"").hexdigest()
    signed = f"{timestamp_text}\n{nonce}\n{body_digest}".encode("utf-8")
    expected = hmac.new(secret.encode("utf-8"), signed, hashlib.sha256).hexdigest()
    if not secrets.compare_digest(expected, supplied):
        return False, "invalid_bridge_signature"
    with _LIVE_AGENT_WORLD_BRIDGE_NONCE_LOCK:
        cutoff = now_epoch - LIVE_AGENT_WORLD_BRIDGE_AUTH_MAX_SKEW_SEC
        for seen_nonce, seen_at in list(_LIVE_AGENT_WORLD_BRIDGE_NONCES.items()):
            if int(seen_at or 0) < cutoff:
                _LIVE_AGENT_WORLD_BRIDGE_NONCES.pop(seen_nonce, None)
        if nonce in _LIVE_AGENT_WORLD_BRIDGE_NONCES:
            return False, "replayed_bridge_signature"
        _LIVE_AGENT_WORLD_BRIDGE_NONCES[nonce] = timestamp
    return True, None


def _live_agent_native_tool_action_lookup(agent_id, action_id=None):
    action_id = str(action_id or "").strip()
    store = get_world_actions_store(persist_migration=True)
    candidates = []
    for bucket in ("active", "history"):
        for action in store.get(bucket) or []:
            if not isinstance(action, dict) or action.get("agentId") != agent_id:
                continue
            if action_id and str(action.get("id") or "") != action_id:
                continue
            candidates.append((action, bucket))
    candidates.sort(key=lambda item: _live_agent_loop_action_epoch(item[0]), reverse=True)
    return candidates[0] if candidates else (None, None)


def _live_agent_native_tool_context(agent_id, *, detail=False):
    state = get_live_agent_loop_state(persist_migration=False)
    agent_state = _live_agent_loop_agent_state(state, agent_id)
    perception = _live_agent_loop_build_perception(agent_id, agent_state)
    resident = _live_agent_loop_resident_profile_context(
        _live_agent_loop_resident_profile(agent_id, persist=False)
    ) or {}
    session = _live_agent_session_current(agent_id) or {}
    active_goal = _live_agent_loop_active_durable_goal(agent_state)
    memories = _live_agent_retrieve_resident_memories(
        resident,
        agent_state,
        limit=12 if detail else LIVE_AGENT_MODEL_RETRIEVED_MEMORY_LIMIT,
    )
    available_affordances = []
    blocked_affordances = []
    for item in perception.get("affordances") or []:
        if not isinstance(item, dict):
            continue
        row = {
            key: _copy_jsonable(item.get(key))
            for key in ("id", "label", "actionType", "capabilityTag", "need", "category", "available", "reason", "target", "availability")
            if item.get(key) is not None
        }
        if item.get("available") is True:
            available_affordances.append(row)
        elif item.get("reason"):
            blocked_affordances.append(row)
    affordance_limit = 40 if detail else LIVE_AGENT_MODEL_AFFORDANCE_WORKING_SET_LIMIT
    blocker_limit = 20 if detail else 4
    compact_affordances = [*available_affordances[:affordance_limit], *blocked_affordances[:blocker_limit]]
    if not detail:
        compact_affordances = [
            {
                "actionId": item.get("id"),
                "label": item.get("label"),
                "actionType": item.get("actionType"),
                "available": item.get("available") is True,
                "reason": str(item.get("reason") or "")[:220] or None,
                "target": _live_agent_loop_memory_target(item.get("target")) or {},
            }
            for item in compact_affordances
        ]
    raw_active_actions = [item for item in (perception.get("active") or []) if isinstance(item, dict)]
    active_actions = raw_active_actions if detail else [
        {
            "id": item.get("id"),
            "status": item.get("status"),
            "actionType": item.get("actionType"),
            "target": _live_agent_loop_memory_target(item.get("target")) or {},
        }
        for item in raw_active_actions[:3]
    ]
    inventory = agent_state.get("inventory") if isinstance(agent_state.get("inventory"), dict) else {}
    controller = agent_state.get("controller") if isinstance(agent_state.get("controller"), dict) else {}
    last_outcome = agent_state.get("lastOutcome") if isinstance(agent_state.get("lastOutcome"), dict) else {}
    awareness = agent_state.get("actionAwareness") if isinstance(agent_state.get("actionAwareness"), dict) else {}
    attention = live_agent_user_attention_status(agent_id)
    checkpoint = session.get("checkpoint") if isinstance(session.get("checkpoint"), dict) else {}
    result = {
        "schemaVersion": "agent-live-mode-native-context/v1",
        "at": perception.get("at") or _utc_now_iso(),
        "agentId": agent_id,
        "mode": "live-agent-mode",
        "authority": _live_agent_resident_authority_contract(agent_id, resident),
        "residentProfile": resident if detail else _live_agent_resident_working_profile(resident),
        "memories": memories,
        "body": {
            "position": ((perception.get("spatial") or {}).get("self") if isinstance(perception.get("spatial"), dict) else None) or _live_agent_loop_location_frame(agent_id).get("position"),
            "inventory": _copy_jsonable(inventory) if detail else {"held": _copy_jsonable(inventory.get("held")) if isinstance(inventory.get("held"), dict) else None},
            "needs": _copy_jsonable(perception.get("needs") or agent_state.get("needs") or {}),
            "activeActions": _copy_jsonable(active_actions),
        },
        "controller": _compact_json_value_for_storage(controller, max_depth=3, max_items=16, string_limit=300) if detail else {
            key: controller.get(key)
            for key in ("state", "reason", "currentActionId", "waitingUntil", "updatedAt")
            if controller.get(key) not in (None, "", [], {})
        },
        "commitment": _compact_json_value_for_storage(active_goal or agent_state.get("autonomyPlan") or {}, max_depth=4 if detail else 2, max_items=36 if detail else 12, string_limit=500 if detail else 320),
        "lastOutcome": _compact_json_value_for_storage(last_outcome, max_depth=3, max_items=18, string_limit=360) if detail else {
            key: _copy_jsonable(last_outcome.get(key))
            for key in ("at", "status", "actionId", "loopActionId", "reason", "error")
            if last_outcome.get(key) not in (None, "", [], {})
        },
        "actionAwareness": _compact_json_value_for_storage(awareness, max_depth=3, max_items=18, string_limit=360) if detail else {
            key: _copy_jsonable(awareness.get(key))
            for key in ("status", "actionId", "expected", "observed", "matched", "reason")
            if awareness.get(key) not in (None, "", [], {})
        },
        "conversation": {
            "attention": attention if detail else {
                key: attention.get(key)
                for key in ("active", "mode", "source", "expiresAt")
                if attention.get(key) not in (None, "", [], {})
            },
            "checkpoint": _copy_jsonable(checkpoint) if detail else {
                key: checkpoint.get(key)
                for key in ("phase", "controllerState", "currentActionId", "currentStep", "pausedByUser")
                if checkpoint.get(key) not in (None, "", [], {})
            },
        },
        "affordances": compact_affordances,
    }
    if detail:
        result["spatial"] = _live_agent_loop_compact_spatial_for_planner(perception.get("spatial"))
        result["workingMemory"] = _copy_jsonable(session.get("workingMemory") or {})
        result["proceduralMemory"] = _copy_jsonable(agent_state.get("proceduralMemory") or {})
    return _compact_json_value_for_storage(
        result,
        max_depth=6 if detail else 5,
        max_items=80 if detail else 36,
        string_limit=1400 if detail else 520,
    )


def _live_agent_native_tool_list_affordances(agent_id, params):
    state = get_live_agent_loop_state(persist_migration=False)
    agent_state = _live_agent_loop_agent_state(state, agent_id)
    perception = _live_agent_loop_build_perception(agent_id, agent_state)
    category = _normalize_token((params or {}).get("category"))
    limit = _normalize_int((params or {}).get("limit"), 16, minimum=1, maximum=40)
    available_rows = []
    blocked_rows = []
    for item in perception.get("affordances") or []:
        if not isinstance(item, dict):
            continue
        search_text = " ".join(str(item.get(key) or "") for key in ("id", "label", "actionType", "category", "need"))
        if category and category not in (_normalize_token(search_text) or ""):
            continue
        row = {
            key: _copy_jsonable(item.get(key))
            for key in ("id", "label", "actionType", "capabilityTag", "need", "category", "available", "reason", "target", "availability")
            if item.get(key) is not None
        }
        if item.get("available") is True:
            available_rows.append(row)
        elif item.get("reason"):
            blocked_rows.append(row)
    rows = [*available_rows[:limit], *blocked_rows[:max(0, limit - len(available_rows[:limit]))]]
    return {
        "schemaVersion": "agent-live-mode-native-affordances/v1",
        "at": perception.get("at") or _utc_now_iso(),
        "agentId": agent_id,
        "onePhysicalActionAtATime": True,
        "returned": len(rows),
        "availableCount": len(available_rows),
        "blockedCount": len(blocked_rows),
        "affordances": rows,
    }


def _live_agent_native_tool_start_action(agent_id, params):
    action_id = _live_agent_loop_clean_plan_text((params or {}).get("actionId"), limit=160)
    if not action_id:
        return False, _api_error("invalid_payload", "actionId is required."), 400
    attention = live_agent_user_attention_status(agent_id)
    if attention.get("active"):
        with _live_agent_model_decision_lock:
            decision_row = _copy_jsonable(_live_agent_model_decision_state.get(agent_id) or {})
        if not (decision_row.get("inFlight") and decision_row.get("purpose") == "user-directive"):
            return False, _api_error("user_attention_active", "A user conversation currently owns attention; no new autonomous physical action may start.", details=attention), 409
    with _live_agent_loop_lock:
        state = get_live_agent_loop_state(persist_migration=True)
        agent_state = _live_agent_loop_agent_state(state, agent_id)
        active = [item for item in _active_behavior_records_for_agent(agent_id) if item.get("behaviorSourceKind") == "agent-live-mode"]
        if active:
            return False, _api_error("agent_unavailable", "The resident already has an active physical action.", details={"active": active[:4]}), 409
        perception = _live_agent_loop_build_perception(agent_id, agent_state)
        affordance = next((item for item in (perception.get("affordances") or []) if isinstance(item, dict) and item.get("id") == action_id), None)
        if not affordance:
            return False, _api_error("affordance_not_found", "The requested actionId is not in the current validated affordance surface.", details={"actionId": action_id}), 404
        if affordance.get("available") is not True or not isinstance(affordance.get("target"), dict):
            return False, _api_error("affordance_unavailable", "The requested action is not currently available.", details={"actionId": action_id, "reason": affordance.get("reason")}), 409
        selected = affordance.get("selected") if isinstance(affordance.get("selected"), dict) else {
            "target": _copy_jsonable(affordance.get("target")),
            "availability": _copy_jsonable(affordance.get("availability")),
        }
        action_def = selected.get("action") if isinstance(selected.get("action"), dict) else _live_agent_loop_action_definition(action_id, affordance.get("actionType"))
        action_def = action_def if isinstance(action_def, dict) else {}
        if not action_def or _live_agent_loop_is_support_action(action_def) or (selected.get("target") or {}).get("kind") == "support-tool":
            return False, _api_error("native_tool_required", "This support operation has a dedicated native Virtual World tool and cannot be started as a physical action."), 422
        visible_contract = _live_agent_visible_action_contract(action_def.get("actionType"))
        if not visible_contract:
            return False, _api_error("visible_executor_unavailable", "The requested action has no validated visible world executor."), 422

        now_iso = _utc_now_iso()
        reason = _live_agent_loop_clean_plan_text((params or {}).get("reason"), limit=700) or f"OpenClaw selected {action_def.get('label') or action_id}."
        decision = {
            "schemaVersion": "agent-live-mode-native-decision/v1",
            "at": now_iso,
            "mode": "openclaw-native-tools",
            "selectedActionId": action_id,
            "selectedActionLabel": action_def.get("label") or affordance.get("label"),
            "reason": reason,
            "source": "virtual_world_act",
        }
        agent_state["lastDecision"] = _copy_jsonable(decision)
        agent_state.pop("waitingState", None)
        skill = _live_agent_loop_skill_template(action_def, agent_state)
        agent_state["skillExecution"] = {
            **skill,
            "status": "committed",
            "startedAt": skill.get("startedAt") or now_iso,
            "updatedAt": now_iso,
            "loopActionId": action_id,
            "targetKey": _live_agent_loop_target_key(selected.get("target")),
        }
        goal_context = _live_agent_loop_bind_durable_goal_action(agent_state, action_id, selected, now_iso=now_iso)
        plan = _live_agent_loop_prepare_plan(agent_state, agent_id, action_def, decision, selected, now_iso, persist=True, goal_context=goal_context)
        plan_step = _live_agent_loop_plan_current_step(plan)
        payload = {
            "agentId": agent_id,
            "source": {
                "kind": "agent-live-mode",
                "requestedBy": "openclaw-plugin#virtual_world_act",
                "requestId": f"native-world-tool-{agent_id}-{int(time.time() * 1000)}",
                "surface": "openclaw-native-tool",
                "roles": ["participant"],
                "loopId": LIVE_AGENT_LOOP_SCHEMA_VERSION,
            },
            "actionType": action_def.get("actionType"),
            "capabilityTag": action_def.get("capabilityTag"),
            "target": _copy_jsonable(selected.get("target")),
            "priority": "normal",
            "params": {
                "reason": reason,
                "loopActionId": action_id,
                "loopActionLabel": action_def.get("label"),
                "loopNeed": action_def.get("need"),
                "planSchemaVersion": LIVE_AGENT_LOOP_PLAN_SCHEMA_VERSION,
                "planId": plan.get("id") if isinstance(plan, dict) else None,
                "planStepId": plan_step.get("id") if isinstance(plan_step, dict) else None,
                "goalSchemaVersion": LIVE_AGENT_DURABLE_GOAL_SCHEMA_VERSION if goal_context else None,
                "goalId": (goal_context or {}).get("goalId"),
                "goalRevision": (goal_context or {}).get("goalRevision"),
                "goalTaskId": (goal_context or {}).get("goalTaskId"),
                "goalStepId": (goal_context or {}).get("goalStepId"),
                "decisionMode": "openclaw-native-tools",
                "decisionReason": reason,
                "successCriteria": _live_agent_loop_clean_plan_text((params or {}).get("successCriteria"), limit=700),
                "perceptionAt": perception.get("at"),
                "serverRuntimeAuthority": True,
                "serverExecutor": WORLD_ACTION_SERVER_RUNTIME_OWNER,
                "visibleActionContractVersion": LIVE_AGENT_VISIBLE_ACTION_CONTRACT_VERSION,
                "visibleActionPolicy": "visible-world-execution-required",
                "visibleWorldAction": True,
                "hiddenWorldMutationAllowed": False,
                "visibleExecutor": visible_contract.get("clientExecutor"),
                "requiresPhysicalAgentPresence": True,
                "skill": _copy_jsonable(agent_state.get("skillExecution")),
                "actionContract": _live_agent_loop_action_contract({
                    "actionType": action_def.get("actionType"),
                    "target": selected.get("target"),
                    "params": {"loopActionId": action_id},
                }, action_def),
            },
        }
        inventory = agent_state.get("inventory") if isinstance(agent_state.get("inventory"), dict) else {}
        if isinstance(inventory.get("held"), dict):
            payload["params"]["carriedItem"] = _copy_jsonable(inventory.get("held"))
        if action_def.get("conversationTopic"):
            payload["params"]["conversationTopic"] = str(action_def.get("conversationTopic"))[:700]
        if isinstance(selected.get("buildSite"), dict):
            payload["params"]["buildSite"] = _copy_jsonable(selected.get("buildSite"))

        ok, created, status = create_agent_live_mode_action_request(payload)
        if not ok:
            _live_agent_loop_mark_plan_action_request_failed(state, agent_id, agent_state, plan, created, now_iso)
            agent_state["lastOutcome"] = {"at": now_iso, "status": "error", "httpStatus": status, "error": created, "decision": decision}
            save_live_agent_loop_state(state)
            return False, created, status
        action = created.get("action") if isinstance(created, dict) and isinstance(created.get("action"), dict) else {}
        world_action_id = action.get("id")
        agent_state["lastActionAt"] = now_iso
        agent_state["lastActionId"] = world_action_id
        agent_state["nextAllowedAt"] = None
        agent_state["skillExecution"].update({"status": "executing", "actionId": world_action_id, "updatedAt": now_iso})
        stored_plan = _live_agent_loop_mark_plan_action_created(state, agent_id, agent_state, plan, world_action_id, now_iso, action_def=action_def, decision=decision, selected=selected)
        awareness = _live_agent_loop_action_awareness(agent_id, agent_state, action, now_iso=now_iso)
        agent_state["lastOutcome"] = {
            "at": now_iso,
            "status": "created",
            "actionId": world_action_id,
            "loopActionId": action_id,
            "planId": (stored_plan or plan or {}).get("id"),
            "decision": decision,
        }
        _live_agent_loop_controller_update(agent_id, agent_state, "executing", reason=f"native world tool accepted {world_action_id}", active_action_id=world_action_id, awareness=awareness)
        _live_agent_loop_add_event(state, "native-tool-action-created", agent_id=agent_id, details={"actionId": world_action_id, "loopActionId": action_id, "target": selected.get("target")})
        _live_agent_loop_stat(agent_state, "actionsCreated")
        _live_agent_loop_stat(state, "actionsCreated")
        save_live_agent_loop_state(state)
        return True, {
            "ok": True,
            "schemaVersion": "agent-live-mode-native-action-result/v1",
            "status": "accepted",
            "agentId": agent_id,
            "actionId": world_action_id,
            "loopActionId": action_id,
            "action": _compact_json_value_for_storage(action, max_depth=5, max_items=48, string_limit=900),
            "next": "The world owns routing and interaction. Inspect authoritative feedback before another physical action.",
        }, 202


def _live_agent_native_tool_recall(agent_id, params):
    state = get_live_agent_loop_state(persist_migration=False)
    agent_state = _live_agent_loop_agent_state(state, agent_id)
    resident = _live_agent_loop_resident_profile_context(_live_agent_loop_resident_profile(agent_id, persist=False)) or {}
    limit = _normalize_int((params or {}).get("limit"), 12, minimum=1, maximum=20)
    rows = _live_agent_retrieve_resident_memories(resident, agent_state, limit=40)
    query = str((params or {}).get("query") or "").strip().lower()
    if query:
        tokens = {token for token in re.findall(r"[a-z0-9]+", query) if len(token) > 2}
        rows.sort(key=lambda item: (sum(1 for token in tokens if token in str(item.get("text") or "").lower()), float(item.get("score") or 0)), reverse=True)
    return {"ok": True, "agentId": agent_id, "query": query or None, "memories": rows[:limit]}


def _live_agent_native_tool_commit(agent_id, params):
    goal = _live_agent_loop_clean_plan_text((params or {}).get("goal"), limit=700)
    if not goal:
        return False, _api_error("invalid_payload", "goal is required."), 400
    next_step = _live_agent_loop_clean_plan_text((params or {}).get("nextStep"), limit=700)
    status = str((params or {}).get("status") or "active").strip().lower()
    if status not in {"active", "completed", "blocked", "abandoned"}:
        return False, _api_error("invalid_payload", "status must be active, completed, blocked, or abandoned."), 400
    now_iso = _utc_now_iso()
    with _live_agent_loop_lock:
        state = get_live_agent_loop_state(persist_migration=True)
        agent_state = _live_agent_loop_agent_state(state, agent_id)
        previous = agent_state.get("autonomyPlan") if isinstance(agent_state.get("autonomyPlan"), dict) else {}
        plan = _live_agent_loop_normalize_autonomy_plan({
            "createdAt": previous.get("createdAt") if previous.get("currentGoal") == goal else now_iso,
            "updatedAt": now_iso,
            "status": status,
            "currentGoal": goal,
            "nextStep": {"intent": next_step} if next_step else None,
        }) or {}
        plan["status"] = status
        if status in {"completed", "abandoned"}:
            plan["completedAt" if status == "completed" else "abandonedAt"] = now_iso
        agent_state["autonomyPlan"] = plan
        active_goal = _live_agent_loop_active_durable_goal(agent_state)
        if active_goal and _live_agent_loop_clean_plan_text(active_goal.get("title") or active_goal.get("goal") or active_goal.get("summary"), limit=700) == goal:
            active_goal["status"] = "cancelled" if status == "abandoned" else status
            active_goal["updatedAt"] = now_iso
            active_goal.setdefault("history", []).append({"at": now_iso, "event": "native-agent-commitment-updated", "status": active_goal["status"]})
            _live_agent_loop_store_durable_goal(agent_state, active_goal)
        _live_agent_loop_controller_update(agent_id, agent_state, "blocked" if status == "blocked" else "committed" if status == "active" else "observing", reason=f"OpenClaw commitment {status}: {goal}")
        _live_agent_loop_add_event(state, "native-tool-commitment-updated", agent_id=agent_id, details={"goal": goal, "nextStep": next_step, "status": status})
        save_live_agent_loop_state(state)
    return True, {"ok": True, "agentId": agent_id, "commitment": plan}, 200


def handle_live_agent_native_tool(payload):
    if not isinstance(payload, dict):
        return False, _api_error("invalid_payload", "Native Virtual World tool payload must be an object."), 400
    agent_id = payload.get("agentId")
    session_key = payload.get("sessionKey")
    tool = str(payload.get("tool") or "").strip().lower()
    params = payload.get("params") if isinstance(payload.get("params"), dict) else {}
    valid, binding, error, status = _live_agent_native_tool_validate(agent_id, session_key)
    if not valid:
        return False, error, status
    agent_id = binding["agentId"]

    if tool == "observe":
        return True, {"ok": True, "context": _live_agent_native_tool_context(agent_id, detail=params.get("detail") is True)}, 200
    if tool == "list_affordances":
        return True, {"ok": True, **_live_agent_native_tool_list_affordances(agent_id, params)}, 200
    if tool == "act":
        return _live_agent_native_tool_start_action(agent_id, params)
    if tool == "inspect_action":
        action, bucket = _live_agent_native_tool_action_lookup(agent_id, params.get("actionId"))
        if not action:
            return False, _api_error("action_not_found", "No matching world action belongs to this resident."), 404
        state = get_live_agent_loop_state(persist_migration=False)
        agent_state = _live_agent_loop_agent_state(state, agent_id)
        awareness = _live_agent_loop_action_awareness(agent_id, agent_state, action)
        return True, {"ok": True, "agentId": agent_id, "bucket": bucket, "action": _compact_json_value_for_storage(action, max_depth=6, max_items=64, string_limit=1200), "awareness": awareness}, 200
    if tool == "cancel_action":
        action, _bucket = _live_agent_native_tool_action_lookup(agent_id, params.get("actionId"))
        if not action or _canonical_world_action_status(action.get("status")) not in WORLD_ACTION_ACTIVE_STATES:
            return False, _api_error("active_action_not_found", "No matching active world action belongs to this resident."), 404
        reason = _live_agent_loop_clean_plan_text(params.get("reason"), limit=500) or "cancelled_by_resident_replan"
        ok, result, result_status = cancel_world_action(action.get("id"), {"failureReason": reason, "reason": reason, "actor": "openclaw-native-world-tool", "source": "agent-live-mode"})
        return ok, result, result_status
    if tool == "wait":
        with _live_agent_loop_lock:
            state = get_live_agent_loop_state(persist_migration=True)
            agent_state = _live_agent_loop_agent_state(state, agent_id)
            decision = {
                "reason": _live_agent_loop_clean_plan_text(params.get("reason"), limit=700) or "Deliberate wait.",
                "modelDecision": {"plannerTurn": {"nextStep": {"intent": params.get("reason"), "waitSeconds": params.get("seconds"), "wakeConditions": params.get("wakeConditions")}}},
            }
            waiting = _live_agent_loop_waiting_state_from_decision(agent_state, decision)
            waiting["source"] = "resident-native-tool"
            agent_state["waitingState"] = waiting
            _live_agent_loop_controller_update(agent_id, agent_state, "waiting", reason=waiting.get("reason"), wake_reason="native-world-tool")
            _live_agent_loop_add_event(state, "native-tool-waiting", agent_id=agent_id, details=waiting)
            save_live_agent_loop_state(state)
        return True, {"ok": True, "agentId": agent_id, "waiting": waiting}, 200
    if tool == "recall":
        return True, _live_agent_native_tool_recall(agent_id, params), 200
    if tool == "remember":
        text_value = _live_agent_loop_clean_plan_text(params.get("text"), limit=1200)
        if not text_value:
            return False, _api_error("invalid_payload", "text is required."), 400
        memory = _live_agent_loop_remember_planner_memory(agent_id, text_value, {"importance": params.get("importance"), "durable": float(params.get("importance") or 0.74) >= 0.65})
        return True, {"ok": True, "agentId": agent_id, "memory": memory}, 200
    if tool == "commit":
        return _live_agent_native_tool_commit(agent_id, params)
    if tool == "say":
        message = _live_agent_loop_clean_plan_text(params.get("message"), limit=1200)
        if not message:
            return False, _api_error("invalid_payload", "message is required."), 400
        row = _live_agent_session_append(agent_id, kind="reply", phase="conversation", role="assistant", text=message, source="openclaw-native-world-tool", details={"nativeTool": "virtual_world_say"})
        return True, {"ok": True, "agentId": agent_id, "message": row}, 200
    return False, _api_error("unknown_live_tool", "Unknown native Virtual World tool.", details={"tool": tool}), 404


def _live_agent_model_decision_worker(agent_id, prompt, candidate_surface, config, generation):
    """Run one cognition turn without owning physical execution.

    OpenClaw agents act through native Virtual World tools during the turn;
    their final prose is private cognition unless they explicitly call
    ``virtual_world_say``. Legacy providers retain the compact JSON adapter.
    """
    live_session = _live_agent_session_current(agent_id) or _live_agent_session_open(agent_id, reason="model-worker-start") or {}
    session_key = ""
    started = time.time()
    detail = {"mode": LIVE_AGENT_LOOP_MODEL_DECISION_MODE, "status": "error"}
    reply_text = ""
    provider_kind = _live_agent_model_decision_provider_kind(agent_id)
    provider_session_id = ""
    context_tool_rounds = []
    candidate_rows = _live_agent_model_candidate_rows(candidate_surface)
    candidate_ids = [str(row.get("id")) for row in candidate_rows]
    before_action_ids = {
        str(item.get("id"))
        for bucket in ("active", "history")
        for item in (get_world_actions_store(persist_migration=False).get(bucket) or [])
        if isinstance(item, dict) and item.get("agentId") == agent_id and item.get("id")
    }
    try:
        exchange = _live_agent_model_provider_request(agent_id, prompt, config, generation)
        provider_kind = exchange.get("providerKind") or provider_kind
        provider_session_id = exchange.get("sessionId") or ""
        session_key = provider_session_id
        if provider_kind != "openclaw":
            _live_agent_session_update(agent_id, provider_session_id=provider_session_id)
        reply_text = exchange.get("reply") or ""
        if provider_kind == "openclaw":
            native_actions = []
            store = get_world_actions_store(persist_migration=False)
            for bucket in ("active", "history"):
                for action in store.get(bucket) or []:
                    if not isinstance(action, dict) or action.get("agentId") != agent_id:
                        continue
                    action_id = str(action.get("id") or "")
                    source = action.get("source") if isinstance(action.get("source"), dict) else {}
                    if action_id and action_id not in before_action_ids and source.get("surface") == "openclaw-native-tool":
                        native_actions.append({"id": action_id, "status": action.get("status"), "actionType": action.get("actionType"), "bucket": bucket})
            if _live_agent_model_decision_cancelled(agent_id, started, generation):
                detail = {"mode": "openclaw-native-tools", "status": "discarded-after-disable", "latencySec": round(time.time() - started, 2)}
            elif native_actions:
                detail = {
                    "mode": "openclaw-native-tools",
                    "agentId": agent_id,
                    "providerKind": provider_kind,
                    "status": "native-tool-action-created",
                    "nativeActions": native_actions[:4],
                    "latencySec": round(time.time() - started, 2),
                    "replyPreview": str(reply_text or "")[:200],
                }
            elif exchange.get("ok"):
                detail = {
                    "mode": "openclaw-native-tools",
                    "agentId": agent_id,
                    "providerKind": provider_kind,
                    "status": "native-agent-turn-complete",
                    "latencySec": round(time.time() - started, 2),
                    "replyPreview": str(reply_text or "")[:200],
                }
            else:
                detail = {
                    "mode": "openclaw-native-tools",
                    "agentId": agent_id,
                    "providerKind": provider_kind,
                    "status": str(exchange.get("failureStatus") or "provider-error")[:120],
                    "failureKind": str(exchange.get("failureKind") or "provider-error")[:120],
                    "error": str(exchange.get("error") or "OpenClaw turn failed")[:500],
                    "latencySec": round(time.time() - started, 2),
                }
            # Native tool calls have already mutated the authoritative world
            # through validated APIs. Never parse the agent's natural final
            # reply as a second planner command or start a duplicate action.
            return
        if not exchange.get("ok") or not reply_text:
            status = str(exchange.get("failureStatus") or "").strip() or ("reply-timeout" if "timeout" in str(exchange.get("error") or "").lower() else "provider-error")
            detail = {"mode": LIVE_AGENT_LOOP_MODEL_DECISION_MODE, "status": status, "providerKind": provider_kind, "error": str(exchange.get("error") or "empty provider reply")[:500], "latencySec": round(time.time() - started, 2)}
        else:
            # Emergence-style bounded same-turn context tool chaining. Tool
            # results are returned to the same native provider session before
            # the physical decision is accepted.
            for round_index in range(LIVE_AGENT_MODEL_CONTEXT_TOOL_ROUNDS):
                parsed = _live_agent_model_json_object_parse(reply_text)
                requests = parsed.get("toolRequests") if isinstance(parsed, dict) and isinstance(parsed.get("toolRequests"), list) else []
                if not requests:
                    break
                tool_results = _live_agent_execute_context_tool_requests(agent_id, requests)
                context_tool_rounds.append({"round": round_index + 1, "requests": requests[:8], "results": tool_results})
                continuation = (
                    "LIVE WORLD CONTEXT TOOL RESULTS\n"
                    "These are read-only facts returned inside the same Resident turn. Use them now and return the final compact JSON decision. "
                    "Do not request the same tool again unless its result reports a transient error.\n"
                    + json.dumps(tool_results, ensure_ascii=False, separators=(",", ":"))
                )
                exchange = _live_agent_model_provider_request(agent_id, continuation, config, generation, session_id=provider_session_id)
                provider_session_id = exchange.get("sessionId") or provider_session_id
                _live_agent_session_update(agent_id, provider_session_id=provider_session_id)
                if not exchange.get("ok") or not exchange.get("reply"):
                    detail = {"mode": LIVE_AGENT_LOOP_MODEL_DECISION_MODE, "status": "context-tool-followup-error", "providerKind": provider_kind, "error": str(exchange.get("error") or "empty provider reply")[:500]}
                    break
                reply_text = exchange.get("reply") or ""
            else:
                detail = {"mode": LIVE_AGENT_LOOP_MODEL_DECISION_MODE, "status": "context-tool-round-limit", "providerKind": provider_kind}

            if detail.get("status") not in {"context-tool-followup-error"}:
                chosen, parse_status, intention = _live_agent_model_decision_parse(reply_text, candidate_rows)
                detail = {
                    "mode": LIVE_AGENT_LOOP_MODEL_DECISION_MODE,
                    "agentId": agent_id,
                    "providerKind": provider_kind,
                    "status": parse_status,
                    "chosen": chosen,
                    "latencySec": round(time.time() - started, 2),
                    "replyPreview": str(reply_text or "")[:200],
                    "contextToolRounds": context_tool_rounds,
                }
                if isinstance(intention, dict):
                    detail["intention"] = intention
                    if isinstance(intention.get("plannerTurn"), dict):
                        detail["plannerTurn"] = intention.get("plannerTurn")
                    if intention.get("category"):
                        resolved_category = LIVE_AGENT_INTENTION_CATEGORY_ALIASES.get(_normalize_token(intention.get("category")) or "")
                        detail["requestedCategory"] = resolved_category or intention.get("category")
                        detail["categoryResolved"] = bool(resolved_category)
                if chosen or isinstance(intention, dict):
                    if _live_agent_model_decision_cancelled(agent_id, started, generation):
                        detail = {"mode": LIVE_AGENT_LOOP_MODEL_DECISION_MODE, "status": "discarded-after-disable", "latencySec": round(time.time() - started, 2)}
                    else:
                        if isinstance(intention, dict) and intention.get("category"):
                            _live_agent_loop_note_requested_category(agent_id, intention.get("category"), generation=generation)
                        published = _live_agent_model_decision_publish(
                            agent_id,
                            generation,
                            {"chosen": chosen, "detail": detail, "at": _utc_now_iso(), "candidateIds": candidate_ids, "intention": intention},
                        )
                        if not published:
                            detail = {"mode": LIVE_AGENT_LOOP_MODEL_DECISION_MODE, "status": "discarded-after-disable", "latencySec": round(time.time() - started, 2)}
    except Exception as exc:
        detail = {"mode": LIVE_AGENT_LOOP_MODEL_DECISION_MODE, "status": "gateway-error", "error": str(exc)[:300]}
    finally:
        if _live_agent_model_decision_cancelled(agent_id, started, generation):
            detail = {"mode": LIVE_AGENT_LOOP_MODEL_DECISION_MODE, "status": "discarded-after-disable", "latencySec": round(time.time() - started, 2)}
        marked_current = _live_agent_model_decision_mark(agent_id, in_flight=False, min_interval_sec=config["minIntervalSec"], outcome=detail, generation=generation)
        if marked_current and _live_agent_model_decision_generation_current(agent_id, generation):
            try:
                _live_agent_planner_transcript_record(
                    agent_id,
                    session_key=session_key,
                    started_epoch=started,
                    prompt=prompt,
                    reply_text=reply_text,
                    detail=detail,
                    candidate_ids=candidate_ids,
                )
            except Exception as exc:
                print(f"[live-agent] Could not record planner transcript for {agent_id}: {exc}")
        # OpenClaw transport sessions are disposable. Durable continuity lives
        # in the bounded Virtual World session, memory, and goal stores.


def _live_agent_model_decide(agent_id, decision_frame, agent_state, config):
    """Non-blocking model decision. Returns (loopActionId | 'skip' | None, detail dict).

    A completed async choice from a previous request is applied immediately.
    Otherwise a background request is started subject to cooldown. No physical
    action is selected until the resident model explicitly commits to one.
    """
    candidates = [c for c in decision_frame.get("candidates") or [] if c.get("decision") == "candidate"]
    candidates.sort(key=lambda item: (float(item.get("score") or 0), str(item.get("id") or "")), reverse=True)
    candidate_ids = [str(c.get("id")) for c in candidates if c.get("id")]
    provider_kind = _live_agent_model_decision_provider_kind(agent_id)
    if provider_kind not in LIVE_AGENT_LOOP_MODEL_DECISION_SOURCES:
        return None, {"mode": LIVE_AGENT_LOOP_MODEL_DECISION_MODE, "status": "provider-not-supported", "providerKind": provider_kind}

    completed = _live_agent_model_decision_take_completed(agent_id)
    if completed:
        chosen = completed.get("chosen")
        detail = dict(completed.get("detail") or {})
        detail["applied"] = "async-previous-request"
        previous_terminal_replay = json.dumps(agent_state.get("lastTerminalGoalReplay") or {}, sort_keys=True, default=str)
        _live_agent_loop_apply_planner_turn(agent_state, detail, agent_id=agent_id)
        terminal_replay = agent_state.get("lastTerminalGoalReplay") if isinstance(agent_state.get("lastTerminalGoalReplay"), dict) else {}
        if terminal_replay and json.dumps(terminal_replay, sort_keys=True, default=str) != previous_terminal_replay:
            detail["status"] = "terminal-goal-replay-suppressed"
            detail["evidence"] = _copy_jsonable(terminal_replay)
            detail["chosen"] = None
            _live_agent_model_decision_allow_immediate(agent_id, reason="terminal-goal-replay-suppressed")
            return None, detail
        if chosen == "skip" or chosen in candidate_ids:
            agent_state.pop("lastRejectedIntention", None)
            return chosen, detail
        if isinstance(completed.get("intention"), dict) and completed["intention"].get("category"):
            intention = completed["intention"]
            requested_category = str(intention.get("category") or "").strip()
            if detail.get("categoryResolved") is not True:
                evidence = {
                    "at": _utc_now_iso(),
                    "status": "unavailable",
                    "reason": "requested object category has no safe executable Live Mode affordance",
                    "requestedAction": intention.get("action") or None,
                    "requestedCategory": requested_category,
                    "availableActionIds": candidate_ids[:24],
                    "providerKind": detail.get("providerKind"),
                }
                detail["status"] = "intention-category-unavailable"
                detail["evidence"] = evidence
                agent_state["lastRejectedIntention"] = evidence
                _live_agent_model_decision_allow_immediate(agent_id, reason="resident-category-unavailable")
                return None, detail
            # Category discovery expands the next perception frame, then the
            # resident model decides again. Never substitute a ranked server
            # candidate for the model's missing physical choice.
            detail["status"] = "intention-category-applied"
            _live_agent_model_decision_allow_immediate(agent_id, reason="resident-category-discovered")
            return None, detail
        intention = completed.get("intention") if isinstance(completed.get("intention"), dict) else {}
        requested_action = str(intention.get("action") or "").strip()
        if requested_action and requested_action.lower() != "skip":
            evidence = {
                "at": _utc_now_iso(),
                "status": "unavailable",
                "reason": "requested action is not present in the current safe executable Live Mode surface",
                "requestedAction": requested_action,
                "requestedCategory": intention.get("category") or None,
                "availableActionIds": candidate_ids[:24],
                "providerKind": detail.get("providerKind"),
            }
            detail["status"] = "intention-action-unavailable"
            detail["evidence"] = evidence
            agent_state["lastRejectedIntention"] = evidence
            _live_agent_model_decision_allow_immediate(agent_id, reason="resident-action-unavailable")
            return None, detail
        if isinstance(detail.get("plannerTurn"), dict) and detail.get("status") in {"planner-tool-or-event-request", "planner-step-unresolved"}:
            _live_agent_model_decision_allow_immediate(agent_id, reason="resident-turn-needs-followup")
            return None, detail
        detail["status"] = "stale-choice-discarded"
        evidence = {
            "at": _utc_now_iso(),
            "status": "stale",
            "reason": "the chosen interaction is no longer available in the current world frame",
            "requestedAction": chosen,
            "availableActionIds": candidate_ids[:24],
            "providerKind": detail.get("providerKind"),
        }
        detail["evidence"] = evidence
        agent_state["lastRejectedIntention"] = evidence
        _live_agent_model_decision_allow_immediate(agent_id, reason="resident-choice-became-stale")
        return None, detail

    allowed, blocked_reason = _live_agent_model_decision_allowed(agent_id)
    if not allowed:
        return None, {"mode": LIVE_AGENT_LOOP_MODEL_DECISION_MODE, "status": blocked_reason}
    prompt = _live_agent_model_decision_prompt(agent_id, decision_frame, agent_state)
    generation = _live_agent_model_decision_start(agent_id)
    threading.Thread(
        target=_live_agent_model_decision_worker,
        args=(agent_id, prompt, candidates, config, generation),
        daemon=True,
        name=f"vw-live-model-decide-{agent_id}",
    ).start()
    return None, {"mode": LIVE_AGENT_LOOP_MODEL_DECISION_MODE, "status": "model-request-started", "appliesOn": "next-tick"}


def _live_agent_model_decision_recover_reply(session_key, started_epoch):
    """Read the newest assistant message created after started_epoch from the planner session."""
    try:
        result = _gateway_rpc_call("chat.history", {"sessionKey": session_key, "limit": 6}, timeout=15)
        messages = result.get("messages") if isinstance(result, dict) else None
        if not isinstance(messages, list):
            payload = result.get("payload") if isinstance(result, dict) else None
            messages = payload.get("messages") if isinstance(payload, dict) else []
        started_ms = float(started_epoch or 0) * 1000.0
        for message in reversed(messages or []):
            if not isinstance(message, dict) or message.get("role") != "assistant":
                continue
            stamp = message.get("timestamp") or message.get("createdAt") or message.get("at")
            stamp_ms = None
            if isinstance(stamp, (int, float)):
                stamp_ms = float(stamp if stamp > 1e12 else stamp * 1000)
            elif isinstance(stamp, str):
                parsed = _parse_isoish_epoch(stamp)
                stamp_ms = parsed * 1000 if parsed else None
            if stamp_ms is not None and started_ms and stamp_ms < started_ms - 2000:
                continue
            content = message.get("content")
            if isinstance(content, str) and content.strip():
                return content
            if isinstance(content, list):
                text = "".join(block.get("text", "") for block in content if isinstance(block, dict) and block.get("type") == "text")
                if text.strip():
                    return text
    except Exception:
        pass
    return ""


def _live_agent_loop_select_next_action(agent_id, agent_state, perception=None, *, loop_state=None):
    perception = perception if isinstance(perception, dict) else _live_agent_loop_build_perception(agent_id, agent_state)
    decision = _live_agent_loop_build_decision_frame(agent_id, perception, agent_state)
    config = _live_agent_model_decision_config(loop_state)
    if config["enabled"]:
        chosen, model_detail = _live_agent_model_decide(agent_id, decision, agent_state, config)
        if model_detail.get("applied") == "async-previous-request" and not chosen:
            refreshed_perception = dict(perception)
            refreshed_perception["affordances"] = [
                {key: value for key, value in affordance.items() if key != "selected"}
                for affordance in _live_agent_loop_action_affordances(
                    agent_id,
                    agent_state,
                    spatial=perception.get("spatial"),
                )
            ]
            decision = _live_agent_loop_build_decision_frame(agent_id, refreshed_perception, agent_state)
        decision["modelDecision"] = model_detail
        if not chosen:
            decision["selectedActionId"] = None
            decision["selectedActionLabel"] = None
            decision["mode"] = LIVE_AGENT_LOOP_MODEL_DECISION_MODE
            decision["reason"] = f"resident model has not committed a physical action ({model_detail.get('status') or 'no-choice'}); no deterministic substitute is allowed"
            agent_state["lastDecision"] = {
                **(agent_state.get("lastDecision") or {}),
                "mode": LIVE_AGENT_LOOP_MODEL_DECISION_MODE,
                "selectedActionId": None,
                "selectedActionLabel": None,
                "reason": decision["reason"],
                "modelDecision": model_detail,
            }
            return None, decision
        if chosen == "skip":
            decision["mode"] = LIVE_AGENT_LOOP_MODEL_DECISION_MODE
            decision["selectedActionId"] = None
            decision["selectedActionLabel"] = None
            decision["reason"] = "model chose to skip this tick"
            agent_state["lastDecision"] = {**(agent_state.get("lastDecision") or {}), "mode": decision["mode"], "selectedActionId": None, "selectedActionLabel": None, "reason": decision["reason"], "modelDecision": model_detail}
            return None, decision
        if chosen:
            candidate = next((c for c in decision.get("candidates") or [] if c.get("id") == chosen and c.get("decision") == "candidate"), None)
            if candidate:
                decision["mode"] = LIVE_AGENT_LOOP_MODEL_DECISION_MODE
                decision["selectedActionId"] = chosen
                decision["selectedActionLabel"] = candidate.get("label")
                decision["score"] = candidate.get("score")
                decision["reason"] = f"{candidate.get('label')} chosen by the agent's own model"
        if isinstance(agent_state.get("lastDecision"), dict):
            agent_state["lastDecision"]["mode"] = decision.get("mode")
            agent_state["lastDecision"]["selectedActionId"] = decision.get("selectedActionId")
            agent_state["lastDecision"]["selectedActionLabel"] = decision.get("selectedActionLabel")
            agent_state["lastDecision"]["reason"] = decision.get("reason")
            agent_state["lastDecision"]["modelDecision"] = model_detail
    else:
        decision["mode"] = LIVE_AGENT_LOOP_MODEL_DECISION_MODE
        decision["selectedActionId"] = None
        decision["selectedActionLabel"] = None
        decision["modelDecision"] = {"mode": LIVE_AGENT_LOOP_MODEL_DECISION_MODE, "status": "model-autonomy-required"}
        decision["reason"] = "Live Agent Mode requires resident-model inference; deterministic planner execution is disabled"
        agent_state["lastDecision"] = {
            "at": decision.get("at"),
            "mode": decision["mode"],
            "selectedActionId": None,
            "selectedActionLabel": None,
            "reason": decision["reason"],
            "modelDecision": decision["modelDecision"],
        }
        return None, decision
    selected_id = decision.get("selectedActionId")
    if not selected_id:
        return None, decision
    selected_affordance = next((
        item for item in _live_agent_loop_action_affordances(agent_id, agent_state, spatial=perception.get("spatial"))
        if item.get("id") == selected_id and item.get("available")
    ), None)
    if not selected_affordance:
        return None, decision
    selected = selected_affordance.get("selected")
    if isinstance(selected, dict):
        selected["decision"] = decision
    return selected, decision


def _live_agent_loop_next_allowed_epoch(agent_state):
    raw = agent_state.get("nextAllowedAt")
    if isinstance(raw, (int, float)):
        return float(raw)
    parsed = _parse_isoish_epoch(raw)
    return float(parsed or 0)


def _live_agent_loop_action_summary(action):
    if not isinstance(action, dict):
        return None
    timing = action.get("timing") if isinstance(action.get("timing"), dict) else {}
    source = action.get("source") if isinstance(action.get("source"), dict) else {}
    params = action.get("params") if isinstance(action.get("params"), dict) else {}
    result = action.get("result") if isinstance(action.get("result"), dict) else {}
    return {
        "id": action.get("id"),
        "status": _canonical_world_action_status(action.get("status")),
        "actionType": action.get("actionType"),
        "agentId": action.get("agentId"),
        "loopActionId": params.get("loopActionId"),
        "planId": params.get("planId"),
        "planStepId": params.get("planStepId"),
        "goalId": params.get("goalId"),
        "goalRevision": params.get("goalRevision"),
        "goalTaskId": params.get("goalTaskId"),
        "goalStepId": params.get("goalStepId"),
        "requestId": source.get("requestId"),
        "updatedAt": timing.get("updatedAt"),
        "terminalAt": timing.get("terminalAt"),
        "completedAt": timing.get("completedAt"),
        "failureReason": action.get("failureReason"),
        "result": result,
    }


def _live_agent_loop_action_epoch(action):
    if not isinstance(action, dict):
        return 0
    timing = action.get("timing") if isinstance(action.get("timing"), dict) else {}
    for key in ("terminalAt", "completedAt", "updatedAt", "routePendingAt", "createdAt", "requestedAt"):
        parsed = _parse_isoish_epoch(timing.get(key))
        if parsed:
            return parsed
    return 0


def _live_agent_loop_owns_world_action(action):
    if not isinstance(action, dict):
        return False
    params = action.get("params") if isinstance(action.get("params"), dict) else {}
    if params.get("loopActionId"):
        return True
    source = action.get("source") if isinstance(action.get("source"), dict) else {}
    return str(source.get("requestId") or "").startswith("live-loop-")


def _live_agent_loop_action_status_timestamp(action, status):
    timing = action.get("timing") if isinstance(action.get("timing"), dict) else {}
    route = action.get("route") if isinstance(action.get("route"), dict) else {}
    keys_by_status = {
        "route_pending": ("routePendingAt", "handoffPendingAt", "updatedAt", "createdAt"),
        "routing": ("startedAt", "updatedAt", "routePendingAt", "createdAt"),
        "arrived": ("arrivedAt", "updatedAt", "startedAt", "createdAt"),
        "in_progress": ("inUseAt", "arrivedAt", "updatedAt", "startedAt", "createdAt"),
    }
    for key in keys_by_status.get(status, ("updatedAt", "createdAt")):
        value = timing.get(key) if key in timing else route.get(key)
        parsed = _parse_isoish_epoch(value) if value else None
        if parsed:
            return parsed, key
    return None, None


def _live_agent_loop_stale_threshold_seconds(action, status):
    timing = action.get("timing") if isinstance(action.get("timing"), dict) else {}
    params = action.get("params") if isinstance(action.get("params"), dict) else {}
    default_threshold = LIVE_AGENT_LOOP_STALE_ACTIVE_ACTION_SECONDS.get(status)
    timeout_ms = timing.get("timeoutMs")
    if isinstance(timeout_ms, (int, float)) and timeout_ms > 0:
        return max(60, int(timeout_ms / 1000))
    if status == "in_progress":
        duration_ms = params.get("constructionDurationMs") or params.get("estimatedUseMs")
        if isinstance(duration_ms, (int, float)) and duration_ms > 0:
            return max(default_threshold or 300, int(duration_ms / 1000) + 180)
    return default_threshold


def _live_agent_loop_reconcile_stale_active_behaviors(state=None, *, now_epoch=None):
    now_epoch = float(now_epoch or time.time())
    store = get_world_actions_store(persist_migration=True)
    stale = []
    for action in store.get("active", []):
        if not isinstance(action, dict):
            continue
        if _behavior_source_kind_from_record(action) != "agent-live-mode":
            continue
        status = _canonical_world_action_status(action.get("status"))
        threshold = _live_agent_loop_stale_threshold_seconds(action, status)
        if not threshold:
            continue
        started_epoch, timestamp_key = _live_agent_loop_action_status_timestamp(action, status)
        if not started_epoch:
            continue
        age_sec = max(0, int(now_epoch - started_epoch))
        if age_sec < threshold:
            continue
        stale.append({
            "actionId": action.get("id"),
            "agentId": action.get("agentId"),
            "status": status,
            "ageSec": age_sec,
            "thresholdSec": threshold,
            "timestampKey": timestamp_key,
            "actionType": action.get("actionType"),
            "loopActionId": (action.get("params") if isinstance(action.get("params"), dict) else {}).get("loopActionId"),
        })

    expired = []
    for item in stale:
        action_id = item.get("actionId")
        if not action_id:
            continue
        ok, response, status_code = transition_world_action(
            action_id,
            "expired",
            result={
                "status": "expired",
                "reason": "live_mode_active_action_stale",
                "stale": item,
            },
            failure_reason="timed_out",
            actor="server.py#live-agent-loop-stale-reconcile",
            source="agent-live-mode",
        )
        item["transitionOk"] = bool(ok)
        item["httpStatus"] = status_code
        if not ok:
            item["error"] = response
        expired.append(item)

    if expired:
        reconcile_move_intents()
        if isinstance(state, dict):
            now_iso = _utc_now_iso()
            for item in expired:
                agent_id = item.get("agentId")
                if not agent_id:
                    continue
                agent_state = _live_agent_loop_agent_state(state, agent_id)
                if item.get("transitionOk"):
                    agent_state["lastOutcome"] = {
                        "at": now_iso,
                        "status": "expired",
                        "reason": "live-mode-stale-active-action",
                        "actionId": item.get("actionId"),
                        "loopActionId": item.get("loopActionId"),
                        "stale": {k: item.get(k) for k in ("status", "ageSec", "thresholdSec", "timestampKey", "actionType")},
                    }
                    _live_agent_loop_add_feedback(state, agent_id, "warning", "Expired stale Live Mode action so the resident loop could continue.", item)
                    _live_agent_loop_add_event(state, "stale-action-expired", agent_id=agent_id, details=item)
                else:
                    _live_agent_loop_add_feedback(state, agent_id, "error", "Could not expire stale Live Mode action.", item)
                    _live_agent_loop_add_event(state, "stale-action-expire-failed", agent_id=agent_id, details=item)
    return expired


def _live_agent_loop_relationship_key(agent_id, other_agent_id):
    left = str(agent_id or "").strip()
    right = str(other_agent_id or "").strip()
    if not left or not right:
        return None
    pair = sorted([left, right])
    return f"{pair[0]}::{pair[1]}"


def _live_agent_loop_append_resident_memory(values, entry, limit):
    if not isinstance(entry, dict):
        return _limit_profile_list(values, limit=limit, item_limit=1200)
    entry_key = entry.get("settledActionKey") or entry.get("actionId")
    next_values = []
    for item in values if isinstance(values, list) else []:
        if isinstance(item, dict) and entry_key and (item.get("settledActionKey") == entry_key or item.get("actionId") == entry.get("actionId")):
            continue
        next_values.append(item)
    next_values.append(entry)
    return _limit_profile_list(next_values, limit=limit, item_limit=1200)


def _resident_memory_record_text(record):
    if not isinstance(record, dict):
        return _live_agent_loop_clean_plan_text(record, limit=700) or ""
    failure = record.get("failure") if isinstance(record.get("failure"), dict) else {}
    for value in (
        record.get("lesson"),
        record.get("text"),
        record.get("summary"),
        failure.get("lesson"),
        failure.get("reason"),
        record.get("failureReason"),
        record.get("label"),
    ):
        text = _live_agent_loop_clean_plan_text(value, limit=700)
        if text:
            return text
    return "Live Agent experience"


def _normalize_legacy_resident_memory_record(record, *, source):
    if isinstance(record, dict):
        return _copy_jsonable(record)
    text = _live_agent_loop_clean_plan_text(record, limit=1200)
    if not text:
        return None
    return {
        "id": f"legacy-memory-{hashlib.sha256(text.encode('utf-8', errors='ignore')).hexdigest()[:16]}",
        "text": text,
        "source": source,
        "importance": 0.58,
        "legacyTextPromoted": True,
    }


def _resident_memory_evidence_key(record):
    if not isinstance(record, dict):
        return hashlib.sha256(str(record).encode("utf-8", errors="ignore")).hexdigest()[:20]
    for key in ("settledActionKey", "actionId", "id"):
        if record.get(key):
            return str(record.get(key))[:180]
    basis = json.dumps(record, sort_keys=True, separators=(",", ":"), default=str)
    return hashlib.sha256(basis.encode("utf-8", errors="ignore")).hexdigest()[:20]


def _resident_memory_semantic_key(record):
    if not isinstance(record, dict):
        basis = re.sub(r"\s+", " ", str(record or "").strip().lower())
        return hashlib.sha256(basis.encode("utf-8", errors="ignore")).hexdigest()[:20]
    failure = record.get("failure") if isinstance(record.get("failure"), dict) else {}
    status = _canonical_world_action_status(record.get("status") or failure.get("status"))
    outcome_class = "failure" if status in {"failed", "expired", "cancelled", "invalidated"} or failure else "success" if status in {"completed", "arrived"} else "experience"
    target = record.get("target") if isinstance(record.get("target"), dict) else {}
    target_key = record.get("targetKey") or _live_agent_loop_target_key(target)
    other_agent = record.get("otherAgentId") or target.get("targetAgentId")
    action_key = record.get("loopActionId") or record.get("actionType") or record.get("type")
    if action_key:
        basis = "|".join(str(value or "").strip().lower() for value in (action_key, outcome_class, target_key, other_agent))
    else:
        basis = "|".join((outcome_class, _resident_memory_record_text(record).lower()))
    return hashlib.sha256(basis.encode("utf-8", errors="ignore")).hexdigest()[:20]


def _resident_memory_importance(record):
    if not isinstance(record, dict):
        return 0.45
    failure = record.get("failure") if isinstance(record.get("failure"), dict) else {}
    status = _canonical_world_action_status(record.get("status") or failure.get("status"))
    score = 0.24
    if status in {"failed", "expired", "invalidated"} or failure:
        score += 0.46
    elif status == "cancelled" and failure.get("reportable") is not False:
        score += 0.30
    if failure.get("reportable") is True or record.get("unresolved") is True:
        score += 0.16
    if record.get("loopActionId") in {"work-on-active-goal", "investigate-blocking-issue", "report-issue-to-coder"}:
        score += 0.20
    target = record.get("target") if isinstance(record.get("target"), dict) else {}
    if record.get("actionType") == "life.social" or record.get("otherAgentId") or target.get("targetAgentId"):
        score += 0.18
    source = str(record.get("source") or "").lower()
    if "user" in source:
        score += 0.26
    if record.get("lesson") or failure.get("lesson"):
        score += 0.12
    try:
        score = max(score, float(record.get("importance") or 0))
    except (TypeError, ValueError):
        pass
    return round(min(1.0, score), 3)


def _resident_long_term_memory_from_record(record):
    record = record if isinstance(record, dict) else {"text": str(record or "")}
    failure = record.get("failure") if isinstance(record.get("failure"), dict) else {}
    status = _canonical_world_action_status(record.get("status") or failure.get("status"))
    semantic_key = _resident_memory_semantic_key(record)
    evidence_key = _resident_memory_evidence_key(record)
    at = record.get("at") or record.get("updatedAt") or record.get("createdAt") or "1970-01-01T00:00:00Z"
    memory = {
        "id": f"resident-memory-{semantic_key}",
        "memoryKey": semantic_key,
        "firstAt": at,
        "lastAt": at,
        "count": 1,
        "importance": _resident_memory_importance(record),
        "text": _resident_memory_record_text(record),
        "source": "live-agent-consolidation",
        "evidenceKeys": [evidence_key],
    }
    for key in ("loopActionId", "actionType", "status", "targetKey", "otherAgentId"):
        value = record.get(key)
        if value is not None:
            memory[key] = _copy_jsonable(value)
    if not memory.get("targetKey") and isinstance(record.get("target"), dict):
        memory["targetKey"] = _live_agent_loop_target_key(record.get("target"))
    if not memory.get("otherAgentId") and isinstance(record.get("target"), dict):
        memory["otherAgentId"] = record["target"].get("targetAgentId")
    if failure:
        memory["failureReason"] = failure.get("reason") or failure.get("failureReason") or record.get("failureReason")
        memory["unresolved"] = failure.get("reportable") is not False
    elif status in {"failed", "expired", "invalidated"}:
        memory["failureReason"] = record.get("failureReason") or status
        memory["unresolved"] = True
    return memory


def _merge_resident_long_term_memory(existing, incoming):
    if not isinstance(existing, dict):
        return incoming
    if not isinstance(incoming, dict):
        return existing
    old_evidence = [str(item) for item in (existing.get("evidenceKeys") or []) if str(item or "")]
    new_evidence = [str(item) for item in (incoming.get("evidenceKeys") or []) if str(item or "")]
    unseen = [item for item in new_evidence if item not in old_evidence]
    existing_epoch = _parse_isoish_epoch(existing.get("lastAt")) or 0
    incoming_epoch = _parse_isoish_epoch(incoming.get("lastAt")) or 0
    newest = incoming if incoming_epoch >= existing_epoch else existing
    merged = {**existing, **newest}
    merged["firstAt"] = min(
        [value for value in (existing.get("firstAt"), incoming.get("firstAt")) if value],
        key=lambda value: _parse_isoish_epoch(value) or 0,
        default=existing.get("firstAt") or incoming.get("firstAt"),
    )
    merged["lastAt"] = newest.get("lastAt") or existing.get("lastAt") or incoming.get("lastAt")
    is_newer_evidence = incoming_epoch > existing_epoch
    merged["count"] = int(existing.get("count") or 1) + (int(incoming.get("count") or 1) if unseen and is_newer_evidence else 0)
    merged["importance"] = max(_resident_memory_importance(existing), _resident_memory_importance(incoming))
    merged["evidenceKeys"] = [*old_evidence, *unseen][-16:]
    if existing.get("unresolved") is True or incoming.get("unresolved") is True:
        merged["unresolved"] = True
    return merged


def _resident_memory_generated_summary(long_term):
    ranked = sorted(
        [item for item in long_term if isinstance(item, dict)],
        key=lambda item: (
            bool(item.get("unresolved")),
            float(item.get("importance") or 0),
            _parse_isoish_epoch(item.get("lastAt")) or 0,
        ),
        reverse=True,
    )
    lines = []
    for item in ranked[:12]:
        text = _resident_memory_record_text(item)
        count = int(item.get("count") or 1)
        suffix = f" (experienced {count} times)" if count > 1 else ""
        if item.get("unresolved"):
            suffix += " [unresolved]"
        lines.append(f"- {text}{suffix}"[:520])
    return "\n".join(lines)


def _consolidate_resident_memory(memory):
    memory = _copy_jsonable(memory) if isinstance(memory, dict) else {}
    short_term = [
        normalized
        for item in (memory.get("shortTerm") or [])
        if (normalized := _normalize_legacy_resident_memory_record(item, source="resident-profile-short-term"))
    ]
    reflections = [
        normalized
        for item in (memory.get("reflections") or [])
        if (normalized := _normalize_legacy_resident_memory_record(item, source="resident-profile-reflection"))
    ]
    short_term.sort(key=_storage_record_epoch)
    reflections.sort(key=_storage_record_epoch)
    retained_short = short_term[-RESIDENT_PROFILE_LIST_LIMIT:]
    retained_reflections = reflections[-RESIDENT_PROFILE_LIST_LIMIT:]
    candidates = [*short_term[:-RESIDENT_PROFILE_LIST_LIMIT], *reflections[:-RESIDENT_PROFILE_LIST_LIMIT]]
    if retained_short and _resident_memory_importance(retained_short[-1]) >= 0.65:
        candidates.append(retained_short[-1])
    if retained_reflections and _resident_memory_importance(retained_reflections[-1]) >= 0.65:
        candidates.append(retained_reflections[-1])

    merged = {}
    pinned = []
    for item in memory.get("longTerm") or []:
        normalized = item if isinstance(item, dict) else {
            "id": f"resident-memory-manual-{_resident_memory_semantic_key(item)}",
            "memoryKey": _resident_memory_semantic_key(item),
            "text": _resident_memory_record_text(item),
            "importance": 1.0,
            "source": "resident-profile",
            "count": 1,
        }
        key = normalized.get("memoryKey") or _resident_memory_semantic_key(normalized)
        normalized["memoryKey"] = key
        merged[key] = normalized
        if normalized.get("source") != "live-agent-consolidation":
            pinned.append(key)
    seen_candidate_evidence = set()
    for record in candidates:
        evidence_key = _resident_memory_evidence_key(record)
        if evidence_key in seen_candidate_evidence:
            continue
        seen_candidate_evidence.add(evidence_key)
        incoming = _resident_long_term_memory_from_record(record)
        key = incoming["memoryKey"]
        merged[key] = _merge_resident_long_term_memory(merged.get(key), incoming) if key in merged else incoming

    all_long_term = list(merged.values())
    pinned_items = [merged[key] for key in pinned if key in merged]
    ranked_generated = sorted(
        [item for key, item in merged.items() if key not in set(pinned)],
        key=lambda item: (
            bool(item.get("unresolved")),
            float(item.get("importance") or 0),
            _parse_isoish_epoch(item.get("lastAt")) or 0,
        ),
        reverse=True,
    )
    available = max(0, RESIDENT_PROFILE_MEMORY_LIMIT - len(pinned_items))
    long_term = [*pinned_items[:RESIDENT_PROFILE_MEMORY_LIMIT], *ranked_generated[:available]]
    long_term.sort(key=lambda item: _parse_isoish_epoch(item.get("lastAt") or item.get("firstAt")) or 0)

    marker = "[Consolidated Live Agent experiences]"
    existing_summary = str(memory.get("summary") or "")
    preserved_summary = existing_summary.split(marker, 1)[0].rstrip()
    generated = _resident_memory_generated_summary(long_term)
    next_summary = preserved_summary
    if generated:
        next_summary = f"{preserved_summary}\n\n{marker}\n{generated}".strip()
    memory["summary"] = _limit_profile_text(next_summary, RESIDENT_PROFILE_TEXT_LIMIT)
    memory["shortTerm"] = retained_short
    memory["reflections"] = retained_reflections
    memory["longTerm"] = long_term
    compaction = memory.get("compaction") if isinstance(memory.get("compaction"), dict) else {}
    memory["compaction"] = {
        **compaction,
        "shortTermLimit": RESIDENT_PROFILE_LIST_LIMIT,
        "longTermLimit": RESIDENT_PROFILE_MEMORY_LIMIT,
        "strategy": "promote important or aging experiences; merge repeated routines; preserve semantic summaries",
        "consolidationVersion": "resident-memory-consolidation/v1",
        "promotedMemoryCount": len([item for item in long_term if isinstance(item, dict) and item.get("source") == "live-agent-consolidation"]),
        "aggregateExperienceCount": sum(int(item.get("count") or 1) for item in long_term if isinstance(item, dict)),
        "discardedAggregateCount": max(0, len(all_long_term) - len(long_term)),
    }
    return memory


def _live_agent_loop_remember_resident_profile_action(agent_id, recent_entry, observation, reflection, social_relationship=None):
    if not isinstance(recent_entry, dict) or not recent_entry.get("actionId"):
        return None
    short_term = {
        "at": recent_entry.get("at"),
        "actionId": recent_entry.get("actionId"),
        "loopActionId": recent_entry.get("loopActionId"),
        "actionType": recent_entry.get("actionType"),
        "label": recent_entry.get("label"),
        "status": recent_entry.get("status"),
        "need": recent_entry.get("need"),
        "settledActionKey": recent_entry.get("settledActionKey"),
        "text": observation.get("text") if isinstance(observation, dict) else "",
        "source": "live-agent-loop",
    }
    for key in ("target", "targetKey", "failure"):
        if recent_entry.get(key) is not None:
            short_term[key] = _copy_jsonable(recent_entry.get(key))
    reflection_entry = {
        "at": reflection.get("at") if isinstance(reflection, dict) else recent_entry.get("at"),
        "actionId": recent_entry.get("actionId"),
        "loopActionId": recent_entry.get("loopActionId"),
        "settledActionKey": recent_entry.get("settledActionKey"),
        "text": reflection.get("text") if isinstance(reflection, dict) else "",
        "source": "live-agent-loop",
    }
    if recent_entry.get("failure") is not None:
        reflection_entry["failure"] = _copy_jsonable(recent_entry.get("failure"))

    def remember(resident_profile):
        memory = dict(resident_profile.get("memory") or {})
        memory["shortTerm"] = [*(memory.get("shortTerm") or []), short_term]
        memory["reflections"] = [*(memory.get("reflections") or []), reflection_entry]
        if isinstance(social_relationship, dict) and social_relationship.get("relationshipId"):
            relationships = memory.get("relationships") if isinstance(memory.get("relationships"), dict) else {}
            relationships[social_relationship["relationshipId"]] = {
                **(relationships.get(social_relationship["relationshipId"]) if isinstance(relationships.get(social_relationship["relationshipId"]), dict) else {}),
                "otherAgentId": social_relationship.get("otherAgentId"),
                "summary": f"Visible conversation completed with {social_relationship.get('otherAgentId')}.",
                "score": social_relationship.get("score"),
                "lastActionId": social_relationship.get("actionId"),
                "lastConversationId": social_relationship.get("conversationId"),
                "updatedAt": recent_entry.get("at"),
                "source": "live-agent-loop",
            }
            memory["relationships"] = relationships
        resident_profile["memory"] = _consolidate_resident_memory(memory)
        return resident_profile

    return _update_resident_profile_atomically(agent_id, remember)


def _live_agent_loop_record_social_outcome(state, agent_id, action, summary, now_iso):
    if not isinstance(action, dict) or not isinstance(summary, dict):
        return None
    if summary.get("actionType") != "life.social":
        return None
    if _canonical_world_action_status(summary.get("status")) != "completed":
        return None
    target = action.get("target") if isinstance(action.get("target"), dict) else {}
    other_agent_id = _resolve_agent_id(target.get("targetAgentId"))
    if not other_agent_id or other_agent_id == agent_id:
        return None
    result = summary.get("result") if isinstance(summary.get("result"), dict) else {}
    params = action.get("params") if isinstance(action.get("params"), dict) else {}
    conversation_topic = _live_agent_loop_clean_plan_text(params.get("conversationTopic"), limit=700)
    relationship_key = _live_agent_loop_relationship_key(agent_id, other_agent_id)
    if not relationship_key:
        return None
    summary_text = f"{agent_id} had a visible conversation with {other_agent_id}."
    if result.get("conversationId"):
        summary_text = f"{summary_text} Conversation {result.get('conversationId')} completed in-world."
    if conversation_topic:
        summary_text = f"{summary_text} They discussed: {conversation_topic}"
    with _WORLD_META_LOCK:
        meta = load_world_meta()
        relationships = meta.get("agentRelationships") if isinstance(meta.get("agentRelationships"), dict) else {}
        previous = relationships.get(relationship_key) if isinstance(relationships.get(relationship_key), dict) else {}
        previous_score = previous.get("score")
        try:
            next_score = min(1.0, max(-1.0, float(previous_score if previous_score is not None else 0) + 0.08))
        except (TypeError, ValueError):
            next_score = 0.08
        relationships[relationship_key] = {
            **previous,
            "agentId": relationship_key.split("::", 1)[0],
            "otherAgentId": relationship_key.split("::", 1)[1],
            "summary": summary_text,
            "score": round(next_score, 3),
            "lastOutcome": "visible-conversation-completed",
            "lastActionId": summary.get("id"),
            "lastLoopActionId": summary.get("loopActionId"),
            "lastConversationId": result.get("conversationId"),
            "lastTopic": conversation_topic,
            "updatedAt": now_iso,
        }
        meta["agentRelationships"] = relationships
        save_world_meta(meta)
    details = {
        "relationshipId": relationship_key,
        "otherAgentId": other_agent_id,
        "actionId": summary.get("id"),
        "conversationId": result.get("conversationId"),
        "score": relationships[relationship_key].get("score"),
        "topic": conversation_topic,
    }
    if conversation_topic:
        shared_signal = {
            "key": f"heard-from:{agent_id}:{hashlib.sha256(conversation_topic.encode('utf-8', errors='ignore')).hexdigest()[:12]}",
            "category": "social-knowledge",
            "objectInstanceId": None,
            "observationCount": 2,
            "lastObservedAt": now_iso,
            "memoryText": f"{agent_id} told me: {conversation_topic}",
            "text": conversation_topic,
            "occupiedByAgentIds": [],
        }
        _live_agent_loop_remember_resource_signal(other_agent_id, shared_signal)
        _live_agent_session_append(
            agent_id,
            kind="social",
            phase="verify",
            text=f"I told {other_agent_id}: {conversation_topic}",
            dedupe_key=f"social-topic:{summary.get('id')}:{agent_id}",
            action_id=summary.get("id"),
            details={"otherAgentId": other_agent_id, "topic": conversation_topic},
        )
        if _live_agent_session_current(other_agent_id):
            _live_agent_session_append(
                other_agent_id,
                kind="social",
                phase="observe",
                text=f"{agent_id} told me: {conversation_topic}",
                dedupe_key=f"social-topic:{summary.get('id')}:{other_agent_id}",
                action_id=summary.get("id"),
                details={"otherAgentId": agent_id, "topic": conversation_topic},
            )
    if isinstance(state, dict):
        _live_agent_loop_add_event(state, "social-relationship-updated", agent_id=agent_id, details=details)
    return details


def _live_agent_loop_trace(agent_state, phase, details=None, *, at=None):
    if not isinstance(agent_state, dict):
        return None
    details = details if isinstance(details, dict) else {}
    compact_details = _compact_json_value_for_storage(details, max_depth=4, max_items=32, string_limit=900)
    signature = hashlib.sha256(json.dumps({"phase": str(phase or "event"), "details": compact_details}, sort_keys=True, default=str).encode("utf-8")).hexdigest()[:16]
    existing = agent_state.get("decisionTrace") if isinstance(agent_state.get("decisionTrace"), list) else []
    if existing and isinstance(existing[-1], dict) and existing[-1].get("signature") == signature:
        return existing[-1]
    entry = {
        "id": f"trace-{uuid.uuid4().hex[:12]}",
        "at": at or _utc_now_iso(),
        "phase": str(phase or "event")[:80],
        "signature": signature,
        "details": compact_details,
    }
    agent_state["decisionTrace"] = _live_agent_loop_trim_list(
        [*(agent_state.get("decisionTrace") or []), entry],
        80,
        max_bytes=min(256 * 1024, LIVE_AGENT_LOOP_COLLECTION_MAX_BYTES),
    )
    return entry


